INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (4708, 'Influência é um multiplicador numérico usado na ordenação de resultados de busca. Um número maior significa que o fator correspondente tem mais influência nos resultados de busca; zero significa que o fator é ignorado. Mudar esses números não requer que o índice de busca seja reconstruído. Mudanças tem efeito imediatamente.', 'pt-br', 0);
