INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (4722, 'Gerenciando e exibindo campos de texto', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (4723, 'Criando campos de texto curtos', 'pt-br', 0);
