INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (4725, 'Cortando o comprimento do texto', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (4726, 'Na página <em>Gerenciar exibição</em>, é possível escolher para exibir uma versão cortada do texto e onde cortá-lo.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (4727, 'Exibindo resumos em vez de texto cortado', 'pt-br', 0);
