INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (4731, 'Direita', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (4732, 'Rótulo de estado', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (4733, '%name: não pode ser maior que @max caracteres.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (4734, 'Um breakpoint separa a altura ou a largura de viewports (telas, impressoras e outros tipos de saída de mídia) em etapas. Por exemplo, um breakpoint de largura de 40em cria duas etapas: uma para larguras de até 40em e outra para larguras acima de 40em. Breakpoints podem ser usados para definir quando os layouts devem mudar de um formato para outro, quando as imagens devem ser redimensionadas e outras alterações que precisam responder às mudanças na altura ou largura de viewport.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (4735, 'Multiplicador de resolução', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (4736, 'Os multiplicadores de resolução são uma medida de resolução de pontos de visualização do dispositivo, definida para que seja a proporção entre o tamanho físico de pixel do dispositivo ativo e o tamanho do <a href="http://en.wikipedia.org/wiki/Device_independent_pixel">pixel independente de dispositivo</a>. O módulo Breakpoint define multiplicadores como 1, 1,5 e 2. Ao definir breakpoints, módulos e temas podem definir quais multiplicadores se aplicam a cada breakpoint.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (4737, 'Definindo breakpoints e grupos de breakpoints', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (4738, 'Módulos e os temas podem usar a API fornecida pelo módulo Breakpoint para definir pontos de interrupção, grupos de pontos de interrupção e também para designar multiplicadores de resolução para pontos de interrupção.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (4739, 'Nome do autor do comentário', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (4740, 'Mudar o formato de texto para %text_format removerá permanentemente o conteúdo que não é permitido nesse formato de texto.<br><br>Salve suas mudanças antes de alternar o formato de texto para evitar perda de dados.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (4741, 'Exibição de visão da entidade', 'pt-br', 0);
