INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (4751, 'Selecionando filtros', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (4752, 'Cada filtro pode ter opções adicionais de configuração. Por exemplo, para o filtro "Limitar tags HTML permitidas", é necessário definir a lista de tags HTML que o filtro deixa no texto.', 'pt-br', 0);
