INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (4753, 'Ao criar ou editar dados em um campo que tenha formatos de texto ativados, os usuários podem selecionar o formato no campo na lista de seleção de formato de texto.', 'pt-br', 0);
