INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (4757, 'Definindo chaves e rótulos de opção', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (4758, 'Ao definir as opções de lista, é possível definir uma chave e um rótulo para cada opção na lista. O rótulo será mostrado para os usuários enquanto a chave é armazenada no banco de dados.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (4759, 'Escolhendo o tipo de campo de lista', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (4760, 'Há três tipos de campos de lista que armazenam diferentes tipos de dados: <em>valor flutuante</em>, <em>número inteiro</em> ou <em>texto</em>. O tipo <em>valor flutuante</em> permite armazenar valores decimais aproximados. O tipo <em>número inteiro</em> permite armazenar números inteiros, como anos (por exemplo, 2012) ou valores (por exemplo, 1, 2, 5, 305). O tipo de campo de lista <em>texto</em> permite armazenar valores de texto. Independentemente do tipo de campo de lista escolhido, você pode escolher quaisquer rótulos para a entrada de dados.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (4761, 'Dependência do módulo necessário @module', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (4762, 'Algumas das atualizações pendentes não podem ser aplicadas porque suas dependências não foram atendidas.', 'pt-br', 0);
