INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (5284, 'Permite que outros usuários entrem em contato com você através de um formulário de contato pessoal que mantém seu endereço de e-mail oculto. Note que alguns usuários privilegiados, como administradores do site, ainda são capazes de contatá-lo mesmo que você opte por desabilitar esta funcionalidade.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (5285, 'Exemplo: ''webmaster@exemplo.com'' ou ''vendas@exemplo.com,suporte@exemplo.com''. Para especificar múltiplos destinatários, separe cada endereço de e-mail com uma vírgula.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (5286, 'O %recipient é um endereço de e-mail inválido.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (5287, '%sender-name (@sender-from) enviou um e-mail para %recipient-name.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (5288, 'Habilitando tradução de campos', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (5289, 'Você pode definir quais campos de uma entidade de conteúdo podem ser traduzidos. Por exemplo, talvez você queira traduzir o título e o campo de corpo enquanto deixa o campo de imagem sem tradução. Se você excluir um campo da tradução, ele ainda será mostrado no formulário de edição de conteúdo, mas quaisquer mudanças feitas nesse campo serão aplicadas a <em>todas</em> as traduções desse conteúdo.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (5290, 'Se a tradução estiver ativa, você pode traduzir uma entidade de conteúdo por meio da aba Traduzir (ou do link Traduzir). A página de traduções de uma entidade fornece uma visão geral do status da tradução para o conteúdo atual e permite à você incluir, editar e excluir suas traduções. Esse processo é semelhante para cada entidade de conteúdo traduzível em seu site.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (5291, 'Mudando o idioma de origem de uma tradução', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (5292, 'Quando você inclui uma nova tradução, o texto original que você está traduzindo é exibido no formulário de edição como <em>origem</em>. Se pelo menos uma tradução do conteúdo original já existir ao incluir uma nova tradução, você poderá escolher entre o conteúdo original (padrão) ou uma das outras traduções como a origem, usando a lista de seleção na seção Idioma de origem. Depois de salvar a tradução, o idioma de origem escolhido é então listado na aba Tradução do conteúdo.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (5293, 'Configurando status de traduções', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (5294, 'Se você editar uma tradução em um idioma, talvez queira configurar o status das outras traduções como <em>desatualizada</em>. É possível configurar esse status marcando a caixa de seleção <em>Sinalizar outras traduções como desatualizadas</em> na seção Tradução do formulário de edição de conteúdo. O status será visível na página Traduções.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (5295, 'Gerenciando e exibindo campos de data', 'pt-br', 0);
