INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (1338, 'Fid', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (5337, 'Você pode adicionar um idioma que não seja fornecido na lista suspensa escolhendo <em>Idioma personalizado</em> no fim da lista. Em seguida, é necessário configurar o código de idioma, nome e direção no formulário fornecido.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (5338, 'Configurando idiomas do conteúdo', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (5339, 'Adicionando um bloco de troca de idiomas', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (5340, 'Tornar um bloco visíveis por idioma', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (5341, 'Escolhendo idiomas do usuário', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7363, 'Campos não traduzíveis só podem ser modificados quando da atualização do idioma original.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7364, 'É necessário editar campos não-traduzíveis de conteúdo moderado no formulário da língua original.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7365, 'Traduções não podem ser marcadas como obsoletas quando o conteúdo é moderado.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (1275, 'A versão do Drupal que está instalado aqui foi cancelada e não está mais disponível para download. Atualizar agora é extremamente recomendado!', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (5342, 'Usuários podem escolher um <em>Idioma do site</em> em suas páginas de perfil. Esse idioma é utilizado para e-mails e pode ser usado pelos módulos para determinar o idioma de um usuário. Ele também poderá ser usado para o texto da interface, se o método <em>Usuário</em> estiver ativo como um método de <em>Detecção e seleção</em> (veja abaixo). Usuários administrativos podem escolher um <em>Idioma de páginas de administração</em> separado para o texto da interface nas páginas de administração. Essa configuração está disponível na página do perfil do usuário somente se o método <em>Páginas de administração da conta</em> estiver ativado (veja abaixo).', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (5343, '<em>URL</em> configura o idioma da interface com base em um prefixo de caminho ou domínio (por exemplo, especificar <em>de</em> para Alemão resultaria em URLs como <em>exemplo.com/de/contato</em>). O idioma padrão não precisa de um prefixo de caminho, mas também pode ter um. Se a detecção de idioma for feita por nome de domínio, um domínio precisa ser especificado para cada idioma.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (5344, '<em>Sessão</em> determina o idioma da interface a partir de um parâmetro de solicitação ou de sessão (por exemplo, <em>exemplo.com?language=de</em> configuraria o idioma da interface para Alemão com base no uso de <em>de</em> como o parâmetro <em>language</em>).', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (5345, '<em>Usuário</em> segue a configuração de idioma definida na página do perfil do usuário.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (5346, 'As <em>Páginas de administração da conta</em> seguem a configuração definida em <em>Idioma das páginas de administração</em> na página do perfil de um usuário administrativo. Esse método é semelhante ao método <em>Usuário</em>, mas apenas configura o idioma do texto da interface nas páginas de administração, independentemente do idioma do texto da interface em outras páginas.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (5347, '<em>Idioma selecionado</em> permite que você informe o idioma padrão do site ou um idioma específico como o idioma de fallback. Este método deve ser listado por último.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (5348, 'O endereço de e-mail do autor do comentário a partir do formulário comentário, se o usuário for anônimo, e os usuários anônimos podem/devem deixar suas configurações de informações de contatos ativas.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (5349, 'Lista separada por vírgula de endereços de e-mail do destinatário.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (5350, 'Promover, mudar o proprietário, editar revisões e executar outras tarefas em todos os tipos de conteúdo.', 'pt-br', 0);
