INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (5366, 'Quando seu site verifica se existem atualizações disponíveis, ele pode notificar uma lista de usuários por e-mail. Coloque cada endereço em uma linha separada. Se estiver em branco, nenhum e-mail será enviado.', 'pt-br', 0);
