INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (5371, 'Esta página permite que os administradores cadastrem novos usuários. Os endereços de e-mail e nomes de usuário devem ser exclusivos.', 'pt-br', 0);
