INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (5374, 'Novos usuários serão solicitados a validar seus endereços de e-mail antes de efetuar login no site e receberão uma senha gerada pelo sistema. Com esta configuração desmarcada, usuários pode efetuar login imediatamente após o registro e podem escolher suas próprias senhas durante o registro.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (5375, 'Endereço de e-mail para notificação', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (5376, 'O endereço de e-mail utilizado como endereço ''De'' para todas as notificações de conta listadas abaixo. Se a opção <em>''Visitantes, mas é necessária a aprovação do administrador''</em> for selecionada acima, um e-mail de notificação também será enviado para esse endereço para quaisquer cadastros novos. Deixe em branco para usar o endereço de e-mail padrão do sistema <em>(%site-email).</em>', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (5377, 'Edite a mensagem de e-mail de boas-vindas enviada para novas contas de usuário criadas por um administrador.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (5378, 'Edite a mensagem de e-mail de boas-vindas enviada aos novos usuários após o registro, quando a aprovação administrativa for necessária.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (5379, 'Edite o e-mail de notificação do administrador do site quando há novos membros aguardando aprovação administrativa.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (5380, 'Edite a mensagem de e-mail de boas-vindas enviada aos novos usuários após o registro, quando nenhuma aprovação administrativa for necessária.', 'pt-br', 0);
