INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7196, 'Usuários com permissão para administrar tipos de conteúdo podem adicionar suporte à mídia adicionando um campo de referência de mídia ao tipo de conteúdo na página de administração do tipo de conteúdo. (O mesmo se aplica aos tipos de blocos, termos de taxonomia, perfis de usuário e outros conteúdos que suportam campos.) Um campo de referência de mídia pode se referir a qualquer tipo de mídia configurado. É possível permitir vários tipos de mídia no mesmo campo.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7197, 'Diferenças entre os campos de referência de mídia, arquivo e imagem', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (1637, '@interval atrás', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7198, 'Campos de referência de <em>mídia</em> oferecem várias vantagens sobre referências básicas de <em>arquivos</em> e <em>imagens</em>:', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7199, 'Os campos de referência de mídia podem fazer referência a vários tipos de mídia no mesmo campo.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7200, 'Os campos também podem ser adicionados aos próprios tipos de mídia, o que significa que metadados personalizados como descrições e tags de taxonomia podem ser adicionados para a mídia referenciada. (Os campos básicos de arquivos e imagens não suportam isso.)', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7201, 'Os tipos de mídia para arquivos de áudio e vídeo são fornecidos por padrão, portanto, não há necessidade de configuração adicional para carregar essas mídias.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7202, 'Projetos contribuídos ou personalizados podem fornecer fontes de mídia adicionais (como sites de terceiros, Twitter, etc.).', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7203, 'Os itens de mídia existentes podem ser reutilizados em quaisquer outros itens de conteúdo com um campo de referência de mídia.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7204, 'Para mais informações, consulte a <a href="@help_url">Página de ajuda de mídia</a>.', 'pt-br', 0);
