INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (5615, 'As tabelas de Views incluem marcação semântica para melhorar a acessibilidade. As células de dados são associadas automaticamente às células de cabeçalho por meio dos atributos id e header. Para melhorar a acessibilidade de suas tabelas, é possível incluir elementos descritivos dentro das configurações da tabela de Views. O elemento <em>cabeçalho</em> pode adicionar um contexto para uma tabela, facilitando sua compreensão. O elemento <em>resumo</em> pode dar uma visão geral de como os dados foram organizados e de como navegar na tabela. Tanto a legenda quanto o resumo são visíveis por padrão e também são implementados de acordo com as diretrizes de HTML5.', 'pt-br', 0);
