INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (5639, 'Abas são botões exibidos em uma barra na parte superior da tela. Algumas abas executam uma ação (como iniciar o modo de Edição), enquanto outras abas alternam qual bandeja é aberta.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (5640, 'Bandejas', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (5641, 'Bandejas são geralmente listas de links que podem ser hierárquicas como um menu. Se uma bandeja for aberta, ela será exibida verticalmente ou horizontalmente abaixo da barra de abas, dependendo da largura do navegador. Somente uma bandeja pode ser aberta por vez. Se você clicar em outra aba, essa bandeja substituirá a bandeja que está sendo exibida. Em navegadores com larguras maiores, o usuário pode alternar de vertical para horizontal usando um link na parte inferior ou direita da bandeja. Menus hierárquicos possuem comportamento de abertura/fechamento apenas no modo vertical; se você exibir uma bandeja contendo um menu hierárquico horizontal, apenas os links do nível superior estarão disponíveis.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (5642, 'Sua conta será bloqueada e você não poderá mais fazer login. Todo o seu conteúdo permanecerá atribuído ao seu nome de usuário.', 'pt-br', 0);
