INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (5710, 'Isso irá reindexar o conteúdo nos índices de busca de todas as páginas de busca ativas. A busca continuará a funcionar, mas conteúdo novo não será indexado até que todo o conteúdo existente tenha sido reindexado. Não é possível desfazer esta ação.', 'pt-br', 0);
