INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (5737, 'O autor desta tradução.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (5738, 'Um booleano indicando se a tradução está ou não visível para não tradutores.', 'pt-br', 0);
