INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (5741, 'Horário em que a tradução foi alterada', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (5742, 'O registro de data e hora do Unix de quando a tradução foi recentemente salva.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (5743, 'Entidades e tipos de entidades', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (5744, 'Subtipos de entidade', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (5745, 'Alguns tipos de entidade de conteúdo são agrupados ainda mais em subtipos (por exemplo, é possível ter tipos de conteúdo de artigo e página dentro do tipo de entidade de conteúdo do site principal e vocabulários de tag e de categoria dentro do tipo de entidade de termo de taxonomia); outros tipos de entidades como contas do usuário, não possuem subtipos. Programadores usam o termo <em>pacote</em> para subtipos de entidades.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (5746, 'Campos e tipos de campos', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (5747, 'Os tipos e subtipos de entidade de conteúdo armazenam a maior parte do texto, arquivos e outras informações em <em>campos</em>. Campos são agrupados por <em>tipo de campo</em> e os tipos de campo definem qual tipo de dados podem ser armazenados nesse campo, como texto, imagens ou referências de termo de taxonomia.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (5748, 'Formatadores e modos de visualização', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (5749, 'Os tipos e subtipos de entidade de conteúdo podem ter um ou mais <em>modos de exibição</em>, que são usados para exibir os itens de entidade. Por exemplo, um item de conteúdo pode ser visualizado no modo de conteúdo completo em sua própria página, com o modo de chamada em uma lista ou com o modo RSS em um feed. Em cada modo de exibição, cada campo pode ser ocultado ou exibido e, se exibido, será possível escolher e configurar o <em>formatador</em> que é usado para exibir o campo. Por exemplo, um campo de texto longo pode ser exibido cortado ou completo e campos de referência de termo de taxonomia podem ser exibidos com texto simples ou vinculados à página do termo de taxonomia.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (5750, 'Widgets e modos de formulário', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7211, '<em>A fonte de mídia não pode ser alterada depois que o tipo de mídia é criado.</em>', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7212, 'Use arquivos de áudio para mídia reutilizável.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7213, 'Use arquivos de vídeo para mídia reutilizável.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7214, 'O sistema de destino contém dados que não foram criados por uma migração.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7215, 'Migrar configurações do Drupal', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (11786, 'tags forçadas de source_module', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7216, 'Site antigo', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (2060, 'Dicas de composição', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (50, 'Configurar as traduções', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (2061, 'Nesta página você pode exportar as expressões traduzidas usadas no seu site. Você pode exportar um arquivo no formato Gettext Portable Object (<em>.po</em>), incluindo o texto original e a tradução (para quando você quiser compartilhar a tradução com outras pessoas), ou no formato Gettext Portable Object Template (<em>.pot</em>), incluindo apenas o texto original (para quando você quiser traduzir o seu site usando um editor Gettext).', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (2062, 'Configurações do formulário de envio', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (2063, 'O nome legível de máquina deve conter apenas letras minúsculas, números e sublinhados.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (2064, 'O tipo de conteúdo %name foi criado.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (2065, 'Tem certeza que deseja reconstruir as permissões ao conteúdo do site?', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (2144, 'Última verificação: @time atrás', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (5751, 'Os tipos e subtipos de entidade de conteúdo podem ter um ou mais <em>modos de formulário</em>, que são usados para edição. Por exemplo, um item de conteúdo pode ser editado em um formato compactado com apenas alguns campos editáveis ou em um formato completo que permite que todos os campos sejam editados. Em cada modo de formulário, cada campo pode ser ocultado ou exibido e, se exibido, será possível escolher e configurar o <em>widget</em> que é usado para editar o campo. Por exemplo, um campo de referência de termo de taxonomia pode ser editado usando uma lista de seleção, botões de opções ou com um widget de autocompletar.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (5752, 'Habilitando tipos de campo, widgets e formatadores', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (5753, 'Manipulador de campo de entidade de views', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (5754, 'Criando um campo', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (5755, 'Na página <em>Gerenciar campos</em> do seu tipo ou subtipo de entidade, é possível incluir, configurar e excluir campos para esse tipo ou subtipo de entidade. Cada campo possui um <em>nome da máquina</em> que é usado internamente para identificar o campo e que deve ser exclusivo em um tipo de entidade. Quando um campo é criado, não é possível mudar o nome da máquina. A maioria dos campos possui dois tipos de configurações. As configurações de nível de campo dependem do tipo de campo e afetam como os dados são armazenados no campo. Quando são configurados, eles não podem mais ser mudados. Exemplos incluem quantos valores de dados são permitidos para o campo e onde os arquivos são armazenados. As configurações de nível de subtipo são específicas para cada subtipo de entidade no qual o campo é usado e podem ser mudadas posteriormente. Exemplos incluem o rótulo do campo, o texto de ajuda, o valor padrão e se o campo é obrigatório ou não. É possível voltar nessas configurações clicando no link <em>Editar</em> do campo na página <em>Gerenciar campos</em>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (5756, 'Reutilizando campos', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (5757, 'Configurando a edição de campo', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (5758, 'Na página <em>Gerenciar exibição de formulário</em> do seu tipo ou subtipo de entidade, você pode configurar o modo como os dados do campo são editados por padrão e em cada modo de formulário. Se o tipo de entidade possui múltiplos modos de formulário (na maioria dos sites, a maioria das entidades não possuem), você poderá alternar entre os modos de formulário na parte superior da página e também alternar entre configurações padrão ou personalizadas na seção <em>Configurações de exibição personalizadas</em>. Para cada campo em cada modo de formulário, você pode selecionar o widget que será usado para edição. Alguns widgets possuem opções de configuração adicionais, como o tamanho de um campo de texto, e elas podem ser editadas usando o botão Editar (semelhante a uma roda). Você também pode mudar a ordem dos campos no formulário. Você pode excluir um campo de um formulário escolhendo <em>Oculto</em> na lista suspensa de widget ou arrastando-o para a seção <em>Desativado</em>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (5759, 'Configurando a exibição do campo', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (5760, 'Na página <em>Gerenciar exibição</em> do seu tipo ou subtipo de entidade, é possível configurar o modo como cada campo é exibido por padrão e em cada modo de exibição. Se seu tipo de entidade possui múltiplos modos de exibição, será possível alternar entre os modos de exibição na parte superior da página e também alternar entre configurações padrão e personalizadas de cada modo de exibição na seção <em>Configurações de exibição personalizadas</em>. Para cada campo em cada modo de exibição, é possível escolher como exibir o rótulo do campo na lista suspensa <em>Rótulo</em>. Você também pode selecionar o formatador para uso na exibição. Alguns formatadores possuem opções de configuração que podem ser editadas usando o botão Editar (semelhante a uma roda). Você também pode mudar a ordem de exibição dos campos. Você pode excluir um campo de um modo de exibição específico escolhendo <em>Oculto</em> na lista suspensa do formatador ou arrastando-o para a seção <em>Desativado</em>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (5761, 'Configurando modos de visualização e de formulário', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (5762, 'Listando campos', 'pt-br', 0);
