INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (5791, 'A revisão de Conteúdo de Bloco é um histórico das mudanças feitas no conteúdo do bloco.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (5792, 'O estilo de imagem responsiva %label foi salvo.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (5793, 'Informações de campo, widget e formatador', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (5794, 'Fornecido por módulos', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (5795, 'Fornecido pelo core do Drupal', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (5796, 'Conforme mencionado anteriormente, alguns tipos de campo, widgets e formatadores são fornecidos pelo core do Drupal. Aqui estão algumas observações sobre como usar alguns deles:', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (5797, '<strong>Campos de número</strong>: Quando você adiciona um campo de número, você pode escolher entre três tipos: <em>decimal</em>, <em>flutuante</em> e <em>inteiro</em>. O tipo de campo de número <em>decimal</em> permite que os usuários digitem valores decimais, com números fixos de casas decimais. O tipo de campo de número <em>flutuante</em> permite que os usuários digitem valores decimais aproximados. O tipo de campo de número <em>inteiro</em> permite que os usuários digitem números inteiros, como anos (por exemplo, 2012) ou valores (por exemplo, 1, 2, 5, 305). Ele não permite decimais.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (5798, 'Definindo estilos de imagem', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (5799, 'Nomeando estilos de imagem', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (5800, 'Quando você define um estilo de imagem, é necessário escolher um nome de exibição e um nome de máquina. O nome de exibição é mostrado em páginas administrativas e o nome de máquina é usado para gerar a URL para acessar uma imagem processada nesse estilo. Há duas abordagens comuns para nomear estilos de imagem: com base nos efeitos que estão sendo aplicados (por exemplo, <em>Quadrado 85x85</em>) ou com base no local em que você planeja utilizar o estilo (por exemplo, <em>Imagem do perfil</em>).', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (5801, 'Configurando campos de imagem', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (5802, 'O tamanho máximo do arquivo que pode ser transferido por upload é limitado pelas configurações do PHP do servidor, mas você pode restringir ainda mais configurando um <em>Tamanho máximo de upload</em> nas configurações do campo (esta configuração pode ser alterada posteriormente). O tamanho máximo do arquivo, seja das configurações do servidor PHP ou da configuração do campo, é exibido automaticamente para usuários no texto de ajuda do campo de imagem.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (5803, 'Você também pode configurar uma imagem padrão que será usada no caso que nenhuma imagem seja transferida por upload em um campo de imagem. Esse padrão pode ser definido para todas as instâncias do campo nas configurações de armazenamento do campo ao criar um campo, podendo ser substituída para cada subtipo de entidade que usa o campo.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (5804, 'Configurando exibições e exibições de formulário', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (2159, 'Quem está online', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (5805, 'Na página <em>Gerenciar exibição</em> é possível escolher o formatador da imagem que determina o estilo de imagem que é usado para exibir a imagem em cada modo de exibição e definir se a imagem deve ser exibida como um link ou não. Na página <em>Gerenciar exibição do formulário</em> é possível configurar o widget de upload de imagem, incluindo a configuração do estilo de imagem de visualização mostrado no formulário de edição de entidade.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (5806, 'Configuração do idioma selecionado', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (5807, 'O idioma padrão selecionado não existe mais.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (5808, 'Configuração de detecção de idioma salva.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (5809, 'Códigos de idioma ou outro texto personalizado para uso como um prefixo de caminho para a detecção de idioma de URL. Para o idioma de substituição selecionado, esse valor pode ser deixado em branco. <strong>A modificação desse valor pode quebrar as URLs existentes. Use com cuidado em um ambiente de produção.</strong> Exemplo: especificar “portugues” como o código do prefixo do caminho para o Português, resulta em URLs como "exemplo.com/portugues/contato".', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (5810, 'A URI de link pode ser acessada pelo usuário.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (5811, 'O caminho ''@uri'' está inacessível.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (5812, 'O caminho ''@uri'' é inválido.', 'pt-br', 0);
