INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (5833, 'A interface padrão do usuário de arrastar-e-soltar para ordenar tabelas na interface administrativa, apresenta um desafio para alguns usuários, incluindo usuários de leitores de tela e outras tecnologias assistivas. A interface de arrastar-e-soltar pode ser desativada em uma tabela clicando em um link rotulado "Mostrar pesos de linha" acima da tabela. A interface de substituição permite que usuários ordenem a tabela escolhendo pesos numéricos em vez de arrastar linhas de tabela.', 'pt-br', 0);
