INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7221, 'Reconheço que posso perder dados. Continue mesmo assim.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7222, 'Há conteúdo conflitante desses tipos:', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7223, 'Na <a href=":cache-settings">página Desempenho</a>, você pode configurar por quanto tempo navegadores e proxies podem armazenar páginas com base no cabeçalho Cache-Control. Esta configuração é ignorada pelo módulo Internal Page Cache, que armazena páginas permanentemente até a invalidação, a menos que eles carreguem um cabeçalho de expiração. Não há outra configuração.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7224, 'O módulo Settings Tray permite que usuários com permissões de <a href=":administer_block_permission">Administrar blocos</a> e <a href=":contextual_permission">Usar links contextuais</a>, editem blocos sem visitar uma página separada. Para mais informações, consulte a <a href=":handbook_url">documentação on-line do módulo Settings Tray</a>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7225, 'Editando blocos no local', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (2260, 'Mensagens de status', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7226, 'Para editar blocos no lugar, clique no botão <strong>Editar</strong> na barra de ferramentas e clique no bloco ou escolha "Editar rápido" no link contextual do bloco. (Consulte o <a href=":contextual">módulo Links Contextuais para obter</a> mais informações sobre como usar links contextuais.)', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7227, 'A bandeja de configurações para o bloco será aberta em uma barra lateral, com uma forma compacta para configurar o que é mostrado no bloco.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7228, 'Salve o formulário e as alterações serão imediatamente visíveis na página.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7229, 'Especifique o formato da entrada do syslog. As variáveis disponíveis são: <dl><dt><code>!base_url</code></dt><dd>URL base do site.</dd><dt><code>!timestamp</code></dt><dd>Metamp de tempo unix da entrada de registro.</dd><dt><code>!type</code></dt><dd>A categoria à qual essa mensagem pertence.</dd><dt><code>!ip</code></dt><dd>Endereço IP do usuário que aciona a mensagem.</dd><dt><code>!request_uri</code></dt><dd>O URI solicitado.</dd><dt><code>!referer</code></dt><dd>Http Referer se estiver disponível.</dd><dt><code>!severity</code></dt><dd>O nível de gravidade do evento; varia de 0 (Emergência) a 7 (Depuração).</dd><dt><code>!uid</code></dt><dd>identificação de usuário.</dd><dt><code>!link</code></dt><dd>Um link para associar com a mensagem.</dd><dt><code>!message</code></dt><dd>A mensagem para armazenar no registro.</dd></dl>', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7230, 'O caminho ''%path'' é inválido ou você não tem acesso a ele.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7231, '%capital_name contém os seguintes termos.', 'pt-br', 0);
