INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7243, 'Habilite esta opção para produzir um link absoluto. Necessário se você quiser usar o caminho como destino de link.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7244, 'Force um parâmetro <code>destination</code> no link para retornar o usuário à view original ao concluir a ação do link. A maioria das operações inclui um destino por padrão e essa configuração não é mais necessária.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7245, 'Texto de dica que aparece dentro do campo Min quando vazio.', 'pt-br', 0);
