INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7247, 'Texto de dica que aparece dentro do campo quando vazio.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7248, 'Não há tipos de fluxo de trabalho disponíveis. Para criar fluxos de trabalho, você precisa instalar um módulo que forneça um tipo de fluxo de trabalho. Por exemplo, o módulo <a href=":content-moderation">Content Moderation</a> fornece um tipo de fluxo de trabalho que permite fluxos de trabalho para entidades de conteúdo.', 'pt-br', 0);
