INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (5873, 'Não há links internos quebrados', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (5874, 'Enviado por @author_name em @date', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (5875, 'Buscas procuram por palavras-chave exatas, sem distinção entre maiúsculas e minúsculas. Palavras-chave mais curtas que o comprimento mínimo são ignoradas.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (5876, 'Use OR em maiúsculas para obter mais resultados. Exemplo: gato OR cachorro (o conteúdo contém "gato" ou "cachorro").', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (5877, 'Você pode usar AND em maiúsculas para requisitar todas as palavras, mas isso é o mesmo que o comportamento padrão. Exemplo: gato AND cachorro (o mesmo que gato cachorro, o conteúdo deve conter "gato" e "cachorro").', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (5878, 'Use aspas para buscar uma frase. Exemplo: "o gato come o rato".', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (5879, 'É possível preceder palavras-chaves com - para excluí-las; deve-se ainda ter pelo menos uma palavra-chave "positiva". Exemplo: gato -cachorro (o conteúdo deve conter gato, mas não deve conter cachorro).', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (5880, 'O usuário é administrador', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (5881, 'Adiciona o usuário anônimo nas entidades correspondidas.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (5882, 'Incluir o usuário anônimo.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (5883, 'A busca de usuário procura por nomes de usuários e nomes de usuário parciais. Exemplo: mar corresponderia aos nomes de usuário mar, delmar e maryjane.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (5884, 'É possível usar * como um curinga dentro de sua palavra-chave. Exemplo: m*r corresponderia aos nomes de usuário mar, delmar e elementary.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (5885, 'Não foi localizada nenhuma view elegível.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (5886, 'A view não é baseada em um tipo de entidade traduzível ou o site não é multilíngue.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (5887, 'O display "@display" usa um link "Mais", mas não há exibições às quais ela possa vincular-se. É necessário especificar uma URL customizada.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (5888, 'Desativar a reescrita SQL omitirá todas as tags de consulta, ou seja, desativará as verificações de acesso de nodes, bem como irá sobrescrever as implementações de hook_query_alter() em outros módulos.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (5889, '@count segundo@count segundos', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (5890, 'Permissões de conta', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (5891, 'A senha com hash', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (5892, 'Senha existente', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (5893, 'Exibe o nome do autor.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (5894, 'Tem certeza que deseja criar um novo @type %name?', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (5895, 'Usando o formulário de contato pessoal', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (5896, 'Os visitantes do site podem enviar por e-mail usuários registrados em seu site usando o formulário de contato pessoal, sem saber ou conhecer o endereço de e-mail do destinatário. Quando um visitante do site visualiza um perfil do usuário, o visualizador verá uma aba ou um link <em>Contato</em> que o leva ao formulário de contato pessoal. O link de contato pessoal não é mostrado quando você visualiza seu próprio perfil e os usuários devem ter as permissões <em>Visualizar informações do usuário</em> (para ver perfis do usuário) e <em>Usar formulários de contato pessoal dos usuários</em> para ver o link. O usuário cujo perfil está sendo visualizado também deve ter seu formulário de contato pessoal ativado (isso é uma configuração na conta do usuário) e os visualizadores com permissão de <em>Administrar usuários</em> podem ignorar essa configuração.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (5897, 'Configurando formulários de contato', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (5898, 'Link para formulários de contato', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (5899, 'Adicionando conteúdo aos formulários de contato', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (5900, '@label (tradução não é suportada).', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (5903, 'Configurando exibições de formulário', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (5904, 'Campos de referência possuem vários widgets disponíveis na página <em>Gerenciar exibição do formulário</em>:', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (5905, 'O widget <em>Caixas de seleção/botões de opções</em> exibe as entidades existentes para o tipo de entidade como caixas de seleção ou botões de opções com base no <em>Número de valores permitido</em> configurado para o campo.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (5906, 'O widget <em>Lista de seleção</em> exibe as entidades existentes em uma lista suspensa ou em uma caixa de lista de rolagem com base no <em>Número de valores permitido</em> configurado para o campo.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (5907, 'O widget <em>Autocompletar automaticamente</em> exibe campos de texto onde os usuários podem digitar etiquetas de entidades com base no <em>Número de valores permitido</em>. O widget pode ser configurado para exibir todas as entidades que contenham os caracteres digitados ou que estejam restritas àquelas que começam com esses caracteres.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (5908, 'O widget <em>Autocompletar automaticamente (estilo de tags)</em> exibe um campo para diversos textos no qual os usuários podem digitar etiquetas de entidade em uma lista separada por vírgulas.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (5909, 'Seu servidor não é capaz de exibir o progresso de upload de arquivo. O progresso de upload de arquivo requer um servidor Apache executando PHP com mod_php ou Nginx com PHP-FPM.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (5910, 'Seu servidor não é capaz de exibir o progresso de upload de arquivo. O progresso de upload de arquivo requer que PHP seja executado com mod_php ou PHP-FPM, e não como FastCGI.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (5911, 'Exibir o caminho de download', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (5912, 'Exibir o filemime como ícone', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (5913, 'Detectar tar', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (5914, 'Vincular este campo à URL de download do arquivo', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (5915, 'Link de arquivo', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (5916, 'Incluir tar na extensão', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (5917, 'Se a parte do nome do arquivo antes da extensão for ''.tar'', inclua-a na saída da extensão.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (5918, 'Exibir a URI de download do arquivo', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (5919, 'Exibir um ícone', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (5920, 'O ícone representa o tipo de arquivo, e não o texto MIME (como "image/jpeg")', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (5921, 'Usando campos de texto com formatos de texto', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (5922, 'Os campos de texto que permitem formatos de texto são aqueles com a indicação "formatado" na descrição. Esses são <em>Texto (formatado, longo, com resumo)</em>, <em>Texto (formatado)</em> e <em>Texto (formatado, longo)</em>. Você não pode alterar o tipo de campo depois que ele for criado.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (5923, 'Configurando o tipo de link permitido', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7372, 'Bloco de conteúdo', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7458, 'Use a URL de vídeo remoto para mídia reutilizável.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (2349, 'O endereço IP do computador do qual o comentário foi enviado.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (5924, 'Nas configurações do campo é possível definir o tipo de link permitido para <em>somente links internos</em>, <em>somente links externos</em> ou <em>links internos e externos</em>. As opções <em>somente links internos</em> e <em>links internos e externos</em> permitem um widget de autocompletar automaticamente para links internos, de modo que o usuário não precisa copiar ou lembrar uma URL.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (5926, '@type %title foi revertido para a revisão de %revision-date.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (5927, 'Aumentando a velocidade de seu site', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (5928, 'Código de idioma padrão do site', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (5929, 'Cache de páginas', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (5930, 'Permitir que os usuários incluam novos termos gradualmente, constrói um vocabulário conforme o conteúdo é incluído e editado. Usuários poderão incluir novos termos se um dos dois widgets de <em>Autocompletar automaticamente</em> for escolhido para o campo de referência de termo de taxonomia na página <em>Gerenciar exibição de formulário</em> para o campo. Também será necessário ativar a opção <em>Criar entidades referenciadas se elas ainda não existirem</em> e restringir o campo para um vocabulário.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (5931, 'Se você escolher <em>Texto (simples)</em> ou <em>Texto (formatado)</em> como o tipo de campo na página <em>Gerenciar campos</em>, então, um campo com uma única linha será exibido. Ao configurar o campo, você pode alterar o comprimento máximo do texto nas <em>Configurações de campo</em>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (5932, 'Se você escolher <em>Texto (simples, longo)</em>, <em>Texto (formatado, longo)</em> ou <em>Texto (formatado, longo com resumo)</em> na página <em>Gerenciar campos</em>, os usuários poderão digitar texto de comprimento ilimitado. Na página <em>Gerenciar exibição de formulário</em>, é possível configurar o número de linhas que são exibidas para os usuários.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (5933, 'Como uma alternativa ao uso de uma versão cortada do texto, é possível inserir um resumo separado escolhendo o tipo de campo <em>Texto (formatado, longo com resumo)</em> na página <em>Gerenciar campos</em>. Mesmo quando a <em>Entrada de resumo</em> está habilitada e os resumos são preenchidos, você pode exibir um texto <em>cortado</em> escolhendo o formato apropriado na página <em>Gerenciar exibição</em>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (5934, 'Link para o usuário', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (5935, 'Exibir o nome do usuário ou do autor.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (5936, 'Senha é obrigatória para a alteração de campo protegido', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (2452, 'Listar e editar os comentários e a fila de aprovação de comentários.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (5937, 'Texto para uso nessa variante, @count será substituído pelo valor.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (5938, 'Texto para uso na forma singular, @count será substituído pelo valor.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (5939, 'Contém apenas caracteres US ASCII', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (5940, 'Transação completa! Obrigado por sua compra.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (5941, 'Resolvendo conteúdo ausente', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (5942, 'As seguintes @entity-type traduções serão excluídas:', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (5943, 'Excluir a tradução de @language', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (5944, 'A tradução @entity-type %label @language foi excluída.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (5945, 'Tem certeza que deseja excluir a tradução @language do @entity-type %label?', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (5946, 'A configuração core.extension não existe.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (5947, 'Não é possível instalar o módulo %module, uma vez que ele não existe.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (5948, 'Não é possível instalar o módulo %module, uma vez que o módulo %dependent_module está instalado.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (5949, 'Não é possível instalar o tema %theme, uma vez que ele não existe.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (5950, 'Não foi possível instalar o tema %theme porque ele precisa do tema %required_theme.', 'pt-br', 0);
