INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (5954, 'A configuração %name depende da extensão %owner  que não será instalada após a importação.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (5955, 'Não foi possível instalar o módulo %module pois ele precisa do módulo %required_module.Não foi possível instalar o módulo %module pois ele precisa dos módulos %required_module.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (5956, 'A configuração %name depende do módulo %module que não estará instalado após a importação.A configuração %name depende dos módulos (%module) que não estarão instalados após a importação.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (5957, 'A configuração %name depende do tema %theme que não será instalado após a importação.A configuração %name depende do tema (%theme) que não será instalado após a importação.', 'pt-br', 0);
