INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (5976, 'Limite cortado: @trim_length caracteres', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (5977, 'Trabalhando com Views multilíngues', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (5978, 'Se o seu site tiver múltiplos idiomas e entidades traduzidas, cada linha de resultado em uma view conterá um tradução de cada entidade envolvida (uma view poderá envolver múltiplas entidades se ela usar relacionamentos). É possível usar um filtro para restringir sua view para um idioma: sem a filtragem, se uma entidade possuir três traduções, ela incluirá três linhas nos resultados e, se você filtrar por idioma, aparecerá um resultado no máximo (podendo ser zero, se essa entidade específica não possuir uma tradução correspondente à sua opção de filtro de idioma). Se uma view usar relacionamentos, cada entidade no relacionamento precisará ser filtrada separadamente. É possível filtrar uma view para uma opção de idioma fixo, como Inglês ou Português, ou para o idioma selecionado pela página na qual a view é exibida (o idioma que é selecionado para a página pelas configurações de detecção de idioma ou para a interface de conteúdo ou do usuário).', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (5979, 'Como cada linha de resultado contém uma tradução específica de cada entidade, filtros de nível de campo também são relativos a essas traduções de entidade. Por exemplo, se sua visualização possuir um filtro que especifica que o título da entidade deve conter uma palavra em inglês específica, você provavelmente filtrará todas as linhas que contenham traduções chinesas, já que elas não conterão tal palavra em inglês. Se sua visualização também possuir um segundo filtro especificando que o título deve conter uma palavra chinesa específica e se a lógica "And" estiver sendo usada para filtragem, você provavelmente acabará não obtendo nenhum resultado na visualização, já que possivelmente nenhuma tradução da entidade conterá as palavras em inglês e em chinês no título.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (5980, 'Independentemente da filtragem, é possível escolher o idioma de exibição (o idioma usado para exibir as entidades e seus campos) por meio de uma configuração na exibição. Suas opções de idioma são as mesmas que as opções de idioma de filtro, com as opções adicionais de "Idioma do conteúdo da linha de visualização" e "Idioma original do conteúdo na linha de visualização", que significa exibir cada entidade na linha de resultados usando o idioma que a entidade possui ou no qual ela foi criada originalmente. Em teoria, haveria a flexibilidade de filtrar, por exemplo, para traduções francesas e, em seguida, exibir os resultados em espanhol. As opções mais comuns seriam usar as mesmas opções de idioma para o idioma de exibição e para cada filtro de entidade na visualização ou usar a configuração de idioma de Linha para a exibição.', 'pt-br', 0);
