INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6087, 'Selecione um grupo de breakpoints dos temas e módulos instalados. Abaixo você pode selecionar quais breakpoints serão usados neste grupo. Você também pode selecionar qual estilo ou estilos de imagem serão usados por cada breakpoint.', 'pt-br', 0);
