INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6124, 'O instalador requer que você crie um diretório de traduções como parte do processo de instalação. Crie o diretório %translations_directory . Mais detalhes sobre a instalação do Drupal  estão disponíveis em <a href=":install_txt">INSTALL.txt</a>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6125, 'O instalador requer permissões de leitura para %translations_directory o tempo todo. A seção de documentação de <a href=":handbook_url"> problemas de hospedagem web </a> oferece ajuda sobre este e outros tópicos.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6126, 'O instalador precisa de permissões de escrita no %translations_directory durante o processo de instalação. O seção <a href=":handbook_url">webhosting issues</a> da documentação oferece ajuda sobre este e outros tópicos.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6127, 'O instalador precisa contatar o servidor de traduções para baixar um arquivo de tradução. Verifique sua conexão de internet e se o seu site pode acessar o servidor de traduções em <a href=":server_url">@server_url</a>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6128, 'O arquivo de tradução para %language não está disponível no servidor de traduções. <a href=":url">Escolha outro idioma</a> ou selecione Inglês (English) e traduza o seu site depois.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6129, 'O arquivo de tradução para %language não pôde ser baixado. <a href=":url">Escolha outro idioma</a> ou selecione Inglês (English) e traduza o seu site depois.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6130, 'O instalador @drupal precisa que você crie um %file como parte do processo de instalação. Copie o arquivo %default_file para %file. Mais detalhes sobre a instalação do Drupal estão disponíveis em <a href=":install_txt">INSTALL.txt</a>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6131, '@drupal requer permissões de leitura a %file em todas as vezes. A seção <a href=":handbook_url">problemas de hospedagem</a> da documentação oferece ajuda neste e em outros tópicos.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6132, 'O instalador @drupal precisa de permissões de escrita para %file durante o processo de instalação. A seção <a href=":handbook_url">problemas de hospedagem</a> da documentação oferece ajuda neste e em outros tópicos.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6133, 'O instalador @drupal falhou ao criar um arquivo %file com o proprietário correto. Acesse seu servidor web, remova o arquivo %file e crie um novo, copiando de %default_file para %file. Mais detalhes sobre a instalação do Drupal estão disponíveis em <a href=":install_txt">INSTALL.txt</a>. A seção <a href=":handbook_url">problemas de hospedagem</a> da documentação fornece ajuda neste e em outros tópicos.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6134, 'Verifique as mensagens e <a href=":retry">tente novamente</a>, ou você pode escolher <a href=":cont">continuar mesmo assim</a>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6135, 'Verifique as mensagens e <a href=":url">tente novamente</a>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6136, 'Os seguintes módulos são necessários, mas não foram encontrados. Mova-os para o subdiretório de módulos apropriado, como <em>/modules</em>. Módulos ausentes: @modules', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6137, 'Atualizando @module', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6138, 'Incompatibilidade de tipo de entidade ao renomear. @old_type não é igual a @new_type para a configuração existente @old_name e @new_name da configuração por etapas.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6139, 'Renomear a operação para configuração simples. A configuração existente @old_name e configuração por etapas @new_name.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7373, 'O campo "%field" não conseguiu renderizar devido ao erro "%error".', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (97, 'Valor', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6140, 'O %driver de banco de dados precisa utilizar a codificação %encoding para funcionar com o Drupal. Recrie o banco de dados com a codificação %encoding. Veja <a href="INSTALL.pgsql.txt">INSTALL.pgsql.txt</a> para mais detalhes.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6141, 'A configuração %setting está atualmente configurada para ''%current_value'' mas precisa ser configurada para ''%needed_value''. Altere-a executando a seguinte consulta: <code>@query</code>', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6142, '@uri', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6143, 'Operando em modo de manutenção. <a href=":url">Ficar online.</a>', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6144, 'Tamanho do campo de texto: @size', 'pt-br', 0);
