INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6147, 'ATENÇÃO: Você não está utilizando uma conexão criptografada, portanto, sua senha será transmitida em texto puro. <a href=":https-link">Aprenda mais</a>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6148, '@name não pode ser maior que %max caracteres, mas possui %length caracteres de comprimento no momento.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6149, '<ul>
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6150, 'Todas as mudanças necessárias em %dir e %file foram feitas, então você agora deveria remover as permissões de escrita deles para evitar riscos à segurança. Se você não tiver certeza de como fazer isso, consulte o <a href=":handbook_url">manual online</a>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6151, 'Restrição de campo único', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6152, 'Um @entity_type com @field_name %value já existe.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6153, 'A mensagem que deve ser enviada. Você pode incluir itens temporários, como [node:title], [user:account-name], [user:display-name] e [comment:body] para representar dados que serão diferentes toda vez que a mensagem for enviada. Nem todos os itens temporários estarão disponíveis em todos os contextos.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6154, 'A mensagem para ser exibida para o usuário atual. Você pode incluir itens temporários, como [node:title], [user:account-name], [user:display-name] e [comment:body] para representar dados que serão diferentes toda vez que a mensagem for enviada. Nem todos os itens temporários estarão disponíveis em todos os contextos.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6155, 'O módulo Ban permite administradores banirem visitantes do site por endereço IP individual. Para mais informações, veja a <a href=":url">documentação online do módulo Ban</a>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6156, 'Administradores podem digitar endereços IP para banimento na página <a href=":bans">Proibições de endereço IP</a>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6157, 'O módulo Autenticação Básica HTTP fornece um provedor de <a href="http://en.wikipedia.org/wiki/Basic_access_authentication">Autenticação Básica HTTP</a> para solicitações de serviço da web. Esse provedor de autenticação autentica as solicitações usando o nome do usuário e senha da Autenticação Básica HTTP, como uma alternativa para o uso do sistema de autenticação baseada em cookie padrão do Drupal. Ele será útil somente se seu site fornecer serviços da web configurados para uso desse tipo de autenticação (por exemplo, <a href=":rest_help">Módulo de Serviços da Web RESTful</a>). Para mais informações, consulte a <a href=":hba_do">documentação on-line para o módulo Autenticação Básica HTTP</a>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6158, 'O módulo Block do core permite que você coloque blocos em regiões dos temas instalados e defina as configurações do bloco. Para mais informações, consulte a <a href=":blocks-documentation">documentação on-line para o módulo Block</a>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6159, 'Você pode ver o local em que estão as regiões do tema atual clicando em <em>Demonstrar regiões de blocos</em> na <a href=":blocks">Página de layout de bloco</a>. As regiões são específicas para cada tema.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6160, 'Para mudar as configurações de um bloco específico, clique no link <em>Configurar</em> na <a href=":blocks">Página de layout de bloco</a>. As opções disponíveis variam dependendo do módulo que fornece o bloco. Para todos os blocos é possível alterar o título do bloco e escolher se ele deve ser exibido ou não.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6161, 'O módulo Breakpoint rastreia os breakpoints de altura, de largura e resolução onde um design responsivo precisa mudar para responder aos diferentes dispositivos em uso para visualizar o site. Este módulo não possui interface com o usuário. Para mais informações, consulte a <a href=":docs">documentação on-line para o módulo Breakpoint</a>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6162, '<a href=":w3">Consultas de mídia</a> são a maneira formal para codificar breakpoints. Por exemplo, um breakpoint de 40em de largura seria gravado como a consulta de mídia "(min-width: 40em)". Na realidade, os breakpoints são apenas consultas de mídia com alguns metadados adicionais, como um nome e informações de multiplicador.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6163, 'O módulo Comment permite que usuários comentem o conteúdo do site, configurem padrões e permissões de comentários e moderem comentários. Para mais informações, consulte a <a href=":comment">documentação on-line para o módulo Comment</a>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6164, 'Habilitando comentários', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6165, 'Definindo as configurações de comentários', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6166, 'Usuários com apropriadas permissões podem substituir as configurações de comentário padrão de um tipo de entidade quando eles criam um item desse tipo.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6167, 'Os comentários de usuários que possuem a permissão <em>Ignorar aprovação de comentário</em> são publicadas imediatamente. Todos os outros comentários serão colocados na fila <a href=":comment-approval">Comentários não aprovados</a>, até que um usuário que tenha permissão para <em>Administrar comentários e configurações de comentário</em> publique ou exclua esses comentários. Os comentários publicados podem ser gerenciados em massa na página de administração <a href=":admin-comment">Comentários publicados</a>. Quando um comentário não tem respostas, ele permanece editável pelo seu autor, desde que o autor tenha a permissão <em>Editar seus próprios comentários</em>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6168, 'Em resposta à @parent_title por @parent_username', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6169, 'Nome para @anonymous', 'pt-br', 0);
