INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6170, '<a href=":login">Efetue login</a> ou <a href=":register">registre-se</a> para postar comentários', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6171, '<a href=":login">Efetue login</a> para postar comentários', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6172, 'Selecione o tipo de comentário para uso neste campo de comentário. Gerencie os tipos de comentário na <a href=":url">Página de visão geral de administração</a>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6173, 'O módulo Configuration Manager fornece uma interface com o usuário para importar e exportar mudanças na configuração entre as instalações do seu website em ambientes diferentes. A configuração é armazenada no formato YAML. Para mais informações, consulte a <a href=":url">documentação on-line para o módulo Configuration Manager</a>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6174, 'Você pode criar e fazer download de um arquivo que consiste em toda a configuração do seu site exportada como arquivos <em>*.yml</em> na página <a href=":url">Exportar</a>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6175, 'É possível fazer upload de uma configuração completa do site a partir de um arquivo na página <a href=":url">Importar</a>. Ao importar dados de um ambiente diferente, os arquivos do site e de importação devem ter valores de configuração correspondentes para o UUID no item de configuração <em>system.site</em>. Isso significa que seus outros ambientes devem ser configurados inicialmente como clones do site de destino. Migrações não são suportadas.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6176, 'É possível revisar as diferenças entre a configuração ativa e um arquivo de configuração importada na página <a href=":synchronize">Sincronizar</a>, a fim de assegurar que as mudanças ocorram conforme o esperado antes de finalizar a importação. A página Sincronizar também mostra itens de configuração que serão incluídos ou removidos.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6177, 'Você pode exportar um único item de configuração selecionando um <em>Tipo de configuração</em> e um <em>Nome de configuração</em> na página <a href=":single-export">Exportação única</a>. A configuração e seu correspondente <em>nome do arquivo *.yml</em> são exibidos na página para você copiar.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6178, 'Você pode importar um único item de configuração colando em formato YAML no formulário da página <a href=":single-import">Importação única</a>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6179, 'Exporte e faça download da configuração completa deste site como um arquivo tar compactado por Gzip.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6180, 'Selecione um item de configuração para exibir sua estrutura YAML.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6181, 'Importe um único item de configuração colando a sua estrutura YAML no campo de texto.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6182, 'Arquivo completo', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6183, 'Item único', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6184, 'Por Etapas', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6185, 'Os seguintes itens em sua configuração ativa possuem mudanças desde a última importação, que poderão ser perdidas na próxima importação.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6186, 'Coleção de configuração de @collection', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6187, '@source_name para @target_name', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6188, 'O módulo Configuration Translation permite traduzir texto de configuração; por exemplo, o nome do site, vocabulários, menus ou formatos de data. Junto com os módulos <a href=":language">Language</a>, <a href=":content-translation">Content Translation</a> e <a href=":locale">Interface Translation</a>, ele permite construir websites multilíngue. Para mais informações, consulte a <a href=":doc_url">documentação on-line para o módulo Configuration Translation</a>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6189, 'Para traduzir a configuração, o website deve ter pelo menos dois <a href=":url">idiomas</a>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6190, 'Os usuários com permissão de <em>Traduzir configuração editada pelo usuário</em> podem acessar a visão geral da tradução de configuração e gerenciar traduções para idiomas específicos. A página <a href=":translation-page">Tradução da configuração</a> mostra uma lista de todo o texto de configuração que pode ser traduzido, como itens individuais ou como listas. Depois de clicar em <em>Traduzir</em>, você recebe uma lista de todos os idiomas. É possível <em>incluir</em> ou <em>editar</em> uma tradução para um idioma específico. Os usuários com permissões de configuração específicas também podem <em>editar</em> o texto para o idioma padrão do site. Para alguns itens de texto de configuração (por exemplo, para as informações do site), as páginas de tradução específicas também podem ser acessadas diretamente de suas páginas de configuração.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6191, 'Você pode optar por converter formatos de data na página <a href=":translation-page">Configuração da tradução</a>. Isso permite não apenas traduzir o texto do rótulo, mas também configurar um <em>Formato de data PHP</em> específico para o idioma.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6192, '@label <span class="visually-hidden">(@source_language)</span>', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6193, 'O módulo Contact permite que visitantes contatem usuários registrados em seu site usando o formulário de contato pessoal, e também permite a configuração de formulários de contato do site inteiro. Para mais informações, consulte a <a href=":contact">documentação on-line para o módulo Contact</a>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6194, 'Na página <a href=":contact_admin">Formulários de contato</a>, é possível configurar os campos e a exibição do formulário de contato pessoal, bem como configurar um ou mais formulários de contato do site inteiro. Cada formulário de contato do site inteiro possui um nome de máquina, um rótulo e um ou mais destinatários definidos. Quando um visitante do site envia o formulário, os valores de campo são enviados para esses destinatários.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6195, 'Um formulário de contato do site inteiro pode ser designado como formulário de contato padrão. Se optar por designar um formulário padrão, o link de menu <em>Contato</em> no menu <em>Rodapé</em> será vinculado à ele. Você pode modificar este link na <a href=":menu-settings">Página de menus</a>, se você tiver o módulo Menu UI instalado. Também é possível criar links para outros formulários de contato e a URL para cada formulário que você configurou tem o formato <em>contato/nome_de_maquina_do_formulario</em>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6196, 'Na página <a href=":contact_admin">Formulários de contato</a>, é possível configurar os campos que serão mostrados nos formulários de contato, incluindo seus rótulos e o texto de ajuda. Se desejar que um conteúdo diferente (como texto ou imagens) apareça em um formulário de contato, use um bloco. Você pode criar e editar blocos na página <a href=":blocks">Layout de bloco</a> se o módulo Block estiver instalado.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6197, '@subject [@form]', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6198, '@sender-name(@sender-url) enviou uma mensagem usando o formulário de contato encontrado em @form-url.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6199, '@subject [@site-name]', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6200, 'Olá @recipient-name,', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6201, 'O @sender-name (@sender-url) lhe enviou uma mensagem através de seu formulário de contato no @site-name.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6202, '@name (não verificado)', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6203, 'O formulário de contato não foi configurado. <a href=":add">Adicione um ou mais formulários</a> .', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6204, 'Para traduzir o conteúdo, o website deve ter pelo menos dois <a href=":url">idiomas</a>. Quando este for o caso, você pode habilitar a tradução para as entidades de conteúdo desejadas na página <a href=":translation-entity">Idioma do conteúdo</a>. Ao habilitar a tradução, é possível escolher o idioma padrão para conteúdo e decidir se o campo de seleção de idioma deve ser mostrado nos formulários de edição de conteúdo.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6205, 'Para traduzir o conteúdo, deve haver pelo menos dois idiomas na página <a href=":url">Administração de idiomas</a>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6206, 'Para configurar a tradução para este campo, <a href=":language-settings-url">ative o suporte de idioma</a> para este tipo.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6207, '<a href=":settings_url">Habilitar tradução</a> para <em>tipo de de conteúdo</em>, <em>vocabulários de taxonomia</em>, <em>contas</em>, ou para qualquer outro elemento que você queira traduzir.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6208, 'O módulo Contextual Links fornece aos usuários com a permissão de <em>Usar links contextuais</em>, acesso rápido às tarefas associadas a determinadas áreas de páginas em seu site. Por exemplo, um menu exibido como um bloco possui links para editar o menu e configurar o bloco. Para mais informações, consulte a <a href=":contextual">documentação on-line para o módulo Contextual Links</a>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6209, 'Passar o mouse sobre a área de interesse tornará o botão de links contextuais visível temporariamente (que é semelhante a um lápis na maioria dos temas e normalmente é exibido no canto superior direito da área). O ícone geralmente é semelhante a este: @picture', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6210, 'O módulo Datetime fornece um campo de data que armazena datas e horas. Ele também fornece os elementos <em>datetime</em> e <em>datelist</em> da Form API para uso em módulos customizados. Consulte as páginas de <a href=":field">ajuda do módulo Field</a> e a <a href=":field_ui">ajuda do módulo Field UI</a> para informações gerais sobre campos e como criá-los e gerenciá-los. Para mais informações, consulte a <a href=":datetime_do">documentação on-line para o módulo Datetime</a>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6211, 'As <em>configurações</em> e a <em>exibição</em> do campo de data podem ser definidas separadamente. Consulte a <a href=":field_ui">ajuda do módulo Field UI</a> para mais informações sobre como gerenciar campos e suas exibições.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6212, 'Datas podem ser exibidas usando o formatador <em>Plano</em> ou <em>Padrão</em>. O formatador <em>Plano</em> exibe a data no formato <a href="http://en.wikipedia.org/wiki/ISO_8601">ISO 8601</a>. Se você escolher o formatador <em>Padrão</em>, é possível escolher um formato em uma lista predefinida que pode ser gerenciada na página <a href=":date_format_list">Formatos de data e hora</a>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6213, 'Ordem da datepart: @order', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6214, 'Tipo de horário: @time_type', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6215, 'Incrementos de tempo: @increment', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6216, 'O módulo Database Logging registra eventos do sistema no banco de dados do Drupal. Para mais informações, consulte a <a href=":dblog">documentação on-line para o módulo Database Logging</a>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6217, 'O módulo Database Logging permite acompanhar um registro de eventos na página <a href="@dblog">Mensagens recentes do registro</a>. O registro é uma lista cronológica de eventos gravados contendo dados de uso, desempenho, erros, avisos e informações operacionais. Administradores devem verificar o registro regularmente para garantir que seu site está funcionando adequadamente.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6218, 'Em caso de erros ou problemas no site, a página de <a href="@dblog">Mensagens recentes de registro</a> pode ser útil para depurar, pois exibe a sequência dos eventos. As mensagens de registro incluem informações de uso, avisos e erros.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6219, 'O número máximo de mensagens a serem mantidas no log do banco de dados. Requer uma <a href=":cron">tarefa de manutenção do cron</a>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6220, 'Páginas que forem adequadas para armazenamento em cache serão armazenadas na primeira vez em que forem solicitadas, de modo que a versão em cache será entregue para todas as solicitações posteriores. Conteúdo dinâmico é manipulado automaticamente para que a exatidão e a taxa de acertos no cache sejam mantidas.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6221, 'Cache de Página Dinâmico Interno', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (11781, 'Na <a href=":formats">Página de formatos e editores de texto</a> você pode ver qual editor de texto está associado com cada formato de texto. Você pode alterar isso clicando no link <em>Configurar</em> e, em seguida, escolher um editor de texto ou <em>nenhum</em> na lista suspensa do <em>Editor de texto</em>. Em seguida, o editor de texto será exibido com qualquer campo de texto para qual esse formato de texto é escolhido.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6223, 'Não foi encontrada nenhuma views elegível. <a href=":create">Crie uma view</a> com uma exibição de <em>Referência de entidade</em> ou adicione a exibição em uma <a href=":existing">view existente</a>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6224, 'O módulo Field permite que campos de dados personalizados sejam definidos para tipos de <em>entidade</em> (veja abaixo). O módulo Field cuida do armazenamento, carregamento, edição e renderização de dados de campos. A maioria dos usuários não interage com o módulo Field diretamente, mas usam a interface do usuário do <a href=":field-ui-help">módulo Field UI</a>. Desenvolvedores de módulos podem usar a Field API para tornar novos tipos de entidade "habilitados para campo” e assim permitir que campos sejam anexados à elas. Para mais informações, consulte a <a href=":field">documentação on-line para o módulo Field</a>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6225, 'Você pode incluir, editar e excluir modos de exibição para entidades na <a href=":view_modes">Página de modos de exibição</a> e também incluir, editar e excluir modos de formulário para entidades na página <a href=":form_modes">Página de modos de formulário</a>. Depois de definir um modo de exibição ou um modo de formulário para um tipo de entidade, ele estará disponível na página Gerenciar exibição ou Gerenciar exibição de formulário para cada subtipo dessa entidade.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6226, 'Ainda não foram adicionados campos. Você pode adicionar novos campos na página <a href="@link">Gerenciar campos</a>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6227, 'O modo %display_mode agora usa as configurações de exibição personalizadas. Talvez você queira <a href=":url">configurá-las</a>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6228, 'Limite de @size.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6229, 'arquivo de @field_name', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7459, 'Links personalizados do menu', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (2950, 'Selecionar qualquer conjunto de atalhos', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6230, 'O módulo File permite criar campos que contenham arquivos. Consulte as páginas <a href=":field">Ajuda do módulo Field</a> e a <a href=":field_ui">ajuda do módulo Field UI</a> para obter informações gerais sobre campos, como criá-los e gerenciá-los. Para mais informações, consulte a <a href=":file_documentation">documentação on-line para o módulo File</a>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6231, 'As <em>configurações</em> e a <em>exibição</em> do campo arquivo podem ser definidas separadamente. Consulte a <a href=":field_ui">ajuda do módulo Field UI</a> para mais informações sobre como gerenciar campos e suas exibições.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6232, 'Os arquivos transferidos por upload podem ser armazenados como <em>públicos</em> ou <em>privados</em>, dependendo das <a href=":file-system">Configurações do sistema de arquivos</a>. Para mais informações, consulte a <a href=":system-help">Página de ajuda do módulo System</a>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6233, 'O arquivo usado no campo @name pode não ser referenciado.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6234, 'O arquivo referenciado pelo campo @name não existe.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6235, 'Usar o formato de texto <a href=":url">@label</a>', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (3052, 'Define uma string que deverá sufixar o valor, tal como ''m'' ou ''kb/s''. Deixe em branco para não utilizar nada. Separe singulares e plurais usando o pipe (''libra|libras'').', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6236, 'Se você encontrar problemas, tente usar entidades de caracteres HTML. Um exemplo comum é semelhante a &amp;amp; para um caractere "e comercial" (símbolo &amp;). Para obter uma lista completa de entidades, consulte a página <a href=":html-entities">entitidades</a> de HTML. Alguns dos caracteres disponíveis incluem:', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6237, 'Limitar tags HTML permitidas e corrigir HTML incorreto', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6238, '<strong>Configure seu website</strong>. Uma vez autenticado, visite a <a href=":admin">Página de administração</a>, onde você pode <a href=":config">Personalizar e configurar</a> todos os aspectos de seu website.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6239, '<strong>Customizar o design de seu website</strong> Para mudar a "aparência" de seu website, visite a <a href=":themes">página de Aparência</a>. É possível escolher entre um dos temas incluídos ou fazer download de temas adicionais na <a href=":download_themes">página de temas do Drupal.org</a>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6240, '<strong>Iniciar a criação de conteúdo</strong> Finalmente, é possível <a href=":content">incluir novo conteúdo</a> no seu website.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6241, 'O módulo Help exibe explicações para o uso de cada módulo listado na <a href=":help">Página de referência de ajuda</a> principal.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6242, 'Páginas com textos de ajuda específicos fornecidos pelos módulos é exibido no bloco Ajuda. Esse bloco pode ser colocado e configurado na <a href=":blocks">Página de layout de bloco</a>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6243, 'O módulo History mantém o rastreio de qual conteúdo um usuário leu. Ele marca o conteúdo como <em>novo</em> ou <em>atualizado</em>, dependendo da última vez que o usuário o viu. Os registros de histórico que forem mais antigos que um mês serão removidos durante o cron, significando assim que um conteúdo mais antigo que um mês é sempre considerado <em>lido</em>. O módulo History não possui uma interface com o usuário, mas fornece um filtro para <a href=":views-help">Views</a> para mostrar conteúdo novo ou atualizado. Para mais informações, consulte a <a href=":url">documentação on-line para o módulo History</a>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6244, 'imagem do @field_name', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7260, 'O módulo Content Moderation permite que você expanda os estados do Drupal “despublicado” e "publicado" para conteúdo. Isto permite que você tenha uma versão publicada ao vivo, mas tenha uma cópia de trabalho separada que está em análise antes de ser publicada. Isso é feito utilizando <a href=":workflows">fluxos de trabalho</a> para aplicar diferentes estados e transições para entidades conforme necessário. Para mais informações, veja a <a href=":content_moderation">documentação online para o módulo Content Moderation</a>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7261, 'Aplicando fluxos de trabalho', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7262, 'Moderando conteúdo', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7263, 'Você pode visualizar uma lista do conteúdo aguardando moderação na <a href=":moderated">página de conteúdo moderado</a>. Isto mostrará qualquer conteúdo em um estado não publicado, como Rascunho ou Arquivado, para ajudar a destacar conteúdo que requer mais trabalho dos editores de conteúdo.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7264, 'Cada transição é exposta como uma permissão. Se um usuário tem permissão para a transição, ele pode usar a transição para mudar o estado do item de conteúdo de Rascunho para Publicado.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7295, 'Consulte a <a href=":list_url" target="_blank">listagem de mídia</a> (abre em uma nova janela) para ajudar a localizar mídia.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7296, 'Tipos de mídia permitidos: %types', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7297, 'Item de mídia', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7298, 'Crie uma nova mídia', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7299, 'A próxima página fornece uma visão geral dos módulos que serão atualizados e também daqueles que não serão atualizados antes de você proceder para realizar a atualização.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7300, 'Importar nova configuração e conteúdo do site antigo', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7301, 'Módulos que não serão atualizados', 'pt-br', 0);
