INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7303, 'O que será atualizado?', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7304, 'O módulo não será atualizadoOs módulos não serão atualizados', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7305, 'Módulo será atualizadoOs módulos serão atualizados', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7306, 'Defina um texto para exibir caso o campo contenha um resultado vazio. Você pode incluir HTML. Você pode inserir dados desta view, conforme os "Padrões de substituição" na seção "Reescrever Resultados" acima.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7307, 'Perfil de instalação experimental utilizado', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7374, 'O campo @uri é obrigatório quando o campo @title é especificado.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7375, 'Idioma para este menu.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (3053, 'Limitador de milhar', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (3054, 'Exibir prefixo e sufixo.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (3055, 'Exibir com prefixo e sufixo.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (3056, '- Selecione um valor -', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (3057, 'Tamanho do corte', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (3058, 'Nenhum campo está sendo exibido.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (3059, 'Nenhum campo está oculto.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (3060, 'Configurações de formatação:', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (3061, 'Os formatos de texto são apresentados em páginas de edição de conteúdo na ordem aqui definida. O primeiro formato disponível para o usuário estará selecionado por padrão.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (3090, 'Nada', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6247, 'Ao criar um campo de imagem, será necessário escolher se as imagens carregadas serão armazenadas no diretório de arquivo públicos ou privados, definido em seu arquivo settings.php e mostradas na <a href=":file-system">Página do sistema de arquivos</a>. Esta opção não pode ser mudada posteriormente. Também é possível configurar seu campo para armazenar arquivos em um subdiretório do diretório público ou privado; essa configuração pode ser alterada posteriormente e ser diferente para cada subtipo de entidade que usa o campo. Para mais informações sobre armazenamento de arquivos, consulte a <a href=":system-help">Página de ajuda do módulo do System</a>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6248, 'Atualmente não há estilos. <a href=":url">Adicione um novo estilo</a>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6249, 'Os valores de altura e largura devem ser especificados no campo @name.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6250, 'O identificador primário para um estilo de imagem.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6251, 'O nome de máquina do estilo.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6252, 'O nome administrativo do estilo.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6253, 'Por padrão, o conteúdo é criado no idioma padrão do site e nenhum seletor de idioma é exibido nas páginas de criação de conteúdo. Na página <a href=":content_language">Idioma do conteúdo</a>, é possível personalizar a configuração do idioma para qualquer entidade de conteúdo suportada em seu site (por exemplo, para tipos de conteúdo ou links no menu). Depois de escolher uma entidade, são fornecidos um menu suspenso para configurar o idioma padrão e uma caixa de seleção para exibir seletores de idioma.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6254, 'A página <a href=":detection">Detecção e seleção</a> fornece vários métodos para decidir qual idioma será usado na exibição do texto da interface. Quando um método detecta e seleciona um idioma da interface, então, os métodos seguintes da lista não são aplicados. Você pode ordená-los por importância, com seu método preferido na parte superior da lista, seguido por um ou vários métodos alternativos.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6255, '<em>Navegador</em> define o idioma da interface com base nas configurações de idioma do navegador. Como os navegadores usam códigos de idioma diferentes para referenciar os mesmos idiomas, você pode adicionar e editar códigos de idioma para mapear os códigos de idioma do navegador para os <a href=":language_list">códigos de idioma</a> usados em seu site.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6256, 'Reordene os idiomas configurados para configurar a ordem dentro do bloco de alternância de idioma e, ao editar conteúdo, na lista de idiomas selecionáveis. Esta ordenação não impacta na <a href=":detection">detecção e seleção</a>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6257, 'O idioma padrão do site também pode ser configurado. Não é recomendado alterar o idioma padrão de um site em produção. <a href=":language-detection">Configure o idioma selecionado</a> na página de detecção e seleção de idiomas para alterar o idioma de substituição para o idioma selecionado.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6258, 'Define como é decidido qual idioma é usado para mostrar elementos de páginas (primariamente textos fornecidos por módulos, como rótulos de campos e texto de ajuda). Esta decisão é feita avaliando uma série de métodos de detecção para idiomas: o primeiro método que obtém um resultado determinará qual idioma será usado para o tipo de texto. Esteja ciente que alguns métodos de detecção de idioma não são confiáveis em certas condições, como detecção pelo navegador quando cache de páginas estão habilitados e um usuário não está autenticado atualmente. Defina a ordem de avaliação dos métodos de detecção nesta página. O idioma padrão pode ser alterado na <a href=":admin-change-language">lista de idiomas</a>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6259, 'Navegadores usam diferentes códigos de idioma para referenciar mesmos idiomas. Internamente, é feito o melhor possível para determinar o idioma correto baseado no código enviado pelo navegador. Você pode adicionar e editar mapeamentos adicionais de idiomas do navegador para <a href=":configure-languages">idiomas do site</a>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6260, 'Mudar o idioma selecionado aqui (e deixar essa opção como a última entre as opções de detecção e seleção) é a maneira mais fácil de mudar o idioma de substituição para o website, se você precisa mudar o modo de funcionamento do seu site por padrão (por exemplo, usando um prefixo de caminho vazio ou usando o domínio padrão). <a href=":admin-change-language">Mudar o idioma padrão do site</a> em si pode ter outros efeitos colaterais indesejados.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6261, 'A explicação das opções de idioma está localizada na <a href=":languages_list_page">página de lista de idiomas</a>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6262, 'Idioma padrão do site (@language)', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6263, 'Use um dos blocos de alternância de idioma para permitir que visitantes do site alternem entre os idiomas. Você pode ativar esses blocos na <a href=":block-admin">página de administração de bloco</a>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6264, 'Para interoperabilidade, use códigos de idioma como <a href=":w3ctags">definidos pelo W3C</a><em>Exemplos: "en", "en-gb" e "zh-hant".</em>', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6265, '%field deve ser uma tag de idioma válido como <a href=":url">definido pelo W3C</a>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6266, 'O prefixo pode ser deixado em branco somente para o <a href=":url">idioma de detecção para substituição selecionado.</a>', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6267, 'O módulo Link permite que você crie campos que contenham URLs internas ou externas e texto opcional do link. Consulte as páginas de <a href=":field">Ajuda do módulo Field</a> e a <a href=":field_ui">Ajuda do módulo Field UI</a> para obter informações gerais sobre campos e como criá-los e gerenciá-los. Para mais informações, consulte a <a href=":link_documentation">documentação on-line para o módulo Link</a>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6268, 'As <em>configurações</em> e a <em>exibição</em> do campo de link podem ser definidas separadamente. Consulte a <a href=":field_ui">ajuda do Field UI</a> para mais informações sobre como gerenciar campos e suas exibições.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6269, 'Um arquivo de tradução não pôde ser verificado. <a href=":url">Consulte o registro</a> para mais detalhes.@count arquivos de tradução não puderam ser verificados. <a href=":url">Consulte o registro</a> para mais detalhes.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (662, '@message (@percent%).', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6270, 'Um arquivo de tradução não pôde ser importado. <a href=":url">Consulte o registro</a> para mais detalhes.@count arquivos de tradução não puderam ser importados. <a href=":url">Consulte o registro</a> para mais detalhes.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6271, 'Uma string de tradução foi ignorada por conter HTML não permitido ou malformado. <a href=":url">Veja o log</a> para mais detalhes.@count strings de tradução foram ignoradas por conterem HTML não permitido ou malformado. <a href=":url">Veja o log</a> para mais detalhes.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7376, 'Tradução do título do link do menu.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (3138, 'Listagem (inteiro)', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6272, 'O módulo Interface Translation permite que você traduza o texto da interface (<em>strings</em>) em diferentes idiomas e também alternar entre eles para exibir o texto da interface. Ele usa a funcionalidade fornecida pelo <a href=":language">módulo Language</a>. Para mais informações, consulte a <a href=":doc-url">documentação on-line para o módulo Interface Translation</a>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6273, 'Você pode verificar o quanto da interface de seu site foi traduzida e para qual idioma na página <a href=":languages">Idiomas</a>. Na página <a href=":translation-updates">Atualizações de tradução disponíveis</a>, é possível verificar se existem atualizações de tradução da interface disponíveis no <a href=":server">servidor de tradução do Drupal</a>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6274, 'É possível traduzir strings individuais diretamente na página <a href=":translate">Tradução da interface do usuário</a> ou fazer download do arquivo de tradução atualmente utilizado para um idioma específico na página <a href=":export">Exportação de tradução da interface</a>. Quando você tiver editado o arquivo de tradução, ele poderá ser importado novamente na página <a href=":import">Importação de tradução da interface</a>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6275, 'Esta página permite que um tradutor procure por strings específicas traduzidas e não traduzidas, sendo usada para criar ou editar traduções. (Nota: como as tarefas de tradução envolvem muitas strings, pode ser mais conveniente <a title="User interface translation export" href=":export">exportar</a> strings para edição em um editor de tradução Gettext instalado em seu computador). As buscas podem ser limitadas à strings de um idioma específico.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6276, 'Esta página permite que tradutores importem manualmente strings traduzidas contidas em um arquivo Gettext Portable Object (.po). A importação manual pode ser usada para traduções personalizadas ou para a tradução de módulos e temas customizados. Para personalizar traduções, você pode fazer download de um arquivo de tradução do <a href=":url">Servidor de tradução Drupal</a> ou <a title="Exportação de tradução de interface de usuário" href=":export">exportar</a> as traduções do site, personalizar as traduções usando um editor de tradução Gettext e importar o resultado usando esta página.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6277, 'Atualizações disponíveis para: @languages. Consulte a página de <a href=":updates">Atualizações de tradução disponíveis</a> para mais informações.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6278, 'Traduções ausentes para: @languages. Consulte a página de <a href=":updates">Atualizações de tradução disponíveis</a> para mais informações.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6279, 'Nenhum status de tradução disponível. Consulte a página de <a href=":updates">Atualizações de tradução disponíveis</a> para mais informações.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6280, 'Configurações de tradução da interface', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6281, 'Importação de tradução da interface', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6282, 'Exportação de tradução da interface', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6283, 'Selecione com que frequência deseja verificar novas traduções da interface para seus módulos e temas atualmente instalados. <a href=":url">Verificar atualizações agora</a>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6284, 'Os arquivos de tradução são armazenados localmente no diretório %path. É possível mudar este diretório na página <a href=":url">Configuração do sistema de arquivos</a>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6285, 'Os arquivos de tradução não serão armazenados localmente. Mude o diretório de tradução da interface na página <a href=":url">Configuração do sistema de arquivos</a>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6286, 'Você selecionou a origem de tradução local, mas nenhum <a href=":url">Diretório de tradução da interface</a> foi configurado.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6287, 'Nenhum idioma traduzível disponível. Primeiro <a href=":add_language">adicione um idioma</a>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6288, 'Nenhum status de tradução disponível. <a href=":check">Verificar manualmente</a>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6289, 'Ele é necessário pelo módulo Menu UI que fornece uma interface para gerenciamento de menus e de links de menu. Para mais informações, consulte a <a href=":menu-help">Página de ajuda do módulo Menu UI</a> e a <a href=":drupal-org-help">documentação on-line para o módulo Custom Menu Links</a>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6290, 'O módulo Menu UI fornece uma interface para gerenciar menus. Um menu é uma coleção hierárquica de links que podem ser internos ou externos ao site, geralmente usado para navegação. Para mais informações, consulte a <a href=":menu">documentação on-line para o módulo Menu UI</a>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6291, 'É possível ativar o bloco recém-criado para este menu na <a href=":blocks">Página de layout de bloco</a>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6292, 'Cada menu possui um bloco correspondente que é gerenciado na <a href=":blocks">Página de layout de bloco</a>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6293, 'Ainda não existem links no menu. <a href=":url">Adicionar link</a>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7377, 'Tradução da descrição do link do menu.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (3252, 'Ação a realizar caso o valor do filtro não seja validado', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (3253, 'Exibir todos os resultados para o campo especificado', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (3254, 'Fornecer um valor padrão', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (3255, 'Exibir "Página não encontrada"', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (3256, 'Exibir um resumo', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (3257, 'Exibir conteúdo de "Nenhum resultado encontrado"', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (3258, 'Número de registros', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (3259, 'Classificação padrão', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (3260, 'Data', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (3261, 'Númerica', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (3262, 'Caso seja selecionada, usuários poderão introduzir múltiplos valores nas formas 1+2+3 (para OU) e 1,2,3 (para E).', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (3263, 'Se esta opção estiver selecionada, várias instâncias deste filtro podem funcionar em conjunto, como se múltiplos valores fossem fornecidos para o mesmo filtro. Esta configuração não é compatível com a opção "Reduzir resultados duplicados".', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (3264, 'Se esta opção estiver selecionada, os números adicionados para este fitro serão excluídos em vez de limitar a view.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (3265, 'Modo Glossário aplica um limite ao número de caracteres usados no valor do filtro, que permite à View Sumário atuar como um glossário.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (3266, 'A quantidade de caracteres a limitar do valor do filtro. Se o valor 1 for usado, todos os campos começando com a primeira letra do valor do filtro seriam selecionados.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (3267, 'Ao exibir o título e o sumário, como transformar maiúsculas/minúsculas no valor do filtro.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (3268, 'Alfabético', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (3269, 'Criar um rótulo', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (3271, 'Escolha o elemento HTML para circundar este campo, como por exemplo: H1, H2, etc.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6294, 'O módulo Migrate fornece uma estrutura para migração de dados, geralmente de uma origem externa, para seu site. Ele não fornece uma interface com o usuário. Para mais informações, consulte a <a href=":migrate">documentação on-line para o módulo Migrate</a>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6295, 'O módulo Migrate Drupal fornece uma estrutura baseada no <a href=":migrate">módulo Migrate</a> que facilita a migração de um site Drupal (6, 7 ou 8) para o seu website. Ele não fornece uma interface com o usuário. Para mais informações, consulte a <a href=":migrate_drupal">documentação on-line para o módulo Migrate Drupal</a>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6296, 'As permissões de acesso ao conteúdo precisam ser reconstruídas. <a href=":node_access_rebuild">Reconstruir permissões</a>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6297, 'O módulo Node gerencia a criação, edição, exclusão, configurações e a exibição do conteúdo principal do site. Itens de conteúdo gerenciados pelo módulo Node são normalmente exibidos como páginas em seu site e incluem um título, alguns metadados (autor, horário da criação, tipo de conteúdo, etc.) e campos opcionais contendo texto ou outros dados (campos são gerenciados pelo <a href=":field">módulo Field</a>). Para mais informações, consulte a <a href=":node">documentação on-line para o módulo Node</a>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6298, 'Quando um novo conteúdo é criado, o módulo Node grava informações básicas sobre o conteúdo, incluindo o autor, a data de criação, e o <a href="@content-type">Tipo de conteúdo</a>. Ele também gerencia as <em>opções de publicação</em> que definem quando o conteúdo é publicado ou não, promovido para a página inicial do site e/ou destacado no topo das listas de conteúdo. Você pode definir uma configuração padrão para cada <a href="@content-type">Tipo de conteúdo</a> do seu site.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6299, 'O módulo Node fornece aos usuários com permissão de <em>Administrar tipos de conteúdo</em> a capacidade para <a href=":content-new">criar novos tipos de conteúdo</a>, além dos tipos padrão já configurados. A criação de tipos de conteúdo personalizados fornece à você a flexibilidade para adicionar <a href=":field">campos</a> e definir as configurações padrão de acordo com as diferentes necessidades de vários conteúdos de sites.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6300, 'A página <a href=":content">Conteúdo</a> lista seu conteúdo permitindo que você inclua um novo conteúdo, filtre, edite ou exclua conteúdo existente, ou execute operações em massa no conteúdo existente.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6302, 'Se o site estiver tendo problemas com permissões de conteúdo, pode ser necessário reconstruir o cache de permissões. A reconstrução removerá todos os privilégios do conteúdo e os substituirá por permissões com base nos módulos e nas configurações atuais. A reconstrução pode levar algum tempo se houver muito conteúdo ou configurações de permissão complexas. Depois que a reconstrução for concluída, o conteúdo usará automaticamente as novas permissões. <a href=":rebuild">Reconstruir permissões</a>', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6303, 'Mantenha os tipos de conteúdo disponíveis e os campos que estejam associados a esses tipos.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6304, 'Nenhum tipo de conteúdo disponível.<a href=":link">Adicionar tipo de conteúdo</a>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6305, 'Node da URL', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6306, 'O módulo Options permite que você crie campos nos quais valores de dados são selecionados a partir de uma lista fixa de opções. Geralmente esses itens são inseridos por meio de uma lista de seleção, caixas de seleção ou botões de opções. Consulte as páginas <a href=":field">Ajuda do módulo Field</a> e a <a href=":field_ui">Ajuda do módulo Field UI</a> para obter informações gerais sobre campos e como criá-los e gerenciá-los. Para mais informações, consulte a <a href=":options_do">documentação on-line para o módulo Options</a>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6307, 'As <em>configurações</em> e a <em>exibição</em> dos campos de lista podem ser definidas separadamente. Consulte a <a href=":field_ui">ajuda do Field UI</a> para mais informações sobre como gerenciar campos e suas exibições.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6308, 'O módulo Internal Page Cache armazena em cache páginas para usuários anônimos no banco de dados. Para mais informações, consulte a <a href=":pagecache-documentation">documentação on-line para o módulo Internal Page Cache</a>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6309, 'As páginas normalmente são idênticas para todos os usuários anônimos, enquanto elas podem ser personalizadas para cada usuário autenticado. É por isso que páginas inteiras podem ser armazenadas em cache para usuários anônimos, embora elas tenham de ser reconstruídas para cada usuário autenticado.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6310, 'Para acelerar seu site para usuários autenticados, consulte o módulo <a href=":dynamic_page_cache-help">Dynamic Page Cache</a>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6311, 'O módulo Path permite que você especifique um apelido ou uma URL personalizada para qualquer caminho interno. Os apelidos não devem ser confundidos com redirecionamentos de URL, que permitem que você redirecione uma URL alterada ou inativa para uma nova URL. Além disso, para tornar as URLs mais legíveis, os apelidos também ajudam mecanismos de busca a indexarem o conteúdo com mais eficiência. Múltiplos apelidos podem ser usados para um caminho interno. Para automatizar os apelidos de caminhos, você pode instalar o módulo contribuído <a href=":pathauto">Pathauto</a>. Para mais informações, consulte a <a href=":path">documentação on-line para o módulo Path</a>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6312, 'Se você criar ou editar um termo de taxonomia, será possível incluir um apelido (por exemplo, <em>musica/jazz</em>) no campo "Apelido da URL". Ao criar ou editar o conteúdo, é possível incluir um apelido (por exemplo, <em>sobre-nos/time</em>) na seção "Configurações do caminho de URL" no campo "Apelido da URL". Apelidos para qualquer outro caminho podem ser incluídos por meio da página <a href=":aliases">Apelidos da URL</a>. Para incluir apelidos, um usuário precisa da permissão <a href=":permissions">Criar e editar apelidos de URL</a>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6313, 'O módulo Path provê uma forma de pesquisar e visualizar uma <a href="@aliases">lista com todas as URLs alternativas</a> que existem no seu site. URLs alternativas podem ser adicionadas, editadas e removidas por esta lista.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6314, 'O caminho interno do sistema.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6315, 'O endereço alternativo.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6316, 'O módulo Responsive Image fornece um formatador de imagem que permite que os navegadores selecionem qual arquivo de imagem deve ser exibido com base nas consultas de quais tipos de arquivo de imagem o navegador suporta, usando os elementos de HTML 5 picture e source e/ou os tamanhos, e atributos srcset e type. Para mais informações, consulte a <a href=":responsive_image">documentação on-line para o módulo Responsive Image</a>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7308, 'Perfis experimentais são fornecidos apenas para fins de teste. Use por sua conta e risco. Para começar a construir um novo site, reinstale o Drupal e escolha um perfil não experimental.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7309, 'Demo: Umami Food Magazine (Experimental)', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (3346, 'Obter o conteúdo em si de uma revisão do conteúdo.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6317, 'Ao criar estilos de imagem responsiva, você define quais opções o navegador possui ao selecionar qual arquivo de imagem deve ser exibido. Na maioria dos casos, isso significa fornecer diferentes tamanhos de imagem com base no tamanho do viewpoint. Na página <a href=":responsive_image_style">Estilos de imagem responsiva</a>, clique em <em>Adicionar estilo de imagem responsiva</em> para criar um novo estilo. Escolha um rótulo, um estilo de imagem de substituição e um grupo de breakpoints e clique em Salvar.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6318, 'Abaixo do campo Tamanho, é possível escolher múltiplos estilos de imagem para que o navegador possa escolher o melhor tamanho do arquivo de imagem para preencher o espaço definido no campo Tamanhos. Geralmente você pode desejar usar estilos de imagem que redimensionam a imagem para ter opções que variam entre a menor largura em px possível para o espaço em que a imagem aparecerá, e a maior largura em px possível, com uma variedade de larguras intermediárias. Talvez você queira fornecer estilos de imagem com larguras que variam de 1.5x a 2x no espaço disponível no layout para considerar telas de alta resolução. Os estilos de imagem podem ser definidos na <a href=":image_styles">Página de estilos de imagem</a> que é fornecida pelo <a href=":image_help">Módulo Image</a>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6319, 'Depois de definir os estilos de imagem responsiva, você poderá usá-los nas configurações de exibição para seus campos de imagem, para que o site apresente imagens responsivas usando a tag de imagem HTML5. Abra a página Gerenciar exibição do tipo de entidade (tipo de conteúdo, vocabulário taxonomia, etc.) ao qual o campo imagem está anexado. Escolha o formato de <em>Imagem responsiva</em>, clique no ícone Editar e selecione um dos estilos de imagem responsiva que você criou. Para obter informações gerais sobre como gerenciar campos e suas exibições, consulte a <a href=":field_ui">Página de ajuda do módulo Field UI</a>. Para obter informações adicionais sobre entidades e campos, consulte a <a href=":field_help">Página de ajuda do módulo Field</a>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6320, 'Consulte a <a href=":responsive_image_help">página de ajuda do Responsive Image</a> para informações sobre o atributo de tamanhos.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6321, 'Configurar estilos de imagem responsiva', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6322, 'O módulo Search fornece a capacidade de configurar páginas de busca com base nos plugins fornecidos por outros módulos. No core do Drupal existem dois plugins de tipo de página: o tipo de página Conteúdo, que fornece busca por palavra-chave para conteúdo gerenciado pelo módulo Node, e o tipo de página Usuários, que fornece busca por palavra-chave para usuários registrados. Módulos contribuídos podem fornecer outros plugins de tipo de página. Para mais informações, consulte a <a href=":search-module">documentação on-line para o módulo Search</a>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6323, 'Para configurar páginas de busca, visite a página <a href=":search-settings">Páginas de busca</a>. Na seção Páginas de busca, é possível incluir uma nova página de busca, editar a configuração de páginas de busca existentes, ativar e desativar páginas de busca e escolher a página de busca padrão. Cada página de busca ativada possui um caminho de URL que começa com <em>busca</em>, e cada uma delas aparece como uma aba ou como um link de tarefa local na <a href=":search-url">página de busca</a>. Você também pode configurar o texto que é mostrado na aba. Além disso, alguns plug-ins de página de busca possuem configurações adicionais que podem ser definidas para cada página de busca.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6324, 'Alguns plug-ins de página de busca, como a página de busca Conteúdo principal, indexam o texto pesquisável usando o índice de busca do core do Drupal e não funcionarão a menos que o conteúdo seja indexado. Como a indexação é feita durante execuções do <em>Cron</em>, ela requer que uma <a href=":cron">tarefa de manutenção Cron</a> seja configurada. Há também várias configurações que afetam a indexação que podem ser configuradas na página <a href=":search-settings">Páginas de busca</a>: o número de itens a serem indexados por execução do Cron, o comprimento mínimo de palavra para indexação e como manipular caracteres em Chinês, Japonês e Coreano.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7310, 'Instala um site de exemplo que mostra algumas das capacidades do Drupal.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7311, 'Demo Umami: Conteúdo', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7312, 'Importa o conteúdo para o Demo Umami.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7313, 'Buscar por palavra-chave, ingrediente, prato', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (3453, 'Valor bruto da URL', 'pt-br', 0);
