INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (3455, 'Aplicar (nesta exibição)', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (3457, 'Isto é um alias de @group: @field.', 'pt-br', 0);
