INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (3463, 'Termo de taxonomia escolhido do widget de autocompletar ou da caixa de seleção.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (3464, 'Node representativo', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (3465, 'Obtém um node representativo simples para cada termo, de acordo com o critério de ordenação escolhido.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (3466, 'Conteúdo com termo', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (3467, 'Relacionar todos os conteúdos classificados com um termo.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (3468, 'Tem ID de termo de taxonomia', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (3469, 'Exibir conteúdo se este possuir os termos de taxonomia selecionados.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (3470, 'Tem termo de taxonomia', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (3471, 'Termos da taxonomia do node', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (3472, 'Todos os termos da taxonomia', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (3473, 'Mostra conteúdo se possui termos de taxonomia selecionados, ou filhos destes termos. Devido à complexidade adicional, isto tem menos opções que as versões sem profundidade.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (3474, 'Tem ID do termo de taxonomia (com profundidade)', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (3475, 'Tem termos de taxonomia (com profundidade)', 'pt-br', 0);
