INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (3478, 'ID do termo de taxonomia a partir da URL', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (3479, 'Resgata um único node representativo para cada usuário, de acordo com o critério de exibição escolhido.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (3480, 'Carregar o filtro padrão da página do node, isso é bom para blocos de taxonomia relacionados', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (3481, 'Componente do caminho', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6325, 'Usuários com permissão de <a href=":search_permission">Usar busca</a> podem usar o bloco de busca e a <a href=":search">Página de busca</a>. Usuários com a permissão de <a href=":node_permission">Visualizar conteúdo publicado</a> podem usar páginas de busca configuradas do tipo <em>Conteúdo</em> para pesquisar conteúdo que possua palavras-chaves exatas. Adicionalmente, usuários com a permissão de <a href=":search_permission">Usar busca avançada</a> podem usar um filtro de pesquisa mais complexo. Usuários com a permissão de <a href=":user_permission">Visualizar informações do usuário</a> podem usar páginas de busca configuradas do tipo <em>Usuários</em> para procurar por usuários ativos que contenham a palavra-chave em qualquer lugar do nome de usuário e usuários com a permissão de <a href=":user_permission">Administrar usuários</a> podem procurar por usuários ativos e bloqueados usando palavra-chave de endereço de e-mail ou nome do usuário.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6326, 'Por padrão, o módulo de Busca suporta apenas a palavra-chave exata correspondente nas buscas de conteúdo. É possível modificar esse comportamento instalando um módulo de stemming específico do seu idioma (como <a href=":porterstemmer_url">Porter Stemmer</a> para inglês americano), que permite que palavras como walk, walking e walked sejam correspondidas no módulo de Busca. Outra abordagem é usar uma tecnologia de busca de terceiros com recursos de stemming ou de correspondência de palavra parcial integrados, como <a href=":solr_url">Apache Solr</a> ou <a href=":sphinx_url">Sphinx</a>. Há também módulos contribuídos que fornecem páginas de busca adicionais. Esses e outros <a href=":contrib-search">módulos contribuídos relacionados à busca</a> podem ser obtidos visitando o Drupal.org.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6327, '… @excerpt … @excerpt …', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6328, 'Este módulo não tem uma interface com o usuário. Ele é usado por outros módulos que precisam serializar dados, como <a href=":rest">REST</a>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6329, 'Para mais informações, veja a <a href=":doc_url">documentação on-line para o módulo Serialization</a>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6330, 'O módulo Shortcut permite que usuários criem conjuntos de links de <em>atalho</em> para páginas comumente visitadas no site. Os atalhos estão contidos em <em>conjuntos</em>. Cada usuário com permissão de <em>Selecionar qualquer conjunto de atalhos</em> pode selecionar um conjunto de atalhos criado por qualquer pessoa no site. Para mais informações, consulte a <a href=":shortcut">documentação on-line para o módulo Shortcut</a>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6331, 'Usuários com permissão de <em>Administrar atalhos</em> podem gerenciar conjuntos de atalhos e editar os atalhos nos conjuntos através da <a href="@shortcuts">Página de administração de atalhos</a>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6332, 'Defina qual conjunto de atalhos você usará na <a href="@shortcut-link">aba Atalhos</a> na página de sua conta.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6333, 'Sem atalhos disponíveis. <a href="@link">Inserir um atalho</a>', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6334, 'Você agora está usando o novo conjunto de atalhos %set_name. Você pode editá-lo nesta página ou <a href="@switch-url">escolher um conjunto diferente</a>', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6335, 'O link para esse atalho.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6336, 'O título para esse atalho.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6337, 'O peso para esse atalho', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6338, 'O nome sob o qual o conjunto de links são armazenados.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6339, 'O título do conjunto.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6340, 'O users.uid para este conjunto.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6341, 'Um shortcut_set.set_name que será exibido para este usuário.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6342, 'Versão: @module-version', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6343, 'Requer: @module-list', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6344, 'Requerido por: @module-list', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6345, 'Este tema requer a versão PHP @php_required e é incompatível com a versão PHP @php_version.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6346, 'O módulo System é integral para o site: ele fornece interfaces com o usuário para muitos dos sistemas e configurações do core, bem como a estrutura básica do menu administrativo. Para mais informações, consulte a <a href=":system">documentação on-line para o módulo System</a>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6347, 'Os usuários com a permissão apropriada podem instalar e desinstalar módulos da página <a href=":modules">Estender</a>. Dependendo do perfil de distribuição ou de instalação que você escolhe ao instalar seu site, vários módulos são instalados e outros são fornecidos, mas não instalados. Cada módulo fornece um conjunto discreto de recursos e os módulos podem ser instalados ou desinstalados de acordo com as necessidades do site. Muitos módulos adicionais contribuídos por membros da comunidade Drupal estão disponíveis para download a partir da <a href=":drupal-modules">Página de módulo Drupal.org</a>. Observe que a desinstalação de um módulo é uma ação destrutiva: ao desinstalar um módulo, todos os dados conectados ao módulo são perdidos definitivamente.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6348, 'Os usuários com permissão apropriada podem instalar e desinstalar temas na página de <a href=":themes">Aparência</a>. Os temas determinam o design e a apresentação de seu site. Dependendo do perfil de distribuição ou de instalação que você escolhe ao instalar seu site, um tema padrão é instalado e possivelmente um tema diferente para páginas de administração. Outros temas são fornecidos, mas não instalados e temas adicionais contribuídos estão disponíveis na <a href=":drupal-themes">Página do tema Drupal.org</a>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6349, 'Quando você estiver executando manutenção do site, será possível evitar que usuários não administrativos (incluindo visitantes anônimos) visualizem seu site colocando-o no <a href=":maintenance-mode">Modo de manutenção</a>. Isso evitará que usuários não autorizados façam mudanças no site enquanto você estiver executando manutenção ou que visualizem um site quebrado enquanto as atualizações estiverem em andamento.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6350, 'Na <a href=":performance-page">Página de desempenho</a>, o site pode ser configurado para agregar arquivos CSS e JavaScript, tornando o tamanho total da solicitação menor. Observe que, para websites de pequeno e médio porte, o módulo <a href=":page-cache">Internal Page Cache</a> deve ser instalado para que as páginas sejam armazenadas em cache e reutilizadas de modo eficiente por usuários anônimos. Finalmente, para sites de todos os tamanhos, o módulo <a href=":dynamic-page-cache">Dynamic Page Cache</a> também deve ser instalado para que as partes não personalizadas de páginas, sejam armazenadas em cache de modo eficiente (para todos os usuários).', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7315, 'O tema usado para o site de demonstração da revista de alimentos Umami.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7316, 'Vá para a página de busca', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7317, '<span class="by-author">por @author_name</span> @created_date', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (3483, 'Usar agregação', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (3665, 'Provedor de autenticação', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6351, 'Seu site possui vários diretórios de arquivo, que são usados para armazenar e processar arquivos gerados e transferidos por upload. O diretório de arquivo <em>public</em>, que é configurado em seu arquivo settings.php, é o local padrão para armazenar arquivos transferidos por upload. Como os links para arquivos neste diretório contém a URL de arquivo direta, quando os arquivos são solicitados, o servidor web os envia diretamente sem chamar o código do site. Isso significa que os arquivos podem ser transferidos por download por qualquer pessoa com a URL do arquivo, de modo que as solicitações não possuem acesso controlado, mas são eficientes. O diretório de arquivo <em>private</em>, também configurado em seu arquivo settings.php é idealmente localizado fora da raiz do website e possui acesso controlado. Como os links para arquivos neste diretório não são diretos, as solicitações para esses arquivos são mediadas pelo código do site. Isso significa que seu site pode verificar a permissão de acesso de cada arquivo antes de decidir cumprir com a solicitação, de modo que as solicitações são mais seguras, porém menos eficientes. O armazenamento privado deve ser usado somente para arquivos que precisam de controle de acesso, e não para arquivos do tipo logotipo de site e imagens de plano de fundo que são usados em cada página. O diretório de arquivo <em>temporary</em> é usado internamente pelo código do site para várias operações e é configurado na página <a href=":file-system">Configurações do sistema de arquivos</a>. Também é possível ver os diretórios de arquivo público e privado configurados nesta página e escolher se público ou privado deve ser o padrão para arquivos transferidos por upload.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6352, 'Na página <a href=":toolkit">Toolkit de imagens</a> é possível selecionar e configurar o conjunto de ferramentas PHP usado para manipular imagens. Dependendo do perfil da distribuição ou de instalação que você escolheu ao instalar seu site, o conjunto de ferramentas GD2 e possivelmente outros conjuntos de ferramentas foram incluídos e outros podem ser fornecidos por módulos contribuídos.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6353, 'Definir e configurar o tema padrão para seu website. <a href=":themes">Temas</a> alternativos estão disponíveis.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6354, 'Você pode colocar blocos para cada tema na página de <a href=":blocks">Layout de bloco</a>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6355, 'Aqui você pode ter uma visão geral dos parâmetros do seu site, bem como de quaisquer problemas detectados na sua instalação. Isto pode ser útil para copiar e colar essas informações em pedidos de suporte nos fóruns do Drupal.org e issue queues dos projetos. Antes de abrir um pedido de suporte, certifique-se que seu servidor web atende aos <a href=":system-requirements">requisitos de sistema.</a>', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6356, 'Defina sua <a href=":user-edit">configuração do fuso horário da conta</a>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6357, 'A versão mínima do Apache necessária para executar o Drupal sem o mod_rewrite ativado é 2.2.16. Consulte a página <a href=":link">ativando URLs limpas</a> para mais informações sobre mod_rewrite.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6358, 'Seu servidor é capaz de utilizar URLs limpas, mas isso não está ativo. O uso de URLs limpas fornece uma melhor experiência ao usuário e é recomendado. <a href=":link">Ativar URLs limpas</a>', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6359, '@phpversion (<a href=":url">mais informações</a>)', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6360, 'O Drupal precisa que as extensões PHP da lista a seguir sejam habilitadas (consulte a <a href=":system_requirements">página de requisitos do sistema</a> para mais informações):', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6361, 'Armazenamento em cache OPcode PHP', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6362, 'Seu servidor web parece não suportar PDO (PHP Data Objects). Pergunte ao seu provedor de hospedagem se ele suporta a extensão PDO nativa. Consulte a página de <a href=":link">requisitos do sistema</a> para mais informações.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6363, 'Seu servidor web parece não oferecer suporte à quaisquer extensões PDO mais comuns de banco de dados. Verifique com seu provedor de hospedagem se ele suporta PDO (PHP Data Objects) e se ele oferece qualquer banco de dados que o <a href="@drupal-databases">Drupal suporta</a>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6364, 'Parece que seu servidor tem a versão errada do PDO instalada. O Drupal 7 requer a extensão PDO do núcleo do PHP. Este sistema tem a versão mais antiga do PECL. Veja a <a hfer="@link">página de requisitos do sistema</a> para mais informações.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6365, 'Para mais informações, consulte a entrada do manual on-line para <a href=":memory-limit">aumentar o limite de memória do PHP</a>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6366, 'Consulte <a href=":url">@url</a> para obter informações sobre o arquivo .htaccess recomendado que deve ser incluído no diretório %directory para ajudar a proteger contra execução de código arbitrária.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6367, 'Última execução há @time', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6368, 'Para mais informações, consulte a entrada do manual on-line para <a href=":cron-handbook">configurando tarefas cron</a>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6369, 'Pode ser necessário configurar o diretório correto na <a href=":admin-file-system">página de configurações do sistema de arquivos</a> ou mudar as permissões do diretório atual para que ele seja gravável.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6370, 'Uma tentativa automática de criar esse diretório falhou, provavelmente devido a um problema de permissões. Para proceder com a instalação, crie o diretório e modifique suas permissões manualmente ou certifique-se de que o instalador tem as permissões para criá-lo automaticamente. Para mais informações, leia o arquivo INSTALL.txt ou o <a href="@handbook_url">manual online</a>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6371, 'Alguns módulos possuem atualizações de esquema do banco de dados para instalar. É necessário executar o <a href=":update">script de atualização de banco de dados</a> imediatamente.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7318, 'Conte-nos o que você acha', 'pt-br', 0);
