INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (3663, 'O arquivo %file não pôde ser salvo porque o upload não foi concluído.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (3664, 'Última página', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6372, 'A configuração trusted_host_patterns não está definida no arquivo settings.php. Isso pode levar a vulnerabilidades de segurança. É <strong>altamente recomendado</strong> que você configure isso. Consulte <a href=":url">Protegendo-se contra ataques de HTTP HOST Header</a> para mais informações.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6373, 'Coloque seu site no <a href=":url">modo de manutenção</a>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6374, 'Todos os erros foram <a href=":url">registrados</a>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6375, 'Foram feitas tentativas de atualização. Se nenhuma falha for exibida abaixo, será possível retornar alegremente para seu <a href=":url">site</a>. Caso contrário, pode ser que você tenha que atualizar seu banco de dados manualmente.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6376, 'Um ou mais problemas foram detectados na sua instalação do Drupal. Verifique o <a href=":status">relatório de status</a> para maiores informações.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6377, 'Captura de tela para o tema @theme', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6378, 'Configurações para o tema @theme', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6379, 'Desinstalar tema @theme', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6380, 'Definir o tema @theme como tema padrão', 'pt-br', 0);
