INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6382, 'Instalar o @theme como tema padrão', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6383, 'Você pode obter mais informações sobre as configurações do agendador de tarefas lendo o <a href="@url">Tutorial do Cron no drupal.org</a>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6384, 'Essa versão não é compatível com Drupal @core_version e deve ser substituída.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6385, 'Este módulo requer a versão @php_required do PHP e é incompatível com a versão @php_version.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6386, 'Definido na página <a href=":information">Informações do site</a>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6387, 'Desenvolvido com <a href="@poweredby">Drupal</a>', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (43, 'Tarefas de instalação', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6388, 'O módulo Taxonomy permite que usuários que tiverem permissão para criar e editar conteúdo, categorizem (marquem) conteúdo desse tipo. Os usuários que tiverem a <a href=":permissions" title="Permissões do módulo Taxonomy">permissão</a> <em>Administrar vocabulários e termos</em> podem incluir <em>vocabulários</em> que contenham um conjunto de <em>termos</em> relacionados. Os termos em um vocabulário podem ser pré-configurados por um administrador ou construídos gradualmente conforme o conteúdo é incluído e editado. Os termos podem ser organizados hierarquicamente, se desejado.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6389, 'Para mais informações, consulte a <a href=":taxonomy">documentação on-line para o módulo Taxonomy</a>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6390, 'Os usuários que possuem permissão de <em>Administrar vocabulários e termos</em> podem incluir e editar vocabulários a partir da <a href=":taxonomy_admin">Página de administração de taxonomia</a>. Os vocabulários podem ser excluídos de sua página <em>Editar vocabulário</em>. Os usuários com permissão de <em>Termo de taxonomia: administrar campos</em> podem incluir campos adicionais para termos nesse vocabulário usando o <a href=":field_ui">módulo Field UI</a>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6391, 'Usuários que tiverem a permissão <em>Administrar vocabulários e termos</em> ou a permissão <em>Editar termos</em> para um vocabulário específico podem incluir, editar e organizar os termos em um vocabulário em uma página de listagem de termos do vocabulário, que pode ser acessada por meio da <a href=":taxonomy_admin">Página de administração de taxonomia</a> e clicando em <em>Listar termos</em> na coluna <em>Operações</em>. Os usuários devem ter a permissão <em>Administrar vocabulários e termos</em> ou a permissão <em>Excluir termos</em> de um vocabulário específico para excluir termos.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6392, 'Um usuário com permissão de <em>Administrar campos</em> de um determinado tipo de entidade pode incluir campos de referência de <em>Termo de taxonomia</em> no tipo de entidade, que permitirá que as entidades sejam classificadas usando termos de taxonomia. Consulte a <a href=":entity_reference">Ajuda de referência de entidade</a> para obter mais informações sobre campos de referência. Consulte as páginas <a href=":field">Ajuda do módulo Field</a> e a <a href=":field_ui">Ajuda do módulo Field UI</a> para informações gerais sobre campos e como criá-los e gerenciá-los.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6393, 'Consulte a página <a href=":entity_reference">Ajuda de referência de entidade</a> para os widgets e formatadores de campo que podem ser configurados para qualquer campo de referência nas páginas <em>Gerenciar exibição</em> e <em>Gerenciar exibição de formulário</em>. Taxonomia adicionalmente fornece um formatador de <em>Categoria RSS</em> que não exibe nada quando o item da entidade é exibido como HTML, mas exibe uma categoria RSS em vez de uma lista quando o item de entidade é exibido em um feed RSS.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6394, 'Nenhum vocabulário disponível. <a href=":link">Adicionar vocabulário</a>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6395, 'Não há termos disponíveis.  <a href=":link">Adicionar termo</a>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6396, 'Formato da descrição do termo.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6397, 'Módulo responsável pelo vocabulário.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6398, 'O módulo Telephone permite que você crie campos que contenham números de telefone. Consulte as páginas <a href=":field">ajuda do módulo Field</a> e a <a href=":field_ui">ajuda do Field UI</a> para obter informações gerais sobre como criar e gerenciar campos. Para mais informações, consulte a <a href=":telephone_documentation">documentação on-line para o módulo Telephone</a>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6399, 'As <em>configurações</em> e a <em>exibição</em> do campo de telefone podem ser configuradas separadamente. Consulte a <a href=":field_ui">ajuda do Field UI</a> para mais informações sobre como gerenciar campos e suas exibições.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6400, 'O módulo Text permite que você crie campos de texto curtos e longos com resumos opcional. Consulte as páginas <a href=":field">ajuda do módulo Field</a> e a <a href=":field_ui">ajuda do Field UI</a> para obter informações gerais sobre como criar e gerenciar campos. Para mais informações, consulte a <a href=":text_documentation">documentação on-line para o módulo Text</a>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6401, 'As <em>configurações</em> e a <em>exibição</em> do campo de texto podem ser configuradas separadamente. Consulte a <a href=":field_ui">ajuda do módulo Field UI</a> para mais informações sobre como gerenciar campos e suas exibições.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7320, 'Um bloco de banner contém um título, resumo, link para o conteúdo e uma imagem de fundo. A imagem de fundo é dimensionada para preencher a largura do navegador.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7321, 'Um bloco de isenção de responsabilidade contém aviso legal e texto de direitos autorais.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7322, 'Bloco de promoção do rodapé', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (4004, 'Sudão do Sul', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (3666, 'Máximo de tentativas', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (3667, 'Valores permitidos para função', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6402, 'Se escolher <em>Texto (simples)</em> ou <em>Texto (simples, longo)</em>, você restringe a entrada somente para <em>texto simples</em>. Se escolher <em>Texto (formatado)</em>, <em>Texto (formatado, longo)</em> ou <em>Texto (formatado, longo, com resumo)</em>, você permite que os usuários gravem texto formatado. Quais opções estão disponíveis para usuários individuais dependem das configurações na <a href=":formats">Página de formatos e editores de texto</a>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6403, 'Número de linhas de resumo: @rows', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6404, 'O módulo Toolbar fornece uma barra de ferramentas para os administradores do site, que exibe abas e bandejas fornecidas pelo próprio módulo Toolbar e por outros módulos. Para mais informações, consulte a <a href=":toolbar_docs">documentação on-line para o módulo Toolbar</a>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6405, 'Módulos desinstalados', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6406, 'Temas desinstalados', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6407, 'Nenhuma informação de atualização disponível. <a href=":run_cron">Rode o agendador de tarefas</a> ou <a href=":check_manually">verifique manualmente</a>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6408, 'Novas atualizações disponíveis para @site_name', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6409, 'Seu site atualmente está configurado para enviar esses e-mails quando quaisquer atualizações estiverem disponíveis. Para receber notificação apenas sobre atualizações de segurança, @url.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6411, 'Houve um problema ao verificar as <a href=":update-report">atualizações disponíveis</a> para o Drupal.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6412, 'Houve um problema ao verificar <a href=":update-report">atualizações disponíveis</a> para seus módulos ou temas.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6413, '%archive_file contém uma versão de %names que não é compatível com o Drupal @version.%archive_file contém versões de módulos ou temas que não são compatíveis com o Drupal @version: %names', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6414, 'Consulte a página de <a href=":available_updates">atualizações disponíveis</a> para mais informações.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6415, 'Verificar atualizações de módulos e temas desinstalados', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6416, 'Descontinuado: Nome do usuário', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6417, 'Descontinuado: use nome da conta ou nome de exibição.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6418, 'O nome de exibição da conta do usuário.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6419, 'O módulo User permite que usuários se registrem, efetuem login e logout. Ele também permite que usuários com as permissões apropriadas gerenciem papéis e permissões do usuário. Para mais informações, consulte a <a href=":user_docs">documentação on-line para o módulo User</a>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (11782, 'Por meio da <a href=":people">Página de administração de pessoas</a>, você pode adicionar e cancelar contas de usuário e designar papéis aos usuários. Ao editar um usuário específico, você pode mudar seu nome de usuário, endereço de e-mail, senha e informações em outros campos.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6420, 'Após criar papéis, é possível configurar permissões para cada papel na <a href=":permissions_user">Página de permissões</a>. Conceder uma permissão dá aos usuários que tiverem sido designados para um papel específico  a opção de executar uma ação no site, como ver o conteúdo, editar ou criar um tipo específico de conteúdo, administrar configurações de um módulo específico ou utilizar uma função específica do site (como busca).', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6421, 'Como Contas de usuário são um tipo de entidade, é possível estendê-las incluindo campos por meio da aba Gerenciar campos na <a href=":accounts">Página de configurações da conta</a>. Ao incluir campos para, por exemplo, uma foto, uma biografia ou um endereço, é possível criar um perfil customizado para os usuários do website. Para mais informações sobre entidades e campos, consulte a <a href=":field_help">Página de ajuda do módulo Field</a>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6422, 'Um papel define um grupo de usuários que possuem determinados privilégios. Esses privilégios são definidos na <a href=":permissions">Página de permissões</a>. Aqui você pode definir os nomes e a ordem de exibição dos papéis no seu site. É recomendado ordenar os papéis do menos permissivo (por exemplo, usuário Anônimo) para o mais permissivo (por exemplo, usuário Administrador). Os usuários que não estão autenticados possuem o papel de usuário Anônimo. Os usuários que estão autenticados possuem o papel de usuário Autenticado, além de quaisquer outros papéis concedidos à sua conta do usuário.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6423, 'Use pelo menos 12 caracteres', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6424, 'Define configurações e comportamento do site inteiro para contas e registro de usuários. Isso inclui métodos de cancelamento de conta, o conteúdo dos e-mails do usuário e campos anexados aos usuários.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6425, 'Gerencia todas as contas do usuário. Isso inclui edição de todas as informações do usuário, mudanças de endereços de e-mail e de senhas, envio de e-mails para usuários e bloqueio e exclusão de contas de usuários.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6426, 'Usuários com as <a href=":permissions-url">permissões</a> %select-cancel-method ou %administer-users podem substituir este método padrão.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6428, 'Criada uma nova conta de usuário para <a href=":url">%name</a>. Nenhum email foi enviado.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6429, 'O novo usuário <a href=":url">%name</a> foi criado sem um endereço de e-mail, de modo que nenhuma mensagem de boas-vindas foi enviada.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6430, 'Uma mensagem de boas-vindas com instruções adicionais foi enviada para o novo usuário <a href=":url">%name</a>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6431, 'As instruções para recuperar a senha serão enviadas para o endereço de e-mail registrado.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6432, 'Enviar instruções para resetar a senha por email.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6433, 'Também conhecido como:', 'pt-br', 0);
