INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6437, 'Para mais informações, consulte a <a href=":views">documentação on-line para o módulo Views</a>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6438, 'Projetos contribuídos que suportam o módulo Views podem ser encontrados na <a href=":node">documentação on-line para módulos contribuídos relacionados a Views</a>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6439, 'Mudando o título aqui significa que ele não mais poderá ser alterado dinamicamente. (Tente alterar isso diretamente em <a href=":url">@name</a>).', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6440, 'Este link é fornecido pelo módulo Views. O caminho pode ser mudado editando a view <a href=":url">@label</a>', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6441, 'Idioma @type selecionado para a página', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6442, '@code (@title)', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6456, 'O módulo Views UI fornece uma interface para gerenciar views do <a href=":views">Módulo Views</a>. Para mais informações, consulte a <a href=":handbook">documentação on-line para o módulo Views UI</a>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7323, 'Um bloco promocional do rodapé contém um título, texto promocional e um link "saiba mais".', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6457, 'Views podem ser ativadas ou desativadas na <a href=":list">Página de lista de views</a>. Para ativar uma view, localize a view na lista "Desativada" e selecione a operação "Ativar". Para desativar uma view, localize a view na lista "Ativada" e selecione a operação "Desativar".', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6458, 'Views podem ser exportadas e importadas como arquivos de configuração usando o <a href=":config">Módulo Configuration Manager</a>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6459, 'Configurações avançadas das Views', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6460, 'Ver @display_title', 'pt-br', 0);
