INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6475, '@display ''@id'': O componente ''@name'' foi desativado porque suas configurações dependem de dependências que foram removidas.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6476, 'Nenhum widget disponível para: %type.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6477, 'Vários caracteres especiais são permitidos, incluindo espaço, ponto (.), hífen (-), apóstrofo (''), sublinhado (_) e o sinal @.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6478, 'A URL para a qual o usuário deve ser redirecionado. Esta poderá ser uma URL interna como /node/1234 ou uma URL externa como @url.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6479, 'O módulo Automated Cron executa as operações do cron para o seu site usando requisições de páginas normais do navegador, em vez de configurar uma tarefa de cron separada. O módulo Automated Cron verifica, no final de cada resposta do servidor, quando foi a última execução de tarefas e, se fizer muito tempo, ele executa as tarefas do cron após o envio da resposta do servidor. Para mais informações, consulte a <a href=":automated_cron-documentation">documentação on-line do módulo Automated Cron</a>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6480, 'Configurando o Cron Automatizado', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6481, 'Na <a href=":cron-settings">página do Cron</a>, você pode definir a frequência (intervalo de tempo) para executar trabalhos do cron.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6482, 'Desativando o Cron Automatizado', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6483, 'Para desativar o cron automatizado, o método recomendado é desinstalar o módulo, a fim de reduzir a sobrecarga do site. Se desejar desativá-lo apenas temporariamente, será possível configurar a frequência para Nunca na página Cron e, em seguida, mudar a frequência de volta quando desejar começar tudo de novo.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6484, 'Cron Automatizado', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6485, 'Fornece uma maneira automatizada para executar tarefas agendadas, executando-as no término de uma resposta do servidor.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6486, 'Configurações do Cron Automatizado', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6487, 'Proibir visitas a partir de endereços IP específicos.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6488, 'É possível colocar um novo bloco em uma região selecionando <em>Colocar bloco</em> na <a href=":blocks">Página de layout de bloco</a>. Quando um bloco é colocado, ele pode ser movido para uma região diferente ao arrastar e soltar ou usando a lista suspensa <em>Região</em> e, em seguida, clicando em <em>Salvar blocos</em>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6489, 'O posicionamento dos blocos é específico de cada tema no site. As mudanças não serão salvas até você clicar em <em>Salvar blocos</em> no final da página.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6490, 'Adicionando tipos de comentários', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6491, '<em>Tipos de comentário</em> adicionais podem ser criados por subtipo de entidade e incluídos na página <a href=":field">Tipos de comentário</a>. Se houver múltiplos tipos de comentários disponíveis, você pode selecionar o tipo apropriado depois de adicionar um <em>Campo de comentários</em>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6492, 'Compare a configuração carregada para seu diretório de sincronização com a configuração ativa antes de concluir a importação.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6493, 'Carregue um arquivo com a configuração completa do site para o diretório de sincronização. Ele então poderá ser comparado e importado na página Sincronizar.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6494, 'O módulo Database Logging registra eventos do sistema no banco de dados do Drupal. Monitore seu site ou depure problemas do site nesta página.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7324, 'Nome da receita', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7325, 'Datas do Umami', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (3853, 'Idiomas existentes', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (3854, 'Adicionar um novo mapeamento', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (3855, 'Código de idioma do navegador', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (3856, 'Os códigos de idioma do navegador devem ser exclusivos.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (3857, 'Os códigos de idioma do navegador podem conter apenas letras minúsculas e um hífen (-).', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (3858, 'Você tem certeza que deseja excluir %browser_langcode?', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (3859, 'Adicione um idioma para ser suportado pelo seu site. Se o idioma desejado não estiver disponível, selecione <em>Idioma personalizado…</em> no no fim da caixa de seleção e forneça um código de idioma e outros detalhes manualmente.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (3860, '- @name -', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (3861, 'Idioma da URL (Prefixo ou domínio).', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (3862, 'Idioma a partir de um parâmetro de solicitação/sessão.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (3863, 'Idioma a partir das configurações de idioma do navegador.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (3877, 'Incluir texto não traduzido', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6495, 'O módulo Internal Dynamic Page Cache armazena no banco de dados, páginas de cache para todos os usuários, manipulando conteúdo dinâmico corretamente. Para mais informações, consulte a <a href=":dynamic_page_cache-documentation">documentação on-line para o módulo Internal Dynamic Page Cache</a>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6496, 'O módulo não precisa de nenhuma configuração. Cada parte da página contém metadados que permitem que o Internal Dynamic Page Cache configure-se sozinho.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6497, 'Os campos de <strong>Referência de entidade</strong> permitem que você crie campos que contenham links para outras entidades (como itens de conteúdo, termos de taxonomia, etc.) dentro do site. Isso permite, por exemplo, incluir um link para um usuário em um item de conteúdo. Para mais informações, consulte a <a href=":er_do">documentação on-line para o módulo Entity Reference</a>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6498, 'Habilitar armazenamento customizado', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6499, 'Um tipo de widget específico da instância', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6500, 'Os tipos de widgets @types são usados em instâncias de campo Drupal 6: tipo de widget @selected_type aplicado ao campo de base Drupal 8', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6501, 'É possível definir quais usuários poderão usar cada formato de texto selecionando papéis. Para garantir a segurança, usuários anônimos e não confiáveis devem ter acesso somente a formatos de texto que os restrinjam a texto simples ou um conjunto seguro de tags HTML. Isso ocorre porque tags HTML podem permitir integração de links ou scripts maliciosos no texto. Usuários registrados mais confiáveis podem receber permissão para usar formatos de texto menos restritivos para criar texto rico. <strong>A configuração incorreta do formato de texto é um risco de segurança.</strong>', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6502, 'Cada formato de texto usa filtros que incluem, removem ou transformam elementos dentro do texto inserido pelo usuário. Por exemplo, um filtro remove tags HTML não aprovadas, enquanto que outro transforma URLs em links clicáveis. Os filtros são aplicados em uma ordem específica. Eles não mudam o conteúdo <em>armazenado</em>: eles definem como ele é processado e exibido.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6503, 'Formatos de texto definem como o texto é filtrado na saída e como tags HTML e outros textos são mostrados, alterados ou removidos. <strong>A configuração errada de um formato de texto é um risco de segurança.</strong> Saiba mais na página de <a href=":filter_help">ajuda do módulo Filter</a>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6504, 'Um formato de texto contém filtros que mudam a exibição da entrada do usuário; por exemplo, remover HTML malicioso ou tornar as URLs clicáveis. Os filtros são executados de cima para baixo e a ordem é importante, já que um filtro pode evitar que outro filtro faça sua tarefa. Por exemplo, quando URLs são convertidas em links antes que tags HTML desaprovadas sejam removidas, todos os links podem ser removidos. Quando isso acontece, a ordem dos filtros poderá precisar ser reorganizada.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6505, 'Configure como o conteúdo é filtrado quando exibido, incluindo quais tags HTML são renderizadas, e ative os filtros fornecidos pelo módulo.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6506, 'Uma lista de tags HTML que podem ser usadas. Por padrão, apenas os atributos <em>lang</em> e <em>dir</em> são permitidos para todas as tags HTML. Cada tag HTML pode ter atributos que são tratados como nomes de atributos permitidos para essa tag HTML. Cada atributo pode permitir todos os valores ou permitir apenas valores específicos. Os nomes ou valores de atributos podem ser gravados como um prefixo e um curinga como <em>jump *</em>. Atributos de eventos JavaScript, URLs JavaScript e CSS são sempre removidos.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6507, 'Configurar idiomas para conteúdo, interface e configuração.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6508, 'Substituindo strings em padrão Inglês', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6509, 'Se a tradução estiver ativada para Inglês, você pode <em>sobrescrever</em> em seu site as strings de texto da interface em Inglês padrão por outras strings de texto em Inglês na página <a href=":translate">Tradução da interface do usuário</a>. A tradução é desativada por padrão para Inglês, mas você pode ativá-la visitando a página <em>Editar idioma</em> para <em>Inglês</em> na página <a href=":languages">Idiomas</a>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6510, 'Configurar a importação de arquivos de tradução e incluir ou personalizar traduções da interface.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6511, 'Gerenciar menus e links de menu.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6512, '<q>Login</q> para usuários anônimos', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6513, 'Reverter para revisão anterior de uma tradução', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6514, 'Tem certeza de que deseja reverter a tradução do idioma @language para a revisão de %revision-date?', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6515, 'Reverter conteúdo compartilhado entre as traduções', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6516, 'Adicionar URLs personalizadas para caminhos existentes.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6517, '- Nenhum (imagem original) -', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6518, 'Somente itens no índice aparecerão nos resultados de busca. Para construir e manter o índice, é necessária uma <a href=":cron">tarefa de manutenção cron</a> corretamente configurada.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6519, 'O comprimento mínimo de caracteres de uma palavra para ela ser incluída no índice. Buscas devem incluir uma palavra-chave com pelo menos esse comprimento.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6520, 'Verificando o status do site', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6521, 'O <a href=":status">Relatório de status</a> fornece uma visão geral da configuração, do status e do funcionamento de seu site. Revise este relatório para assegurar-se de que não haja problemas a serem resolvidos e para localizar informações sobre o software que seu site e servidor da web estão usando.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6522, 'Para que o site e seus módulos continuem operando normalmente, um conjunto de operações administrativas de rotina deve ser executado regularmente; essas operações são conhecidas como tarefas <em>cron</em>. Na <a href=":cron">Página cron</a>, é possível configurar o cron para executar periodicamente como parte das respostas do servidor instalando o módulo <em>Automated Cron</em> ou é possível desativar isso e acionar o cron a partir de um processo externo em seu servidor da web. É possível verificar o status das tarefas cron visitando a <a href=":status">Página de relatório de status</a>. Para mais informações, consulte a <a href=":handbook">documentação on-line para configurar tarefas cron</a>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6523, 'URL base para arquivo público', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6524, 'A URL base que será usada para URLs de arquivo público. Isto pode ser mudado em settings.php', 'pt-br', 0);
