INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6655, 'O módulo BigPipe envia páginas com conteúdo dinâmico de uma maneira que permite que navegadores mostrem-as muito mais rápido. Para mais informações, consulte a <a href=":big_pipe-documentation">documentação on-line para o módulo BigPipe</a>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6656, 'O módulo não requer nenhuma configuração. Cada parte da página contém metadados que o BigPipe usa para configurar a si mesmo.', 'pt-br', 0);
