INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6680, 'Os nomes de domínio para uso nesses idiomas. <strong>A modificação desse valor pode quebrar as URLs existentes. Use com cuidado em um ambiente de produção.</strong> Exemplo: especificar “br.exemplo.com" como o domínio de idioma para o Português do Brasil resulta numa URL como "http://br.exemplo.com/contato”.', 'pt-br', 0);
