INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6702, 'O módulo Syslog registra eventos enviando mensagens para o serviço de criação de registros do sistema operacional do seu servidor web. O Syslog é uma ferramenta de administração de registros do sistema operacional que fornece informações valiosas para uso no gerenciamento de sistemas e na auditoria de segurança. Mais adequado para sites de médio e grande porte, o Syslog fornece ferramentas de filtragem que permitem que as mensagens sejam roteadas por tipo e severidade. Para mais informações, consulte a <a href=":syslog">documentação on-line para o módulo Syslog</a>, bem como as páginas de documentação do PHP para as funções <a href="http://php.net/manual/function.openlog.php">openlog</a> e <a href="http://php.net/manual/function.syslog.php">syslog</a>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6703, 'Módulos experimentais localizados: %module_list. <a href=":url">Módulos experimentais</a> são fornecidos somente para propósitos de teste. Utilize por sua conta e risco.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6704, 'O armazenamento em cache PHP OPcode pode melhorar o desempenho do seu site consideravelmente. É <strong>altamente recomendado</strong> ter o <a href="http://php.net/manual/opcache.installation.php" target="_blank">OPcache</a> instalado em seu servidor.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6705, 'Proteção desativada', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6706, '<a href=":url">Módulos experimentais</a> são fornecidos somente para propósitos de teste. Utilize por sua conta e risco.', 'pt-br', 0);
