INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6946, 'Estes são os provedores de autenticação suportados para esta exibição. Quando essa exibição for solicitada, o cliente será forçado a se autenticar com um dos provedores selecionados. Certifique-se de configurar os requisitos apropriados na seção <em>Acesso</em> porque o Sistema de Autenticação efetuará retorno para o usuário anônimo se a autenticação falhar. Por exemplo: requer Acesso: Papel | Usuário autenticado.', 'pt-br', 0);
