INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7055, 'O módulo Inline Form Errors torna mais fácil para os usuários identificarem quais erros precisam ser resolvidos, fornecendo um resumo de todos os erros e colocando as mensagens de erro individuais ao lado dos próprios elementos de formulário. Para mais informações, consulte a <a href=":inline_form_error">documentação on-line para o módulo Inline Form Errors</a>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7056, 'Exibindo mensagens de erro', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7057, 'Quando um formulário não é preenchido corretamente (por exemplo, se um campo necessário for deixado em branco), uma mensagem de aviso é exibida na parte superior do formulário. Esta mensagem se conecta aos elementos de formulário afetados e as mensagens de erro individuais são exibidas ao lado de cada elemento de formulário.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7058, 'Exibindo mensagens de erro em navegadores com validação de formulários HTML5', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7341, 'Médio 8:7 (266x236)', 'pt-br', 0);
