INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (3524, 'Entidade renderizada', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (12033, 'Apresenta as entidades referenciadas renderizadas por entity_view().', 'pt-br', 0);
