INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (3527, 'Renderizado como @mode', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (3724, '<strong>Nota:</strong> nas exibições de ''Referência de entidade'', todos os campos serão exibidos sequencialmente, a menos que uma seleção explícita de campos sequenciais seja é feita aqui.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (3073, 'Modo de exibição', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (4648, 'Permitindo extensões de arquivo', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (4580, 'Configurações de exibição de página', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (4581, 'Configurações de exibição de bloco', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (4582, 'Ver informações básicas', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (4649, 'Nas configurações de campo, é possível definir as extensões de arquivo permitidas (por exemplo <em>pdf, docx, psd</em>) para os arquivos que serão transferidos por upload com o campo de arquivo.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (4650, 'Restringindo o tamanho máximo do arquivo', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (4651, 'O tamanho máximo do arquivo que usuários podem fazer upload é limitado pelas configurações do PHP do servidor, mas é possível restringir ainda mais inserindo o valor desejado como a configuração de <em>Tamanho máximo do upload</em>. O tamanho máximo do arquivo é exibido automaticamente para usuários no texto de ajuda do campo de arquivo.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (4652, 'Exibindo arquivos e descrições', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (4653, 'Nas configurações de campo, é possível permitir que usuários alternem se arquivos individuais são exibidos. Nas configurações de exibição, é possível escolher um dos seguintes formatos: <ul><li><em>Arquivo genérico</em> exibe links para os arquivos e inclui ícones que simbolizam as extensões de arquivos. Se <em>descrições</em> forem ativadas e informadas, então, a descrição será exibida em vez do nome do arquivo.</li><li><em>URL para arquivo</em> exibe o caminho completo para o arquivo como texto simples.</li><li><em>Tabela de arquivos</em> lista os links para os arquivos e os tamanhos em uma tabela.</li><li><em>Gabinete RSS</em> exibe apenas o primeiro arquivo e apenas em um feed RSS, que é formatado de acordo com a sintaxe RSS 2.0 para gabinetes.</li></ul> Um arquivo ainda pode ser vinculado diretamente pela sua URI, mesmo que não seja exibido.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (3725, 'Selecione os campos que serão buscados quando estiver usando o widget de autocompletar.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (3983, '@field_name', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (4099, 'Tipo de item para referenciar', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (11772, 'Criar entidades referenciadas se elas ainda não existirem', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (4334, 'Campos de referência de entidades em linha', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (4335, 'Retorna resultados como uma matriz PHP de rótulos e de linhas renderizadas.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (4742, 'Gerenciando e exibindo campos de referência de entidade', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (4743, 'Selecionando tipo de referência', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (4744, 'Nas configurações do campo você pode selecionar para quais tipos de entidade você deseja criar uma referência.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (4745, 'Filtrando e classificando campos de referência', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (4746, 'Dependendo do tipo de entidade escolhido, opções adicionais de filtragem e de classificação estão disponíveis para a lista de entidades que podem ser referenciadas nas configurações de campo. Por exemplo, a lista de usuários podem ser filtrada por papel e classificada por nome ou ID.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (4747, 'Exibindo uma referência', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (4748, 'Uma referência de entidade pode ser exibida como um rótulo simples, com ou sem um link para a entidade. Como alternativa, a entidade referenciada pode ser exibida como um teaser (ou em qualquer outro modo de exibição disponível) dentro da entidade de referência.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (12034, 'Ver configurações do manipulador', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (4981, 'Configurações de ordenação', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (5443, '@label referido a partir de @field_name', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (5444, '@field_name: @label', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (12035, 'Destino UUID', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (12036, 'Renderização recursiva detectada durante a renderização da entidade @entity_type @entity_id. Abortando renderização.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (5901, '@entity usando @field_name', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (5902, 'Relacionar cada @entity com um @field_name configurado para o @label.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6222, 'As <em>configurações</em> e a <em>exibição</em> do campo de referência de entidade podem ser definidas separadamente. Consulte a <a href=":field_ui">ajuda do Field UI</a> para mais informações sobre como gerenciar campos e suas exibições.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (12037, 'Entity Reference Revisions', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (12021, 'Adiciona um tipo de campo de referência de entidade com suporte à revisão.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (12038, 'Revisões de referência de entidades campos inline', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (12039, 'Lista de revisões de referência de entidades', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (12040, 'Revisões de referência da entidade', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (12041, 'Revisão da Entidade', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (12042, 'Todos os tipos de entidades com informações de revisão, por exemplo, nodes, comentários ou usuários.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (12043, 'ID de revisão @label', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (12044, 'A revisão da entidade referenciada', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (12045, 'A exibição "@display" precisa de um campo de busca para funcionar corretamente. Consulte as configurações do formato de lista de revisões de referência da entidade.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (12046, 'A exibição "@display" usa campo %field como campo de busca, mas o campo não está mais presente. Consulte as configurações do formato de lista de revisões de referência da entidade.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (12047, 'Entity Reference Revisions Source', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (12048, 'Seleciona entidades referenciais para um campo de revisões de referência de entidades.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (12049, 'O módulo Entity Reference Revisions permite que você crie campos que contenham links para outras entidades (como itens de conteúdo, termos de taxonomia, etc.) dentro do site. Isso permite, por exemplo, que você inclua um link para um usuário dentro de um item de conteúdo. Para mais informações, consulte <a href="!er_do">a documentação on-line para o módulo Entity Reference Revisions</a> e a página de ajuda do módulo <a href="!field_help">Field</a>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (12050, 'Diff de campos para Parágrafos', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (12051, 'Este lote encontrou um erro.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (12052, 'Um campo de entidade contendo uma entidade de referência para uma revisão específica.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (12053, '@current processadas de @total tipos de entidades.', 'pt-br', 0);
