INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6245, 'O módulo Image permite que você crie campos que contenham arquivos de imagem e configure <a href=":image_styles">Estilos de imagem</a> que podem ser usados para manipular a exibição de imagens. Consulte as páginas de <a href=":field">Ajuda do módulo de Field</a> e <a href=":field_ui">Ajuda do módulo Field UI</a> para obter informações gerais e de terminologia sobre entidades, campos e como criar e gerenciar campos. Para mais informações, consulte a <a href=":image_documentation">documentação on-line para o módulo Image</a>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6246, 'O conceito de estilos de imagem é a possibilidade de carregar uma imagem única e exibi-la de várias formas. Cada variação de exibição ou <em>estilo de imagem</em>, é o resultado da aplicação de um ou mais <em>efeitos</em> na imagem original. Como exemplo, é possível carregar uma imagem de alta resolução com uma proporção de aspecto 4:3 e exibi-la em uma escala reduzida, com corte quadrado ou em preto e branco (ou em qualquer combinação desses efeitos). O módulo Image fornece uma maneira para se fazer isso de modo eficiente: você configura um estilo de imagem com os efeitos desejados na <a href=":image">Página de estilos de imagem</a> e os efeitos são aplicados na primeira vez em que uma imagem específica é solicitada nesse estilo. A imagem resultante é salva e, na próxima vez em que esse mesmo estilo for solicitado, a imagem salva será recuperada sem necessidade de recalcular os efeitos. O core do Drupal fornece vários efeitos que podem ser usados para definir estilos. Outros efeitos podem ser fornecidos por módulos contribuídos.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (6301, 'O módulo Node trás um número de permissões disponíveis para cada tipo de conteúdo, que podem ser atribuidos à papeis na <a href="@permissions">página de permissões</a>.', 'pt-br', 0);
