INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7060, 'Coloca mensagens de erro adjacentes às entradas do formulário, para melhorar a usabilidade e acessibilidade.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7061, 'Configurações da formatação do idioma', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7063, 'Criando itens de mídia', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7064, 'Quando um novo item de mídia é criado, o módulo Mídia registra informações básicas sobre ele, incluindo o autor, a data de criação e o <a href=":media-type">tipo de mídia</a>. Também gerencia as <em>opções de publicação,</em>que definem se o item é ou não publicado. As configurações padrão podem ser configuradas para cada tipo de mídia em seu site.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7065, 'Criando tipos de mídia personalizados', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7066, 'O módulo Mídia dá aos usuários com os <em>tipos de mídia Administer</em> a permissão para <a href=":media-new">criar novos tipos</a> de mídia, além dos padrão já configurados. Cada tipo de mídia tem uma fonte de mídia associada (como a fonte de imagem) que suporta a geração de miniaturas e extração de metadados. Campos gerenciados pelo <a href=":field">módulo Field</a> podem ser adicionados para armazenar esses metadados, como largura e altura, bem como quaisquer outros valores associados.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7067, 'O módulo Mídia também permite que você crie várias versões de qualquer item de mídia e reverta para versões mais antigas usando as configurações de <em>informações da revisão</em>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7068, 'O módulo Mídia disponibiliza uma série de permissões, que podem ser definidas por função na <a href=":permissions">página de permissões</a>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7070, 'Gerenciar tipos de mídia.', 'pt-br', 0);
