INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7665, 'Os módulos <a href=":jsonapi-docs">JSON:API</a> e <a href=":rest-docs">RESTful Web Services</a> servem a propósitos semelhantes. <a href=":comparison">Leia a comparação dos módulos RESTFul Web Services e JSON:API</a> para determinar a melhor escolha para o seu site.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7666, 'Alguns recursos multilíngue não funcionam bem com JSON:API atualmente. Consulte a <a href=":jsonapi-docs">documentação de suporte multilíngue JSON:API</a> para mais informações sobre o status atual do suporte multilíngue.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7667, 'Atualmente, o suporte à revisão é somente leitura e apenas para os tipos de entidades "Conteúdo" e "Mídia" em JSON:API. Consulte a documentação de <a href=":jsonapi-docs">suporte à revisão JSON:API</a> para obter mais informações sobre o status atual do suporte à revisão.', 'pt-br', 0);
