INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8766, 'Adicionado /atualizado %project_name com sucesso', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8066, 'Que tipos de dados um site tem?', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8067, 'O que é uma entidade de conteúdo?', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8068, 'O que é um campo?', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8070, 'O que é um campo referenciado?', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8265, 'Quais são as partes de um layout?', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8266, 'Encontre o subtipo específico para o qual deseja criar um layout e clique em <em>Gerenciar exibição</em> na lista <em>Operações</em>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8267, 'Em <em>Opções de layout</em>, marque <em> Usar o Layout Builder</em>. Você também pode marcar a caixa abaixo para permitir que cada item da entidade tenha seu layout individualmente personalizado (se ela for deixada desmarcada, o site usará o mesmo layout para todos os itens deste subtipo de entidade).', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8268, 'Clique em <em>Salvar</em>. Você será redirecionado à página de <em>Gerenciar exibição</em> mas não mais verá a tabela de campos do gerenciador de exibição clássico.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8269, 'Clique em <em>Gerenciar layout</em> para entrar no modo de gerenciamento de layout. Um layout padrão será configurado para você com uma única seção de uma coluna contendo os campos do subtipo da sua entidade.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8270, 'Para remover a seção padrão e iniciar a partir de um layout vazio, encontre e clique no botão <em>Remover</em> para a seção padrão, que se parece com um X. Confirme clicando em <em>Remover</em> na caixa de diálogo pop-up.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8271, 'Adicione novas seções, cada uma com uma a quatro colunas, ao seu layout. Por exemplo, você pode querer uma seção de uma coluna na parte superior, uma seção de duas colunas no meio e, em seguida, uma seção de uma coluna na parte inferior. Para adicionar uma seção, clique em <em>Adicionar seção</em> e clique no número desejado de colunas. Para seções de várias colunas, defina as porcentagens de largura da coluna e clique em <em>Adicionar</em> na caixa de diálogo pop-up.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8311, 'Como uma alternativa ao sistema de páginas de busca do módulo do core Search, você pode usar módulos contribuídos para fornecer buscas no site. Por exemplo, os módulos contribuídos <a href="https://www.drupal.org/project/apachesolr">Apache Solr</a> e <a href="https://www.drupal.org/project/sphinx">Sphinx</a> usam tecnologia de terceiros para fornecer buscas no site.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8312, 'Quais são as limitações do módulo core Search?', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8767, 'Exibir endereços de e-mail do usuário', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8854, 'Postando comentários', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9502, 'Imagens só podem ser adicionadas por URL.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8465, 'Reordenando e desativando links do menu', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8466, 'Desativar links de menu ou alterar a ordem e a hierarquia dos links do menu.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8467, 'Clique em <em>Editar menu</em> no menu que deseja editar.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8471, '[site:name]: O nome do seu site.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7349, 'Artigos laterais', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9096, 'CkEditor 5 compatibilidade de formato de texto fundamental', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7350, 'Mais artigos em destaque', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8598, 'Gerenciando a visão geral de configuração', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8665, '<em>Revisão padrão</em>: se marcado, quando o conteúdo chegar neste estado, ele se tornará a revisão padrão do conteúdo; o conteúdo publicado é automaticamente a revisão padrão.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8649, 'Clique em <em>Salvar</em>', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8666, 'Decida em qual estado o conteúdo deve ser criado.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8667, 'Decida na lista de transições permitidas entre estados. Por exemplo, você pode dessejar uma transição entre <em>Conceituação</em> e <em>Revisão</em>. Cada transição tem um rótulo; por exemplo, a transição Conceituação para Revisão pode ser rotulada como "Conceito da revisão".', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8668, 'Clique em <em>Adicionar fluxo de trabalho</em>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8669, 'Digite um nome no campo <em>Rótulo</em>, selecione <em>Moderação de conteúdo</em> no <em>Tipo de fluxo de trabalho</em> do campo e clique em <em>Salvar</em>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8670, 'Verifique se a lista de <em>Estados</em> corresponde aos estados que você planejou. Você pode adicionar estados ausentes clicando em <em>Adicionar um novo estado</em>. Você pode editar ou excluir estados clicando em <em>Editar</em> ou <em>Excluir</em> em <em>Operações</em> (se a opção <em>Excluir</em> não estiver disponível, primeiro você precisa excluir quaisquer <em>Transições</em> para ou a partir deste estado).', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8671, 'Verifique se a lista de <em>Transições</em> corresponde com seu plano. Você pode adicionar transições ausentes clicando em <em> Adicionar uma nova transição</em>. Você pode editar ou excluir transições clicando em <em>Editar</em> ou em <em>Excluir</em>, em <em>Operações</em>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8672, 'Marque os subtipos da entidade nas quais deseja aplicar o fluxo de trabalho. Por exemplo, você pode optar por aplicar seu fluxo de trabalho ao tipo de conteúdo <em>Página</em>, mas não para <em>Artigo</em>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8673, 'Nas <em>Configurações do fluxo de trabalho</em>, selecione o <em>Estado de moderação padrão</em> para novos conteúdos.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8674, 'Clique em <em>Salvar</em> para salvar seu fluxo de trabalho.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8762, 'Para importar arquivos privados do seu site Drupal atual, digite um diretório de arquivos local contendo seu site (por exemplo,. /var/www/docroot). Deixe em branco para usar o mesmo valor do diretório de arquivos públicos.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8865, 'Quais componentes da interface administrativa estão disponíveis?', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8866, 'Recursos de acessibilidade para permitir que todos os usuários executem tarefas administrativas. Consulte @accessibility_topic para mais informações.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8867, 'O que são seções do menu administrativo?', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8868, 'O menu administrativo, que você pode navegar visitando <em>@admin_link</em> em seu site ou usando uma barra de ferramentas administrativa, tem as seguintes seções (algumas podem não estar disponíveis, dependendo de quais módulos estão atualmente instalados em seu site e suas permissões):', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8869, '<strong>Conteúdo:</strong> Encontrar, gerenciar e criar novas páginas; gerenciar comentários e arquivos.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8870, '<strong>Estrutura:</strong> Posicione e edite blocos, configure tipos e campos de conteúdo, configure menus, administre taxonomia e configure alguns módulos contribuídos.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8871, '<strong>Aparência:</strong> Alternar entre temas, instalar temas e atualizar temas existentes.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8872, '<strong>Estender:</strong> Atualizar, instalar e desinstalar módulos.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8873, '<strong>Configuração:</strong> Configura as configurações para várias funcionalidades do site, incluindo alguns módulos contribuídos.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8874, '<strong>Pessoas:</strong> Gerenciar contas de usuários e permissões.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8875, '<strong>Relatórios:</strong> Exibir informações sobre segurança do site, atualizações necessárias e atividades do site.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8876, '<strong>Ajuda:</strong> Obtenha ajuda no uso da interface administrativa.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8877, 'Instale os módulos core mencionados acima para utilizar o aspecto correspondente da interface administrativa. Veja tópicos relacionados listados abaixo para mais detalhes sobre alguns aspectos da interface administrativa.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8878, 'Criando um item de conteúdo', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9365, 'O diretório raiz do stage não poderá ser criado em "@dir".', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9366, 'O diretório raiz do stage "@dir" não possui permissão de escrita.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9095, 'Está faltando a configuração do plugin habilitado "%plugin_label" (%plugin_id).', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9022, 'Configurações do tipo de bloco', 'pt-br', 0);
