INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9063, 'admin/content/files/usage/{{ fid }}', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9064, '@interval', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9068, 'Quando o CKEditor 5 é escolhido no menu suspenso do <em>editor de texto</em>, sua configuração de barra de ferramentas é exibida. Você pode adicionar e remover botões da barra de <em>Ferramentas ativa</em> arrastando-os e soltando-os. Separadores e linhas podem ser adicionados para organizar os botões.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9069, 'Filtrando conteúdo HTML', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9070, 'Ao contrário de outros editores de texto, a configuração do plugin determina as tags e atributos permitidos em formatos de texto usando o CKEditor 5. Se usar o filtro <em>Limitar tags HTML permitidas e corrigir HTML defeituoso</em>, os valores deste filtro serão automaticamente definidos com base em plugins habilitados e itens de barra de ferramentas.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9071, 'Desenvolvendo plugins do CKEditor 5 no Drupal', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9072, 'Consulte a <a href=":dev_docs_url">documentação on-line</a> para obter informações detalhadas sobre o desenvolvimento de plugins CKEditor 5 para uso no Drupal.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9073, 'O editor embutido no WYSIWYG (CKEditor 5) vem com uma série de recursos de acessibilidade. O CKEditor 5 vem com <a href=":shortcuts">atalhos de teclado embutidos</a>, o que pode ser benéfico tanto para usuários avançados quanto para usuários somente de teclado.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9074, 'Para suportar o conteúdo de páginas multilíngue, o CKEditor 5 pode ser configurado para incluir um botão de idioma na barra de ferramentas.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9075, 'Com o CKEditor 5 este é um
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9076, 'CKEditor 5', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9077, 'Par Formato de texto mais Editor de texto usando CKEditor 5', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9078, 'Configurações do CKEditor 5', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9079, 'Títulos ativados', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9080, 'Editando Origem', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9081, 'Tag Permitida', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9082, 'O botão @name foi copiado para a barra de ferramentas ativa.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9083, 'O botão @name foi removido da barra de ferramentas ativa.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9084, 'O plugin de <em>Edição de fonte</em> foi habilitado para suportar tags e/ou atributos que não são explicitamente suportados por quaisquer plugins CKEditor 5 disponíveis.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9085, 'Estes são os títulos que aparecerão nos títulos suspensos. Se um título não for escolhido aqui, isso não significa necessariamente que a tag correspondente seja proibida no formato de texto.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9086, 'Tags HTML manualmente editáveis', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9087, 'Uma lista de tags HTML que podem ser usadas durante a edição da fonte. Só é necessário adicionar tags que ainda não são suportadas por outros plugins habilitados. Por exemplo, se "Bold" estiver ativado, não é necessário adicionar a tag <code>&lt;strong&gt;</code>, mas pode ser necessário adicionar <code>&lt;dl&gt;&lt;dt&gt;&lt;dd&gt;</code> em um formato que não tenha um plugin de lista de definição, mas que exija marcação de lista de definição.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9367, 'Você não tem permissão para visualizar @item_label.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9368, 'Removendo mídia.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9216, 'Esquema de Cores Olivero', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9267, 'A linha @line-number não contém um valor válido. Insira um seletor CSS válido contendo uma ou mais classes, seguido por um símbolo de pipe e um rótulo.As linhas @line-numbers não contém um valor válido. Insira um seletor CSS válido contendo uma ou mais classes, seguido por um símbolo de pipe e um rótulo.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9268, 'A seguinte tag não possui o atributo obrigatório <code>@required_attribute_name</code>: <code>@provided_element</code>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9269, 'A tag a seguir não tem o mínimo de @min_attribute_value_count valores permitidos para o atributo obrigatório <code>@required_attribute_name</code>: <code>@provided_element</code>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9270, 'Os estilos só podem ser especificados para tags já suportadas.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9271, 'Um estilo só pode ser especificado para uma tag HTML 5. <code>@tag</code> não é uma tag HTML5.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9272, 'Um estilo só deve especificar classes não suportadas por outros plugins. As <code>@classes</code> classes em <code>@tag</code> já são suportadas pelo plugin %plugin habilitado.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9273, 'Um estilo só deve especificar classes não suportadas por outros plugins. As <code>@classes</code> classes em <code>@tag</code> são suportadas pelo plugin %plugin. Remova esse estilo e habilite esse plugin.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9274, 'Etiqueta única na lista', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9275, 'A etiqueta %label não é única.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9276, 'O módulo Text Editor fornece uma estrutura que outros módulos (como o <a href=":ckeditor5">módulo CKEditor5</a>) podem usar para fornecer barras de ferramentas e outras funcionalidades que permitem aos usuários formatar texto mais facilmente do que digitar tags HTML diretamente. Para mais informações, consulte a <a href=":documentation">documentação online do módulo Text Editor</a>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9277, 'Para pesquisar ajuda, você precisará instalar o módulo Search, configurar uma página de pesquisa e adicionar um bloco de pesquisa à página de Ajuda ou outra página administrativa. (Uma página de pesquisa é fornecida automaticamente e, se você usar o tema administrativo principal Claro, um bloco de pesquisa de ajuda será exibido na página principal da Ajuda.) Em seguida, os usuários com permissões de pesquisa e permissão para exibir a ajuda poderão pesquisar ajuda. Consulte a <a href=":search_help">página de ajuda do módulo Search</a> para mais informações.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9278, 'Um tema base é um tema que não se destina a ser usado diretamente em um site, mas atua como um andaime para a construção de outros temas. O tema do core Stable 9 é um exemplo; outros temas básicos podem ser baixados na <a href="https://www.drupal.org/project/project_theme">página Download &amp; Extend no drupal.org</a>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9279, 'Os módulos do core Filter, RDF, Responsive Image e Path fornecem opções de configurações e exibição para entidades e campos.', 'pt-br', 0);
