INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9667, 'Fornece uma barra de ferramentas de administração para exibir links fornecidos por módulos.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9671, 'Todas as permissões serão concedidas automaticamente à essa papel.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9873, 'Como os tópicos de ajuda são traduzidos?', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9867, 'O que é um tópico de ajuda?', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9868, 'Um tópico de ajuda descreve um conceito ou etapas para realizar uma tarefa, relacionado a um recurso fornecido por um ou mais módulos ou temas. Se o módulo Search do núcleo estiver ativado, esses tópicos também poderão ser pesquisados.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9869, 'Onde estão listados os tópicos de ajuda?', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9870, 'Os tópicos de ajuda de nível superior estão listados em @help_link. Links para outros tópicos, incluindo tópicos de ajuda que não são de nível superior, podem ser encontrados sob o título "Relacionado" ao visualizar uma página de tópico.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9871, 'Como os tópicos de ajuda são providos?', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9872, 'Módulos e temas podem fornecer tópicos de ajuda como plug-ins baseados em arquivos Twig em um subdiretório do projeto chamado <em>help_topics</em>; os metadados do plug-in são fornecidos via sintaxe YAML em cada arquivo Twig. Os tópicos de ajuda baseados em plug-ins fornecidos por módulos e temas serão atualizados automaticamente quando um módulo ou tema for atualizado. Use os plug-ins em <em>core/modules/help/help_topics</em> como um guia ao escrever e formatar um plug-in de tópico de ajuda para seu tema ou módulo.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (10148, 'Ideal para textos longos, como corpo ou descrição sem um sumário', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (10067, 'Ideal para armazenar durações que consistem em datas (e horas) de início e término', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (10021, 'Editar @entity_label', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (10068, 'Escolha entre definir data e hora, ou apenas data, para cada duração', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (10069, 'O sistema valida automaticamente se a data (e hora) de término é posterior ao início e ambos os campos são preenchidos', 'pt-br', 0);
