INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (10076, 'Nenhum kit de ferramentas de imagem está configurado no site. Verifique as extensões instaladas do PHP ou adicione um kit de ferramentas contribuído que não exija uma extensão PHP. Certifique-se de que pelo menos um kit de ferramentas de imagem válido esteja instalado.', 'pt-br', 0);
