INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (10812, 'O módulo Admin Toolbar aprimora o módulo <a href=":toolbar">Toolbar</a> fornecendo acesso rápido a todos os links administrativos na parte superior do seu site. O Admin Toolbar continua sendo um módulo muito "leve", integrando-se de perto com todas as funcionalidades da barra de ferramentas. Ele pode ser usado em conjunto com todos os sub-módulos incluídos no Admin Toolbar para acesso rápido a comandos do sistema, como limpeza de todos os caches, <a href=":automated_cron">Executar cron,</a>Executar Atualizações, etc.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (10813, 'O Admin Toolbar melhora em muito a experiência do usuário para aqueles que interagem regularmente com a barra de ferramentas do Drupal, fornecendo acesso rápido e completo a todos os links na barra de ferramentas Drupal sem ter que clicar para chegar lá.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (10814, 'O módulo Admin Toolbar Links Access Filter fornece uma solução alternativa para o problema comum que usuários com a permissão <em>Usar as páginas administrativas e ajuda</em> possuem de ver links de menu que eles não possuem acesso.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (10815, 'Para usar o Admin Toolbar Extra Tools somente instale-o como qualquer outro módulo. Não existem outras configurações.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (10772, 'Limpar cache de Twig', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (10816, 'Cache do Twig limpo.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (10757, 'Fornece um menu de interface drop-down melhorado para a barra de ferramentas do site.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (10766, 'Busca do Admin Toolbar', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (10817, 'O módulo Admin Toolbar Extra Tools vem empacotado com o módulo <a href=":admin-toolbar">Admin Toolbar</a> e adiciona funcionalidade à ele. A funcionalidade adicional é acessada através de links extras na barra de ferramentas da administração principal. Alguns links para páginas de administração do Admin Toolbar Extra Tools estão localizados na parte inferior desta página.', 'pt-br', 0);
