INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7094, 'Cria novas revisões automaticamente. Usuários com permissão de "Administrar mídia" poderão sobrescrever essa opção.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7095, 'Baixe miniaturas através de uma fila. Ao usar fontes de mídia remotas, a geração de miniaturas pode ser um processo lento. O uso de uma fila permite que esse processo seja tratado em segundo plano.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (11080, 'Representa a imagem no estilo de imagem fornecido.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (11081, 'O módulo <a href=":project">Token</a> fornece uma interface de usuário para o sistema de tokens do site. Ele também adiciona alguns tokens adicionais que são usados extensivamente durante o desenvolvimento do site. Os tokens são partes especialmente formatadas de texto que servem como espaços reservados para um valor gerado dinamicamente. Para obter mais informações, abrangendo tanto o sistema de tokens quanto as ferramentas adicionais fornecidas pelo módulo Token, consulte a <a href=":online">documentação on-line</a>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (11082, 'Seu site usa um sistema de token compartilhado para exposição e uso de tokens de placeholder e seus valores de substituição apropriados. Isso permite que qualquer módulo forneça tokens de placeholder para strings sem ter que reinventar a roda. Ele também garante consistência na sintaxe usada para tokens, tornando o sistema como um todo mais fácil para os usuários finais usarem.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (11083, 'A lista dos tokens disponíveis para este site é exibida abaixo.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (11084, '%name está usando os seguintes tokens inválidos: @invalid-tokens.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (11085, 'Link de menu computado para o node (disponível apenas durante a gravação do node).', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (11086, '%name deve conter pelo menos um token.%name deve conter pelo menos @count tokens.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (11087, '%name deve conter no máximo um token.%name deve conter no máximo @count tokens.', 'pt-br', 0);
