INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (11278, 'Se um apelido automatizado deve ser criado ou não.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (11279, 'Padrão do Pathauto', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (11280, 'Marque para quais tipos esse padrão deve ser aplicado. Deixe vazio para permitir qualquer um.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (11281, 'Marque para quais idiomas esse padrão deve ser aplicado. Deixe vazio para permitir qualquer um.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (11282, '@label sendo apelidado', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (11283, 'Apelido atualizado para %label @id.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (11284, '1 %label apelido foi atualizado.@count %label apelidos foram atualizados.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (11285, 'Quando um padrão inclui certos caracteres (como aqueles com sotaque) o Pathauto deve tentar transliterá-los para o alfabeto EUA-ASCII?', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (11286, 'Esta página fornece uma lista de todos os padrões no site e permite que você os edite e reordene-os.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (11287, 'O título %element está usando os seguintes caracteres inválidos: @invalid-caracteres.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (11288, 'Converta valores de token em minúsculas.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (11289, 'Tem certeza que quer desativar o padrão %label?', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (11290, 'Padrões desativados são ignorados ao gerar apelidos.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (11291, 'Padrão desativado %label.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (11292, 'Tem certeza que quer ativar o padrão %label?', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (11293, 'Padrão ativado %label.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (11294, 'Atualizar o apelido de uma entidade', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (11295, 'O módulo Pathauto fornece um mecanismo para automatizar a criação de apelidos de <a href="path">caminhos</a>. Isso torna as URLs mais legíveis e ajuda os mecanismos de busca a indexar o conteúdo de forma mais eficaz. Para mais informações, consulte a <a href=":online">documentação online do Pathauto</a>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (11296, 'O Pathauto é acessado a partir das abas que adicionam à lista de <a href=":aliases">apelidos de URL</a>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (11297, 'Criando Padrões Pathauto', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (11298, 'A página <a href=":pathauto_pattern">"Padrões"</a> é usada para configurar a apelidação automática de caminho. Novos padrões são criados aqui usando o botão de <a href=":add_form">adicionar padrão do Pathauto</a>, que apresenta uma forma de simplificar a criação de padrões através do uso dos <a href="token">tokens disponíveis</a>. A página de padrões fornece uma lista de todos os padrões do site e permite que você os edite e reordene-os. Um apelido é gerado para o primeiro padrão que se aplica.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (11299, 'A página <a href=":settings">"Configurações"</a> é usada para personalizar as configurações globais do Pathauto para criação automatizada de padrões.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (11300, 'Geração em Massa', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (11301, 'A página <a href=":pathauto_bulk">"Gerar em massa"</a> permite criar apelidos de URL para itens que atualmente não possuem apelidos. Isso é normalmente usado ao instalar o Pathauto em um site que tem conteúdo sem apelidos e que precisam de apelidos em massa.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (11302, 'Excluir Apelidos', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (11303, 'A página <a href=":pathauto_delete">"Excluir apelidos"</a> permite remover apelidos de itens que foram atribuídos anteriormente usando o Pathauto.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (11304, 'Você precisa selecionar um tipo de padrão, depois um padrão, um filtro e um rótulo. Outros tipos podem ser ativados na página <a href=":settings">Configurações</a>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (11305, 'Tipos de entidades habilitadas', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (11306, 'Habilitar para adicionar um campo de caminho e permitir definir padrões de apelidos para o tipo dado. Os tipos desativados já definem um campo de caminho em si ou atualmente possuem um padrão.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (11307, 'Tipo quebrado', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (11308, 'AliasType', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (11309, 'A geração em massa pode ser usada para gerar apelidos para itens que atualmente não possuem apelidos. Isso é normalmente usado ao instalar o Pathauto em um site que tem conteúdo sem apelidos e que precisa ser apelidado em massa.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (11310, 'Ele também pode ser usado para regenerar apelidos de URL para itens que possuem um apelido antigo e para os quais o padrão do Pathauto foi alterado.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (11311, 'Observe que isso só afetará itens configurados para ter seu apelido de URL definido automaticamente. Itens cujo o apelido URL é definido manualmente, não são afetados.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (11312, 'O %element-title não permite que os padrões terminem com o espaço branco.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (11313, 'Selecione os tipos de caminhos para gerar apelidos de URL', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (11314, 'Selecione quais apelidos de URL gerar', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (11315, 'Gerar um apelido de URL apenas para caminhos sem apelido', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (11316, '<a href=":url">As configurações do Pathauto</a> são definidas para ignorar caminhos que já possuem um apelido de URL. Você só pode criar apelidos de URL para caminhos que não têm nenhum.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (11317, 'Atualize o apelido de URL para caminhos com um antigo apelido de URL', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (11318, 'Regenerar apelidos de URL para todos os caminhos', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (11319, 'Um nome curto para ajudá-lo a identificar esse padrão na lista de padrões.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (11320, 'Apenas exclua apelidos gerados automaticamente', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (11321, 'Quando marcados, os apelidos que foram definidos manualmente não serão afetados por esta exclusão em massa.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (11322, 'Exclusão em massa de apelidos de URL', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (11323, 'Todos os seus apelidos de caminho gerados automaticamente foram excluídos.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (11324, 'Todos os seus apelidos de caminho %label gerados automaticamente foram excluídos.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (11325, 'Tokens que são seguros de usar e não precisam ser limpos.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (11326, 'Tokens seguros', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (11327, 'Lista de tokens que são seguros de usar em padrões de apelido e não precisam ser limpos. Por exemplo, urls, apelidos, nomes de máquinas. Separados com uma vírgula.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (11328, 'Padrão %label salvo.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (11329, 'Duplicar padrão Pathauto', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (11330, 'Escolha a ação para realizar.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (11331, 'Argumento de ação inválido "@invalid_action". Por favor, use um de: @valid_actions', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (11332, 'Argumento de tipo inválido "@invalid_types". Por favor, escolha entre os seguintes: @valid_types', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (11333, 'Gerar um apelido de URL apenas para caminhos sem apelido.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (11334, 'Atualize o apelido de URL para caminhos com um antigo apelido de URL.', 'pt-br', 0);
