INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (11336, 'O nome da variável do padrão.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (11337, 'O valor da variável do padrão.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (11338, 'O <strong>comprimento máximo do apelido</strong> e <strong>o comprimento máximo do componente</strong> possuem 100 com padrão e têm um limite de @max do Pathauto. Você deve digitar um valor que é o comprimento da coluna “apelido” da tabela de banco de dados url_alias menos o comprimento de quaisquer strings que possam ser adicionadas ao final da URL. O valor recomendado e padrão é de 100.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (11339, '<strong>Nota:</strong> não há confirmação. Certifique-se de sua ação antes de clicar no botão "Excluir apelidos agora!".<br />Você pode querer fazer um backup do banco de dados e/ou das tabelas path_alias e path_alias_revision antes de usar esse recurso.', 'pt-br', 0);
