INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (1834, 'A profundidade vai buscar os nodes marcados com termos na hierarquia. Por exemplo, se você tiver um termo chamado "fruta" e um sub-termo chamado "maçã", com uma profundidade 1 (ou maior), o filtro vai pegar o termo "fruta" e também todos os nodes que possuem o termo "maçã". Se o número for negativo, ocorre o inverso. Se a profundidade for -1 (ou menor) o buscar "maçã", os nodes com o termo "fruta" também serão retornados.', 'pt-br', 0);
