INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (2113, 'O bloco <em>Desenvolvido com Drupal</em> é um link para a página do projeto Drupal que você pode por, opcionalmente, no seu site. Apesar de não ser obrigatório exibir esse link, usá-lo é uma forma de mostrar apoio ao Drupal.', 'pt-br', 0);
