INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (2120, 'Limite de memória do PHP', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (2121, 'Talvez você devesse aumentar o limite da memória do seu PHP para %memory_minimum_limit, para evitar erros durante o processo de instalação.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (2122, 'Talvez você devesse aumentar o limite da memória do seu PHP para %memory_minimum_limit, para evitar erros durante o processo de atualização.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (2123, 'Dependendo das suas configurações, o Drupal pode rodar com um limite de memória do PHP de %memory_limit. Mesmo assim, um limite de memória de pelo menos %memory_minimum_limit é recomendado, especialmente se o seu site for usar módulos adicionais.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (2124, 'Aumente o limite de memória editando o parâmetro memory_limit parameter no arquivo %configuration-file. Em seguida, reinicie o seu servidor web (ou contate o seu administrador de sistemas ou a sua hospedagem e peça assistência).', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (2125, 'Contate seu administrador de sistemas ou a sua hospedagem e peça assistência para aumentar o limite de memória do PHP.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (2126, 'Desprotegido', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (2127, 'O arquivo %file não está protegido contra modificações e isso é um risco à segurança do site. Você deve alterar as permissões do arquivo para que ele seja somente leitura.', 'pt-br', 0);
