INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (2147, 'Selecionar a freqüência com que deseja que seja verificado se existem atualizações dos seus módulos e temas instalados.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (2148, 'Nesta página você verificar se existem atualizações para os módulos e temas instalados neste site. Note que cada módulo ou tema é parte de um "projeto", que pode ou não ter um nome igual e que pode incluir vários módulos ou temas.', 'pt-br', 0);
