INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (2151, 'Há atualizações disponíveis para um ou mais módulos ou temas.  Para garantir o funcionamento adequado do seu site, é recomendável atualizar assim que for possível.', 'pt-br', 0);
