INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (2639, 'Itens do conteúdo podem ser exibidos usando diversos modos de exibição: Resumo, Conteúdo completo, Impressão, RSS, etc. <em>Resumo</em> é um formato curto normalmente usado em listas de múltiplos itens de conteúdo. <em>Conteúdo completo</em> é normalmente usado quando o conteúdo é exibido em sua própria página.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (2640, 'Aqui você pode definir quais campos aparecem ou não quando um conteúdo do tipo %type é exibido em cada modo de exibição, e definir como os campos serão exibidos em cada modo de exibição.', 'pt-br', 0);
