INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (3441, 'Avançado. Use outra view para gerar a subpesquisa de relacionamento. Isto permite usar filtro e mais de uma ordenação. Se selecionar uma view aqui, as opções de ordenação acima serão ignoradas. Sua vista deve ter um ID de sua base como seu único campo, e deve ter algum tipo de ordenação.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (3442, 'Irá gerar novamente a subpesquisa para este relacionamento toda vez que esta view for executada ao invés de somente quando estas opções são salvas. Use para testes se estiver fazendo alterações em outro lugar. CUIDADO: isso impacta seriamente o desempenho.', 'pt-br', 0);
