INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (3692, 'O ID do link de menu (mlid) é a chave primária de número inteiro.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (3693, 'O ID do link pai (plid) é o mlid do link acima na hierarquia ou zero, se o link está no nível superior em seu menu.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (3694, 'O caminho Drupal ou caminho externo para o qual este link aponta.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (3695, 'Para links que correspondem a um caminho Drupal (externo = 0), isso conecta o link para um {menu_router}.path para junções.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (3696, 'O texto exibido para o link, que pode ser modificado por um retorno de chamada de título armazenado em {menu_router}.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (3697, 'O nome do módulo que gerou este link.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (3698, 'Uma sinalização para indicar se o link aponta para uma URL completa começando com um protocolo, como http:// (1 = externo, 0 = interno).', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (3699, 'Sinalização indicando se quaisquer links têm este link como um pai (1 = filhos existentes, 0 = sem filhos).', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (3700, 'Sinalização indicando se esse link deve ser renderizado como expandido nos menus. Links expandidos sempre possuem seus links filhos exibidos, em vez de somente quando o link estiver na trilha ativa (1 = expandido, 0 = não expandido)', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (3701, 'Peso do link entre os links no mesmo menu na mesma profundidade.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (3702, 'A profundidade em relação ao nível superior. Um link com plid == 0 terá profundidade == 1.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (3703, 'Uma sinalização para indicar se o usuário criou ou editou manualmente o link (1 = customizado, 0 = não customizado).', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (3704, 'O primeiro mlid no caminho materializado. Se N = profundidade, então pN deve ser igual a profundidade. Se a profundidade > 1 então p(N-1) deve ser igual ao plid. Todos os pX onde X > profundidade devem ser iguais a zero. As colunas p1 .. p9 também são chamados de pais.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (3705, 'O segundo mlid no caminho materializado. Veja p1.', 'pt-br', 0);
