INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (4213, 'No UNIX, Linux e Mac OS X, você localizará a configuração no arquivo <em>/etc/syslog.conf</em>, no <em>/etc/rsyslog.conf</em> ou no diretório <em>/etc/rsyslog.d</em>. Esses arquivos definem a configuração de roteamento. As mensagens podem ser sinalizadas com os códigos <code>LOG_LOCAL0</code> a <code>LOG_LOCAL7</code>. Para obter informações sobre os recursos e níveis de severidade do Syslog e como configurar <em>syslog.conf</em> ou <em>rsyslog.conf</em>, consulte a página manual <em>syslog.conf</em> ou <em>rsyslog.conf</em> na sua linha de comandos.', 'pt-br', 0);
