INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (4404, 'Habilitando um editor de texto para um formato de texto', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (4405, 'Configurando um editor de texto', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (4406, 'Uma vez que um editor de texto é associado a um formato de texto, é possível configurá-lo clicando no link <em>Configurar</em> para este formato. Dependendo do editor de texto específico, você pode configurá-lo, por exemplo, incluindo botões na sua barra de ferramentas. Geralmente, esses botões fornecem ferramentas de formatação ou de edição ou inserem tags HTML no campo de origem. Para mais detalhes, consulte a página de ajuda do editor de texto específico.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (4407, 'Usando diferentes editores e formatos de texto', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (4408, 'Se você mudar o formato de texto em um campo de texto, o editor de texto também mudará porque a configuração do editor de texto está associada ao formato de texto individual. Isso permite o uso do mesmo editor de texto com diferentes opções para diferentes formatos de texto. Usuários também poderão escolher entre formatos de texto com editores de texto diferentes se eles estiverem instalados.', 'pt-br', 0);
