INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (4433, 'Linhas e parágrafos são automaticamente reconhecidos. As tags de quebra de linha, &lt;br /&gt;, de parágrafo,  &lt;p&gt; e de fim de parágrafo,  &lt;/p&gt;, são inseridas automaticamente. Se os parágrafos não forem reconhecidos, basta inserir algumas linhas em branco.', 'pt-br', 0);
