INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (4439, 'Excluir um idioma removerá todas as traduções da interface associadas a ele e o conteúdo nesse idioma será configurado para que seja um idioma neutro. Não é possível desfazer esta ação.', 'pt-br', 0);
