INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (4443, 'Observe que a importação de arquivos .po grandes pode levar vários minutos.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (4444, 'Os itens de conteúdo podem ser editados usando diferentes formulários. Aqui é possível definir quais campos são mostrados e ocultados quando o conteúdo %type é editado em cada formulário e definir como os widgets de campo são exibidos em cada formulário.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (4445, 'Editar tipo de conteúdo %label', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (4446, 'Ou o conteúdo foi modificado por outro usuário, ou você já submeteu modificações. Consequentemente, suas alterações não podem ser salvas.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (4447, 'Usar rótulo do campo: @display_label', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (4462, 'A largura de cada coluna será calculada automaticamente com base no número de colunas fornecidas. Se classes adicionais forem inseridas ou se um tema injetar classes com base em um sistema de grade, desativar esta opção pode ser benéfico.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (4464, 'Inclui classes de coluna de views padrão como views-col, col-1 e clearfix no resultado. Você pode usar isto para rapidamente reduzir a quantidade de marcação que a view oferece por padrão, ao custo de tornar mais difícil aplicar CSS.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (4465, 'Classe personalizada da coluna', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (4466, 'Classes adicionais para cada coluna. Separados por um espaço.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (4467, 'Classe padrão da linha', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (4468, 'Inclui classes padrão de linhas de views como views-row, row-1 e clearfix no resultado. Você pode usar isto para rapidamente reduzir a quantidade de marcação que a view oferece por padrão, ao custo de tornar mais difícil aplicar CSS.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (4469, 'Classe personalizada da linha', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (4470, 'Classes adicionais para cada linha. Separadas por espaço.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (4471, 'Assistente padrão', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (4472, 'Todas as consultas geradas por Views incluirão o nome das views e apresentam ''view-name:display-name'' como uma sequência no término da cláusula SELECT. Isso simplifica a identificação de consultas de views nos registros do servidor de banco de dados, mas deve ser usado somente para solucionar problemas.', 'pt-br', 0);
