INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (4548, 'Nas configurações de campo, é possível definir o texto de link adicional para <em>opcional</em> ou <em>obrigatório</em> em qualquer campo de link.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (4549, 'Exibindo texto do link', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (4550, 'Se o texto do link foi informado para uma URL, então, por padrão, esse texto será exibido como um link para a URL. Se desejar exibir o texto do link <em>e</em> a URL, escolha o formato de link apropriado no menu suspenso na página <em>Gerenciar exibição</em>. Se desejar exibir somente a URL, mesmo se o texto do link foi informado, escolha <em>Link</em> como o formato e, em seguida, mude suas <em>Configurações de formato</em> para exibir <em>Somente URL</em>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (4551, 'Incluindo atributos nos links', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (4552, 'É possível incluir atributos nos links mudando as <em>Configurações de formato</em> na página <em>Gerenciar exibição</em>. Incluir <em>rel="nofollow"</em> notifica os mecanismos de busca que links não devem ser seguidos.', 'pt-br', 0);
