INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (4559, 'O módulo Serialization fornece um serviço para serializar e desserializar dados para/de formatos como JSON e XML.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (4560, 'Serialização é o processo de converter estruturas de dados como matrizes e objetos em uma string. Isso permite que os dados sejam representados de uma maneira que seja fácil trocar e armazenar (por exemplo, para transmissão pela Internet ou para armazenamento em um sistema de arquivos local). Essas representações podem ser desserializadas para as estruturas de dados originais.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (4561, 'O serializador divide esse processo em duas partes. A normalização converte um objeto em uma estrutura de matriz normalizada. A codificação pega essa matriz e a converte em uma string.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (4562, 'O processo de desinstalação remove todos os dados relacionados a um módulo.', 'pt-br', 0);
