INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (4639, 'Configurando blocos', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (4640, 'É possível controlar a visibilidade de um bloco restringindo-o a páginas, tipos de conteúdo e/ou papéis específicos, configurando as opções apropriadas em <em>Configurações de visibilidade</em> da configuração de bloco.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (4641, 'A menos que você esteja tendo problemas com paginadores relacionados a esse campo, isso deve ser deixado em 0. Se você estiver usando múltiplos paginadores em uma página, pode ser necessário configurar esse número para um valor mais alto para não entrar em conflito com a matriz ?page=. Valores altos podem adicionar muitas vírgulas em suas URLs e por isso, evite-os.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (4642, 'ID do índice: @id', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (4643, 'Digite o nome do arquivo de configuração sem a extensão <em>.yml</em>. (por exemplo, <em>system.site</em>)', 'pt-br', 0);
