INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7102, 'A hora que o item de mídia foi editado pela última vez.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7103, 'tipo de mídia', 'pt-br', 0);
