INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7105, '%tipo é usado por @count item de mídia em seu site. Você não pode remover este tipo de mídia até que você tenha removido todos os itens de mídia do tipo %.%tipo é usado por @count itens de mídia em seu site. Você não pode remover este tipo de mídia até que você tenha removido todos os itens de mídia do tipo %.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7106, 'Vinculado ao item de mídia', 'pt-br', 0);
