INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7109, 'É possível mudar as configurações do menu somente para a versão <em>publicada</em> deste conteúdo.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7110, 'Para ver uma revisão, você também precisa de permissão para ver o item de conteúdo.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7111, 'Para reverter uma revisão, você também precisa de permissão para editar o item de conteúdo.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7112, 'Para excluir uma revisão, você também precisa de permissão para excluir o item de conteúdo.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7113, 'Endereço alternativo.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7114, 'Você só pode alterar o apelido da URL para a versão <em>publicada</em> deste conteúdo.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7115, 'O suporte ao REST para tipos de conteúdo (fornecido pelo módulo <a href=":node">Nó)</a> é ativado por padrão. Para habilitar o suporte para outros tipos de entidades de conteúdo, você pode usar um <a href=":config" target="blank">processo baseado na edição de configuração</a> ou no módulo REST <a href=":restui">UI</a>contribuído .', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7116, 'Faixa de data limitada', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7117, 'Sua instalação PHP tem um intervalo de data limitado.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7118, 'Você está executando em um sistema onde PHP é compilado ou limitado a usar inteiros de 32 bits. Isso limitará a faixa de datas e horários aos anos 1901-2038. Leia sobre as <a href=":url">limitações do PHP de 32 bits</a>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7119, 'Aconteceu um erro no cliente', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7120, 'Para executar o cron de fora do site, acesse <a href=":cron" class="system-cron-settings__link">@cron</a>', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7121, 'Tempos de execução de trabalhos individuais do cron serão registrados no watchdog', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7122, 'Excluir arquivos temporários após', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7123, 'Arquivos temporários não são referenciados mas estão no sistema de arquivos e, portanto, podem aparecer em listas administrativas. <strong>Aviso:</strong> se ativado, os arquivos temporários serão excluídos permanentemente e podem não ser recuperáveis.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (34, 'Adiciona o papel @label para o(s) usuário(s) selecionado(s)', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (35, 'Remover o papel @label dos usuários selecionados', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7124, 'Este fluxo de trabalho está em uso. Você não pode remover este fluxo de trabalho até remover todo o conteúdo que o utiliza.', 'pt-br', 0);
