INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7433, 'Exibir ativos de mídia de serviços de terceiros, como YouTube ou Twitter, pode ser arriscado. Isso ocorre porque muitos desses serviços retornam HTML arbitrário para representar esses ativos, e que o HTML pode conter código JavaScript executável. Se tratado de forma inadequada, isso pode aumentar o risco de seu site ser comprometido.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7434, 'Para mitigar riscos, os ativos de terceiros são exibidos em um iFrame, que efetivamente proteje qualquer código executável executando dentro dele. Para obter ainda mais segurança, o iFrame pode ser servido a partir de um domínio alternativo (que também aponta para o seu site Drupal), que você pode configurar nesta página. Isso ajuda a proteger cookies e outras informações confidenciais.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7435, 'Domínio iFrame', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7436, 'Digite um domínio diferente do qual servir conteúdo oEmbed, incluindo os prefixos <em>http://</em> ou <em>https://</em>. Este domínio precisa ser direcionado para este site, ou o conteúdo oEmbed existente pode não ser exibido corretamente.', 'pt-br', 0);
