INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7578, 'O módulo JSON:API é uma implementação totalmente compatível da <a href=":spec">Especificação JSON:API</a>. Seguindo convenções compartilhadas, você pode aumentar a produtividade, aproveitar a ferramenta generalizada e focar no que importa: sua aplicação. Os clientes construídos em torno de JSON:API são capazes de tirar proveito de recursos como cache de resposta eficiente, que às vezes pode eliminar totalmente as solicitações de rede. Para mais informações, consulte a <a href=":docs">documentação on-line do módulo JSON:API</a>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7579, 'JSON:API é uma implementação particular do REST que fornece convenções para relações de recursos, coleções, filtros, paginação e classificação. Essas convenções ajudam os desenvolvedores a construir clientes mais rapidamente e incentiva o reaproveitamento de códigos.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7580, 'Expõe entidades como uma API web JSON:API-specification-compliant.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7581, 'Banner da Home para Umami', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7582, 'Se marcado e este link do menu tiver filhos, o menu sempre aparecerá expandido. Esta opção pode ser sobrescrita para toda a árvore do menu quando um bloco de menu for usado.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7583, 'Verificados', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7584, 'Este @label está sendo editado pelo usuário @user, e portanto está bloqueado para ser editado por outros. Este bloqueio está ativo há @age. <a href=":url">Clique aqui para desbloquear</a>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7585, 'Isso também removerá 1 instância de bloco posicionado.
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7586, 'Se deve logar o endereço IP com comentários ou não.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7587, 'Selecione o estado atribuído ao novo conteúdo. Este estado aparecerá como padrão nos formulários de conteúdo e os estados de destino  disponíveis serão baseados nas transições disponíveis a partir deste estado.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7588, 'Permite que usuários configurem exibições e exibição de formulários organizando campos em várias colunas.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7589, 'Formulários e links dentro do conteúdo da ferramenta layout builder foram desativados.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7590, 'Layouts padrão', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7591, 'O Layout Builder pode ser habilitado seletivamente na página "Gerenciar exibição" na interface do <a href=":field_ui">campo .</a> Isso permite controlar a saída de cada tipo de display individualmente. Por exemplo, uma "página Básica" pode ter modos de exibição como Full e Teaser, com cada modo de exibição tendo layouts diferentes selecionados.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7592, 'Layouts substituídos', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7593, 'Se ativado, cada item de conteúdo individual pode ter um layout personalizado. Uma vez que o layout de um item de conteúdo individual seja substituído, alterações no layout padrão não o afetarão mais. Os layouts substituídos podem ser revertidos para coincidir e serem sincronizados com o layout padrão.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7594, 'Permite que usuários adicionem e organizem blocos e campos de conteúdo diretamente no conteúdo.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7595, 'Escolha um layout para esta seção', 'pt-br', 0);
