INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7626, '%capital_name contém 1 link de menu com revisões pendentes. A manipulação de uma árvore de menus com links com revisões pendentes não é suportada, mas você pode re-habilitar a manipulação obtendo cada link de menu para um estado publicado.%capital_name contém links de menu @count com revisões pendentes. A manipulação de uma árvore de menus com links com revisões pendentes não é suportada, mas você pode re-habilitar a manipulação obtendo cada link de menu para um estado publicado.', 'pt-br', 0);
