INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7636, '%capital_name contém 1 termo com revisões pendentes. Arrastar e soltar termos com revisões pendentes não é suportado, mas você pode ree habilitar o suporte de arrastar e soltar, levando cada termo a um estado publicado.%capital_name contém termos @count com revisões pendentes. Arrastar e soltar termos com revisões pendentes não é suportado, mas você pode ree habilitar o suporte de arrastar e soltar, levando cada termo a um estado publicado.', 'pt-br', 0);
