INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7746, 'Falha ao conectar no servidor do banco de dados. O servidor reporta a seguinte mensagem: %error.<ul><li>O servidor do banco de dados está rodando?</li><li>O banco de dados existe ou o usuário do banco de dados tem privilégios suficientes para criar o banco de dados?</li><li>Você digitou o nome correto do banco de dados?</li><li>Você digitou o nome de usuário e senha corretos?</li><li>Você digitou o nome do hospedeiro e o número da porta corretos do banco de dados?</li></ul>', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7747, 'Falha ao conectar no servidor do banco de dados. O servidor reporta a seguinte mensagem: %error.<ul><li>O servidor do banco de dados está rodando?</li><li>O banco de dados existe, e você digitou o nome correto do banco de dados?</li><li>Você digitou o nome de usuário e senha corretos?</li><li>Você digitou o nome do hospedeiro e o número da porta corretos?</li></ul>', 'pt-br', 0);
