INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7797, 'O filtro %media-embed-filter-label precisa de <code>&lt;drupal-media&gt;</code> entre as tags HTML permitidas.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7798, 'A tag <code>&lt;drupal-media&gt;</code> nas tags HTML permitidas não contém os seguintes atributos: <code>%list</code>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7799, 'O filtro %media-embed-filter-label precisa ser colocado após o filtro %filter.O filtro %media-embed-filter-label precisa ser colocado após os seguintes filtros: %filters.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7800, 'Se você deseja mudar isso, <a href=":display">adicione um estilo de imagem ao campo %field_name</a>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7801, 'O display padrão para o tipo de mídia %type não está atualmente usando um estilo de imagem no campo %field_name. Não usar um estilo de imagem pode levar a downloads de arquivos muito maiores. @action_item', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7802, 'O modo de exibição que é usado por padrão', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7803, 'Tipos de mídia selecionáveis na Biblioteca de Mídia', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7804, 'Exibir modos selecionáveis na caixa de diálogo "Editar mídia"', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7805, 'Filtra a mídia não publicada se o usuário atual não puder visualizá-la.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7806, 'O modo de exibição em que um item de mídia incorporado deve ser exibido por padrão. Isso pode ser substituído usando o atributo <code>data-view-mode</code>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7807, 'Se nada for selecionado, tudo será permitido.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7808, 'Modos de exibição selecionáveis na caixa de diálogo ''Editar mídia''', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7809, 'Se dois ou mais modos de exibição forem selecionados, os usuários poderão atualizar o modo de exibição que um item de mídia incorporado deve ser exibido depois que for incorporado.  Se menos de dois modos de exibição forem selecionados, a mídia será incorporada usando o modo de exibição padrão e nenhuma opção de modo de exibição aparecerá depois que um item de mídia for incorporado.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7810, 'A fonte de mídia referenciada está faltando e precisa ser informada novamente.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7811, '
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7812, 'Você pode incorporar itens de mídia (usando a tag <code>&lt;drupal-media&gt;</code>).', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7813, 'Durante a renderização de mídia incorporada: renderização recursiva detectada para %entity_id. Abortando a renderização.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7814, 'Durante a renderização de mídia incorporada: o item de mídia com UUID "@uuid" não existe.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (11789, 'Durante a renderização de mídia incorporada: o modo de exibição "@view-mode-id" não existe.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7815, 'Incorpore itens de mídia usando uma tag personalizada <code>&lt;drupal-media&gt;</code>. Se usado em conjunto com os filtros ''Alinhamento/Legenda'', certifique-se de que este filtro esteja configurado para ser executado depois deles.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7816, 'O módulo Media Library fornece uma interface visual rica para gerenciamento de mídia e permite que a mídia seja reutilizada em campos de referência de entidades ou incorporada ao conteúdo de texto. Ele substitui a página de administração de <a href=":media-collection">mídia,</a>permitindo que os usuários alternem entre a interface de estilo de tabela existente e uma nova interface no estilo grade para navegar e executar operações administrativas na mídia.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7817, 'Para saber mais sobre gestão de mídia, comece revisando a <a href=":media-help">documentação do módulo Media</a>. Para mais informações sobre a biblioteca de mídia e funcionalidades relacionadas, consulte a <a href=":media-library-handbook">documentação on-line para o módulo Media Library</a>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7818, 'Diálogo de seleção', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7819, 'Ao selecionar uma mídia para um campo de referência de entidade ou um editor de texto, a biblioteca de mídia abre uma caixa de diálogo para ajudar os usuários a encontrar e selecionar facilmente mídias. A caixa de diálogo pode alternar entre uma interface de grade ou de tabela e novos itens de mídia podem ser carregados nele diretamente.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7820, 'Dentro do diálogo, os itens de mídia são divididos por tipo. Se mais de um tipo de mídia puder ser selecionado pelo usuário, os tipos disponíveis serão exibidos como um conjunto de abas verticais. Para usuários que têm permissões apropriadas, cada tipo de mídia também pode apresentar um formulário curto que permite carregar ou criar novos itens de mídia desse tipo.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7821, 'Interface de estilo grade versus estilo de tabela', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7822, 'O módulo Media Library fornece uma nova interface no estilo grade para a página de administração de mídia que exibe a mídia como miniaturas, com informações textuais mínimas, permitindo que os usuários naveguem visualmente mídia em seu site. A interface de estilo de tabela existente é mais adequada para exibir informações adicionais sobre itens de mídia, além de ser mais acessível aos usuários com tecnologia assistiva.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7823, 'Reutilização de mídia em campos de referência de entidades', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7824, 'Qualquer campo de referência de entidade que faz referência para mídia pode usar a biblioteca de mídia. Para habilitar, configure a exibição de formulário para que o campo use o widget "Biblioteca de mídia".', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7825, 'Incorporando mídia em conteúdo de texto', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7826, 'Para usar a biblioteca de mídia dentro do CKEditor, você deve adicionar o botão "Inserir da Biblioteca de Mídia" na barra de ferramentas do CKEditor e ativar o filtro "Incorporar mídia" no formato de texto associado ao editor de texto.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7827, 'Ambas as interfaces de estilo de tabela e estilo de grade são visualizações regulares e podem ser personalizadas através da Views UI, incluindo classificação e filtragem. Este é o caso tanto da página de administração quanto da caixa de diálogo.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7828, 'Configurações da biblioteca de mídia', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7829, 'Gerenciar configurações da biblioteca de mídia.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7830, 'Configurações da biblioteca de mídia', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7831, 'Habilitar interface do usuário avançada', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7832, 'Sempre será usado um apelido de caminho definido para um idioma específico ao exibir esta página nesse idioma, e tem precedência sobre os pseudônimos de caminho definidos como <em>- Não especificado -</em>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7833, 'Não há apelidos de caminho disponíveis. <a href=":link">Adicionar apelido de URL</a>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7834, 'A página de busca para qual o formulário envia os dados, ou Padrão para a página de busca padrão.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7835, 'Temas experimentais encontrados: %theme_list. Temas experimentais são fornecidos apenas para fins de teste. Use por sua conta e risco.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7836, 'Diretório de sincronização de configuração', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7837, 'Seu arquivo %file deve definir a configuração %setting como uma string contendo o diretório no qual os arquivos de configuração podem ser encontrados.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7838, 'tema experimental', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7839, 'Um caminho do sistema de arquivos local no qual os arquivos temporários serão armazenados. Este diretório não deve ser acessível pela web. Isto deve ser alterado no arquivo settings.php.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7840, 'Tem certeza que deseja instalar um tema experimental?', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7841, 'Temas experimentais são fornecidos somente para fins de testes. Use por sua conta e risco.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7842, 'Os seguintes temas são experimentais: @themes', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7843, 'Modo de internacionalização.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7844, 'Idioma da tabela taxonomy_vocabulary.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7845, 'Tradução do nome ou da descrição.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7846, 'Código do idioma da tabela locales_target', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7847, 'Resumo obrigatório', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7848, 'Sempre exibir o resumo', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7849, 'O resumo também ficará visível quando marcado como obrigatório.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7850, 'O campo de resumo é obrigatório para @name', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7851, 'Sempre mostrar o campo de resumo', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7852, 'O campo de resumo será sempre visível', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7853, 'Muitas solicitações de recuperação de senha do seu endereço IP. Ele está temporariamente bloqueado. Tente novamente mais tarde ou entre em contato com o administrador do site.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7854, 'Limitar os operadores disponíveis', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7855, 'Lista de operadores disponíveis', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7856, 'Limita os operadores disponíveis que serão mostrados nos filtros expostos.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7857, 'Restrinja os operadores a', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7858, 'Selecionar nenhum fará com que todos estejam disponíveis.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7859, 'Você selecionou o operador "@operator" como valor padrão, mas o mesmo não está incluído na lista de operadores restritos.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7860, 'Fornece uma interface para criar fluxos de trabalho com transições entre diferentes estados (por exemplo, publicação ou status do usuário) fornecidas por outros módulos.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7861, 'Indica de qual espaço de trabalho esta revisão pertence.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7862, 'Mudar para produção', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7863, 'Você gostaria de mudar para a versão de produção do site?', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7866, 'Miniatura da biblioteca de mídia (220x220)', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7867, 'Apagar {{ name }}', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7868, 'Visualizando tópicos de ajuda', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7869, 'Os tópicos de ajuda de alto nível são listados na página principal <a href=":help_page">da Ajuda</a>. Links para outros tópicos, incluindo tópicos de ajuda não-de alto nível, podem ser encontrados no título "Relacionado" ao visualizar uma página de tópicos.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7870, 'Fornecendo tópicos de ajuda', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7871, 'Traduzindo tópicos de ajuda', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7872, 'O título e o texto de corpo dos tópicos de ajuda fornecidos por módulos e temas contribuídos são traduzíveis usando o módulo <a href=":locale_help">Interface Translation</a>. Tópicos fornecidos por módulos e temas personalizados também são traduzíveis se tiverem sido vistos pelo menos uma vez em um idioma não-inglês, o que desencadeia colocar seu texto traduzível no banco de dados de tradução.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7873, 'Configurando busca da ajuda', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7874, 'Consulte a <a href=":help_page">página Ajuda</a> para obter mais tópicos.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7875, 'Busca de ajuda', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7876, 'Configure as configurações de um bloco que foi colocado anteriormente em uma região de um tema.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7877, 'Clique no nome do tema que contém o bloco.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7878, 'Opcionalmente, clique em <em>Demonstrar regiões de bloco</em> para ver as regiões do tema.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7879, 'Se você quiser apenas alterar a região onde um bloco está localizado, ou a ordem dos blocos dentro de uma região, arraste blocos para as posições desejadas e clique em <em>Salvar blocos</em>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7880, 'Se você quiser alterar configurações adicionais, encontre a região onde o bloco que deseja atualizar está localizado atualmente e clique em <em>Configurar</em> na linha da descrição do bloco.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7881, 'Editar as configurações do bloco. As configurações disponíveis variam dependendo do módulo que fornece o bloco, mas para todos os blocos você pode alterar:', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7882, '<em>Título do bloco</em>: O cabeçalho para o bloco no seu site -- para alguns blocos, você precisará marcar a caixa <em>Sobrescrever título</em> para inserir um título', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7883, '<em>Título do display</em>: Marque esta caixa se quiser que o título seja exibido', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7884, '<em>Visibilidade</em>: Adiciona condições para quando o bloco deve ser exibido', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7885, '<em>Região</em>: Altera a região no tema em que o bloco é exibido', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7886, 'Clique em <em>Salvar bloco</em>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7887, 'O que são blocos?', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7888, 'Os blocos são caixas de conteúdo renderizadas em uma área ou região de uma página web do seu site. Os blocos são posicionados e configurados especificamente para cada tema.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7889, 'O que é a descrição de bloco?', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7890, 'A descrição do bloco é um nome de identificação para um bloco, que é mostrado na interface administrativa. Não é exibida no site.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7891, 'Qual é o título do bloco?', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7892, 'O título do bloco é o título que é mostrado opcionalmente aos visitantes quando o bloco é colocado em uma região.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7893, 'Coloque um bloco em uma região de um tema.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7894, 'Clique no nome do tema onde deseja colocar o bloco.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7895, 'Encontre a região onde deseja colocar o bloco e clique em <em>Colocar bloco</em> nessa região. Uma caixa de diálogo será mostrada.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7896, 'Encontre o bloco que deseja colocar e clique em <em>Colocar bloco</em>. Uma caixa de diálogo de <em>Configurar bloco</em> será mostrada.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7897, 'Digite a descrição do seu bloco (para ser exibido para administradores) e o corpo de texto para o seu bloco.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7898, 'Digite um rótulo para este tipo de bloco (mostrado na interface administrativa). Opcionalmente, edite o nome de máquina gerado automaticamente ou a descrição.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7899, 'Clique em <em>Salvar</em>. Você será redirecionado para a página <em>Tipos de bloco</em>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7900, 'Clique em <em>Gerenciar campos</em> na linha do seu novo tipo de bloco e adicione os campos desejados ao seu tipo de bloco.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7901, 'Opcionalmente, clique em <em>Gerenciar a exibição de formulário</em> ou em <em>Gerenciar exibição</em> para alterar o formulário de edição ou exibição de campo para seu tipo de bloco.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7902, 'Use links contextuais para acessar tarefas administrativas sem navegar no menu administrativo.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7903, 'O que são links contextuais?', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7904, '<em>Links contextuais</em> dão aos usuários com a permissão <em>Usar links contextuais</em> acesso rápido à tarefas administrativas relacionadas a áreas de páginas não administrativas. Por exemplo, se uma página em seu site exibe um bloco, o bloco teria um link contextual que permitiria aos usuários com permissão configurar o bloco. Se o bloco contiver um menu ou uma view, ele também teria um link contextual para editar os links do menu ou da view. Clicar em um link contextual leva você diretamente para a página administrativa relacionada, sem precisar navegar pelo sistema de menu administrativo.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7905, 'Certifique-se que o módulo Contextual Links está instalado e que você tenha um papel com a permissão de <em>Usar links contextuais</em>. Opcionalmente, certifique-se que um módulo de barra de ferramentas esteja instalado (seja o módulo Toolbar do core ou um módulo contribuído substituto).', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7906, 'Visite uma página não administrativa em seu site, como a página inicial.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7907, 'Localize um bloco ou outra área na página que deseja editar ou configurar.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7908, 'Torne visível o botão de links contextuais colocando o mouse sobre aquela área na página. Na maioria dos temas, este botão parece um lápis e é colocado no canto superior direito da área da página (canto superior esquerdo para idiomas da direita para a esquerda), e colocar o mouse sobre a área também irá delinear temporariamente a área afetada. Alternativamente, clique no botão de alternar links contextuais na extremidade direita da barra de ferramentas (extremidade esquerda para idiomas da direita para a esquerda), que tornará visíveis na página todos os botões de link contextuais, até que ele seja clicado novamente.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7909, 'Enquanto o botão de links contextuais para a área de interesse é visível, clique no botão para exibir a lista de links para essa área. Clique em um link na lista para visitar a página administrativa correspondente.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7910, 'Complete sua tarefa administrativa e salve suas configurações, ou cancele a ação. Você deve ser redirecionado para a página de onde começou.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7911, 'O que são atualizações de segurança?', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7912, 'Qualquer software ocasionalmente tem bugs, e às vezes esses bugs têm implicações de segurança. Quando os bugs de segurança são corrigidos no software principal, módulos ou temas que seu site usa, são liberados em uma <em>atualização de segurança</em>. Você precisará aplicar atualizações de segurança para manter seu site seguro.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7913, 'Tarefas de segurança', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7914, 'Acompanhar as atualizações, atualizar o software principal e atualizar módulos e/ou temas contribuídos fazem parte de manter seu site seguro. Veja os tópicos relacionados listados abaixo para tarefas específicas.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7915, 'Visão geral de acessibilidade', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7916, 'A interface padrão de arrastar-e-soltar de usuário para ordenar tabelas na interface administrativa representa um desafio para alguns usuários, incluindo usuários que usam somente teclado e usuários de leitores de tela e outras tecnologias assistivas. A interface arrastar-e-soltar pode ser desativada em uma tabela clicando em um link rotulado <em>mostrar pesos</em> na linha acima da tabela. A interface de substituição permite que usuários ordenem a tabela escolhendo pesos numéricos (com números crescentes) em vez de arrastar linhas da tabela.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7917, 'Visão geral da interface de administração', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7918, 'Um sistema de menu que você pode navegar para encontrar páginas para tarefas administrativas. O módulo Toolbar do core exibe este menu no lado superior ou esquerdo da página (lado direito em idiomas da direita para a esquerda). Há também módulos contribuídos que substituem o módulo Toolbar do core, com recursos adicionais, como o módulo <a href="https://www.drupal.org/project/admin_toolbar">Admin Toolbar</a>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7919, 'O módulo Shortcuts do core melhora a barra de ferramentas com uma lista configurável de links para tarefas comumente usadas.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8079, 'Telefone (módulo Telephone): Armazena números de telefones', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7920, 'Se você instalar o módulo do core Contextual Links, páginas não administrativas conterão links que levam as tarefas administrativas relacionadas.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7921, 'O módulo Help do core exibe tópicos de ajuda e fornece um bloco de ajuda que pode ser colocado em páginas administrativas para fornecer uma visão geral de sua funcionalidade.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7922, 'Consulte os tópicos relacionados listados abaixo para tarefas específicas.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7923, 'Configure seu site para os usuários poderem buscar por ajuda.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7924, 'No menu administrativo <em>Gerenciar</em>, navegue até <em>Configurações</em> &gt; <em>Busca e metadados</em> &gt; <em>Páginas de busca</em>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7925, 'Verifique se uma página de busca de ajuda está listada na seção <em>Páginas de busca</em>. Se não, adicione uma nova página do tipo <em>Ajuda</em>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7926, 'Crie, veja e use um conjunto de atalhos para acessar páginas administrativas.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7927, 'O que são atalhos?', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7928, '<em>Atalhos</em> são links rápidos para páginas administrativas. Eles são gerenciados pelo módulo Shortcut do core. Um site pode ter um ou mais <em>conjuntos de atalhos</em> que podem ser compartilhados por um ou mais usuários (por padrão, há apenas um conjunto compartilhado por todos os usuários). Cada conjunto contém um número limitado de atalhos. Os usuários precisam ter a permissão de <em>Usar atalhos</em> para ver atalhos, a permissão <em>Editar o conjunto de atalhos atuais</em> para adicionar, excluir ou editar os atalhos no conjunto atribuído à eles; e a permissão <em>Selecionar qualquer conjunto de atalho</em> para selecionar um conjunto de atalho diferente ao editar seu perfil de usuário. Há também uma permissão de <em>Administrar atalhos</em> que permite que um administrador faça qualquer uma dessas ações, bem como selecione conjuntos de atalhos para outros usuários.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7929, 'Navegue até uma página administrativa que você deseja em sua lista de atalhos.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7930, 'Repita até que todos os links desejados sejam adicionados ao conjunto de atalhos.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7931, 'Clique em <em>Atalhos</em> na barra de ferramentas para exibir seus atalhos e verifique se a lista está completa.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7932, 'Opcionalmente clique em <em>Editar atalhos</em> na extremidade direita da lista de atalhos para remover links ou alterar sua ordem.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7933, 'Clique em qualquer link na barra de atalho para ir diretamente à página administrativa.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7934, 'Configure as definições do seu site, incluindo o nome do site, slogan, e-mail principal, fuso horário padrão, país padrão e o formato de data a ser utilizado.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7935, 'Digite o nome do site, slogan e o principal endereço de e-mail do site.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7936, 'Clique em <em>Salvar configuração</em>. Você deve ver uma mensagem indicando que as configurações foram salvas.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7937, 'Selecione o país e o fuso horário padrão para o seu site.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7938, 'Veja os <em>Padrões</em> para os formatos padrão de data longa, média e curta. Se algum deles não corresponder ao formato de data que deseja usar em seu site, clique em <em>Editar</em> nessa linha para editar o formato.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7939, 'Ajuste a <em>Formatar string</em> até que o formato <em>Exibido</em> corresponda ao que você deseja. (As strings de formato de data são compostas por códigos de formato de data PHP.)', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7940, 'Clique em <em>Salvar formato</em>. Você deve ver uma mensagem indicando que o formato foi salvo.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7941, 'Repita as três etapas anteriores para quaisquer outros formatos de data que precisem ser alterados.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7942, 'Configure seu site para responder aos erros do site adequadamente, incluindo respostas de páginas 403 e 404.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7943, 'O que são as respostas 403 e 404?', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7944, 'Quando um usuário visita uma página web, o servidor web envia um código de resposta, além do conteúdo da página. Uma resposta normal, sem erro, tem código 200. Se a página não existir no site, o código de resposta é 404. Se a página existir, mas o usuário não estiver autorizado a visitar a página, o código de resposta é 403. O software principal fornece respostas padrão para códigos 403 e 404, mas se preferir, você pode criar suas próprias páginas para cada um.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7945, 'Quais outros erros podem ocorrer?', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7946, 'Em algumas situações, seu site pode gerar mensagens de erro. Estes podem ser devido a erros do usuário (como inserir valores inválidos em um formulário ou configuração incorreta), erros de tempo de execução PHP ou bugs de software. Alguns erros podem resultar em uma <em>tela branca da morte</em> (uma resposta totalmente em branco na página web); erros menos drásticos gerarão mensagens de erro. Você pode configurar o que acontece quando uma mensagem de erro é gerada.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7947, 'Se desejar, crie páginas que serão usadas para respostas 403 e 404. Observe as URLs para estas páginas.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7948, 'Para um site em produção, selecione <em>Nenhum</em> nas <em>Mensagens de erro para exibir</em>. Para um site que esteja em desenvolvimento, selecione uma das outras opções para que você esteja ciente dos erros que o site está gerando.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7949, 'Define as configurações relacionadas de como as contas de usuários são criadas e excluídas.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7950, 'Quais são as configurações relacionadas a criação e exclusão de contas de usuário?', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7951, 'Você pode deixar que novos usuários se registrem, com ou sem verificação de e-mail ou aprovação administrativa ou você dizer que apenas administradores com permissão de <em>Administrar usuários</em> possam registrar novos usuários.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7952, 'Você pode configurar o que acontece com o conteúdo que um usuário criou, se sua conta for <em>cancelada</em> (excluída).', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7953, 'Você pode editar as mensagens de e-mail enviadas aos usuários quando suas contas estão pendentes, aprovadas, criadas, bloqueadas ou canceladas, ou quando solicitam uma redefinição de senha.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7954, 'Quais são variáveis na mensagem do texto do email?', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7955, '<em>Variáveis</em> são strings de texto curtas, incluídas entre colchetes [] que você pode inserir no texto da mensagem de e-mail configurada. Quando uma mensagem individual é gerada, os dados do seu site são substituídos pelas variáveis. Algumas variáveis comumente utilizadas são:', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7956, '[site:login-url]: A URL onde os usuários podem se autenticar no seu site.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7957, '[user:display-name]: O nome do usuário apresentado.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7958, '[user:mail]: O e-mail alternativo do usuário.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7959, '[user:one-time-login-url]: Uma URL temporária que um usuário pode usar para fazer login uma vez, se precisar recuperar sua senha.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8080, 'O que é um formatador?', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7960, 'Selecione o método que deseja usar para criar contas de usuário e marque ou desmarque a caixa que requer verificação de e-mail para corresponder às configurações desejadas para o seu site.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7961, 'Selecione a opção desejada para o que acontece com o conteúdo que um usuário criou se sua conta for cancelada.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7962, 'Opcionalmente, edite o texto das mensagens de e-mail relacionadas as contas de usuários.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7963, 'Verifique se as outras configurações estão corretas.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7964, 'Os tópicos podem ser fornecidos por módulos ou temas. Tópicos de ajuda de alto nível em seu site:', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7965, 'Ambas as interfaces de estilo de tabela e estilo de grade são visualizações regulares e podem ser personalizadas através da <a href=":views-ui">Views UI</a>, incluindo classificação e filtragem. Este é o caso tanto da página de administração quanto da caixa de diálogo.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7966, 'Na interface com estilo grade, os campos exibidos (incluindo qual estilo de imagem é usado para imagens) podem ser personalizados configurando o modo de exibição "Biblioteca de mídia" para cada um de seus <a href=":media-types">tipos de mídia</a>. As imagens em miniatura na interface com estilo grade podem ser personalizadas configurando o estilo de imagem "Media Library thumbnail (220×220)".', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7967, 'Ao adicionar novos itens de mídia dentro da caixa de diálogo, os campos que são exibidos podem ser personalizados configurando o modo de formulário "Biblioteca de mídia" para cada um de seus <a href=":media-types">tipos de mídia</a>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7968, 'Fornece a API que permite renomear URLs.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7969, 'O espaço de trabalho superior.', 'pt-br', 0);
