INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7971, 'Apenas espaços de trabalho de nível superior podem ser publicados.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7972, 'Mesclar em @target_label', 'pt-br', 0);
