INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7982, 'O campo que será usado como link de item RSS para cada linha. Deve ser um caminho interno não processado como "node/123" ou uma URL processada e relativa a raiz, produzida por campos como “Link para o conteúdo”.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7983, 'Renderização recursiva detectada ao renderizar a entidade %entity_type: %entity_id usando o campo %field_name na %parent_entity_type: %parent_bundle %parent_entity_id. Interrompendo a renderização.', 'pt-br', 0);
