INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7990, 'O instalador do @drupal requer que o arquivo %default-file não seja excluído ou modificado do download original.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (7991, 'O Field Discovery falhou na versão do core do Drupal @core. Este site tinha o módulo Field instalado? Erro: @message', 'pt-br', 0);
