INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8151, 'Aguarde que o módulo seja desinstalado. Você deve ser redirecionado para a página <em>Desinstalar</em> com uma mensagem dizendo que o módulo foi desinstalado.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8022, 'Dependendo da sua configuração, o Drupal pode funcionar com um limite de @apcu_size APCu. No entanto, um limite de APCu @apcu_default_size (padrão) ou acima é recomendado, especialmente se o seu site usar módulos adicionais personalizados ou contribuídos.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8023, 'Memória disponível: @available.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8024, 'O cache PHP APCu pode melhorar consideravelmente o desempenho do seu site. É <strong>altamente recomendável</strong> ter o <a href="https://www.php.net/manual/apcu.installation.php" target="_blank">APCu</a> instalado em seu servidor.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8025, 'A versão do Drupal da qual você está tentando atualizar é muito antiga', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8026, 'Versão de esquema não suportada: @module', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8027, 'A versão instalada do módulo %module é muito antiga para ser atualizada. Atualize primeiro para uma versão intermediária (última versão removida: @last_removed_version, versão instalada: @installed_version).', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8028, 'Fornece uma interface de usuário para criar e gerenciar views.', 'pt-br', 0);
