INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8041, 'Revise as <a href=":url">sugestões para resolver essa incompatibilidade</a> para reparar sua instalação e, em seguida, execute novamente o update.php.', 'pt-br', 0);
