INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8049, 'O seguinte módulo está marcado como instalado na configuração core.extension, mas está faltando:Os seguintes módulos estão marcados como instalados na configuração core.extension, mas estão faltando:', 'pt-br', 0);
