INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8053, 'A versão instalada do módulo %module é muito antiga para ser atualizada. Atualize primeiro para uma versão antes de @versions (atualizações ausentes: @missing_updates).A versão instalada do módulo %module é muito antiga para ser atualizada. Atualize primeiro para uma versão anterior de umas das seguintes versões: @versions (atualizações ausentes: @missing_updates).', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8054, '@module_name (<span class="admin-missing">ausente</span>)', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8055, '@module_name (<span class="admin-missing">incompatível com</span> esta versão do core do Drupal)', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8056, '@module_name (<span class="admin-missing">incompatível com</span> versão @version)', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8057, '@module_name<span class="admin-disabled">(desativado)</span>', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8058, 'Não é possível instalar @theme devido as dependências de módulos faltantes.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8059, 'Versão vazia', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8060, 'Versão inválida: @existing_version', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8061, 'Estável 9', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8062, 'Um tema base usando a marcação do core do Drupal 9.0.0 e CSS.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8063, 'Proibe visitantes de um ou mais endereços IP de acessar e visualizar seu site.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8064, 'Digite um <em>endereço IP</em> e clique em <em>Adicionar</em>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8065, 'Você deve ver o endereço IP digitado listado em <em>Endereços IP banidos</em>. Repita as etapas acima para proibir endereços IP adicionais.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8069, 'Dentro de itens de entidade, os dados são armazenados em <em>campos</em> individuais, cada um dos quais contém um tipo de dados, como texto formatado ou simples, imagens ou outros arquivos ou datas. Os campos podem ser adicionados por um administrador em subtipos de entidade, de modo que todos os itens da entidade de um determinado subtipo de entidade tenham a mesma coleção de campos disponíveis, e eles possam ser de valor único ou de valor múltiplo. Quando você cria ou edita itens da entidade, você está especificando os valores para os campos no item da entidade.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8071, 'Um <em>campo de referência</em> é um campo que armazena uma relação entre uma entidade e uma ou mais entidades, que podem pertencer ao mesmo tipo de entidade ou diferente. Por exemplo, um campo <em>de referência de conteúdo</em> em um tipo de conteúdo armazena uma relação entre um item de conteúdo e um ou mais itens de conteúdo.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8072, 'Quais tipos de campos estão disponíveis?', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8073, 'Os seguintes tipos de campo são fornecidos pelo sistema principal e módulos principais (muitos mais são fornecidos por módulos contribuídos):', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8074, 'Booleano, Número (fornecido pelo sistema principal): Armazena valores verdadeiros/falsos e números', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8075, 'Comentário (fornecido pelo módulo Comment): Permite que usuários adicionem comentários em uma entidade', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8076, 'Data, Timestamp (módulo Datetime): Armazena datas e horas', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8077, 'Email (core system): Armazena endereços de e-mail', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8078, 'Link (módulo Link): Armazena URLs e textos de links', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8081, 'Um <em>formatador</em> é uma maneira de exibir um campo; a maioria dos tipos de campo oferecem vários tipos de formatadores e a maioria dos formatadores possuem configurações que definem ainda mais como o campo é exibido. Também é possível ocultar completamente um campo da exibição, e você tem a opção de mostrar ou ocultar o rótulo do campo quando ele é exibido.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8082, 'O que é um widget?', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8083, 'Um <em>widget</em> é uma maneira de editar um campo. Alguns tipos de campo, como campos de linha única de texto simples, têm apenas um widget disponível (neste caso, um campo de entrada de texto de linha única). Outros tipos de campo oferecem opções para o widget; por exemplo, os campos <em>de lista</em> de um valor único podem usar um widget de botão <em>Select</em> ou <em>Radio</em> para edição. Muitos tipos de widget têm configurações que definem ainda mais como o campo pode ser editado.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8084, 'Gerenciando a visão geral da estrutura de conteúdo', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8085, 'Além dos módulos de campo listados na seção anterior, existem módulos adicionais do core que você pode usar para gerenciar sua estrutura de conteúdo:', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8086, 'Configure seu sistema para que o cron seja executado automaticamente.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8087, 'O que são tarefas agendadas?', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8088, 'Para garantir que seu site e seus módulos continuem funcionando bem, um grupo de operações administrativas deve ser executado periodicamente. Essas operações são chamadas de tarefas de <em>cron</em> e executar estas tarefas é conhecido como <em>executar o cron</em>. Dependendo da frequência com que o conteúdo é atualizado em seu site, pode ser que precise executar o cron com uma frequência que varia de hora em hora a semanal para manter seu site funcionando bem.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8089, 'Quais opções estão disponíveis para executar o cron?', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8090, 'Se o módulo do core Automated Cron está instalado, seu site pode executar o cron periodicamente em uma frequência que você pode configurar.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8091, 'Você pode configurar uma tarefa em seu servidor web visitando a <em> URL do cron</em>, que é exclusiva do seu site, periodicamente.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8092, 'Você também pode executar o cron manualmente, mas esta não é a maneira recomendada de se certificar de que é executado periodicamente.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8093, 'Se você quiser executar agora o cron, clique em <em>Executar cron</em> e espere que o cron termine.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8094, 'Se você tiver uma maneira para configurar tarefas em seu servidor web, copie o link onde ele diz <em>Para executar o cron de fora do site, vá para</em>. Configure uma tarefa para visitar essa URL no cronograma desejado de cron, como uma vez por hora ou uma vez por semana. (Em servidores semelhantes ao Linux, você pode usar o comando <em>wget</em> para visitar uma URL). Se você configurar uma tarefa externa, você deve desinstalar o módulo Automated Cron.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8095, 'Se você não está configurando uma tarefa externa e tiver o módulo Automated Cron do core instalado, selecione um cronograma para execuções automatizadas do cron nas <em>Configurações do Cron</em> &gt; <em>Rodar agendador de tarefas a cada</em>. Clique em <em>Salvar configurações</em>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8096, 'O que é um módulo?', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8097, 'Um <em>módulo</em> é um conjunto de arquivos PHP, JavaScript e/ou CSS que amplia os recursos do site e adiciona funcionalidade. Um conjunto de <em>módulos Core</em> é distribuído como parte do download do software principal. Módulos <em>adicionais contribuídos</em> podem ser baixados separadamente na página <a href="https://www.drupal.org/project/project_module">Download &amp; Estender no drupal.org</a>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8098, 'O que é um módulo Experimental?', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8099, 'Um módulo <em>Experimental</em> é um módulo que ainda está em desenvolvimento e ainda não está estável. O uso de módulos experimentais em produção não é recomendado.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8100, 'O que está instalando e desinstalando?', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8101, 'Instalar um módulo do core ou um módulo contribuído baixado significa ligá-lo, para que você possa usar seus recursos e funcionalidade. Desinstalar significa desligá-lo e remover toda a sua configuração. Um módulo não pode ser desinstalado se outro módulo instalado depender dele, ou se você tiver criado conteúdo em seu site usando o módulo -- você precisará excluir o conteúdo e desinstalar módulos dependentes primeiro.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8102, 'Ampliando a visão geral', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8103, 'Consulte os tópicos relacionados listados abaixo para ajuda na execução de tarefas relacionadas a extensão de funcionalidades do seu site.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8104, 'Visão geral de manutenção e solução de problemas', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8105, 'Aqui estão algumas tarefas e dicas relacionadas a manutenção do seu site, e solução de problemas que podem surgir em seu site. Veja os tópicos relacionados abaixo para mais informações.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8106, 'Configure seu site para que o cron seja executado periodicamente.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8107, 'Se o seu site não estiver se comportando como esperado, limpe o cache antes de tentar diagnosticar o problema.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8108, 'No site existem vários relatórios que podem ajudá-lo a diagnosticar problemas. Há também dois módulos do core que podem ser usados para registro de erros: Database Logging e Syslog.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8109, 'Encontre o subtipo específico para qual deseja adicionar o campo e clique em <em>Gerenciar campos</em>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8110, 'Clique <em>Adicionar campo</em>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8111, 'O campo <em>Rótulo</em> agora deve ser visível. Digite um rótulo para o campo, que é usado como rótulo de campo para edição e exibição de conteúdo.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8112, 'Clique em <em>Salvar e continuar</em>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8113, 'Na próxima tela, digite um valor para o <em>Número de valores permitidos</em>. Você pode limitar o campo a um valor por item de entidade, um número definido de valores ou defini-lo para ter valores ilimitados. Clique em <em>Salvar configurações de campo</em>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8114, 'Na próxima tela, opcionalmente edite as configurações para o campo, que variam de acordo com o tipo de campo que você está criando. Para todos os campos você pode editar o <em>Rótulo</em>, o texto de <em>Ajuda</em> (texto exibido abaixo do campo na página de edição do conteúdo) e <em>Campo obrigatório</em> (para forçar que um valor seja digitado para salvar o conteúdo ao editar). Você também pode configurar um valor padrão para o campo.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8115, 'Encontre o subtipo específico do qual deseja configurar o display e clique em <em>Exibir</em> na lista <em>Operações</em>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8116, 'Use as setas de arrasto para ordenar os campos na ordem que deseja.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8117, 'Arraste todos os campos que você não deseja ver no display para a seção <em>Desativar</em>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8152, 'Execute relatórios para saber sobre o estado e a saúde do seu site.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8118, 'Na coluna <em>Rótulo</em>, selecione a posição para cada etiqueta de campo na exibição ou <em>- Oculto -</em> para ocultar um rótulo. Você também pode escolher <em>- Visualmente Escondido -</em> se você quiser que o texto da etiqueta apareça na página HTML para que os leitores de tela e mecanismos de busca possam lê-lo, mas sem mostrá-lo.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8119, 'Na coluna <em>Formato</em>, selecione o formatador para exibir cada campo.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8120, 'Depois de selecionar os formatadores desejados, clique na engrenagem de configurações em cada linha para alterar as configurações do formatador.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8121, 'Quando terminar de fazer alterações, clique em <em>Salvar</em>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8122, 'Teste a apresentação para o subtipo de entidade visualizando sua entidade. Se necessário, retorne a essas etapas para refinar ainda mais a apresentação.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8123, 'Encontre o subtipo específico para o qual deseja configurar o formulário de edição e clique em <em>Exibir formulário</em> na lista <em>Operações</em>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8124, 'Arraste todos os campos que você não deseja ver no formulário de edição para a seção <em>Desativar</em>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8125, 'Na coluna <em>Widget</em>, selecione o widget para editar cada campo.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8126, 'Depois de selecionar os widgets desejados, clique na engrenagem de configurações em cada linha para alterar as configurações do widget.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8127, 'Teste o formulário de edição para o subtipo da sua entidade editando ou criando uma entidade. Se necessário, retorne a essas etapas para refinar ainda mais o formulário.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8128, 'Em <em>Adicionar um novo campo</em>, selecione o tipo de campo de referência que deseja adicionar. A seção <em>Referência</em> da lista selecionada mostra os tipos mais comuns de campo de referência. Escolha <em>Outro...</em> se o tipo de entidade que você deseja fazer referência não estiver listado.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8129, 'Na próxima tela, verifique se o tipo de entidade que você deseja referenciar é mostrado no <em>Tipo de item para referência</em> ou, caso contrário, selecione isto. Digite um valor para o <em>Número de valores permitidos</em>. Você pode limitar o campo para um valor por item de entidade, um número definido de valores ou defini-lo para ter valores ilimitados. Clique em <em>Salvar configurações de campo</em>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8130, 'Na tela seguinte, opcionalmente edite as configurações para <em>Rótulo</em>, <em>Texto de Ajuda</em> (texto a ser exibido abaixo do campo na página de edição de conteúdo) e <em>Campo Obrigatório</em> (para que um valor seja digitado para salvar o conteúdo durante a edição).', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8131, 'Na seção <em>Tipo de Referência</em>, você geralmente deseja limitar os subtipos da entidade que podem ser referenciados. Por exemplo, se você estiver criando uma referência de <em>Conteúdo</em>, você pode marcar uma ou duas opções de <em>Tipo de conteúdo</em>. As escolhas serão ainda mais fáceis para os editores de conteúdo procurarem se você também escolher um valor de classificação (normalmente o título da entidade ou o campo de rótulos).', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8132, 'Limpa os dados armazendos no cache do site.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8133, 'O que é cache?', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8134, 'Alguns dos cálculos que são feitos quando seu site carrega uma página levam muito tempo para serem executados. Para economizar tempo quando esses cálculos precisariam ser feitos novamente, seus resultados podem ser <em>armazenados</em> em cache no banco de dados do seu site. Existem mecanismos internos para <em>limpar</em> dados armazenados em cache quando as condições ou suposições que entraram no cálculo mudaram, mas você também pode limpar os dados armazenados manualmente. Quando seu site está se comportando mal, um bom primeiro passo é limpar o cache e ver se o problema desaparece.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8135, 'Clique em <em>Limpar todos os caches</em>. Os dados do seu site armazenados em cache serão limpos.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8136, 'Coloque seu site no modo de manutenção para realizar operações de manutenção e, em seguida, retorne ao modo normal quando terminar.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8137, 'O que é o modo de manutenção?', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8138, 'Quando seu site estiver no modo de manutenção, a maioria dos visitantes do site verá uma simples página com mensagem do modo de manutenção, em vez de usar todas as funcionalidades do site. Usuários com a permissão <em>Usar o site no modo de manutenção</em> que já estão autenticados poderão usar o site completo e a página de autenticação em <em>/user</em> também estará acessível para qualquer um.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8139, 'Marque <em>Colocar o site no modo de manutenção</em> e, opcionalmente, troque a <em>Mensagem para exibir quando estiver no modo de manutenção</em> e clique em <em>Salvar configuração</em>. Seu site estará em modo de manutenção.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8140, 'Realize suas operações de manutenção.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8141, 'Desmarque <em>Colocar o site no modo de manutenção</em> e clique em <em>Salvar configuração</em>. Seu site estará de volta no modo normal de operação.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8142, 'Instale um módulo core ou um módulo contribuído que já tenha sido baixado.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8143, 'Digite uma palavra do nome do módulo ou da descrição na caixa do filtro para tornar a lista de módulos menor. Localize o módulo que deseja instalar.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8144, 'Marque a caixa ao lado do nome do módulo que deseja instalar. Você também pode marcar mais de uma caixa para instalar vários módulos ao mesmo tempo. Se a caixa do módulo que você está tentando instalar estiver desativada, expanda as informações para ver porquê -- pode ser que você precise baixar um módulo adicional que seu módulo precisa.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8145, 'Clique em <em>Instalar</em> na parte inferior da página. Se você optou por instalar um módulo com dependências que ainda não estavam instaladas, ou se você escolheu um módulo Experimental, confirme sua escolha na próxima página.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8146, 'Aguarde a instalação do módulo (ou módulos). Você deve ser redirecionado para a página <em>Estender</em> com uma mensagem dizendo que o módulo ou módulos foram instalados.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8147, 'Digite uma palavra do nome do módulo ou da descrição na caixa do filtro para tornar a lista de módulos menor. Localize o módulo que deseja desinstalar.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8148, 'Na coluna <em>Descrição,</em> veja se há razões porque este módulo não pode ser desinstalado. Por exemplo, você pode ter criado conteúdo usando este módulo (que você precisaria excluir primeiro), ou pode existir outro módulo instalado que exija que este módulo seja instalado (você precisaria desinstalar o outro módulo primeiro).', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8149, 'Se não houver razões listadas, o módulo pode ser desinstalado. Marque a caixa na coluna <em>Desinstalar,</em> ao lado do nome do módulo.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8150, 'Clique em <em>Desinstalar</em> na parte inferior da página. Verifique a lista de módulos a serem desinstalados e a configuração a ser excluída na página de confirmação e clique em <em>Desinstalar</em>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8153, 'Se você tiver o módulo Database Logging do core instalado, no menu administrativo <em>Gerenciar</em>, navegue até <em>Relatórios</em> &gt; <em>Mensagens recentes do registro</em> para ver um relatório de erros e das mensagens informacionais geradas pelo seu site. Você pode filtrar o relatório por <em>Gravidade</em> para ver apenas as mensagens mais críticas, se desejar.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8154, 'Clique <em>Adicionar usuário</em>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8155, 'Informe o <em>endereço de E-mail</em>, <em>Nome de usuário</em> e <em>Senha</em> (duas vezes) para o novo usuário.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8156, 'Verifique se os <em>papéis</em> selecionados para o novo usuário estão corretos.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8157, 'Se você quiser que o novo usuário receba uma mensagem de e-mail notificando-o da nova conta, marque <em>Notificar o usuário de nova conta</em>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8158, 'Opcionalmente, altere outras configurações no formulário.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8159, 'Clique em <em>Criar nova conta</em>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8160, 'Você será deixado a página <em>Adicionar usuário</em>. Repita estes passos se você precisa criar mais contas de usuário.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8161, 'Criar um novo papel.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8162, 'Clique em <em>Adicionar papel</em>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8163, 'Digite o <em>Nome do papel</em> desejado. Se quiser, clique em <em>Editar</em> para alterar o <em>Nome de máquina</em> para o papel.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8164, 'Clique em <em>Salvar</em>. Você deve ser redirecionado para a página <em>Papéis</em> e seu novo papel deve estar na lista de papéis.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8165, 'O que é um usuário?', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8166, 'Usuário é qualquer pessoa acessando ou visitando seu site. Usuários <em>anônimos</em> são usuários que não estão logados e usuários <em>autenticados</em> são usuários que estão logados.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8167, 'O que é um papel?', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8168, '<em>Papéis</em> são usados para agrupar e classificar usuários. Cada usuário ter um ou mais papéis. Existem também papéis especiais para todos os usuários anônimos e autenticados.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8169, 'O que é uma permissão?', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8170, 'A concessão de uma <em>permissão</em> para um papel permite que os usuários que foram designados para desempenhar esse papel executem uma ação no site, como ver conteúdo, editar ou criar um determinado tipo de conteúdo, administrar configurações para um determinado módulo ou usar uma função específica do site (como a busca).', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8171, 'Visão geral do gerenciamento de contas e visitantes', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8172, 'Modifique as permissões para um papel existente.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8173, 'Revise as permissões para o papel, prestando especial atenção às permissões marcadas com <em>Aviso: Dê somente para papéis confiáveis; esta permissão tem implicações de segurança.</em> Na linha da permissão e da coluna do papel, Marque ou desmarque permissões para este papel.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8174, 'Clique <em>Salvar permissões</em>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8175, 'Atualizando ou excluindo um usuário existente.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8176, 'Digite todo ou parte do nome do usuário ou endereço de e-mail da conta de usuário que deseja atualizar ou excluir e clique em <em>Filtro</em>. Uma pequena lista de contas de usuário, incluindo a conta de interesse, deve ser mostrada na tabela; se não, modifique o texto do filtro até que você possa encontrar a conta de interesse.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8177, 'Clique em <em>Editar</em> na área de <em>Operações</em> da conta de interesse.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8178, 'Para excluir a conta do usuário, role até a parte inferior e clique em <em>Cancelar conta</em>. Selecione o que deve acontecer com o conteúdo do usuário na próxima tela e clique em <em>Cancelar conta</em>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8179, 'Para atualizar a conta do usuário, digite novos valores no formulário e clique em <em>Salvar</em>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8180, 'Manipulador de seleção', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8181, 'Configurações do manipulador de seleção', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8182, 'Linguagens de programação', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8183, 'A mídia foi removida.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8184, 'Utilitários Olivero', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8185, 'Habilite o menu mobile para todas as larguras', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8186, 'Cor de fundo do cabeçalho da marca', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8187, 'Busque por palavra-chave ou frase.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8188, 'Nav média', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8189, 'Grade média', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8193, 'Informação de schema para o módulo %module estava faltando no banco de dados. Você deve revisar manualmente as atualizações dos módulos e seu banco de dados para verificar se alguma atualização foi pulada, e incluir %last_update_hook.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8194, 'Adicione, remova ou reorganize os campos em formulários de contato pessoal para todo o site.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8195, 'O que são os campos nos formulários de contato?', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8196, 'Clique em <em>Gerenciar campos</em> no formulário que deseja alterar os campos e adicione ou remova um ou mais campos no formulário.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8197, 'Clique em <em>Gerenciar exibição de formulário</em> para alterar a ordem ou cofiguração dos campos no formulário.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8198, 'Configure formulários de contato pessoal para usuários cadastrados no site.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8199, 'Na seção <em>Configurações de contato</em> marque/desmarque a caixa para habilitar/desabilitar o formulário de contato para novas contas de usuário.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8200, 'Clique <em>Salvar configurações</em>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8201, 'Verifique se as permissões estão corretas para os papéis do seu site, incluindo o <em>usuário Anônimo</em> genérico e o <em>usuário Autenticado</em>. Para usar formulários de contato pessoal, usuários precisam tanto da permissão de <em>Ver informações do usuário</em> (na seção <em>User</em>, que permite visualizar perfis de usuários) quanto <em>Usar os formulários de contatos pessoais dos usuários</em> (na seção <em>Contact</em>, que permite que eles usem formulários de contato se puderem visualizar perfis de usuários).', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8202, 'Criar um novo formulário de contato para todo o site.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8203, 'Clique <em>Adicionar formulário de contato</em>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8204, 'Preencha o <em>Rótulo</em> (título) para o formulário, <em>Destinatários</em>e, opcionalmente, as outras configurações.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8205, 'Clique em <em>Salvar</em>. Você deve ver seu novo formulário de contato na tabela, juntamente com um link para visualizá-lo.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8206, 'O que são formulários de contato?', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8247, 'O que é desempenho do site?', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8248, 'O desempenho do site, neste contexto, refere-se a fatores de velocidade, como o tempo de carga da página e o tempo de resposta após uma ação do usuário em uma página.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8207, 'Existem dois tipos diferentes de formulários de contato fornecidos pelo módulo Contact do core: formulários de contato pessoais, que permitem que usuários entrem em contato com outros usuários no site e formulários de contato em todo o site, que permitem que usuários entrem em contato com os gerentes ou administradores do site. Um site pode ter mais de um formulário de contato para todo o site; cada um com seus próprios campos para preencher, destinatários e URL. Você também pode alterar os campos que são mostrados nos formulários de contato pessoal.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8208, 'Visitantes do site podem enviar um e-mail aos usuários cadastrados em seu site usando o formulário de contato pessoal, sem saber ou descobrir o endereço de e-mail do destinatário. Quando um usuário com as permissões corretas está visitando o perfil de outro usuário, ele verá uma aba de <em>Contato</em> ou link, que o leva ao formulário de contato pessoal, caso o usuário cujo perfil esteja sendo visto tenha seu formulário de contato pessoal ativado (esta é uma configuração da conta de usuário).', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8209, 'Tarefas de gerenciamento de formulários de contato', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8210, 'Veja os tópicos relacionados abaixo para tarefas específicas.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8211, 'Clique em <em>Editar</em> para escolher qual formulário de todo o site deseja que seja o padrão.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8212, 'Marque <em>Fazer deste o formulário padrão</em> e clique em <em>Salvar</em>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8213, 'Clique em <em>Salvar configurações</em>. Você deve ser redirecionado para a página <em>Gerenciar campos</em>, com seu novo campo na lista.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8214, 'Seja para forçar a saída ser um link absoluto (começando com http: ou https:)', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (11790, 'Se forçar essa URL a apontar para um local seguro (começando com https:)', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8215, 'Tradução %langcode verificada para %project.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8216, 'Tradução %langcode baixada para %project.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (663, 'Importando tradução %langcode para %project.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8217, 'Tradução %langcode importada para %project.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8218, 'Parece que você tem conteúdo em seu novo site que <strong>pode ser substituído</strong> se você continuar a executar esta atualização. A atualização deve ser realizada em uma instalação limpa do Drupal @version. Para mais informações, consulte o <a target="_blank" href=":id-conflicts-handbook">manual de atualização</a>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8219, 'Uma atualização já foi realizada neste site. Para realizar uma nova migração, crie uma nova instalação limpa e vazia do Drupal @version. Reversões ainda não são suportadas através da interface do usuário. Para mais informações, consulte o <a href=":url">manual de atualização</a>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8220, 'Atualize um site importando seus arquivos e dados do seu banco de dados para uma nova instalação limpa e vazia do Drupal @version. Consulte o <a href=":url">manual de atualizações de site Drupal</a> para mais informações.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8221, 'Esta instalação vazia do Drupal @version para você importar o site antigo.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8222, 'O nome do menu (= set name) para este atalho de link.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8223, 'Existem erros com alguns temas instalados. Visite a página do <a href=":link">Relatório de status</a> para mais informações.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8224, 'Existem erros com alguns módulos instalados. Visite a página do <a href=":link">Relatório de status</a> para mais informações.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8225, 'O nome de máquina da exibição deve conter apenas letras minúsculas, números ou sublinhados.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8226, 'O módulo %name possui uma entrada de armazenamento de chave/valor em system.schema, mas está faltando em seu site. <a href=":url">Mais informações a respeito deste erro</a>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8227, 'O módulo %name possui uma entrada de armazenamento de chave/valor em system.schema, mas não está instalado. <a href=":url">Mais informações a respeito deste erro</a>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8228, 'Faltando dados necessários para configuração: %config', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8229, 'Formulário de busca (estreito)', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8230, 'Formulário de busca (largo)', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8231, 'O que são breakpoints?', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8232, 'Breakpoints são o ponto em que o conteúdo do seu site responderá para fornecer ao usuário o melhor layout possível para consumir as informações. Um breakpoint separa a altura ou largura das versões (telas, impressoras e outros tipos de saída de mídia) em etapas. Por exemplo, um breakpoint com largura de 40em cria duas etapas: uma para larguras até 40em e outra para larguras acima de 40em. Os breakpoints podem ser usados para definir quando os layouts devem mudar de uma forma para outra, quando as imagens devem ser redimensionadas e outras alterações que precisam responder a alterações na altura ou largura do viewport.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8233, 'O que são consultas de mídia?', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8234, 'Consultas de mídia são uma maneira formal de codificar breakpoints. Por exemplo, um breakpoint de largura em 40em seria escrito como a consulta de mídia "(min-width: 40em)". Breakpoints são realmente apenas consultas de mídia com alguns metadados adicionais, como informações de nome e multiplicador.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8235, 'O que são multiplicadores de resolução?', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8236, 'O que é um grupo de breakpoint?', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8237, 'Gerenciando breakpoints e pré-visualização de grupos de breakpoints', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8238, 'O módulo <em>Breakpoint</em> permite definir breakpoints e grupos de breakpoints em arquivos YAML. Módulos e temas podem usar a API fornecida pelo módulo <em>Breakpoint</em> para definir breakpoints e grupos de breakpoints e atribuir multiplicadores de resolução para breakpoints.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8239, 'Padrões W3C para consultas de mídia', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8240, 'O que é um tema?', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8241, 'Um <em>tema</em> é um conjunto de arquivos que definem a aparência visual do seu site. O core e os módulos habilitados em seu site determinam qual conteúdo (incluindo texto HTML e outros dados armazenados no banco de dados, imagens carregadas e quaisquer outros arquivos ou ativos) são exibidos nas páginas do seu site. O tema determina a marcação HTML e o estilo CSS que envolve o conteúdo. Vários temas básicos são fornecidos com o core. <em>Temas contribuídos adicionais</em> podem ser baixados separadamente na página <a href="https://www.drupal.org/project/project_theme">Download &amp; Estender no drupal.org</a>, ou você pode criar seu próprio tema.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8242, 'O que é um tema base?', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8243, 'O que é um layout?', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8244, 'Pré-visualizar a alteração da aparência do site', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8245, 'O módulo core field UI fornece uma interface de usuário para gerenciamento de campos e seu display em entidades.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8246, 'O módulo core Layout Builder fornece uma interface de usuário mais flexível para configurar a exibição de entidades.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8250, 'O cache está economizando saída HTML já renderizadas e outros dados calculados para uso posterior na primeira vez que é necessário. Isso economiza tempo, porque da próxima vez que os mesmos dados são necessários, eles podem ser rapidamente recuperados em vez de recalculados. Os sistemas de cache automático também incluem mecanismos para excluir cálculos em cache ou marcá-los como não mais válidos quando os dados subjacentes mudam. Para facilitar isso, os dados armazenados em cache possuem uma <em>vida útil</em>, que é o tempo máximo antes que os dados sejam excluídos do cache (forçando o recalculo).', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8251, 'O que é agregação de arquivos?', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8252, 'Agregação é quando os arquivos CSS e JavaScript são mesclados e compactados em um formato muito menor do que o original. Isso permite uma transmissão mais rápida e renderização mais rápida na outra extremidade.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8253, 'O que posso fazer para melhorar o desempenho do meu site?', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8254, 'Módulo Internal Page Cache', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8255, 'Armazena páginas solicitadas por usuários que não estão autenticados (usuários anônimos). Não use esta opção se o seu site precisa enviar saídas diferentes para diferentes usuários anônimos.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8256, 'Módulo Internal Dynamic Page Cache', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8257, 'Cache dados para usuários autenticados e anônimos, com dados não armazenados na página convertidos em espaços reservados e calculados quando a página é solicitada.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8258, 'Módulo Big Pipe', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8259, 'Altera a forma como as páginas são enviadas aos usuários de modo que as partes em cache são enviadas primeiro com espaços reservados e as partes da página não cacheadas ou personalizadas são transmitidas posteriormente. Isso permite que o navegador renderize a maior parte da página rapidamente e preencha os detalhes mais tarde.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8260, 'Configurações de página de desempenho', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8261, 'No menu administrativo <em>Gerenciar</em>, se você navegar para <em>Configurações</em> &gt; <em>Desenvolvimento</em> &gt; <em>Desempenho</em>, você encontrará uma configuração para a idade máxima do cache, bem como a opção de ativar a agregação de arquivos CSS e JavaScript.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8262, 'Documentação online para o módulo interno Page Cache', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8263, 'Documentação online para o módulo interno Dynamic Page Cache', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8264, 'Documentação online para o módulo BigPipe', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8272, 'Em cada seção, clique em <em>Adicionar bloco</em> para adicionar um bloco. Você verá uma lista dos blocos disponíveis em seu site, além de uma seção chamada <em>Campos de conteúdo</em> com um bloco para cada campo de seu item de conteúdo. Cada bloco pode ser configurado, se desejado, com um <em>Título</em> e, para blocos de campo de conteúdo, você também pode configurar formatador do campo. Continue adicionando blocos às suas seções até que todos os blocos e campos desejados sejam exibidos.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8273, 'Verifique seu layout. Você pode marcar a caixa <em>Mostrar prévia do conteúdo</em> para mostrar uma prévia de como será o seu layout ou desmarque para ver os nomes dos campos e blocos em cada seção.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8274, 'Se necessário, reordene os blocos arrastando-os para novos locais. Se você passar o mouse sobre um bloco, aparecerá um menu contextual que permitirá alterar a configuração do bloco, remover o bloco ou <em>mover</em> blocos dentro da seção usando uma interface mais compacta.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8275, 'Quando estiver satisfeito com seu layout, clique em <em>Salvar layout</em>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8276, 'Criando padrões de layout', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8277, 'Construindo layouts usando o Layout Builder UI', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8278, 'Instale um tema principal, ou um tema contribuído que já tenha sido baixado. Escolha os temas padrão para usar no site e em páginas administrativas.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8279, 'Localize os temas que deseja usar como tema padrão do site e para páginas administrativas.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8280, 'Para cada um desses temas, se o tema estiver na seção <em>Temas Desinstalados</em>, clique no link <em>Instalar</em> para instalar o tema. Aguarde a instalação do tema (as traduções podem ser baixadas). Você deve ser redirecionado para a página <em>Aparência</em>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8281, 'Localize o tema que deseja que seja o tema padrão, que agora deve estar na seção <em>Temas Instalados</em>. Se ele ainda não estiver rotulado como <em>tema padrão</em>, clique no link <em>Definir como padrão</em>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8282, 'Na parte inferior da página, selecione o <em>Tema da área de administração</em> que deseja usar em páginas administrativas. Clique em <em>Salvar</em> caso tenha selecionado um novo tema.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8283, 'Se você alterou o tema padrão do seu site, visite a página inicial do site ou outra página na parte não-administração do seu site e verifique se o site está usando o novo tema. Se você alterou o tema da administração, verifique se o novo tema é usado em páginas administrativas.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8284, 'Desinstala um tema que foi instalado anteriormente, mas não está mais sendo usado no site.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8285, 'Localize o tema que deseja desinstalar na seção <em>Temas instalados</em>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8286, 'O formulário ficou desatualizado. Pressione o botão voltar, copie qualquer trabalho não salvo e então recarregue a página.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8287, 'Identificador de implantação', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8288, 'Configure uma ou mais páginas de busca.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8289, 'Role até a seção <em>Páginas de busca</em>. Você verá uma lista das páginas de busca já configuradas em seu site.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8290, 'Para configurar uma página de busca existente, clique em <em>Editar</em>. Ou, para adicionar uma nova página de busca, selecione o <em>Tipo de página de busca</em> e clique em <em>Adicionar página de busca</em>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8291, 'Digite o <em>Rótulo</em> desejado e o <em>Caminho</em> da URL para a página de busca.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8292, 'Para páginas de busca de <em>Conteúdo</em>, selecione o nível de influência desejado na classificação de resultados de busca dos fatores de <em>Classificação de conteúdo</em> disponíveis.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8293, 'Clique em <em>Salvar</em>. Você será redirecionado para a página <em>Páginas de busca</em>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8294, 'Verifique se a página de busca correta está listada como <em>Padrão</em> na coluna <em>Status</em>. Se não, clique em <em>Definir como padrão</em> na lista <em>Operações</em> para a página de busca correta.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8295, 'Opcionalmente, desabilite ou exclua quaisquer páginas de busca que você não deseja ter disponível no site (a desabilitação é temporária, enquanto a exclusão é permanente).', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8296, 'Gerencie o índice de busca e certifique-se de que o site está totalmente indexado para busca.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8297, 'O que é o índice de busca?', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8298, 'Em <em>Acelerador de indexação</em>, selecione o <em>número de itens para indexar por execução do Cron</em>. Um número menor tornará o Cron mais rápido e reduzirá a possibilidade de tempo limite; um número maior garantirá que mais do seu site seja indexado em menos execuções do Cron.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8299, 'Em <em>Configurações de indexação padrão</em>, digite o <em>Comprimento mínimo da palavra para indexar</em> desejado. Palavras menores que esse comprimento serão retiradas de ambas as palavras-chave ao buscar e indexar conteúdo.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8300, 'Se o seu site usa idiomas Chinês, Japonês ou Coreano, opcionalmente marque o <em>Manuseio simples do CJK</em> nas <em>Configurações de indexação padrão</em> para fornecer algum suporte para esses idiomas.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8301, 'Clique em <em>Salvar configuração</em>e você deve ser redirecionado para a página <em>Páginas de busca</em>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8302, 'Clique em <em>Re-indexar o site</em> se você alterou a configuração de indexação ou mais tarde, se você acredita que o índice de busca foi corrompido.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8303, 'Depois de esperar que o cron seja executado diversas vezes, verifique se o conteúdo foi totalmente indexado para busca. O status geral é listado em <em>progresso de indexação</em>e o status de cada página de busca é mostrado na coluna de <em>progresso de indexação</em> da seção <em>Páginas de busca</em>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8304, 'O que são páginas de busca?', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8305, 'O módulo Search do core organiza a busca do site em <em>páginas</em>. Cada página permite que usuários busquem um determinado tipo de conteúdo com uma configuração específica. A configuração inclui informar uma URL que começa com <em>busca</em>, um nome para a página e opções adicionais para alguns tipos de página de busca.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8306, 'Quais módulos fornecem busca no site?', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8307, 'O módulo Search do core fornece a capacidade de configurar páginas de busca. Os tipos de página de busca são fornecidas por módulos do core e contribuídos. Os módulos do core que fornecem tipos de página de busca são:', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8308, 'O módulo Node para buscar páginas de conteúdo', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8309, 'O módulo User, para buscar perfis de usuários', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8310, 'O módulo Help, para buscar tópicos de ajuda', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8313, 'Existem duas limitações principais do módulo Search do core. Primeiro, ele não é apropriado para sites muito grandes - se você tem um site grande, olhe para outras tecnologias de busca como Apache Solr. Em segundo lugar, o tipo de página de busca node só suporta correspondência exata de palavras-chave, que não é o comportamento que a maioria dos usuários espera. Você pode melhorar isso instalando um módulo específico para seu idioma (como <a href="https://www.drupal.org/project/porterstemmer">Porter Stemmer</a> para Inglês americano), o que faz com que, por exemplo, uma busca pela palavra caminhada corresponda às páginas que contêm as palavras caminhar, caminham e caminharam.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8314, 'Quais são as permissões de busca?', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8315, 'Usuários com permissão de <em>Usar busca</em> podem usar o bloco de <em>Formulário de busca</em> e a página <em>Busca</em>. Esta permissão é necessária para qualquer busca configurada no módulo core Search.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8316, 'Adicionalmente a <em>Usar busca</em>, a permissão <em>Ver informações do usuário</em> é necessária para buscar usuários.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8317, 'Adicionalmente a <em>Usar busca</em>, a permissão <em>Ver conteúdo publicado</em> é necessária para buscar conteúdo.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8318, 'Os usuários com permissão de <em>Usar pesquisa avançada</em> podem usar filtros de busca mais complexos quando realizarem buscas de conteúdo.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8319, 'Configurando a visão geral da busca do site', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8320, '<a href="https://www.drupal.org/documentation/modules/search">Documentação online para o módulo de pesquisa</a>', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8321, 'Raiz do documento para arquivos', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8322, 'Raiz do documento para arquivos públicos', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8323, 'Raiz do documento para arquivos privados', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8324, 'Permite que o menu mobile alterne em todas as larguras.', 'pt-br', 0);
