INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8342, 'Acessibilidade da interface administrativa', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8343, 'Usando a interface administrativa', 'pt-br', 0);
