INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8359, 'Desinstalando um tema não utilizado', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8360, 'Criando uma conta de usuário', 'pt-br', 0);
