INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8364, 'Configurando como contas de usuários são criadas e deletadas', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8365, 'Modificando ou excluindo uma conta de usuário', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8366, 'Link do módulo', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8367, 'Menu mobile todas as larguras', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8368, 'Cor de fundo da marca do site', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8369, '<em>Você ainda não criou nenhum conteúdo para a página inicial.</em>', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8370, 'Drupal é uma plataforma de código aberto para construir experiências digitais incríveis. É feito, usado, ensinado, documentado e comercializado pela <a href="@drupal_community">comunidade drupal.</a> Nossa comunidade é composta por pessoas de todo o mundo com um conjunto compartilhado de <a href="@drupal_values">valores</a>, colaborando juntos de forma respeitosa. Como gostamos de dizer:', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8371, 'Venha para o código, fique pela comunidade.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8372, 'Há algumas maneiras de começar com o Drupal:', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8373, '<a href="@drupal_user_guide">Guia do Usuário:</a> Inclui a instalação, administração, construção de sites e manutenção do conteúdo de um site Drupal.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8374, '<a href="@create_content">Criar conteúdo:</a> Quer ir direto ao trabalho? Comece adicionando conteúdo. <strong>Nota:</strong> as informações nesta página desaparecerão assim que você adicionar conteúdo ao seu site. Continue lendo e marque recursos de interesse.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8375, '<a href="@drupal_extend">Estender o Drupal:</a> O core do software do Drupal pode ser estendido e personalizado de maneiras notáveis. Instale funcionalidades adicionais e altere a aparência do seu site usando módulos contribuídos por nossa comunidade.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8376, 'Guarde esses links para nossos grupos comunitários ativos e recursos de suporte do Drupal.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8377, '<a href="@drupal_events">Próximos Eventos:</a> Aprenda e conecte-se com outras pessoas em conferências e eventos realizados ao redor do mundo.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8378, '<a href="@drupal_community">Página da Comunidade:</a> Lista dos principais grupos da comunidade Drupal com seu próprio conteúdo.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8379, 'A migração falhou com uma exceção no plugin de origem: @e em @file linha @line', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8380, 'A exibição %display possui o caminho node/%. Isso não vai produzir o que você deseja. Se você quer ter várias versões de exibição do node, use o Layout Builder.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8381, 'Veja <a href="https://www.php.net/manual/datetime.format.php#refsect1-datetime.format-parameters" target="_blank">a documentação de formatos de data em PHP</a>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8382, 'Um formato de data definido pelo usuário. Veja o <a href="https://www.php.net/manual/pt_BR/datetime.format.php#refsect1-datetime.format-parameters">manual do PHP</a> para opções disponíveis.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8383, 'Gerenciar traduções de qualquer entidade que o usuário pode editar', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8384, 'O módulo Filter permite que administradores configurem formatos de texto. Os formatos de texto alteram a forma como as tags HTML e outros textos serão <em>processados e exibidos</em> no site. Eles são usados para transformar texto e também ajudam a defender seu site contra entradas potencialmente prejudiciais de usuários mal-intencionados. Editores de texto visuais podem ser associados a formatos de texto usando o <a href=":editor_help">módulo Text Editor</a>. Para mais informações, consulte a <a href=":filter_do">documentação on-line do módulo Filter</a>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8385, 'Existem quatro tipos principais de dados. <em>Conteúdo</em> é a informação (texto, imagens, etc.) destinadas a serem exibidas aos visitantes do site. <em>Configuração</em> são dados que definem como o conteúdo é exibido; algumas configurações (como etiquetas de campo) também podem ser visíveis para os visitantes do site. <em>Estado</em> são dados temporários sobre o estado do seu site, como a última vez que o sistema <em>cron</em> empregos correu. <em>A sessão</em> é um subconjunto de informações do Estado, relacionadas às interações dos usuários com o site, como cookies de sites e se estão ou não conectados.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8386, 'Lista (módulo Options): Armazena valores escolhidos a partir de listas pré-definidas, onde os valores podem ser números ou texto. Veja a seção abaixo para mais informações sobre os campos da lista.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8387, 'Referência (sistema central): Armazena referências de entidades. Veja a seção acima', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8388, 'Texto (módulo Text): Armazena textos formatados e não formados. Veja a seção abaixo para mais informações sobre campos de texto.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8389, 'Quais configurações estão disponíveis para os tipos de campo Lista?', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8390, 'Os campos de lista <em>associam chaves</em> pré-definidas (ou códigos de valor) com <em>rótulos</em> que o usuário vê. Por exemplo, você pode definir um campo de lista que mostra ao usuário os nomes de vários locais, enquanto nos bastidores um código de localização é armazenado no banco de dados. Cada tipo de campo de lista corresponde a um tipo de chave armazenada. Por exemplo, um campo <em>List (inteiro)</em> armazena inteiros, enquanto o campo <em>Lista (texto)</em> armazena strings de texto. Uma vez escolhido o tipo de campo, a configuração principal para um campo de lista é a lista <em>de valores Permitido,</em> que associa as teclas com os rótulos.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8391, 'Quais tipos de campos de texto estão disponíveis?', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8392, 'Existem vários tipos de campos de texto com diferentes características. Campos de texto podem ser <em>simples</em> ou <em>formatados</em>: campos de texto simples não contêm HTML, enquanto os campos formatados podem conter HTML e são processados através de <em>filtros de texto</em> (estes são fornecidos pelo módulo Filter do core; se você tiver esse módulo habilitado, consulte o tópico relacionado com filtros abaixo para obter mais informações). Campos de texto também podem ser de comprimento regular (com um limite de 255 caracteres) ou <em>longos</em> (com um limite de caracteres muito grande), e campos de texto longos formatados podem incluir um atributo de <em>resumo</em>. Todas as possíveis combinações dessas características existem como tipos de campo de texto; por exemplo, <em>Texto (simples)</em> e <em>Texto (formatado, longo, com resumo)</em> são dois exemplos de tipos de campo de texto.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8393, 'O que é um menu?', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8394, 'Um menu é uma coleção de <em>links de menu</em>  usados para navegar em um site. Menus e links de menu podem ser fornecidos por módulos ou administradores de sites.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8395, 'Gerenciando pré-visualização de menus', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8440, 'Opcionalmente, selecione o <em>Item pai padrão</em> para adicionar links para itens de conteúdo abaixo de um local padrão na estrutura do menu.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8441, 'Adicionando um link em um menu', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9807, 'Editar tipo de comentário %label', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8396, 'O módulo Menu UI do core fornece uma interface de usuário para gerenciar menus, incluindo a criação de novos menus, reordenação de links de menu e desativação de links fornecidos por módulos. Ele também fornece a capacidade para adicionar links no menu para itens de conteúdo quando estes estão sendo editados, se configurado no tipo de conteúdo. O módulo Custom Menu Links do core fornece a capacidade de adicionar links personalizados aos menus. Cada menu pode ser exibido colocando um bloco em uma região do tema. Alguns temas também podem exibir um menu fora do sistema de blocos. Veja os tópicos relacionados listados abaixo para tarefas específicas.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8397, 'Habilitando web services', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8398, 'O que é um web service?', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8399, 'Um serviço web permite que seu site forneça seu conteúdo e dados para outros sites e aplicativos. Normalmente os dados são transportados via <a href="https://en.wikipedia.org/wiki/Hypertext_Transfer_Protocol">HTTP</a> em um formato serializado de leitura de máquina.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8400, 'O que é serialização?', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8401, 'Serialização é o processo de conversão de estruturas de dados complexas em cadeias de texto, para que possam ser trocadas e armazenadas. O processo inverso é chamado de <em>deserialização</em>. JSON e XML são os dois formatos de serialização de dados mais usados para serviços web.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8402, 'O que é autenticação básica HTTP?', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8403, '<a href="http://en.wikipedia.org/wiki/Basic_access_authentication">Autenticação básica HTTP</a> é um método para autenticar solicitações enviando um nome de usuário e senha junto com a solicitação.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8404, 'Quais módulos fornecem serviços web?', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8405, 'Módulo JSON:API', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8406, 'Módulo RESTful Web Services', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8407, 'Módulo Serialization', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8408, 'Fornece uma estrutura para adicionar formatos de serialização específicos para outros módulos usarem.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8409, 'Módulo HTTP Basic Authentication', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8410, 'Também existem módulos contribuídos que fornecem serviços web.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8411, 'Documentação on-line para o módulo RESTful Web Services', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8412, 'Documentação on-line para o módulo JSON:API', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8413, 'Comparação dos módulos RESTFul Web Services e JSON:API', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (10736, 'Conectando editores de texto à formatos de texto', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8414, 'O que é um editor de texto?', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8415, 'Gerenciando filtros e formatos de texto', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8416, 'Configure formatos de texto no site.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8417, 'O que são filtros de texto e formatos de texto?', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8418, 'Um filtro de texto é uma etapa de processamento que pode ser aplicada ao texto, seja para transformá-lo de alguma forma (como converter URLs no texto em links HTML) ou para se defender contra entradas potencialmente perigosas dos usuários do site. Um formato de texto é uma sequência ordenada de filtros de texto. Os filtros de texto são fornecidos por módulos. Formatos de texto são gerenciados pelo módulo Filter do core.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8419, 'Campos de texto que possuem a palavra "formatado" no nome do tipo de campo, como em <em>Texto (formatado)</em>, usam formatos de texto. Usuários escolhem o formato de texto quando estão editando o texto no campo e quando o texto é mostrado no site, ele é processado pelo formato de texto escolhido. Administradores podem configurar formatos de texto e atribuir permissões para quem pode usar cada formato. Se o módulo Text Editor do core estiver habilitado, administradores também poderão associar editores visuais à formatos de texto.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8420, 'Quais filtros de texto estão disponíveis?', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8421, 'Alguns dos filtros de texto mais usados são:', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8422, 'Limita quais tags HTML podem ser usadas; útil tanto para a segurança do site quanto para forçar o design do site.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8423, 'Quebras de linha na fonte HTML são exibidas como espaços horizontais. Este filtro converte quebras de linha em tags de parágrafo e de quebra de linha HTML.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8424, 'Pega URLs no texto e as transforma em links HTML.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8425, 'Para formatos de texto que permitem tags HTML de imagem, restringe as imagens para URLs internas deste site.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8426, 'Clique em <em>Configurar</em> para configurar um formato de texto existente ou em <em>+Adicionar formato de texto</em> para criar um novo formato de texto.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8427, 'Digite o <em>nome</em> desejado para o formato de texto.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8428, 'Verifique os <em>Papéis</em> que podem usar este formato de texto. Algumas tags HTML permitem que usuários incorporem links ou scripts maliciosos em texto. Para garantir segurança, usuários anônimos e não confiáveis só devem ter acesso a formatos de texto que os restrinjam ao uso de texto simples ou a um conjunto seguro de tags HTML. <strong>A configuração inadequada do formato de texto é um risco à segurança.</strong>', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8429, 'Se o módulo Text Editor do core está instalado, consulte o tópico relacionado para conectar um editor de texto a este formato de texto.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8430, 'Em <em>Filtros ativos</em>, verifique os filtros de texto que deseja utilizar.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8431, 'Em <em>Ordem de filtro de processamento</em>, arraste os filtros para a ordem correta. Escolha a ordem cuidadosamente; por exemplo, se você tem um filtro cujo resultado é adicionar uma tag HTML específica ao texto, ele deve ser executado após um filtro que restringe tags HTML, para evitar a exclusão das novas tags adicionadas pelo primeiro filtro.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8432, 'Nas <em>Configurações de filtro</em>, verifique e ajuste as configurações de cada filtro ativo que possua opções de configuração.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8433, 'Clique em <em>Salvar configuração</em>, que irá redirecioná-lo para a página <em>Formatos texto e editores</em>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8434, 'Repita essas etapas se você tiver formatos de texto adicionais para configurar.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8435, 'No menu administrativo <em>Gerenciar</em>, navegue até <em>Estrutura</em> &gt; <em>Layout de bloco</em>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8436, 'Configurar as opções do menu para um tipo de conteúdo', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8437, 'Para um tipo de conteúdo existente, configure os menus disponíveis que serão mostrados como opções em telas de edição de conteúdo; links para itens de conteúdo desse tipo podem ser adicionados nesses menus durante a edição.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8438, 'Localize o tipo de conteúdo que deseja configurar e clique em <em>Editar</em> na lista <em>Operações</em>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8439, 'Nas <em>Configurações de menu</em>, marque os menus que deseja que estejam disponíveis quando editar um item de conteúdo desse tipo.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9425, 'Exibir como diferença de tempo (por exemplo, ''6 meses atrás'')', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8442, 'Adiciona um link em um menu. Observe que você também pode adicionar um link em um menu na página de edição de conteúdo, se as configurações do menu foram configuradas para o tipo de conteúdo.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8443, 'Localize o menu desejado e clique em <em>Adicionar link</em> na lista <em>Operações</em>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8444, 'Digite o <em>Título do link de menu</em> a ser exibido.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8445, 'Digite o <em>Link</em>, um dos seguintes:', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8446, 'Um caminho interno, como <em>/node/add</em>', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8447, 'Uma URL externa completa', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8448, 'Comece a digitar o título de um item de conteúdo e selecione-o quando o título completo aparecer', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8449, '<em>&lt;nolink&gt;</em> para mostrar o <em>Título do link de menu</em> como texto plano sem um link', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8450, 'link <em>&lt;front&gt;</em> para a página inicial do seu site', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8451, 'Certifique-se de que <em>Habilitado</em> está marcado; se não, o link do menu não será exibido.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8452, 'Opcionalmente, digite uma <em>Descrição</em> que será exibida quando um usuário pairar sobre o link.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8453, 'Opcionalmente, marque <em>Mostrar como expandido</em> para mostrar automaticamente as os filhos deste link (se houverem) quando ele for mostrado.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8454, 'Opcionalmente, selecione o <em>Link pai</em> se este link de menu deve ser filho de outro link de menu.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8455, 'Clique em <em>Salvar</em>. Você será redirecionado para a página <em>Adicionar link</em> para adicionar outro link.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8456, 'Localize o menu que você acabou de adicionar um link e clique em <em>Editar</em> na lista <em>Operações</em>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8457, 'Verifique se a ordem dos links está correta. Se não estiver, arraste os links do menu até que a ordem esteja correta e clique em <em>Salvar</em>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8458, 'Criando um menu', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8459, 'Crie um novo menu.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8460, 'Clique em <em>Adicionar menu</em>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8461, 'Digite o título do menu, usado como o título padrão do bloco se o menu for exibido como um bloco. Se desejar, também edite o nome de máquina do menu, que é por padrão derivado do título.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8462, 'Digite um resumo administrativo que será exibido na página <em>Menus</em>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8463, 'Se o seu site tem mais de um idioma, escolha o idioma para o menu.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8464, 'Clique em <em>Salvar</em>. Você estará na página de edição do menu, pronto para adicionar links ao menu se o módulo core Custom Menu Links estiver instalado; ver tópicos relacionados para outras tarefas.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8468, 'Arraste os links do menu para uma nova ordem ou marque/desmarque <em>Ativado</em> para ativar ou desativar links de menu.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8469, 'Clique em <em>Salvar</em> para salvar suas alterações.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8470, '<a href="https://www.php.net/manual/datetime.format.php#refsect1-datetime.format-parameters">Referência de códigos de formato de data PHP</a>', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8472, '[site:url]: A URL do seu site.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8473, 'Gerenciamento listagens de conteúdo (views)', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8474, 'O que é uma view?', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8475, 'Uma <em>view</em> é uma lista de itens em seu site; por exemplo, um bloco mostrando os comentários mais recentes, uma página listando itens de notícias ou uma lista de usuários registrados. As listagens podem ser formatadas em uma tabela, grade, lista, calendário, feed RSS e outros formatos (alguns formatos de saída podem exigir que você instale módulos adicionais contribuídos).', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8476, 'Quais são os componentes de uma view?', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8477, 'Quando você criar uma view pela primeira vez, você especificará que tipo de <em>dados-base</em> estão sendo apresentados na view, que não pode ser alterado. Depois de escolher um tipo de dados-base, você pode editar os seguintes componentes que permitem à você especificar quais dados serão apresentados, em qual ordem e em qual formato:', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8478, '<em>Displays</em>: se a saída vai para uma página, bloco, feed, etc.; uma única view pode ter vários displays, cada um com configurações diferentes.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8479, '<em>Formato</em>: o estilo de saída para cada exibição, como item de conteúdo, grade, tabela ou lista HTML.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8480, '<em>Fields</em>: se o formato permitir, os campos específicos para exibir.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8481, '<em>Critérios de filtro</em>: critérios para limitar os dados de saída, como o conteúdo é publicado, o tipo de conteúdo, etc. Filtros podem ser <em>expostos</em> para permitir que usuários escolham como filtrar os dados.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8482, '<em>Critérios de classificação</em>: como classificar os dados. A classificação também pode ser exposta para os usuários.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8483, '<em>Cabeçalho</em> e <em>Rodapé</em>: conteúdo para ser exibido na parte superior ou inferior da exibição da view.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8484, '<em>Comportamento sem resultados</em>: o que fazer se os critérios do filtro não resultarem em dados para exibir.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8485, '<em>Paginador</em>: quantos itens exibir e como paginá-los se houverem itens adicionais para exibir.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8486, '<em>Avançados</em> &gt; <em>Filtros contextuais</em>: igual filtros regulares, exceto que os critérios vêm do <em>contexto</em>, como a data atual, a página em que a view é exibida, etc.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8487, '<em>Avançado</em> &gt; <em>Relacionamentos</em>: dados adicionais para puxar e exibir, relacionados de alguma forma aos dados básicos da view (como dados do usuário que criou o item de conteúdo).', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8488, '<em>Avançado</em> &gt; <em>Formulário exposto</em>: se você tiver filtros expostos ou classificações, como exibir o formulário para o usuário.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8489, 'Visão geral de Views', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8490, 'O módulo Views do core lida com a exibição de views e o módulo Views UI do core permite que você crie, edite e exclua views na interface administrativa. Consulte os tópicos relacionados listados abaixo para tarefas específicas (se o módulo Views UI estiver instalado).', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8491, 'Adicionando um novo display a uma view existente', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8492, 'Adiciona um novo display em uma view existente. Isso permite que você exiba dados semelhantes em uma view existente, usando configurações semelhantes, em um novo bloco, página, feed, etc.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8493, 'Em <em>Displays</em>, clique em <em>Adicionar</em>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8494, 'Na lista pop-up, clique no link para o tipo de exibição que deseja adicionar. Os tipos mais comuns são <em>Página</em> e <em>Bloco</em>. O novo display será adicionado à sua exibição e você estará editando esse display.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8495, 'Opcionalmente, clique no link próximo do <em>Nome do display</em> e digite um novo nome para este display na interface administrativa.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8496, 'Criando uma nova view', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8497, 'Crie uma nova view para listar conteúdo ou outros itens em seu site.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8498, 'Clique em <em>Adicionar view</em>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8499, 'No campo <em>Nome da view</em>, digite um nome para a view, que é como ela será listada na interface administrativa.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8500, 'Em <em>Configurações da view</em> &gt; <em>Mostrar</em>, selecione o tipo de dados base a serem exibidos em sua view. Isso não pode ser alterado depois.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8501, 'Opcionalmente, selecione ou digite as configurações de filtragem, classificação e exibição de página/bloco. Estes podem ser adicionados ou alterados mais tarde.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8502, 'Clique em <em>Salvar e editar</em>. Sua view será criada. Edite-a seguindo as etapas nos tópicos relacionados abaixo.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8503, 'Editando um display de view existente', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8504, 'Editar um display de view existente para modificar quais dados são exibidos ou como são exibidos.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8505, 'Em <em>Displays</em>, clique no display que deseja editar.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8506, 'Em seções contendo listas (como <em>Campos</em> e <em>Critérios de filtros</em>), para modificar ou excluir um item existente, clique no nome do item. Para adicionar um novo item, clique em <em>Adicionar</em> na lista drop-down. Para alterar a ordem dos itens, clique em <em>Reorganizar</em> na lista drop-down.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8507, 'Para seções que contêm configurações individuais (como <em>Título</em> e <em>Formato</em>), muitas vezes há dois links para cada configuração. O primeiro link mostra o valor atual; clique nesse link para alterar o valor. Se houver um segundo link chamado <em>Configurações</em>, clique nesse link para alterar os detalhes das configurações. Por exemplo, se o seu <em>Formato</em> é mostrado atualmente como <em>Lista não-formatada</em>, clique em <em>Lista não-formatada</em> para trocar para um formato de <em>Grade</em> ou <em>Tabela</em>. Clique em <em>Configurações</em> ao lado do tipo de formato para alterar as configurações do formato escolhido.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8508, 'Quando você terminar de alterar todas as configurações, verifique se o display está correto clicando em <em>Atualizar pré-visualização</em>. Retorne para editar as configurações, se necessário.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8509, 'Quando você tiver verificado o display, clique em <em>Salvar</em>. Alternativamente, se você cometeu erros e deseja descartar suas alterações, clique em <em>Cancelar</em>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8510, 'Para acessibilidade e otimização para mecanismo de busca, todas as imagens que transmitem significado em sites devem ter um texto alternativo. O Drupal também permite a digitação de texto de título para imagens, mas isso pode confundir usuários com leitores de tela e seu uso não é recomendado. Campos de imagem podem ser configurados para que os campos de texto alternativos e de título estejam habilitados ou desabilitados. Se habilitados, os campos podem ser definidos para serem obrigatórios. A configuração recomendada é habilitar e obrigar texto alternativo e desativar o texto de título.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8511, 'Este deve ser um caminho interno como %add-node. Você também pode começar a digitar o título de um conteúdo para selecioná-lo. Digite %front para vincular à primeira página. Digite %nolink para exibir somente texto de link. Digite %button para exibir apenas o texto de link acessível ao teclado.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8512, 'Comece digitando o título de um conteúdo para selecioná-lo. Você também pode digitar um caminho interno, como %add-node ou um externo como %url. Digite %front para vincular à página inicial. Digite %nolink para exibir apenas o texto do link. Digite %button para exibir apenas o texto do link acessível pelo teclado.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8513, 'É potencialmente inseguro exibir conteúdo oEmbed em um frame que é servido a partir do mesmo domínio do seu principal site Drupal, pois isso pode permitir a execução de código de terceiros. Consulte as <a href="https://oembed.com/#section3">Considerações de Segurança oEmbed</a>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8514, 'É potencialmente inseguro exibir conteúdo oEmbed em um frame que é servido a partir do mesmo domínio do seu principal site Drupal, pois isso pode permitir a execução de código de terceiros. <a href=":url">Você pode especificar um domínio diferente para servir conteúdo oEmbed nas configurações de mídia</a>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8515, 'Se marcado, usuários que criarem novos itens de mídia na biblioteca de mídia verão um resumo de seus itens de mídia selecionados e poderão inserir sua seleção diretamente no campo de mídia ou editor de texto.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8516, 'Um sinal para indicar se o link deve ser renderizado em menus. (1 = um link de menu desativado que pode ser mostrado em telas de administração, -1 = um retorno de chamada do menu, 0 = um link normal e visível)', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8517, 'Código de idioma do link de menu.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8518, 'Definir ID de tradução.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8519, 'ID do link de menu do idioma de origem do link de menu.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8520, 'Usuários com a permissão de <em>Administrar menus e links de menu</em> podem adicionar, editar e excluir menus personalizados na página <a href=":menu">Menus</a>. Menus personalizados podem ser menus especiais do site, menus de links externos ou qualquer combinação de links internos e externos. Você pode criar um número ilimitado de menus adicionais e cada um deles terá um bloco associado automaticamente (se você tiver o módulo <a href=":block_help">Block</a> instalado). Ao selecionar <em>Editar menu</em>, você pode adicionar, editar ou excluir links do menu selecionado. A página de listagem de links fornece uma interface de arrastar e soltar para controlar a ordem dos links e criar uma hierarquia dentro do menu.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8521, 'Link pai padrão', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8522, 'Escolha o link do menu para ser o pai padrão para um novo link no formulário de criação de conteúdo.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8523, 'O link do menu selecionado não está em um dos menus selecionados.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8524, '<strong>Aviso:</strong> Atualmente, há 1 link de menu em %title. Ele será excluído (links definidos pelo sistema serão redefinidos).<strong>Aviso:</strong> Atualmente existem @count links de menu em %title. Eles serão excluídos (links definidos pelo sistema serão redefinidos).', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8525, 'Nome do módulo do Drupal @version', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8526, 'Nome de máquina do Drupal @version', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8527, 'O nome legível do mapeamento', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8528, 'O nome de máquina do mapeamento', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8529, 'O grupo a que este mapeamento pertence', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8530, 'Os mapeamentos ligados ao grupo de breakpoints', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8531, 'Sobre a busca', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9637, 'A URL da página inicial do site com o prefixo do idioma, se houver.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8532, 'Você pode exibir seus atalhos ativando o bloco <em>Atalhos</em> na <a href=":blocks">Página de administração de blocos</a>. Certos módulos administrativos também exibem seus atalhos; por exemplo, o módulo <a href=":toolbar-help">Toolbar</a> do core fornece um link de menu correspondente.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8533, 'O novo conjunto é criado copiando links do conjunto de atalhos padrão.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8534, 'O novo conjunto é criado copiando links do conjunto %default.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8535, 'A chave principal menu.mlid para este link de menu (= shortcut link).', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8536, 'Administrar menus e links de menu', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8537, 'O menu só é visível se o link do menu da página atual estiver neste nível ou abaixo dele. Use o nível 1 para sempre exibir este menu.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8538, 'Idioma do menu.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8539, 'Modo Menu i18n.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8540, 'Administrar papéis e permissões', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8541, 'O controle de inundação bloqueou a tentativa de login para uid %uid de %ip', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8542, 'O controle de inundação bloqueou a tentativa de login para uid %uid', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8543, 'O controle de inundação bloqueou a tentativa de login de %ip', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8544, 'Entrada do link do menu', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8545, 'Ao fornecer um link de menu como uma aba, o Drupal precisa saber qual será o link do menu pai dessa aba. Às vezes o pai já existe, mas outras vezes você precisará criá-lo. O caminho de um pai será sempre o mesmo caminho com a última parte deixada de fora, por exemplo, se o caminho para essa view é <em>foo/bar/baz</em>, o caminho pai será <em>foo/bar</em>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8546, 'Link normal de menu', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8547, 'Se está criando um link de menu pai, digite o título do link.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8548, 'Se está criando um link de menu pai, digite a descrição do link.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8549, 'Se o link do menu pai for uma aba, digite o peso da aba. As abas mais pesadas descerão e as abas mais leves serão posicionadas mais perto do primeiro link do menu.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8550, 'Views não podem criar links de menu normais para caminhos com um % neles.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8551, 'Se "Personalizado", consulte <a href="https://www.php.net/manual/datetime.format.php#refsect1-datetime.format-parameters" target="_blank">a documentação do PHP</a> para formatos de data. Caso contrário, digite o número de unidades de tempo diferentes para exibir, cujo padrão é 2.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8552, 'Cor Primária de Marca', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8553, 'Um tema de front-end para Drupal limpo, acessível e flexível.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8554, 'Largo (1090)', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8555, 'Olivero Medium', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8556, 'Blocos de conteúdo', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8557, 'Falha ao obter dados de atualização disponíveis:', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8558, 'Consulte <a href="@url">os requisitos do PHP OpenSSL</a> no manual do Drupal.org por possíveis razões do porquê isso pode acontecer e o que você pode fazer para resolvê-los.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8559, 'Verifique <a href="@url">seus registros do sistema local</a> para mensagens de erro adicionais.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8560, 'Verifique seus registros do sistema local para mensagens de erro adicionais.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8561, 'Configurações de atualização do Drupal', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8562, 'Por razões de segurança, seu upload foi rejeitado.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8563, 'Exportando a configuração completa do site', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8564, 'Clique em <em>Exportar</em> e salve o arquivo.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8565, 'Selecione o <em>Tipo de configuração</em> que deseja exportar e selecione o <em>Nome de configuração</em> específico para exportar.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8566, 'Use seu navegador para copiar o texto na caixa marcada <em>Aqui está sua configuração</em> na área de transferência.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8567, 'Cole o texto copiado em um editor de texto simples em seu computador ou outro dispositivo e salve-o usando o nome do arquivo sugerido abaixo da caixa de texto.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8568, 'Importando sua configuração completa do site', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8569, 'Navegue para encontrar o <em>Arquivo de configuração</em> que deseja importar.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8570, 'Clique em <em>Carregar</em>. Seu arquivo de configuração será descompactado e colocado no diretório de sincronização de configuração, e você será redirecionado para a página <em>Sincronizar</em>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8571, 'Revise as diferenças entre a configuração do upload e a configuração ativa, se houver, e clique em <em>Importar tudo</em> para importar as alterações.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8572, 'Selecione o <em>Tipo de configuração</em> que deseja importar.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8573, 'No seu computador ou outro dispositivo, copie para a área de transferência a configuração em formato YAML que deseja importar.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8574, 'Cole o texto da área de transferência na caixa <em>Cole aqui sua configuração</em>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8575, 'Clique em <em>Importar</em>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8576, 'Gerenciamento e implantação de configuração', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8577, 'O que é o sistema de configuração?', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8578, 'O sistema de configuração fornece para administradores a capacidade de personalizar o site e de mover e sincronizar as alterações de configuração entre os sites de desenvolvimento e o site em produção. Ele faz isso de 2 maneiras:', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8579, 'Fornecendo armazenamento para configuração', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8580, 'Fornecer um processo no qual as alterações de configuração podem ser importadas e exportadas entre instâncias do mesmo site; por exemplo, de "dev" para "staging" para "live"', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8581, 'O que são dados de configuração?', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8582, 'Dados de configuração descrevem configurações que definem como seu site se comporta ou é exibido. Por exemplo, quando um administrador do site atualiza as configurações usando um formulário administrativo, essas configurações são armazenadas como dados de configuração. Os dados de configuração descrevem configurações tão simples quanto um nome de site e tão complexas quanto uma view ou estilo de imagem.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8583, 'Quais tipos de configuração existem?', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8584, 'Configuração ativa', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8585, 'A configuração ativa é a configuração de trabalho atual de um site. O armazenamento da configuração ativa é definido pelo site e reside no banco de dados por padrão.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8586, 'Um item de configuração simples é um grupo de configurações, como as configurações de um módulo ou tema. Cada item de configuração simples tem sua própria estrutura única.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8664, '<em>Publicado</em>: se marcado, quando o conteúdo chegar a este estado será visível no site (aos usuários com permissão).', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8587, 'As entidades de configuração são itens de configuração definidos pelo usuário agrupados por tipo, como views, estilos de imagem e tipos de conteúdo. Cada entidade de configuração dentro de um tipo tem uma estrutura semelhante.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8588, 'A configuração padrão pode ser definida por um módulo, tema ou perfil de instalação em seus diretórios <em>config/install</em> ou <em>config/optional</em>. A configuração é fornecida em arquivos YAML (extensão de arquivo .yml). YAML é um padrão de serialização de dados legível por humanos que é usado pelo software principal para vários propósitos. Uma vez que a configuração padrão foi importada para a configuração ativa do site (através da instalação da extensão), essa configuração é de propriedade do site, não da extensão. Isso significa que futuras atualizações da extensão não substituirão a configuração ativa do site para essa extensão.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8589, 'O que é sincronização de configuração?', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8590, 'Sincronização de configuração é o processo de exportação e importação de configuração para manter a configuração sincronizada entre diferentes versões de um site; por exemplo, entre um site de desenvolvimento e o site em produção.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8591, 'Cada site tem identificador exclusivo também chamado de <em>UUID</em>, que identifica o site para o sistema em qualquer instância do site, desde que as instâncias do site tenham sido reproduzidas como clones (clonagem é quando a base de código e o banco de dados são copiados para criar uma nova instância do site). Quando as instâncias do site são clonadas, uma instância "dev" do site tem o mesmo UUID que a instância "live". Quando as instâncias do site compartilham o mesmo UUID, a configuração pode ser exportada de uma instância para outra.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8592, 'A seguinte lista contém termos e conceitos relacionados à sincronização de configuração:', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8593, 'Configuração exportada', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8594, 'Quando a configuração é exportada, a configuração ativa é exportada como um conjunto de arquivos no formato YAML. Ao usar a interface administrativa do usuário para <em>Configuração de sincronização</em>, a configuração pode ser exportada como um arquivo de exportação completo ou um arquivo de um único item. Este arquivo pode então ser importado para a instância do site de destino.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8595, 'Configuração importada', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8596, 'Configuração importada é a configuração que foi exportada a partir de outra instância do site (a "fonte") e agora está sendo importada em outra instância do site (o "destino"), atualizando assim sua configuração ativa para corresponder ao conjunto de dados de configuração importado.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8597, 'O local do diretório de sincronização de configuração está definido no arquivo <em>settings.php</em>. Quando a configuração é exportada, a configuração ativa é exportada e descrita em arquivos YAML que são armazenados no diretório de sincronização de configuração. Após a primeira exportação, o sistema compara a configuração ativa do site com os dados de configuração no diretório de sincronização, e somente exportará os itens de configuração ativos que são diferentes de suas contra-partes no diretório de sincronização.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8599, 'As tarefas de gerenciamento de configuração, como exportar ou importar configuração e sincronização de configuração, podem ser feitas através da interface administrativa fornecida pelo módulo Configuration Manager do core ou por uma ferramenta CLI (Command-line Interface). Para definir um caminho de diretório de sincronização de configuração que não seja o valor padrão, é necessário acesso de leitura/gravação às configurações do arquivo <em>settings.php</em>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8600, 'A maioria dos módulos e temas também fornecem formas de configuração para atualizar a configuração que eles fornecem. Veja os tópicos relacionados listados abaixo para tarefas específicas.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8601, 'Gerenciamento de mídia', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8602, 'O que são itens de mídia?', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8603, 'O que é a biblioteca de mídia?', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8604, 'A biblioteca de mídia é uma interface visual do usuário para gerenciar e reutilizar itens de mídia. Adicione itens de mídia ao conteúdo usando campos de referência de mídia e o widget de campo da biblioteca de mídia.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8605, 'O que é um estilo de imagem?', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8606, 'Um estilo de imagem é um conjunto de etapas de processamento, conhecidos como <em>efeitos, </em>que podem ser aplicados às imagens. Exemplos de efeitos incluem dimensionamento e corte de imagens para diferentes tamanhos. Estilos de imagem responsivos podem associar estilos de imagem aos breakpoints de tamanho do seu tema. Isso permite fornecer imagens dimensionadas para a largura do navegador.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8607, 'Visão geral da gestão de mídia', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8608, 'Os seguintes módulos fornecem funcionalidade relacionada à mídia:', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8609, 'Itens de mídia e tipos de mídia são gerenciados pelo módulo Media.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8610, 'O módulo Media do core fornece um campo de referência de mídia para adicionar mídia à entidades de conteúdo. Os módulos File e Image do core também fornecem campos de referência. Recomenda-se usar o campo de referência Media porque é mais versátil.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8611, 'O módulo Media Library do core fornece a biblioteca de mídia e o widget de campo da biblioteca de mídia. Com este módulo instalado, o widget de campo da biblioteca de mídia torna-se o widget padrão para editar campos de referência de mídia.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8612, 'O módulo Image do core fornece uma interface de usuário para definir estilos de imagem. O módulo Responsive Image do core fornece estilos de imagem responsivas. Usando o módulo Breakpoint do core e um tema habilitado para breakpoint, esses estilos responsivos podem fornecer imagens dimensionadas para o navegador.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8613, '<a href="https://www.drupal.org/docs/8/core/modules/media">Módulo Media</a>', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (10733, 'Adicionando um estilo de imagem', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8614, 'Clique em <em>Adicionar estilo de imagem</em>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8615, 'Digite um <em>nome descritivo de estilo de imagem</em>e clique em <em>Criar novo estilo</em>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8616, 'Em <em>Efeito</em>, escolha um efeito para aplicar e clique em <em>Adicionar</em>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8617, 'Configure o efeito na próxima página. A maioria dos efeitos requer alguma configuração adicional depois de adicionados.  Por exemplo, para o efeito <em>Crop,</em> digite a <em>Largura</em> e <em>Altura</em> para cortar a imagem e escolha o ponto <em>Âncora.</em> Clique <em>em Adicionar efeito</em>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8618, 'Repita as duas etapas anteriores até que todos os efeitos tenham sido adicionados.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8619, 'Arraste para mudar a ordem dos efeitos. Em seguida, clique em <em>Salvar</em> para salvar a nova ordem.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8763, 'Adicione <a href=":modules">módulos contribuídos</a> para ampliar as funcionalidades do seu site.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8620, 'O estilo de imagem agora pode ser usado para formatar um campo contendo uma imagem em seus layouts ou exibições de campo tradicionais. Também pode ser usado como parte de um estilo de imagem responsivo. Veja os tópicos relacionados abaixo para mais informações.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8621, 'Adicionando um novo tipo de mídia', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8622, 'Se ainda não houver um tipo de mídia para o tipo de mídia que deseja usar em seu site, clique em <em>Adicionar tipo de mídia</em>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8623, 'Digite um <em>nome</em> e uma <em>descrição</em> para seu tipo de mídia e selecione a <em>Fonte de mídia</em>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8624, 'Para a maioria das fontes de mídia, existem informações adicionais que precisam ser armazenadas com seu item de mídia em um campo no seu tipo de mídia. Em <em>Configuração de origem de mídia</em>, selecione um campo existente para reutilizar e armazenar essas informações, ou selecione <em>- Criar</em> para criar um novo campo.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8625, 'Observe os tipos de metadados na seção <em>Mapeamento de campo</em> que podem ser mapeados para campos no seu tipo de mídia.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8626, 'Opcionalmente, adicione campos adicionais para os metadados acima destacados ou, para outras informações que você deseja armazenar ao seu tipo de mídia clicando em <em>Gerenciar campos</em> (veja o tópico relacionado abaixo).', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8627, 'Se você tiver adicionado campos de metadados, clique em <em>Editar</em>. Em <em>Mapeamento de campo</em>, selecione os campos adicionados para cada pedaço de informações de metadados.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8628, 'Agora você pode usar esse tipo de mídia adicionando um campo de referência de mídia para qualquer subtipo de entidade de conteúdo. Veja o tópico relacionado abaixo.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8629, 'Migrando e atualizando', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8630, 'O que estão atualizando e migrando?', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8631, '<em>A atualização</em> é o processo de mudança de uma versão menor do software para uma versão mais recente, como da versão 8.3.4 para 8.3.5, ou 8.3.5 para 8.4.0. Começando pela versão 8.x, você também pode atualizar para as principais versões 9, 10 e adiante, se seus módulos adicionais, temas e perfis de instalação forem compatíveis. <em>A atualização</em> é o processo de mudança de uma versão principal mais antiga do software para uma versão mais recente, como da versão 7 para 8. <em>Migrar</em> é o processo de importação de dados para um site.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8632, 'Para atualizar um site de Drupal 6 ou 7 para Drupal 8 ou posterior, mantendo o conteúdo e a configuração iguais, você instalará a nova versão do software e módulos adicionais e temas em um novo site e, em seguida, migrará o conteúdo e outros dados do seu site antigo para o novo site.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8633, 'Visão Geral da Migração', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8634, 'Fornece uma API subjacente para migração de dados.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8635, '<a href="https://www.drupal.org/docs/upgrading-drupal">Atualizando o Drupal</a>', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8636, 'Migração de dados para uma atualização usando a interface do usuário', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8637, 'Leia a introdução e siga na página os <em>Passos de preparação</em>. Em seguida, clique em <em>Continuar</em>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8638, 'Selecione a versão do Drupal do site de origem. Digite também as credenciais do banco de dados e diretórios de arquivos públicos e privados (diretório de arquivos privados não está disponível quando migrar do Drupal 6). Clique na <em>Revisar atualização</em>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8639, 'Se na próxima página que você ver contiver uma mensagem sobre conteúdo conflitante, isso significa que o site onde você está executando a atualização não está vazio. Se você continuar, você perderá os dados no site. Se isso for aceitável, clique no botão para continuar; caso contrário, inicie esses passos em um site Drupal novo e limpo.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8640, 'Na página <em>O que será atualizado?</em>, revise a lista de módulos cujos dados não serão atualizados. Se essa lista não está vazia e você deseja migrar os dados desses módulos, você precisará baixar módulos contribuídos e/ou instalar módulos do core ou contribuídos e iniciar essas etapas novamente.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8641, 'Quando a lista de módulos que serão ou não atualizados atender suas expectativas, clique em <em>Realizar atualização</em> e aguarde a atualização ser concluída. Você verá uma mensagem com o número de tarefas de atualização que foram bem sucedidas ou falharam e você pode revisar o registro de mensagens de atualização clicando no link na página de resultados.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8642, '<a href="https://www.drupal.org/docs/upgrading-drupal/upgrading-from-drupal-6-or-7-to-drupal-8-and-newer">Atualização do Drupal 6 ou 7 para Drupal 8 (e mais novo)</a>', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8643, 'Configurando um estilo de imagem responsivo', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8644, 'Clique em <em>Adicionar estilo de imagem responsivo</em>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8645, 'Digite um <em>Rótulo</em> descritivo para o seu estilo.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8646, 'Selecione um <em>Grupo de Breakpoint</em> entre os grupos definidos pelos temas e módulos instalados.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8647, 'Na página seguinte, localize os conjuntos de campo para os breakpoints fornecidos pelo <em>Grupo de Breakpoint</em> selecionado.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8648, 'Para cada breakpoint que você deseja usar, expanda o conjunto de campo correspondente. Selecione o botão de rádio <em>selecionar um único estilo de imagem</em> em <em>Tipo</em> para o breakpoint e selecione o <em>Estilo de imagem</em> a ser usado nas imagens quando esse breakpoint estiver em vigor. Repita esta etapa para o resto dos breakpoints que deseja usar.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8650, 'Agora você pode usar esse estilo de imagem responsivo para formatar um campo contendo uma imagem, em seus layouts ou displays de campo tradicionais. Veja os tópicos relacionados abaixo para mais informações.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8651, 'Entidade criada', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8652, 'Nome do tipo de node antecessor.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8653, 'Nome de máquina do tipo de node antecessor.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8654, 'sub-navegação @title', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8655, 'Movendo conteúdo entre estados de fluxo de trabalho', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8656, 'Quem pode alterar os estados do fluxo?', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8657, 'Clique <em>Editar</em> para editar a entidade.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8658, 'Na parte inferior da página, selecione o novo estado de fluxo de trabalho em <em>Alterar para:</em> e clique em <em>Salvar</em>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8659, 'Quem pode configurar um fluxo de trabalho?', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8660, 'Faça um plano para o novo fluxo de trabalho:', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8661, 'Decida quais estados de fluxo de trabalho você precisa; por exemplo, <em>Conceituação</em>, <em>Revisão</em> e <em>Final</em>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8662, 'Decida sobre as configurações de cada estado:', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8663, '<em>Rótulo</em>: o nome do estado', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8764, 'Driver de banco de dados fornecido por módulo', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8675, 'Opcionalmente (recomendado), crie uma view para o seu fluxo de trabalho personalizado, a fim de fornecer para editores de conteúdo, uma página onde podem ver qual conteúdo precisa ser moderado. Você pode fazer isso se o módulo Views UI estiver instalado, seguindo os passos do tópico <em>Criando uma nova view</em> listado abaixo. Quando a view for criada, em <em>Configurações da view</em> &gt; <em>Mostrar</em>, selecione o tipo de dados de revisão para o qual configurou o fluxo de trabalho e certifique-se de exibir o campo <em>Estado de fluxo de trabalho</em> em sua view.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8676, 'Gerenciando fluxos de trabalho de moderação de conteúdo', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8677, 'O que é um fluxo de trabalho de moderação de conteúdo?', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8678, 'Em alguns sites, conteúdos novos e revisões de conteúdo precisam ser <em>moderadas</em>. Ou seja, eles precisam passar por vários <em>estados</em> antes de se tornarem visíveis para os visitantes do site. A coleção de estados e a definição das transições entre estados é conhecida como <em>fluxo de trabalho</em>. Por exemplo, um novo conteúdo pode começar em um estado de <em> Rascunho</em>, passar por vários estados de <em>Revisão</em> antes de ser <em>Publicado</em> no site.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8679, 'Visão geral dos fluxos de trabalho de moderação de conteúdo', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8680, 'O módulo Content Moderation do core permite que você expanda os estados nativos “despublicado” e "publicado" para conteúdo. Isto permite que você tenha uma versão publicada ao vivo, mas tenha uma cópia de trabalho separada que está em análise antes de ser publicada. Isso é feito utilizando fluxos de trabalho para aplicar diferentes estados e transições para entidades conforme necessário.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8681, 'O módulo core Workflows permite gerenciar fluxos de trabalho com estados e transições.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8682, 'Consulte os tópicos relacionados listados abaixo para tarefas específicas e informações adicionais.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8683, 'Documentação on-line sobre Moderação de Conteúdo', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8684, 'Se %identifier for uma conta válida, um e-mail será enviado com instruções para recuperar sua senha.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8685, 'A tradução de @language não foi adicionada. Para adicionar uma tradução, você precisa modificar a configuração.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8686, 'Nenhuma página é especificada', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8687, 'Fornece marcação para a área usando qualquer formato de texto disponível.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8688, 'Fornece marcação para a área com filtragem mínima.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8689, 'Você pode digitar dados a partir desta view de acordo com as “Substituições globais de token disponíveis" acima. Você pode incluir as seguintes tags HTML permitidas: <code>@tags</code>', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8690, 'Você pode incluir as seguintes tags HTML permitidas com esses "Padrões de substituição": <code>@tags</code>', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8691, 'Não há @entity_type_plural correspondendo a "%value".', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8692, 'Diversas @entity_type_plural são chamadas %value. Especifique qual você quer ao acrescentar o identficador entre parênteses, como "@value (@id)".', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8693, 'Múltiplas @entity_type_plural correspondem a esta referência; "%multiple". Especifique aquela que você quer acrescentando o identificador entre parênteses, como "@value (@id)".', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8694, 'O módulo ''@module_name'' está fornecendo o driver de dispositivo de banco de dados ''@driver_name''.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8695, 'Falha ao conectar ao servidor. O servidor reporta a seguinte mensagem: <p class="error">@message</p> Para mais ajuda sobre como adicionar ou atualizar código no seu servidor, veja o <a href=":handbook_url">manual</a>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8696, 'Tabelas HTML podem ser criadas com cabeçalhos e elementos de descrição/sumário.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8697, 'Texto alternativo é obrigatório por padrão em imagens adicionadas através do CKEditor (note que isto pode ser sobrescrito).', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8698, 'Elementos semânticos do HTML5 figure e figcaption estão disponíveis para adicionar legendas as imagens.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8699, 'Este log não é persistente', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8700, 'Os registros do módulo de registro de banco de dados podem ser limpos por administradores e tarefas automatizadas de cron, de modo que não devem ser usados para <a href=":audit_trail_wiki">registro forense</a>. Para fins forenses, use o módulo Syslog.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8701, 'Por razões de segurança, o arquivo que você enviou foi renomeado para %filename.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8702, 'Separe extensões com vírgula ou espaço. Cada extensão pode conter caracteres alfanuméricos, ''.'', e ''_'', e deve começar e terminar com um caractere alfanumérico.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8703, 'A lista de extensões permitidas não é válida. Os caracteres permitidos são a-z, 0-9, ''.'', e ''_''. O primeiro e o último caracteres não podem ser ''.'' ou ''_'', e esses dois caracteres não podem aparecer um ao lado do outro. Separe extensões com vírgula ou espaço.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8704, 'Adicione %txt_extension à lista de extensões permitidas para carregar arquivos com segurança com uma extensão de %extension. A extensão %txt_extension será adicionada automaticamente.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8705, 'No menu administrativo <em>Gerenciar</em>, navegue até <em>Estrutura</em> &gt; @layout_link.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8706, 'Configure o bloco e clique em <em>Salvar bloco</em>. Consulte @configure_topic para obter detalhes de configuração.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8707, 'Configuração de tradução', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8708, 'Para entidades de configuração, encontre a entidade específica que deseja traduzir na próxima página e clique em <em>Traduzir</em> em <em>Operações</em>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8709, 'Digite traduções para os campos de texto traduzíveis para o item de configuração e salve.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8710, 'Configurando configurações de idiomas e traduções', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8711, 'Em <em>Configurações de idiomas personalizados</em>, encontre os tipos de entidade de conteúdo que devem ter configurações de idiomas personalizados em seu site. Marque a caixa ao lado de cada um. Uma seção aparecerá abaixo da lista, com configurações para o tipo de entidade.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8712, 'Para cada tipo de entidade selecionada na seção de configurações abaixo, marque as caixas para cada subtipo de entidade que deve ser <em>Traduzível</em> em seu site. Se o tipo de entidade não tiver subtipos, existe apenas uma caixa de seleção para o tipo de entidade como um todo.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8713, 'Para cada tipo de entidade ou subtipo, selecione o <em>Idioma padrão</em>. Além disso, se você quiser ter outros idiomas disponíveis, além do padrão, quando criar conteúdo, selecione a caixa <em>Mostrar seletor de idiomas na criação e edição de páginas</em>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8765, 'Erro adicionando / atualizando', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8981, 'Traduza a configuração do seu site para outro idioma. Veja @language_add_topic se você precisar adicionar um novo idioma.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8714, 'Para cada tipo ou subtipo <em>Traduzível</em>, procure a lista de campos para o tipo ou subtipo e verifique se apenas os campos que devem ser traduzíveis são marcados. Por exemplo, você provavelmente gostaria de traduzir um campo <em>Título</em>, mas talvez não queira traduzir um campo de <em>Data de início</em>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8715, 'Clique em <em>Salvar configuração</em> quando todas as alterações forem realizadas.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8716, 'Trabalhando com idiomas e traduções', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8717, 'Que texto pode ser traduzido em seu site?', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8718, 'Existem três tipos de texto que podem ser traduzidos:', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8719, 'O texto da interface do usuário que é fornecido pelo software principal, seu perfil de instalação, temas e módulos, são fornecidos em Inglês mas podem ser traduzidos para outros idiomas. Você também pode baixar traduções que os membros da comunidade desenvolveram.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8720, 'Trabalhando com visão geral de idiomas', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8721, 'Adicionando um idioma', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8722, 'Adicione um idioma ao seu site.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8723, 'Clique em <em>Adicionar idioma</em>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8724, 'Se o idioma estiver na lista de <em>nomes do idioma</em>, selecione-o e clique em <em>Adicionar idioma</em>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8725, 'Se o seu idioma não estiver na lista, selecione <em>Idioma personalizado...</em> e digite o <em>Código de idioma</em>, <em>Nome do idioma</em> e <em>Direção</em> para o idioma. Clique em <em>Adicionar idioma personalizado</em>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8726, 'Configurando detecção e seleção de idiomas', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8727, 'Configure os métodos usados para decidir qual idioma será usado para exibir texto em seu site.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8728, 'O que é um método de detecção de idiomas?', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8729, 'Um método de detecção de idioma é uma maneira de seu site decidir qual idioma deve ser usado para exibir texto. Esta decisão é tomada avaliando uma série de métodos de detecção para idiomas; o primeiro método de detecção que obtém um resultado, determinará qual idioma é usado. Se você tiver mais de um idioma em seu site, você pode configurar os métodos de detecção que são usados e a ordem que eles são avaliados, tanto para texto da interface do usuário quanto para texto de conteúdo. O texto de configuração sempre usa o método de texto da interface e a maioria dos sites usa os mesmos métodos de detecção para todos os tipos de texto.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8730, 'Quais métodos de detecção de idiomas estão disponíveis?', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8731, 'Os métodos de detecção disponíveis dependem de quais módulos estão instalados. Alguns dos métodos de detecção de idiomas mais usados são:', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8732, 'Use o idioma a partir da URL, que pode estar em um prefixo de caminho como <em>exemplo.com/br/page_path</em> para o idioma Português (br) ou em um domínio como <em>br.exemplo.com/page_path</em>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8733, 'Para usuários conectados, use o idioma que eles definiram em seus perfis.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8734, 'Use as preferências de idioma do navegador do usuário.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8735, 'Use o idioma mais recentemente selecionado a partir de um bloco <em>de alternância de idiomas.</em>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8736, 'Use o idioma a partir de um parâmetro de sessão ou de um parâmetro de solicitação; por exemplo, adicionando <em>?language=br</em> ao final da URL.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8737, 'Marque as caixas dos métodos de detecção de idiomas desejados e desmarque as caixas para os métodos que você não deseja usar.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8738, 'Se quiser, arraste os métodos para mudar sua ordem.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8739, 'Clique em <em>Salvar configurações</em>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8740, 'Clique em <em>Configurar</em> em cada método de detecção ativado e verifique se as configurações estão correta (ou atualize-as).', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8741, 'Importando um arquivo de tradução', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8742, 'Importe um arquivo (extensão.po) contendo traduções para texto da interface do usuário.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8743, 'Navegue para encontrar o <em>Arquivo de tradução</em> que deseja importar. Selecione o idioma e marque as opções de importação desejadas.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8744, 'Clique em <em>Importar</em> e aguarde que seu arquivo seja importado.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8745, 'Traduzindo textos da interface do usuário', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8746, 'Traduza as strings de texto da interface do usuário do Inglês para um idioma não-Inglês configurado em seu site.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8747, 'Usando os filtros, procure por uma string ou conjunto de strings que você deseja traduzir; certifique-se de selecionar o <em>Idioma de tradução</em> correto se você tiver mais de um idioma não-Inglês em seu site.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8748, 'Digite novas traduções e clique em <em>Salvar traduções</em>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8749, 'Repita essas etapas até que todo o texto desejado da interface do usuário seja traduzido para todos os idiomas do seu site.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8750, 'Verificando o status da tradução da interface', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8751, 'Verifique o status atual das traduções de interface e veja se há alguma atualização disponível.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8752, 'Olhe para a coluna de <em>tradução de interface</em> na tabela de idiomas para encontrar a porcentagem de texto da interface do usuário que foi traduzida para cada idioma.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8753, 'Opcionalmente, clique em <em>Verificar manualmente</em> para atualizar o relatório.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8754, 'Veja o relatório para saber se algum idioma tem atualizações de tradução que você pode baixar.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8755, 'Você pode usar o grupo de módulos <em>Migração</em> para executar a etapa de migração de atualização do Drupal 6 ou 7 para Drupal 8 ou posterior, bem como outras migrações. Esses módulos também fornecem APIs que podem ser usadas por programadores para escrever software personalizado para migrações. Aqui estão as funções dos principais módulos de migração:', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8756, '[user:account-name]: O nome da conta do usuário.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8757, 'A indexação da Ajuda está totalmente finalizada. Alguns resultados podem estar faltando ou incorretos.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8758, 'Você será informado se uma atualização foi realizada neste site.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8759, 'Você precisa digitar as credenciais de banco de dados do site Drupal que deseja atualizar. Você também pode incluir seu diretório de arquivos na atualização. Por exemplo, arquivos locais, /var/www/docroot ou arquivos remotos http://www.exemplo.com.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8760, 'Você será informado se houver conteúdo no site que possa ser substituído por esta atualização.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8761, 'Finalmente, uma mensagem é exibida sobre o número de tarefas de atualização que foram bem sucedidas ou falharam.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9749, '<code>rsync</code> não está disponível.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8768, 'Usuários sem essa permissão não terão acesso à endereços de e-mail em páginas de usuários ou em outros locais onde eles possam ser mostrados, como em Views e respostas JSON:API.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8769, 'O nome de usuário ou endereço de e-mail é inválido.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8770, 'O formulário de redefinição de senha foi enviado com uma conta desconhecida ou inativa: %name.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8771, 'Sempre mostrar a exibição padrão', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8772, 'Publicar espaço de trabalho', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8773, 'Publicar o espaço de trabalho %source_label', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8774, 'Não existem alterações que possam ser publicadas de %source_label para %target_label.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8775, 'Você gostaria de publicar o conteúdo do espaço de trabalho %label?', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8776, 'Publicar conteúdos do espaço de trabalho.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8777, 'Publicado com sucesso.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8778, 'A publicação falhou. Todos os erros foram registrados.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8779, 'Há @count item que pode ser publicado de %source_label para %target_labelHá @count itens que podem ser publicados de %source_label para %target_label', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8780, 'Publicar @count item para @targetPublicar @count itens para @target', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8781, 'Tópico de ajuda %topic inexistente', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8782, 'Falha ao obter dados de aviso de segurança:', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8783, 'Consulte <a href=":url">Solucionando problemas de feed</a> para possíveis causas e resoluções.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8784, 'Verifique <a href=":url">seus registros do sistema local</a> para mensagens de erro adicionais.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8785, 'Avisos críticos de segurança', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8786, 'O módulo System exibe anúncios de segurança altamente críticos e sensíveis ao tempo para os administradores do site. Alguns anúncios de segurança serão exibidos até que uma atualização de segurança crítica seja instalada. Anúncios que não estão associados a uma versão específica aparecerão por um período fixo de tempo. <a href=":handbook">Mais informações sobre avisos críticos de segurança</a>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8787, 'Apenas os anúncios de segurança mais críticos serão mostrados. <a href=":advisories-list">Ver todos os anúncios de segurança</a>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8788, '(<a href=":system-help">O que são anúncios críticos de segurança?</a>)', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8789, 'Anúncios críticos de segurança', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8790, 'Configurações de avisos de segurança', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8791, 'Exibir avisos críticos de segurança', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8792, 'De quanto em quanto tempo verificar se há avisos de segurança, em horas', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8793, 'O feed de aviso de segurança JSON do Drupal.org não pôde ser decodificado.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8794, '[user:display-name]
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8795, 'O rótulo do link.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8796, 'Pré-cabeçalho', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8797, 'Banner de Topo', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8798, 'Hero (largura total)', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8799, 'Move o conteúdo do estado %from para o estado %to.Move o conteúdo dos estados %from para o estado %to.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8800, 'Seu servidor não suporta atualização de módulos e temas a partir desta interface. Em vez disso, atualize os módulos e temas carregando as novas versões diretamente para o servidor, conforme documentado em <a href=":doc_url">Estendendo o Drupal</a>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8801, 'Seu servidor não suporta a adição de módulos e temas a partir desta interface. Em vez disso, adicione módulos e temas carregando-os diretamente para o servidor, conforme documentado em <a href=":doc_url">Estendendo o Drupal</a>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8802, 'Atualizar módulos e temas requer <strong>acesso @backends</strong> ao seu servidor. Consulte <a href=":doc_url">Estendendo o Drupal</a> para outros métodos de atualização.Atualizar módulos e temas requer acesso ao seu servidor através de um dos seguintes métodos: <strong>@backends</strong>. Consulte <a href=":doc_url">Estendendo o Drupal</a> para outros métodos de atualização.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8803, 'Adicionar módulos e temas requer <strong>acesso @backends</strong> ao seu servidor. Consulte <a href=":doc_url">Estendendo o Drupal</a> para outros métodos.Adicionar módulos e temas requer acesso ao seu servidor através de um dos seguintes métodos: <strong>@backends</strong>. Consulte <a href=":doc_url">Estendendo o Drupal</a> para outros métodos.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8804, 'Configurando comentários', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8805, 'Configure um tipo/subtipo de entidade de conteúdo para permitir comentários, usando um tipo de comentário que você configurou. Consulte @content_structure_topic para saber mais sobre entidades e campos de conteúdo e @comment_type_topic para configurar um tipo de comentário.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8806, 'Quem pode configurar comentários?', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8807, 'Para seguir estas etapas, o módulo Field UI deve ser instalado. Você precisará da permissão de <em>@comment_permissions_link</em> do módulo Comment para alterar as configurações de comentários para um campo de comentários. Você também precisará ter a permissão correta para adicionar campos ao tipo de entidade ou subtipo onde os comentários estão anexados. Por exemplo, para adicionar um campo de comentários aos itens de conteúdo fornecidos pelo módulo Node, você precisaria da permissão <em>Administrar tipos de conteúdo</em> do módulo Node.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8808, 'Siga os passos descritos em <em>Adicionando um campo a um subtipo de entidade</em> para adicionar um campo de tipo <em>Comentários</em> ao tipo de entidade ou subtipo desejado.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8809, 'Na primeira página de configurações de campo, escolha o tipo de <em>Comentário</em> a ser usado para este tipo de entidade ou subtipo. Você também irá notar que o campo <em>Número de valores permitidos</em> não pode ser alterado para campos de comentários.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8810, 'Na página de configurações de campo seguinte, digite as configurações desejadas para o campo de comentários:', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8811, '<em>Threading</em>: se os comentários são ou não coletados por threads, com pessoas capazes de responder a comentários específicos em vez da própria entidade de conteúdo.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8812, '<em>Comentários por página</em>: o número máximo de comentários exibidos em uma página (um paginador será adicionado se você exceder esse limite).', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8813, '<em>Comentários anônimos</em>: se comentaristas anônimos podem ou são obrigados a deixar informações de contato com seus comentários (só se aplica se usuários anônimos tiverem permissão para postar comentários).', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (10731, '<em>Mostra o formulário de resposta na mesma página dos comentários</em>: se o formulário de resposta ao comentário é exibido na mesma página dos comentários. Se isso não for selecionado, clicar em <em>Responder</em> abrirá uma nova página com o formulário de resposta.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8814, '<em>Pré-visualizar comentários</em>: se a visualização de comentários antes do envio é <em>Obrigatória</em>, <em>Opcional</em> ou <em>Desativada</em>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8815, '<em>Valor padrão</em>: cada entidade individual tem suas próprias configurações de comentários, mas aqui você pode definir padrões para as configurações de comentários para este tipo de entidade ou subtipo. Os valores das configurações de comentários são:', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8816, '<em>Aberto</em>: comentários são permitidos.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8817, '<em>Fechado</em>: comentários passados permanecem visíveis, mas não são permitidos novos comentários.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8818, '<em>Oculto</em>: comentários passados estão ocultos e novos comentários não são permitidos.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8819, 'Documentação online para configurações de comentário de conteúdo', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8820, 'Criando um tipo de comentário', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8821, 'Crie um novo tipo de comentário. Consulte @comment_overview_topic para obter informações sobre comentários e tipos de comentários.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8822, 'Quem pode criar tipos de comentários?', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8823, 'Usuários com permissão <em>@comment_permissions_link</em> (normalmente administradores) podem criar tipos de comentários.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8824, 'No menu administrativo <em>Gerenciar</em>, navegue até <em>Estrutura</em> &gt; <em>@comment_types_link</em>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8825, 'Clique em <em>Adicionar tipo de comentário</em>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8826, 'No campo <em>Rótulo</em>, digite um nome para o tipo de comentário, que é como ele será listado na interface administrativa.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8827, 'No campo <em>Tipo de entidade alvo</em>, selecione o tipo de entidade a ser comentada. Consulte @content_structure_topic para saber mais sobre entidades e campos de conteúdo.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8828, 'Clique em <em>Salvar</em>. O tipo de comentário será criado.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8829, 'Opcionalmente, se você tiver o módulo core Field UI instalado, você poderá seguir as etapas dos tópicos relacionados para adicionar campos ao novo tipo de comentário, configurar o formulário de edição e configurar a exibição.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8830, 'Desabilitando comentários', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8831, 'Desligue os comentários de uma determinada entidade (veja @content_structure_topic para mais sobre entidades de conteúdo e campos). Observe que se você quiser desativar o comentário para todas as entidades de um tipo de entidade ou subtipo, você precisará editar as configurações de campo para o campo de comentários; consulte @comment_config_topic para saber mais sobre a configuração do campo de comentários.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8832, 'Quem pode desabilitar comentários?', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8833, 'Você precisará da permissão <em>@comment_permissions_link</em> para desativar os comentários. Você também precisará de permissão para editar a entidade em que os comentários estão.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8834, 'Encontre a entidade para a qual deseja desativar os comentários e edite-a. Por exemplo, para desativar comentários em um item de conteúdo, você pode encontrá-lo navegando no menu administrativo <em>Gerenciar</em> <em>Conteúdo</em>, filtrando para encontrar o item de conteúdo e clicando em <em>Editar</em>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8835, 'Em <em>Configurações de comentário</em>, selecione a configuração de comentário desejada:', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8836, 'Salvar a entidade.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8837, 'Moderando comentários', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8838, 'Decide quais comentários são mostrados no website.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8839, 'Quem pode moderar comentários?', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8840, 'Usuários com permissão de <em>@comment_permissions_link</em> (normalmente administradores) podem moderar comentários. Você também precisará da permissão <em>Acessar a pré-visualização de conteúdo</em> do módulo Node (se estiver instalado) para navegar até a página de gerenciamento de comentários.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8841, 'No menu administrativo <em>Gerenciar</em>, navegue até <em>Conteúdo</em> &gt; <em>@comment_published_link</em>. É apresentada uma lista de todos os comentários.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8842, 'Para despublicar comentários, selecione um ou mais comentários marcando as caixas do lado esquerdo (lado direito em idiomas da direita para a esquerda). Em seguida, selecione <em>Despublicar comentário</em> na lista <em>de seleção de <em>Ação</em> e clique em <em>Aplicar aos itens selecionados</em>. Se você selecionar a ação <em>Excluir comentário</em>, você pode, em vez disso, excluir os comentários indesejados.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8843, 'Para alterar o conteúdo de um comentário, clique em <em>Editar</em> do botão suspenso de um comentário específico.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8844, 'Para publicar comentários que ainda não estão visíveis no site, navegue até a aba <em>@comment_unpublished_link</em>. Selecione um ou mais comentários marcando as caixas do lado esquerdo (lado direito em idiomas da direita para a esquerda). Em seguida, selecione <em>Publicar comentário</em> na lista de seleção de <em>Ação</em> e clique em <em>Aplicar aos itens selecionados</em>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8845, 'Documentação online para moderando comentários', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8846, 'Gerenciando comentários', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8847, 'O que é um comentário?', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8848, 'O que é um tipo de comentário?', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8849, 'Comentários são divididos em <em>tipos de comentários</em>, que são os subtipos da entidade para o tipo de entidade de comentários. Cada tipo de comentário tem seus próprios campos e suas próprias configurações de forma e exibição; cada tipo pode ser usado para comentários em um único tipo de entidade. Você pode configurar diferentes tipos de comentários para diferentes propósitos de comentários em seu site; por exemplo, você pode configurar um tipo de comentário para receitas que tem campos "Como é o gosto?" e "As instruções funcionaram?", e outro tipo de comentário para entradas de blog que tem apenas um campo de corpo de comentários genérico.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8850, 'O que é moderação?', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8944, 'Visão geral das configurações de caminhos, apelidos e URLs', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8945, 'O módulo Path do core fornece a funcionalidade de apelidos de URL. O módulo contribuído <a href="https://www.drupal.org/project/pathauto">Pathauto</a> permite configurar apelidos de URL gerados automaticamente para itens de conteúdo e outras páginas. Veja os tópicos relacionados listados abaixo para tarefas específicas.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8946, 'Configurando taxonomia', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9555, 'No menu administrativo <em>Gerenciar</em>, navegue até <em>Configuração</em> &gt; <em>Região e Idioma</em> &gt; <em>@translation_settings_link</em>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8851, '<em>Moderação</em> é um fluxo de trabalho onde comentários postados por alguns usuários em seu site são verificados antes de serem publicados, para evitar spam e outros maus comportamentos. O software principal fornece uma funcionalidade básica de moderação: você pode configurar permissões para que novos comentários postados por alguns papéis de usuário comecem como despublicados até que um usuário com um papel diferente revise e publique-os. Os módulos contribuídos fornecem moderação adicional e funcionalidade de redução de spam, como exigir que usuários não confiáveis façam um teste CAPTCHA antes de enviar comentários e deixar que os membros da comunidade sinalizem os comentários como possíveis spam. Consulte @users_overview_topic para saber mais sobre usuários, permissões e funções.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8852, 'Visão geral do gerencimento de comentários', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8853, 'O módulo do core Comment oferece a seguinte funcionalidade:', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8855, 'Criando tipos de comentários; o módulo core Field UI permite anexar campos para tipos de comentários e anexar campos de referência de comentários à outras entidades para que as pessoas possam comentar sobre eles.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8856, 'Configurando comentários', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8857, 'Moderando comentários como discutido acima', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8858, 'O que é edição rápida?', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8859, 'Clique no botão <em>Editar</em> dos links contextuais na barra de ferramentas (na maioria dos temas, parece um lápis). <em>Editar</em> contextual links com o mesmo ícone aparecerá por toda a página.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8860, 'Encontre o link contextual para a parte da página que deseja editar. Por exemplo, se você quiser editar as configurações de um bloco, o link deve estar no canto superior direito do bloco ou no canto superior esquerdo para idiomas da direita para a esquerda.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8861, 'Faça suas edições e envie o formulário.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8862, 'A interface administrativa principal tem conformidade incorporada com muitos padrões de acessibilidade para que a maioria das páginas sejam acessíveis em seu estado padrão à maioria dos usuários. No entanto, certas páginas se tornam mais acessíveis para alguns usuários através do uso de uma interface não padrão ou melhorada. Essas interfaces incluem:', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8863, 'Habilitando erros de formulários inline', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8864, 'Erros que ocorrem quando você envia um formulário, como não preencher um campo necessário, às vezes são difíceis para os usuários entenderem e localizarem. Para tornar esses erros mais fáceis de serem encontrados, a melhor prática é colocar um resumo dos erros na parte superior da página do formulário. Para torná-los mais fáceis de entender, a melhor prática é exibir mensagens de erro com os campos de formulário a que estão relacionados. Ambas as práticas são implementadas pelo módulo core Inline Form Errors.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8879, 'Crie e publique um item de conteúdo. Consulte @content_overview_topic para saber mais sobre tipos de conteúdo e itens de conteúdo.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8880, 'Quem pode criar conteúdo?', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8881, 'Usuários com permissão de <em>@content_permissions_link</em> podem visitar a página <em>Conteúdo</em> conforme descrito neste tópico. Cada tipo de conteúdo tem suas próprias permissões de criação. Por exemplo, para criar conteúdo do tipo Artigo, um usuário precisaria da permissão Criar novo conteúdo. Além disso, os usuários com as permissões de <em>Pular o controle de acesso de conteúdo</em> ou <em>Administrar conteúdo</em> podem criar itens de conteúdo de todos os tipos. Alguns módulos contribuídos alteram a estrutura de permissões para criação de conteúdo.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8882, 'No menu administrativo <em>Gerenciar</em>, navegue até <em>@content_link</em>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8883, 'Clique em <em>Adicionar conteúdo</em>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8884, 'Se houver mais de um tipo de conteúdo definido em seu site que você tem permissão para criar, clique no nome do tipo de conteúdo que deseja criar.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8885, 'No formulário de edição de conteúdo, digite o <em>título</em> do seu conteúdo, que será exibido como o título da página quando o item de conteúdo for exibido em uma página e também como o rótulo do item de conteúdo em telas de administração.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8886, 'Preencha os outros campos mostrados no formulário de edição para este tipo de conteúdo específico.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8887, 'Deixe marcado o campo <em>Publicado</em> para publicar o conteúdo imediatamente, ou desmarque-o para torná-lo despublicado. Conteúdo despublicado geralmente não é mostrado para usuários não administrativos do site.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8888, 'Opcionalmente, clique em <em>Pré-visualizar</em> para pré-visualizar o conteúdo.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8889, 'Clique em <em>Salvar</em>. Você verá o conteúdo em uma página.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8890, 'Criando um tipo de contéudo', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8891, 'Crie um novo tipo de conteúdo. Consulte @content_overview_topic para saber mais sobre tipos de conteúdo.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8892, 'Quem pode criar um tipo de conteúdo?', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8893, 'Usuários com permissão de <em>@content_permissions_link</em> (normalmente administradores) podem criar novos tipos de conteúdo.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8894, 'No menu administrativo <em>Gerenciar</em>, navegue até <em>Estrutura</em> &gt; <em>@comment_types_link</em>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8895, 'Clique em <em>Adicionar tipo de conteúdo.</em>', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8896, 'No campo <em>Rótulo</em>, digite um nome para o tipo de comentário, que é como ele será listado na interface administrativa.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8897, 'Opcionalmente, digite uma <em>Descrição</em> para o tipo de conteúdo. Você também pode ajustar algumas das configurações na seção de abas verticais da página de edição.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8898, 'Clique em <em>Salvar e gerenciar campos</em>. Seu tipo de conteúdo será criado e, supondo que você tenha o módulo core Field UI instalado, você será levado para a página <em>Gerenciar campos</em> para o tipo de conteúdo. (Se você não tiver o módulo core Field UI instalado, o botão mostrará <em>Salvar</em>.)', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8899, 'Se você tiver o módulo core field UI instalado, siga as etapas nos tópicos relacionados para adicionar campos ao novo tipo de conteúdo, configure o formulário de edição e configure a exibição.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8900, 'Editando um item de conteúdo', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8901, 'Encontre um item de conteúdo e edite-o, ou atualize um grupo de itens de conteúdo em massa. Consulte @node_overview_topic para saber mais sobre tipos de conteúdo e itens de conteúdo.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8902, 'Quem pode procurar e editar conteúdo?', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8947, 'Crie um vocabulário de taxonomia e adicione um campo de referência para esse vocabulário à uma entidade de conteúdo. Consulte @taxonomy_overview_topic para obter informações sobre taxonomias e @content_structure_topic sobre entidades de conteúdo.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8948, 'Quem pode configurar um vocabulário de taxonomia?', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8903, 'Usuários com permissão de <em>@content_permissions_link</em> podem usar a página <em>Conteúdo</em> para encontrar conteúdo. Cada tipo de conteúdo tem suas próprias permissões de edição. Por exemplo, para editar o conteúdo do tipo Artigo, um usuário precisaria da permissão <em>Artigo: Editar o próprio conteúdo</em> para editar um artigo que criou ou a permissão <em>Artigo: Editar qualquer conteúdo</em> para editar um artigo que outra pessoa criou. Além disso, usuários com as permissões de <em>Pular o controle de acesso de conteúdo</em> e <em>Administrar conteúdo</em> podem editar itens de conteúdo de todos os tipos. Alguns módulos contribuídos alteram a estrutura de permissão para edição de conteúdo.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8904, 'Opcionalmente, use filtros para reduzir a lista de itens de conteúdo mostrados:', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8905, '<em>Título</em>: palavra-chave(s) do título', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8906, '<em>Tipo de conteúdo</em>', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8907, '<em>Status de Publicação</em>', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8908, '<em>Idioma</em>', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8909, 'Se você digitar ou selecionar valores de filtro, clique em <em>Filtro</em> para aplicar os filtros.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8910, 'Opcionalmente, classifique a lista clicando em um cabeçalho de coluna. Clique novamente para reverter a ordem.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8911, 'Para editar o título ou outros valores de campo para um item de conteúdo, clique em <em>Editar</em> na linha do item de conteúdo. Atualize os valores e clique em <em>Salvar</em>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8912, 'Alguns tipos de edições podem ser feitas em massa para vários itens de conteúdo. Por exemplo, para publicar vários itens de conteúdo não publicados, marque as caixas na coluna esquerda (coluna direita em idiomas da direita para a esquerda) para selecionar os itens de conteúdo desejados. Para <em>Ação</em>, selecione a ação <em>Publicar conteúdo</em>. Clique em <em>Aplicar nos itens selecionados</em> para fazer a alteração. As outras ações em <em>Ação</em> funcionam de forma semelhante.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8913, 'O que é um item de conteúdo?', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8914, 'Um <em>item de conteúdo</em> é um tipo de entidade de conteúdo para conteúdo em nível de página que pode ter campos que armazenam texto, marcação HTML, imagens, arquivos anexados e outros dados. Consulte @content_structure_topic para saber mais sobre entidades e campos de conteúdo.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8915, 'O que é um tipo de conteúdo?', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8916, 'Os itens de conteúdo são divididos em <em>tipos de conteúdo</em>, que são os subtipos da entidade para o tipo de entidade de item de conteúdo; cada tipo de conteúdo tem seus próprios campos e configurações de exibição. Por exemplo, você pode configurar tipos de conteúdo para páginas, artigos, receitas, eventos e entradas de blog em seu site.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8917, 'Visão geral do gerenciamento de conteúdo', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8918, 'O módulo Node do core permite definir tipos de conteúdo e adicionar e editar itens de conteúdo. O módulo Field UI do core permite que você anexe campos a cada tipo de conteúdo e gerencie o formulário de edição e exibição para cada tipo de conteúdo. Veja os tópicos relacionados listados abaixo para tarefas específicas. Muitos outros módulos do core e contribuídos e perfis de instalação, fornecem tipos de conteúdo pré-definidos, modificam a estrutura de permissão para itens de conteúdo e fornecem outras funcionalidades.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8919, 'Criando um apelido de URL para um item de conteúdo', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8920, 'Dar a uma página de item de conteúdo um apelido de URL humano ou seo-friendly; você pode seguir passos semelhantes para criar um apelido para uma página de termo de taxonomia. Veja @overview_topic para mais informações sobre apelidos.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8921, 'Quem pode criar apelidos de URLs?', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8922, 'Usuários com permissão de <em>@path_permissions_link</em> podem criar apelidos. Para seguir os passos deste tópico, você também precisará de permissão para editar o item de conteúdo.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8923, 'Localize e abra o formulário de edição de conteúdo do item de conteúdo ou crie um novo item de conteúdo (veja tópicos relacionados sobre a criação e edição de conteúdo).', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8924, 'Em <em>Apelido de URL</em> no formulário de edição, digite o apelido desejado (por exemplo, "/sobre-nos"). Certifique-se de que o apelido começa com um caractere "/".', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8925, 'Verifique se a página pode ser visitada com o novo apelido, por <em>exemplo, https://exemplo.com/sobre-nos</em>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8926, 'Editando um apelido de URL', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8927, 'Altere um apelido de URL existente para corrigir o caminho ou o valor do apelido. Veja @path_overview_topic para mais informações sobre apelidos.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8928, 'Quem pode gerenciar apelidos de URLs?', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8929, 'Usuários com as permissões de <em>@path_permissions_link</em> podem editar apelidos.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8930, 'No menu administrativo <em>Gerenciar</em>, navegue até <em>Configurações</em> &gt; <em>Busca e metadados</em> &gt; <em>@path_aliases_link</em>. Uma lista de todos os apelidos do site será apresentada.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8931, 'Clique em <em>Editar</em> no botão suspenso no apelido que deseja alterar.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8932, 'Faça as alterações necessárias e clique em <em>Salvar</em>. Você será redirecionado para a página da lista de apelidos de URL.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8933, 'Note que você também pode adicionar novos apelidos a partir desta página, para qualquer caminho de seu site.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8934, 'Configurando apelidos para URLs', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8935, 'O que é uma URL?', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8936, 'URL é a abreviação de "Uniform Resource Locator", que é o endereço da página na web. É o "nome" pelo qual um navegador identifica uma página para mostrá-la. No exemplo "Visite-nos em <em>exemplo.com</em>.", <em>https://exemplo.com</em> seria a URL para a página inicial do seu site. Usuários usam URLs para localizar conteúdo na web.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8937, 'O que é um caminho?', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8938, 'Um caminho é a exclusiva última parte da URL para uma função específica ou peça de conteúdo. Por exemplo, para uma página cuja URL completa é <em>https://exemplo.com/node/7,</em>o caminho é <em>node/7</em>. Aqui estão alguns exemplos de caminhos que você pode encontrar em seu site:', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8939, 'node/7: Campinho para um item de conteúdo específico.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8940, 'taxonomy/term/6: Caminho para uma página de um termo de taxonomia.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8941, 'user/3: Caminho para uma página de perfil de usuário.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8942, 'O que é um apelido?', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8943, 'O software core permite que você forneça URLs mais compreensíveis para páginas em seu site, que são chamadas de <em>apelidos</em>. Por exemplo, se você tiver uma página "Sobre nós" com o caminho <em>node/7</em>, você pode configurar um apelido <em>sobre</em> para que seus visitantes vejam como <em>https://www.exemplo.com/sobre</em>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8949, 'Usuários com permissão de <em>@taxonomy_permissions_link</em> podem configurar um vocabulário. Para adicionar um campo na interface administrativa, o módulo Field UI do core deve ser instalado e você também precisará da permissão de <em>Administrar campos</em> para a entidade a qual você está adicionando o campo.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8950, 'No menu administrativo <em>Gerenciar</em>, navegue até <em>Estrutura</em> &gt; <em>@taxonomy_admin_link</em>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8951, 'Clique em <em>Adicionar vocabulário</em>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8952, 'No campo <em>Nome</em>, digite um nome para o vocabulário (por exemplo "Ingredientes"), que é como ele será mostrado na interface administrativa. Opcionalmente, adicione uma descrição.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8953, 'Clique em <em>Salvar</em>. Seu vocabulário será criado e você verá a página que lista todos os termos deste vocabulário.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8954, 'Opcionalmente, clique em <em>Adicionar termo</em> para adicionar um termo ao novo vocabulário. No campo <em>Nome</em>, digite o nome do termo (por exemplo: “Manteiga"). Clique em <em>Salvar</em>. Você receberá uma confirmação sobre o termo que criou. Você pode, opcionalmente, continuar a adicionar mais termos.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8955, 'Se você tiver o módulo Field UI do core instalado, siga as instruções existentes em <em>Adicionando um campo de referência a um subtipo de entidade</em> para adicionar um campo de referência de taxonomia ao tipo de entidade de sua escolha. A página de configurações permitirá que você escolha o <em>Vocabulário</em> que você criou como vocabulário para referência.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8956, 'Você pode também desejar configurar a exibição e formulário de exibição do novo campo (ver tópicos relacionados).', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8957, 'Gerenciando taxonomia', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8958, 'O que é uma taxonomia?', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8959, '<em>Taxonomia</em> é usada para classificar o conteúdo do site. Um exemplo comum de taxonomia são as tags usadas para classificar ou categorizar posts em um site de blog; um site de culinária poderia usar uma taxonomia de ingredientes para classificar receitas. Os itens individuais de taxonomia são conhecidos como <em>termos</em> (as tags do blog ou ingredientes de receita nesses exemplos); e um conjunto de termos é conhecido como <em>vocabulário</em> (o conjunto de todas as tags de postagem do blog, ou o conjunto de todos os ingredientes da receita nesses exemplos). Tecnicamente, os termos da taxonomia são um tipo entidade e os subtipos da entidade são os vocabulários; veja @content_structure_topic para mais informações sobre entidades de conteúdo. Como outras entidades, os termos de taxonomia podem ter campos anexados; por exemplo, você pode configurar um campo de imagem para conter um ícone para cada termo.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8960, 'Um vocabulário individual pode organizar seus termos em uma hierarquia ou pode ser plano. Por exemplo, as tags de blog normalmente têm uma estrutura plana, enquanto um vocabulário de ingredientes de receita pode ser hierárquico (por exemplo, tomates podem ser um sub-termo de vegetais, e sob tomates, você poderia ter tomates verdes e vermelhos).', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8961, 'Os termos da taxonomia são normalmente anexados como campos de referência para outras entidades de conteúdo, que é como você pode usá-los para classificar o conteúdo. Quando você configura um campo de referência de taxonomia, você pode permitir que os usuários digitem termos de duas maneiras:', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8962, 'Novos termos podem ser criados diretamente no formulário de edição de conteúdo.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8963, 'Lista fixa de termos', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8964, 'A lista de termos é curada e gerenciada fora do formulário de edição de conteúdo, e usuários ao editar conteúdo, só podem selecionar termos da lista existente.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8965, 'Visão geral do gerenciamento de taxonomia', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8966, 'O módulo Taxonomy do core permite que você crie e edite vocabulários de taxonomia e termos de taxonomia. O módulo Field UI do core fornece uma interface de usuário para adicionar campos à entidades, incluindo o campo de referência de taxonomia, e configurar a edição e exibição de campo. Veja os tópicos relacionados listados abaixo para tarefas específicas.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8967, '<em>Configurações da página</em>, <em>Configurações de bloco</em>, etc.: configurações específicas do tipo de exibição, como a URL para uma exibição de página. A maioria dos tipos de exibição suporta uma configuração de <em>Acesso</em> onde você pode escolher uma Permissão ou Papel que um usuário deve ter para ver a view.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8968, 'O que são operações em lote?', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8969, 'Adicionando formuário de operações em lote em uma view', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8970, 'Quem pode editar views?', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8971, 'O módulo Views UI do core precisará ser instalado e você precisará da permissão <em>@views_permissions</em> para editar uma view.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8972, 'No menu administrativo <em>Gerenciar</em>, navegue até <em>Estrutura</em> &gt; <em>@views</em>. Uma lista de todas as views é apresentada.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8973, 'Se ainda não houver um <em>Formulário de operações em massa</em> na lista de <em>Campos</em> para a view, clique em <em>Adicionar</em> na seção <em>Campos</em> para adicioná-lo. (O nome exato do campo de formulário operações em massa irá variar e pode conter palavras-chave como "atualização em massa", "elemento de formulário" ou "operações" -- não confundir com <em>links de operações</em> que são aplicados a cada item em uma linha.) Se o campo de operações em massa já existir, clique no nome de campo para editar suas configurações.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8974, 'Verifique as ações que deseja disponibilizar na lista de <em>Ações selecionadas</em> e clique em <em>Aplicar (todos os displays)</em>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8975, 'Verifique se as configurações de <em>Acesso</em> para a view são menos restritivas que as permissões necessárias para executar as operações em massa. Pessoas com permissão para ver a view, mas que não têm permissão para fazer as operações em massa, terão problemas.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8976, 'Clique em <em>Salvar</em>. As ações estarão disponíveis como operações em massa na view.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8977, 'Crie e baixe um arquivo contendo toda a configuração do seu site exportado como arquivos YAML. Consulte @config_overview_topic para obter mais informações sobre configuração.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8978, 'Exporte um único item de configuração para um arquivo. Consulte @config_overview_topic para obter mais informações sobre a configuração.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8979, 'Importe a configuração completa do seu site a partir de um arquivo de arquivo, como um que foi exportado anteriormente (ver @export_full_topic). Consulte @config_overview_topic para obter mais informações sobre a configuração.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8980, 'Importe um único item de configuração em formato YAML, como aquele que foi exportado anteriormente (ver @export_single_topic). Consulte @config_overview_topic para obter mais informações sobre a configuração.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9587, 'Criar e editar blocos de conteúdo', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8982, 'Encontre o tipo de entidade de configuração ou o item de configuração simples que deseja traduzir na coluna <em>Rótulo</em> da lista. Clique em <em>Lista</em> em <em>Operações</em> para uma entidade de configuração ou <em>Traduzir</em> para configuração simples. (Veja @config_overview_topic para saber mais sobre tipos de entidades de configuração e configuração de entidades.)', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8983, 'O formulário de contato sempre terá campos de <em>Assunto</em> e <em>Mensagem</em>. Se você quiser adicionar mais campos, siga os passos em @adding_fields_topic.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8984, 'Alterar o estado de fluxo de trabalho de uma determinada entidade. Consulte @workflows_overview_topic para uma visão geral dos fluxos de trabalho e @content_structure_topic para uma visão geral das entidades de conteúdo.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8985, 'Crie ou edite um fluxo de trabalho com vários estados de fluxo de trabalho (por exemplo <em>Conceito</em>, <em>Arquivado</em>, etc.) para moderar conteúdo. Consulte @workflows_overview_topic para obter mais informações sobre fluxos de trabalho.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8986, 'Decida quais funções devem ter permissões para fazer cada transição; veja @user_overview_topic para uma visão geral de papéis e permissões.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8987, 'Decida em quais <em>tipos</em> e subtipos de entidade o fluxo de trabalho deve ser aplicado. Somente tipos de entidades que suportam revisões podem receber definições de fluxos de trabalho. Consulte @content_structure_topic para obter mais informações sobre entidades de conteúdo e campos.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8988, 'Configure as configurações de idioma e tradução para um ou mais tipos de entidades de conteúdo (consulte @content_structure_topic para uma visão geral das entidades de conteúdo). Para fazer isso, você deve ter pelo menos dois idiomas configurados. Posteriormente, você terá uma operação <em>Traduzir</em> disponível para suas entidades de conteúdo, seja como uma guia ou link quando estiver visualizando ou editando conteúdo, ou em páginas de administração de conteúdo.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8989, 'Um <em>layout</em> é um modelo que define onde blocos e outras peças de conteúdo devem ser exibidos. O módulo do core Layout Discovery permite que módulos e temas registrem layouts, e o módulo core Layout Builder fornece uma interface visual para colocar campos e blocos em layouts para subtipos de entidades e itens de entidades individuais (veja @content_structure_topic para mais sobre entidades e campos).', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8990, 'Os principais itens de mídia do core incluem áudio, imagens, documentos e vídeos. Você pode adicionar outros tipos de mídia, como postagens em redes sociais, através do uso de módulos contribuídos. Os itens de mídia podem ser arquivos localizados no sistema de arquivos do seu site ou itens remotos referenciados por uma URL. Os itens de mídia são entidades de conteúdo e são divididos em tipos de mídia (que são subtipos de entidades); tipos de mídia podem ter campos. Consulte @content_structure_topic para obter mais informações sobre entidades e campos de conteúdo.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8991, 'O conteúdo (blocos, itens de conteúdo, etc.) pode ser escrito em Inglês ou em outro idioma e pode ser traduzido para idiomas adicionais. Veja @content_structure_topic para saber mais sobre conteúdo.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8992, 'Muitos itens de configuração também incluem texto que pode ser traduzido. A configuração padrão fornecida pelo software do seu site é fornecida em Inglês; você também pode baixar traduções fornecidas pela comunidade. Veja @config_overview_topic para saber mais sobre configuração.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8993, 'Expõe <em>entidades</em> à outros aplicativos usando uma implementação totalmente compatível da <a href="https://jsonapi.org">Especificação JSON:API</a>. Consulte @content_structure_topic para obter mais informações sobre entidades de conteúdo e campos.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8994, 'Configure um formato de texto para que, quando um usuário estiver editando texto e selecione esse formato de texto, um editor de texto instalado em seu site seja mostrado. Configure o editor de texto, como escolher quais botões e funções estão disponíveis. Consulte @filter_overview_topic para saber mais sobre formatos de texto.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8995, 'Siga as etapas @filter_overview_topic para adicionar um novo formato de texto ou configurar um formato de texto existente. Quando você chegar ao passo sobre editores de texto, retorne a este tópico.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8996, 'Retorne ao @filter_overview_topic para concluir a configuração do formato de texto e não se esqueça de salvar o formato de texto.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8997, 'Adicionar um campo à um subtipo de entidade. Consulte @content_structure_topic para uma visão geral dos tipos de entidades e subtipos, bem como uma visão geral dos tipos de campo.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8998, 'Em <em>Adicionar um novo campo</em>, selecione o tipo de campo que deseja adicionar. Consulte @content_structure_topic para uma visão geral dos tipos de campo.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (8999, 'Configure os <em>formatadores</em> usados para exibir os campos de um subtipo de entidade, sua ordem no display e as configurações de formatação. Consulte @content_structure_topic para obter mais informações.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9000, 'Configure os <em>widgets</em> usados para editar os campos de um subtipo de entidade, sua ordem no formulário e as configurações do widget. Consulte @content_structure_topic para obter mais informações.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9001, 'Adicionar um campo de referência de entidade a um subtipo de entidade. Consulte @content_structure_topic para obter mais informações sobre entidades e campos de referência.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9002, 'Verifique o status de indexação da página de pesquisa Ajuda. Se não estiver totalmente indexado, veja @cron_topic sobre como executar o Cron até que a indexação esteja concluída.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9003, 'No futuro, você pode clicar em <em>Reconstruir o índice de pesquisa</em> nesta página ou @cache_topic, a fim de forçar o texto de ajuda de tópico a ser re-indexado para pesquisa. Isso deve ser feito sempre que um módulo, tema, idioma ou tradução de string for atualizado.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9004, 'Adicione um novo estilo de imagem que pode ser usado para processar e exibir imagens. Consulte @media_topic para uma visão geral dos estilos de imagem.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9005, 'Configure um subtipo de entidade para ter seus campos exibidos usando um layout (veja @content_structure_topic para mais sobre entidades e campos).', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9006, 'Um layout consiste em uma ou mais <em>seções</em>. Cada seção pode ter de uma a quatro <em>colunas</em>. Você pode colocar blocos, incluindo blocos especiais para os campos no subtipo da entidade, em cada coluna de cada seção (veja @block_overview_topic para mais informações sobre blocos).', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9007, 'Adicionar um novo tipo de mídia que pode ser referenciado em campos de referência de mídia; tipos de mídia são um tipo de entidade de conteúdo. Consulte @media_topic para obter uma visão geral sobre itens de mídia e tipos de mídia e @content_structure_topic para obter mais informações sobre entidades de conteúdo e campos.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9588, 'Adicionar novo bloco de conteúdo', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9008, 'Migrar dados para um novo site vazio, como parte de uma atualização de uma versão mais antiga do Drupal. Consulte @migrate_overview_topic para uma visão geral da migração e atualização.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9009, 'Configure um estilo de imagem responsivo, que pode ser usado para exibir imagens em diferentes tamanhos em diferentes dispositivos. Consulte @media_topic para uma visão geral dos estilos de imagem responsivos e @breakpoint_overview_topic para uma visão geral dos pontos de interrupção.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9010, 'Selecione um <em>estilo de imagem Fallback</em> para usar quando nenhum dos outros estilos se aplicar. Veja @image_style_topic se você precisar adicionar um novo estilo.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9011, 'Siga os passos de @search_index_topic para garantir que o índice de pesquisa seja atualizado.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9012, 'Os tipos de pesquisa de <em>Conteúdo</em> e <em>Ajuda</em> fornecidos pelo software principal pré-indexam seu conteúdo e armazenam os resultados em várias tabelas de banco de dados que são coletivamente chamadas de <em>índice de pesquisa</em>. O processo de indexação renderiza o conteúdo e divide-o em palavras, que podem ser combinadas de forma mais eficiente com consultas de palavras-chave quando os usuários realizam pesquisas. A indexação da pesquisa acontece durante as execuções do cron. Veja @cron_topic para obter mais informações sobre o cron.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9013, 'Siga os passos de @cron_topic para garantir que uma tarefa de cron tenha sido configurada.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (10740, 'Para configurar a pesquisa do site usando o módulo do core Busca, você precisará configurar uma ou mais páginas de pesquisa. Você também precisará verificar ou alterar permissões para que as funções desejadas do usuário possam pesquisar o site. (Consulte @user_overview_topic para obter mais informações sobre funções e permissões.) Para pesquisa de conteúdo, você também precisa ter certeza que o índice de pesquisa está configurado e que o site está totalmente indexado. Finalmente, você pode querer colocar o bloco de <em>Formulários de pesquisa</em> nas páginas do seu site ou adicionar a página de pesquisa à um menu de navegação, para dar aos usuários fácil acesso à pesquisa. Veja os tópicos relacionados listados abaixo para tarefas específicas.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9014, 'Limpa o cache do site. Veja @cache_topic para instruções.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9015, 'Desinstalar um módulo. Seu site deve estar no <em>modo de manutenção</em> quando você desinstalar módulos. Veja @maintenance_topic para mais detalhes.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9016, 'Siga os passos de @view_edit_topic para editar as outras configurações do display.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9017, 'Encontre a seção cujas configurações deseja alterar, como critérios de <em>Formato</em> ou de <em>Filtro</em>. (Veja @views_overview_topic para obter mais informações.)', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9018, 'O core permite que você configure fluxos de trabalho nos quais cada transição tem uma permissão associada que pode ser concedida a um determinado papel. Consulte @configuring_workflows_topic para obter mais informações.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9019, 'Usuários com permissões suficientes podem alterar o estado de fluxo de trabalho de uma determinada entidade. Consulte @changing_states_topic para obter mais informações.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9020, 'Os provedores remotos oEmbed não puderam ser recuperados devido aos erros: @error. Usando dados armazenados anteriormente. Isso pode conter informações desatualizadas.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9021, 'O banco de dados de provedores remotos oEmbed retornou uma lista inválida ou vazia. Usando dados armazenados anteriormente. Isso pode conter informações desatualizadas.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9023, 'Logo de navegação', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9024, '@bundle_type não é @bundles ou @last', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9025, '@bundle_type não é @bundle', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9026, 'Você tem certeza que deseja remover %label @entity-type da região %region?', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9027, 'Isto removerá o posicionamento do bloco. Você precisará <a href=":url">posicioná-lo novamente</a> para desfazer esta ação.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9028, 'O(a) %label @entity-type foi removida da região %region.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9029, 'O arquivo de destino "%file" já existe', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9030, 'O arquivo não pode ser enviado, porque o destino “%destination” é inválido.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9031, 'Para obter mais informações, consulte o <a href=":html-specifications">Padrão de vida HTML</a> ou use seu mecanismo de busca favorito para encontrar outros sites que expliquem HTML.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9032, 'Converte uma imagem para um formato (como JPEG).', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9033, 'Determina o idioma do conteúdo com o parâmetro de solicitação chamado ''language_content_entity''.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9034, 'A definição de campo de origem para o tipo de mídia %type não existe.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9035, 'Nome autor/proprietário', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9036, 'URL autor/proprietário', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9037, 'Nome padrão do item de mídia', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9038, 'URI de miniatura local', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9039, 'URL de origem de recursos', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9040, 'Largura do recurso', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9041, 'Altura do recurso', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9042, 'Representação HTML do recurso', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9043, 'Para informações mais detalhadas, consulte o guia <a href="https://www.drupal.org/docs/updating-drupal">Atualizar o Drupal</a>. Se você não tem certeza o que esses termos significam, você provavelmente deve entrar em contato com seu provedor de hospedagem.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9044, 'Definido na página <a href="@appearance">Configurações de aparência</a> .', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9045, 'Salvar e ir para lista', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9046, 'A atualização automática do core do Drupal não é suportada. Consulte o <a href=":update-guide">guia Atualizar o Drupal</a> para mais informações sobre como atualizar o core do Drupal manualmente.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9047, 'Outras páginas de permissões', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9048, 'A página principal de Permissões pode ser muito pesada, de modo que cada módulo que define permissões tem sua própria página para defini-las. Existem links para essas páginas na página <a href=":modules">Estender</a>. Ao editar um tipo de conteúdo, vocabulário, etc., há também uma aba Gerenciar permissões para permissões relacionadas a essa configuração.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9049, 'A conta %name foi desabilitada.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9050, 'Exclua a conta e faça que seu conteúdo pertença ao usuário de nome %anonymous-name user. Esta ação não pode ser desfeita.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9051, 'Exclua a conta e seu conteúdo. Esta ação não pode ser desfeita.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9052, 'Para fazer login neste site, seu navegador deve aceitar cookies do domínio %domain.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9053, 'Método de cancelamento', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9589, 'Fornece um tipo de campo para URLs internas e externas.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9590, 'Configuração padrão atualizada para %langcode', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9054, 'Esta view será exibida visitando este caminho em seu site. Você pode usar "%" ou parâmetros de rota como "%node" em sua URL para representar valores que serão usados para filtros contextuais. Por exemplo, "node/%node/feed" ou "view_path/%". Parâmetros de rota nomeados são necessários quando este caminho corresponde a um caminho existente. Por exemplo, caminhos como “taxonomy/term/%taxonomy_term" ou “user/%user/custom-view".', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9055, 'Identificador do campo de ordenamento', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9056, 'Isso aparecerá na URL após o ? como valor do parâmetro ''sort_by'', para identificar esse campo de classificação. Não pode ficar em branco. São permitidas apenas letras, dígitos e os caracteres ponto (''.''), hífen (''-''), sublinhado (''_'') e til (''~'').', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9057, 'Este identificador já é usado pelo manipulador de tipo %label.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9058, 'Alternar para este espaço de trabalho', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9059, 'Mudanças no espaço de trabalho', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9060, 'Este espaço de trabalho não possui alterações.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9061, '@entity_type_label: @entity_bundle_label', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9065, 'Bloco de Código', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9066, 'O módulo CKEditor 5 fornece um editor de texto visual altamente acessível e altamente utilizável e adiciona uma barra de ferramentas aos campos de texto. Usuários podem usar botões para formatar conteúdo e criar HTML semanticamente correto e válido. O módulo CKEditor usa a estrutura fornecida pelo módulo <a href=":text_editor">Text Editor</a>. Ele requer que o JavaScript esteja ativo no navegador. Para obter mais informações, consulte a <a href=":doc_url">documentação on-line do módulo CKEditor 5</a> e do <a href=":cke5_url">site do CKEditor 5</a>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9067, 'Habilitando CKEditor 5 para formatos de texto individuais', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9088, 'Configuração da barra de ferramentas CKEditor 5', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9089, 'Pressione a seta para baixo para adicionar à barra de ferramentas.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9090, 'Mova este botão na barra de ferramentas pressionando as teclas de seta esquerda ou direita. Pressione a tecla de seta para cima para remover da barra de ferramentas.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9091, 'Valor inválido da barra de ferramentas.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9092, 'Elemento CKEditor 5', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9093, 'A seguinte tag não é válida HTML: %provided_element.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9094, 'Plugins configuráveis habilitados CKEditor 5', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9097, 'O CKEditor 5 só funciona com formatos de texto baseados em HTML. O filtro "%filter_label" (%filter_plugin_id) implica que este formato de texto não é mais HTML.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9098, 'O CKEditor 5 precisa de pelo menos as tags &lt;p&gt; e &lt;br&gt; para poder funcionar. Eles não são permitidos pelo filtro "%filter_label" (%filter_plugin_id).', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9099, 'A compilação atual do CKEditor 5 requer os seguintes elementos e atributos: <br><code>@list</code><br>Os seguintes elementos não são suportados: <br><code>@diff</code>', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9100, 'A compilação atual do CKEditor 5 requer os seguintes elementos e atributos: <br><code>@list</code><br>Os seguintes elementos estão faltando: <br><code>@diff</code>', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9101, 'As condições de item do CKEditor 5 da barra de ferramentas devem ser atendidas', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9102, 'O item %toolbar_item da barra de ferramentas requer que os carregamentos de imagem sejam ativados.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9103, 'O item %toolbar_item toolbar requer que o filtro %filter seja ativado.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9104, 'O item %toolbar_item da barra de ferramentas requer que o plugin %plugin seja ativado.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9105, 'O item %toolbar_item toolbar requer que os plugins %plugins sejam habilitados.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9106, 'Item da barra de ferramentas CKEditor 5', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9107, 'O item de barra de ferramentas %toolbar_item não é válido.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9108, 'Dependência de item de barra de ferramentas do CKEditor 5', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9109, 'Depende de %toolbar_item, que não está habilitado.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9110, 'Mova um botão para a <em>Barra de ferramentas ativa</em> para ativá-lo ou para a lista de <em>Botões disponíveis</em> para desativá-lo. Botões podem ser movidos com o mouse ou com as teclas de seta do teclado. Os nomes de grupos de barra de ferramentas são fornecidos para suportar leitores de tela. Os grupos de barras de ferramentas vazios serão removidos ao salvar.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9111, 'Extensão PostgreSQL pg_trgm', 'pt-br', 0);
