INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9126, 'O módulo MySQL fornece a conexão entre o Drupal e um MySQL, MariaDB ou banco de dados equivalente. Para obter mais informações, consulte a <a href=":mysql">documentação on-line do módulo MySQL</a>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9127, 'O módulo PostgreSQL fornece a conexão entre o Drupal e um banco de dados PostgreSQL. Para obter mais informações, consulte a <a href=":pgsql">documentação on-line do módulo PostgreSQL</a>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9128, 'O módulo SQLite fornece a conexão entre o Drupal e um banco de dados SQLite. Para obter mais informações, consulte a <a href=":sqlite">documentação on-line do módulo SQLite</a>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9129, 'Módulos depreciados encontrados: %module_list.', 'pt-br', 0);
