INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9591, 'Permite que os usuários traduzam o texto da interface e alternem entre os idiomas da interface.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9138, '<a href=":url">Módulos depreciados</a> são módulos que podem ser removidos na próxima grande versão do core do Drupal e o módulo contribuído relevante. Use por sua conta e risco.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9139, '<a href=":url">Módulos depreciados</a> são módulos que podem ser removidos na próxima grande versão deste projeto. Use por sua conta e risco.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9140, '<a href=":url">Módulos depreciados</a> são módulos que podem ser removidos na próxima grande versão do core do Drupal. Use por sua conta e risco.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9141, 'O módulo @name está depreciado. (mais informações)', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9142, 'sobre o status do módulo @name', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9143, 'O seguinte módulo é experimental: @modules.Os seguintes módulos são experimentais: @modules.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9144, 'Obtenha a @label real de uma revisão de @label', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9145, 'A conexão de banco de dados suporta o tipo JSON.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9146, '<a href="https://www.drupal.org/docs/system-requirements">A conexão com o banco de dados não suporta JSON.</a>', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9147, 'Widget de mídia', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9148, 'Nem todas as funcionalidades podem estar disponíveis porque algumas informações não puderam ser recuperadas.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9149, 'Permitir que o usuário redimensione imagens', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9150, 'O PostgreSQL possui a extensão pg_trgm habilitada.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9151, 'A extensão <a href=":pg_trgm">pg_trgm</a> do PostgreSQL não está presente. A extensão será exigida pelo Drupal 10 para melhorar o desempenho ao usar PostgreSQL. Consulte <a href=":requirements">os requisitos do servidor de banco de dados Drupal</a> para mais informações.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9152, 'O Drupal não pôde verificar a extensão pg_trgm: @error.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9153, 'Texto alternativo sobrescrito', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9154, 'Sobrescrever texto alternativo da imagem da mídia', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9155, 'Adicionar legenda da mídia', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9156, 'Legenda da mídia', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9157, 'Desabilitar legenda', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9158, 'Habilitar legenda', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9159, 'O Package Manager é uma estrutura para atualizar o core do Drupal e instalar módulos e temas contribuídos via Composer. Ele não possui interface de usuário, mas fornece uma API para criar uma cópia temporária do site atual, fazer alterações na cópia e depois sincronizar essas alterações de volta ao site ativo.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9160, 'O Package Manager despacha eventos antes e depois de várias operações, e o código externo pode se integrar à ele assinando esses eventos. Para mais informações, veja <code>package_manager.api.php</code>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9161, 'Módulos não podem ser desinstalados enquanto o Package Manager aplica alterações em stage no código ativo.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9162, 'Pós-atualização @extension', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9163, 'Pressione a seta para baixo para ativar', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9164, 'Imagem decorativa', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9165, 'Adicionar texto alternativo faltante', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9166, 'Alterar texto alternativo da imagem', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9167, 'A edição de origem só deve usar tags e atributos de outra forma indisponíveis', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9168, 'Os seguintes @element_type(s) já são suportados por plugins habilitados e não devem ser adicionados ao campo "Tags HTML editáveis manualmente" da edição de código-fonte: %overlapping_tags.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9169, 'Os seguintes @element_type já são suportados por plugins disponíveis e não devem ser adicionados ao campo "Tags HTML editáveis manualmente" da Edição de código-fonte. Em vez disso, habilite os seguintes plugins para oferecer suporte para esses @element_types: %overlapping_tags.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9170, 'Não existe configuração em stage.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9171, 'A configuração em stage é idêntica a configuração ativa.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9172, 'A principal maneira de alterar a aparência geral do seu site é alternar o tema padrão. Os módulos principais Layout Builder e Layout Discovery permitem que você defina layouts para o conteúdo do seu site, e o módulo principal Breakpoint ajuda os temas para alterar a aparência em dispositivos de tamanhos diferentes. Consulte os tópicos relacionados listados abaixo para tarefas específicas.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9173, 'Usando a edição de configurações em linha (rápida)', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9174, 'Edite as configurações no local.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9175, 'O módulo principal Settings Tray fornece capacidade de editar rapidamente as configurações em linha. Ele requer o módulo principal Contextual Links para expor os links que permitem editar no local.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9176, 'Quem pode editar as configurações no local?', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9177, 'Para seguir estas etapas para editar as configurações no local, o módulo principal Settings Tray deve estar instalado. Além disso, o módulo principal Toolbar ou um módulo substituto da comunidade deve ser instalado. Você precisa ter a permissão <em>Usar links contextuais</em>, bem como a permissão para editar o conteúdo ou as configurações específicas.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9178, 'Encontre e visite uma página em seu site que tenha as configurações que você gostaria de editar.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9179, 'Clique no link para abrir o menu de links contextuais e clique em <em>Edição rápida</em>. Um formulário de edição para as configurações deve aparecer na página.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9180, 'Edição in-loco ou <em>rápida</em>. A edição in-loco da configuração é fornecida pelo módulo principal Settings Tray. Consulte @settings_tray_topic para mais informações.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9181, 'Expõe entidades e outros recursos para outros aplicativos usando uma implementação <a href="https://en.wikipedia.org/wiki/Representational_state_transfer">REST</a> . Os dados são trocados usando um formato de serialização, como JSON, e transferidos usando um método de autenticação, como a Autenticação Básica HTTP.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9182, 'Configurações de carregamento de imagem', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9183, 'Atributo de carregamento', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9184, 'Carregamento de imagem', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9185, 'Imagens de renderização preguiçosas com atributo de carregamento de imagem nativo (<em>loading="lazy"</em>). Isso melhora o desempenho, permitindo que os navegadores carreguem imagens com preguiça.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9186, 'Lazy (<em>loading="lazy"</em>)', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9187, 'Eager (<em>loading="eager"</em>)', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9188, 'Atributo de carregamento de imagem', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9189, 'Selecione o atributo de carregamento para imagens. <a href=":link">Saiba mais sobre o atributo de carregamento de imagens.</a>', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9190, 'Atrasa o carregamento da imagem até que essa seção da página fique visível no navegador. Em caso de dúvida, recomenda-se o carregamento preguiçoso.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9191, 'Forçar os navegadores a baixar uma imagem o mais rápido possível. Este é o padrão do navegador por motivos de legado. Use essa opção somente quando a imagem for sempre esperada para renderizar.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9192, 'Carregamento de imagem: @attribute', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9193, 'Sua instalação do PHP é muito antiga. O Drupal requer pelo menos o PHP %version. Recomenda-se atualizar para o PHP versão %recommended ou superior para o melhor suporte contínuo. Consulte a <a href="http://php.net/supported-versions.php">documentação de suporte à versão do PHP</a> e a página de <a href=":php_requirements">Requisitos do PHP para Drupal</a> para mais informações.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9194, 'Recomenda-se atualizar para o PHP versão %recommended ou superior para o melhor suporte contínuo.  Consulte a <a href="http://php.net/supported-versions.php">documentação de suporte à versão do PHP</a> e a página de <a href=":php_requirements">Requisitos do PHP para Drupal</a> para mais informações.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9195, 'Exibir informações sobre o status @lifecycle do tema @theme', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9196, 'Drupal multisite não é suportado pelo Package Manager.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9197, 'O Xdebug está ativo, o que pode ter um impacto negativo no desempenho do Package Manager e de qualquer módulo que o utilize.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9198, 'Permitir lista reversa', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9199, 'Permitir índice de início', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9200, 'Permitir que o usuário reverta uma lista ordenada', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9201, 'Permite que o usuário especifique o índice inicial de uma lista ordenada', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9202, 'Consulte <a href=":handbook">esta página do manual</a> para obter detalhes sobre problemas de compatibilidade de módulos contrib.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9203, 'A Edição de código-fonte nunca deve permitir o self-XSS.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9204, 'A seguinte tag no campo edição de código-fonte "Tags HTML editáveis manualmente" é um risco de segurança: %dangerous_tag.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9205, 'Habilitar Alinhamentos', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9206, 'Tipo de alinhamento', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9207, 'Permitir substituição do modo de exibição', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9208, 'Esses são os tipos de alinhamento que aparecerão na lista suspensa de alinhamento.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9209, 'Permite que o usuário sobrescreva o modo de visualização padrão', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9210, 'CKEditor 5 Media plugin em sincronia com as configurações de filtro', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9211, 'A configuração do plugin do CKEditor 5 "%cke5_media_plugin_label" "%cke5_allow_view_mode_override_label" deve estar em sincronia com a configuração "%filter_media_plugin_label" do filtro "%filter_media_allowed_view_modes_label": quando marcada, dois ou mais modos de visualização devem ser permitidos pelo filtro.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9212, 'Você pode optar por enviar email somente se uma atualização de segurança estiver disponível ou ser notificado sobre todas as versões mais recentes. Se houver atualizações disponíveis do core do Drupal ou de qualquer um dos módulos e temas instalados, seu site sempre mostrará uma mensagem na página do <a href=":status_report">relatório de status</a>. Se houver uma atualização de segurança, uma mensagem de erro será apresentada nas páginas de administração para usuários com <a href=":update_permissions">permissão para exibir notificações de atualização</a>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9213, 'Parabéns e bem-vindo a comunidade Drupal.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (11791, 'O plugin %plugin precisa de outro plugin para criar <code>@non_creatable_tag</code> os seguintes atributos: <code>@attributes_on_tag</code>. Habilite um plugin que suporte a criação dessa tag. Se não houver nenhum, você pode configurar o plugin de edição de código-fonte para suportá-lo.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9214, 'Configurações do Esquema de Cores Olivero', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9215, 'Essas configurações ajustam a aparência do tema Olivero. Alterar a cor abaixo alterará os valores de tonalidade base, saturação e luminosidade que o tema Olivero usa para determinar suas cores internas.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9217, 'Derivados serão formados a partir desta cor.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9218, 'Cor Primária Base', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9219, '@fieldName mudou para @fieldValue', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9220, 'Impossível desinstalar o módulo %module porque: @reason.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9221, 'Não foi possível instalar o tema %theme pois ele depende do módulo %required_module.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9222, 'Se o botão <em>Fonte</em> estiver disponível na barra de ferramentas, os usuários podem clicar neste botão para desativar o editor visual e editar o código HTML diretamente. Depois de voltar, o editor visual usa as tags HTML permitidas via configuração de plugin (e não explicitamente proibidas por filtros) para formatar o texto. As tags não habilitadas através da configuração do plugin serão retiradas do código HTML quando o usuário voltar para o editor de texto.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9223, 'tema @theme', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9224, 'A configuração <code>update_fetch_with_http_fallback</code> deve ser desativada.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9225, 'Resolva todos os problemas abaixo para continuar a instalação. Para obter ajuda para configurar o servidor de banco de dados, consulte o <a href="https://www.drupal.org/docs/installing-drupal">manual de instalação</a> ou entre em contato com o provedor de hospedagem.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9226, 'Atualizar para o Drupal @current_major só é suportado a partir da versão Drupal @required_min_version ou superior. Se você está tentando atualizar a partir de uma versão mais antiga, primeiro atualize para a versão mais recente do Drupal @previous_major. (<a href=":url">Guia de atualização do Drupal 9</a>)', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9227, 'Migrando um Formato de Texto Existente para o CKEditor 5', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9228, 'Ao alternar um formato de texto existente para usar o CKEditor 5, um processo automático é iniciado que ajuda os formatos de texto a alternar para CKEditor 5 do CKEditor 4 (ou nenhum editor de texto) com o mínimo de esforço e perda de dados zero.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9229, 'Esse processo foi projetado para que não haja risco de perda de dados ao mudar para o CKEditor 5. No entanto, algumas das funcionalidades do seu editor podem não ser 100% equivalentes em relação ao que estava disponível anteriormente. Na maioria dos casos, essas mudanças são mínimas. Após a conclusão do processo, as mensagens de status e/ou aviso resumirão quaisquer alterações ocorridas e informações mais detalhadas estarão disponíveis nos registros do site.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9282, 'Em <em>Configuração da barra de ferramentas</em>, arraste os botões entre <em>Botões Disponíveis</em> e <em>Barra de ferramentas ativa</em>; somente os botões na <em>Barra de ferramentas ativa</em> serão mostrados para o usuário. Focar ou passar o mouse sobre um botão exibirá uma dica de ferramenta explicando o que o botão faz.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9592, 'configurações de carregamento oEmbed', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9593, 'oEmbed incorporado', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9230, 'O CKEditor 5 tentará habilitar plugins que forneçam itens de barra de ferramentas equivalentes aos usados antes de mudar para o CKEditor 5. Todos os principais plugins CKEditor 4 e muitos plugins contrib populares já têm equivalentes CKEditor 5. Em alguns casos, a funcionalidade que exigia módulos contrib agora está incorporada ao CKEditor 5. Nos casos em que um plugin não tem um equivalente, nenhuma perda de dados ocorrerá, mas os elementos fornecidos anteriormente através do plugin podem precisar ser adicionados manualmente como HTML via edição de código-fonte.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9231, 'Considerações adicionais de migração para formatos de texto com HTML restrito', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9232, 'O campo “Tags HTML permitidas" no filtro "Limitar tags HTML permitidas e corrigir HTML defeituoso" agora é somente leitura', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9233, 'Esse campo representa com precisão as tags/atributos permitidos por um formato de texto, mas as tags permitidas são baseadas em quais plugins estão habilitados e como eles são configurados. Por exemplo, ativar o plugin Sublinhado adiciona a tag &lt;u&gt; a "Tags HTML permitidas".', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9234, 'As tags &lt;p&gt; e &lt;br &gt; serão automaticamente adicionadas ao seu formato de texto.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9235, 'O CKEditor 5 requer as tags &lt;p&gt; e &lt;br &gt; para obter a funcionalidade básica. Elas serão automaticamente adicionados a "Tags HTML permitidas" em formatos que anteriormente não os permitiam.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9236, 'Tags/atributos que não são explicitamente suportados por qualquer plugin são suportados pela Edição de Código-fonte', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9237, 'Quando uma tag/atributo necessário não é suportado diretamente por um plugin disponível, o plugin "Edição de código-fonte" é ativado. Este plugin é normalmente usado para sobrescrever a interface do usuário do CKEditor 5 e editar o conteúdo como fonte HTML. Nas configurações de Edição de código-fonte, tags/atributos que não estão disponíveis por meio de outros plugins são adicionados à configuração "Tags HTML editáveis manualmente" da Edição de código-fonte para que sejam suportados pelo formato de texto.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9238, 'Para manter os recursos desse formato de texto, <a target="_blank" href=":ck_migration_url">a migração do CKEditor 5</a> fez o seguinte:', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9239, 'Para manter os recursos desse formato de texto, a migração do CKEditor 5 fez o seguinte:', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9240, 'Plugins habilitados: (%plugins).', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9241, 'Adicionadas estas tags/atributos à configuração <a target="_blank" href=":source_edit_url">Tags HTML editáveis manualmente</a> do plugin de edição de código-fonte: @tag_list', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9242, 'Adicionadas estas tags/atributos à configuração Tags HTML editáveis manualmente do plugin de edição de código-fonte: @tag_list', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9243, 'Detalhes adicionais estão disponíveis <a target="_blank" href=":dblog_url">em seus registros</a>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9244, 'Detalhes adicionais estão disponíveis em seus logs.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9245, 'A atualização para o CKEditor 5 adicionou suporte para algumas tags/atributos anteriormente não suportados.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9246, 'Um plugin introduziu suporte para o seguinte:', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9247, 'para', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9248, 'A tag @tag foi adicionada porque é <a target="_blank" href=":fundamental_tag_link">exigida pelo CKEditor 5</a>.As tags @tag foram adicionadas porque são <a target="_blank" href=":fundamental_tag_link">exigidas pelo CKEditor 5</a>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9249, 'A tag @tag foi adicionada porque é exigida pelo CKEditor 5.As tags @tag foram adicionadas porque são exigidas pelo CKEditor 5.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9250, 'A etiqueta %tags;As etiquetas %tags;', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9251, 'Este atributo: %attributes;Estes atributos: %attributes;', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9252, 'A migração do %text_format para o CKEditor 5 foi salva.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (73, 'Ocorreu um erro durante a execução da resposta do Ajax: !error', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9253, 'Faixa de data (módulo Datetime range): Armazena períodos de data/hora com um início e um fim', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9254, 'Encontre a view que você gostaria de editar e clique em <em>Editar</em> no botão suspenso. Observe que as operações em massa funcionam melhor em uma view com display de página e um formato de tabela.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9255, 'Observe que os usuários anônimos com essa permissão podem editar qualquer conteúdo criado por qualquer usuário anônimo.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9256, 'Observe que os usuários anônimos com essa permissão podem excluir qualquer conteúdo criado por qualquer usuário anônimo.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9257, 'O estilo de imagem de fallback é normalmente a imagem de menor tamanho que você espera que apareça neste espaço. A imagem de fallback só deve aparecer em um site se ocorrer um erro.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9258, 'A relação de %relationship_name usada no %handler_type %handler não está presente na exibição %display_name.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9259, 'Configurar @type @current de @total: @item', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9260, 'Nível do Cabeçalho', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9261, 'Falha nas atualizações para o tipo de entidade %entity_type, por %entity_ids. Verifique os registros.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9262, 'Não é possível atualizar %entity_type %view devido ao erro @message %function (linha %line de %file). <pre>@backtrace_string</pre>', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9263, 'Bloquear entidade de conteúdo alterada', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9264, 'Estilo do Rótulo', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9265, 'Tag de estilo + classes', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9266, 'Uma lista de classes que serão fornecidas na lista suspensa "Estilo". Insira uma ou mais classes em cada linha no formato: element.classA.classB|Etiqueta. Exemplo: h1.Title|Título. Exemplo avançado: h1.fancy.title|Título chique.<br />Esses estilos devem estar disponíveis no arquivo CSS do seu tema.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9280, 'Um editor de texto é um software (normalmente, uma biblioteca JavaScript) que fornece botões e outros mecanismos de comando para facilitar a edição de texto HTML. Alguns editores são chamados <em>de editores visuais</em> ou <em>WYSIWYG (What You See Is What You Get</em>); esses editores ocultam os detalhes HTML do usuário e, em vez disso, mostram a saída formatada na tela. O módulo core Text Editor fornece uma estrutura para implantar editores de texto em seu site. O módulo do core CKEditor 5 fornece o CKEditor 5, que é um editor de texto JavaScript amplamente utilizado que cria HTML limpo e válido; o módulo também impõe restrições de tags HTML no formato de texto associado. Vários módulos contribuídos fornecem outros editores; para instalar um novo editor, além de instalar o módulo, talvez seja necessário baixar a biblioteca do editor de um site de terceiros.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9281, 'Selecione <em>CKEditor 5</em> como o <em>editor de texto</em> ou outro editor de texto que você instalou. O restante dessas etapas pressupõe que você selecionou <em>CKEditor 5</em>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9424, 'Renderizar a entidade referenciada.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9633, 'Fornece o driver de banco de dados SQLite.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9283, 'Arraste botões dentro da <em>Barra de ferramentas ativa</em> para a ordem desejada e agrupe botões arrastando-os entre identificadores de grupo; arraste <em>um novo identificador de grupo</em> para a barra de ferramentas para adicionar grupos adicionais.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9284, 'Se você adicionar botões que exijam configuração, a seção <em>Configurações do plugin CKEditor 5</em> ficará visível e fornecerá seus respectivos formulários de configuração.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9285, 'Clique no link para o seu tema administrativo (como o tema Claro do core), próximo a parte superior da página e verifique se já há um bloco de pesquisa para ajuda localizado na região Ajuda. Caso contrário, siga as etapas no tópico relacionado para colocar o bloco de <em>Formulário de Pesquisa</em> na região Ajuda. Ao configurar o bloco, escolha <em>Ajuda</em> como a página de pesquisa e na guia <em>Páginas</em> em <em>Visibilidade</em>, digite /<em>admin/help</em> para tornar o formulário de pesquisa visível apenas na página principal de <em>Ajuda</em>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9286, 'Clique no link de atalho para adicionar a página à sua lista de atalhos -- no tema administrativo Claro do core, o link se parece com uma estrela e é exibido ao lado do título da página. No entanto, se a página já estiver no seu conjunto de atalhos, clicar no link de atalho irá removê-la do seu conjunto de atalhos.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9287, 'O módulo Shortcut cria um link de adicionar/remover para cada página do seu site; o link permite que você adicione ou remova a página atual do conjunto de atalhos habilitado atualmente (se o tema exibi-lo e você tiver permissão para editar o conjunto de atalhos). O tema administrativo Claro do core exibe esse link ao lado do título da página, como uma estrela cinza ou amarela. Se você clicar na estrela cinza, você adicionará essa página ao seu conjunto preferido de atalhos. Se a página já fizer parte do seu conjunto de atalhos, o link será uma estrela amarela e permitirá que você remova a página atual do seu conjunto de atalhos.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9288, 'Grade - Responsiva', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9289, 'Número máximo de colunas', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9290, 'Largura mínima da célula', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9291, 'O número máximo de colunas que serão exibidas dentro da grade.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9292, 'Largura mínima da célula de grade', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9293, 'A largura mínima das células da grade. Se o contêiner de grade se tornar estreito, as células de grade refluirão para a próxima linha, conforme necessário.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9294, 'Espaçamento da linha de grade', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9295, 'O espaçamento entre as células da grade.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9296, 'O código da aplicação Drupal deve ter permissão de escrita para usar atualizações automáticas. Isso inclui o core do Drupal, módulos, temas e as dependências do Composer no diretório <code>vendor</code>. Isso torna as atualizações automáticas incompatíveis com algumas plataformas de hospedagem.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9297, 'Como o Package Manager modifica a base de código do site atual, ele é intencionalmente limitado de certas formas para evitar alterações inesperadas no site ativo:', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9298, 'Não oferece suporte a instalações multi-site do Drupal.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9299, 'Não realiza automaticamente operações de controle de versão, por exemplo, com o Git. Os administradores do site são responsáveis por confirmar as atualizações.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9300, 'Ele pode manter apenas uma cópia do site por vez. Se uma cópia do site já existe, outra não pode ser criada até que a cópia existente seja destruída.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9301, 'Associa a cópia temporária do site ao usuário ou sessão que a criou originalmente, e apenas esse usuário ou sessão pode fazer alterações nela.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9302, 'Não permite que módulos sejam desinstalados enquanto as alterações estão sendo sincronizadas no site principal.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9303, 'O novo pacote @package será instalado no diretório @path, que já existe mas não é gerenciado pelo Composer.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9304, '@message Veja a <a href=":package-manager-help">página de ajuda</a> para informações sobre como resolver o problema.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9305, 'As alterações em stage não foram aplicadas, e o site está em um estado indeterminado. É altamente recomendável restaurar o código e o banco de dados a partir de um backup.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9306, 'Tarefas pós-aplicação estão sendo executadas na mesma solicitação em que as alterações em stage foram aplicadas ao código ativo. Isso pode resultar em comportamentos imprevisíveis.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9307, 'Falha ao baixar o arquivo de miniatura remoto devido a "%error".', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9308, 'O Gerenciador de Pacotes não é suportado pelo seu ambiente.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9309, 'Configurações do plugin CKEditor 5', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9310, 'Insira um valor como "512" (bytes), "80 KB" (kilobytes) ou "50 MB" (megabytes) para restringir o tamanho de arquivo permitido. Se deixados vazios, os tamanhos dos arquivos podem ser limitados apenas pelos tamanhos máximos de postagem e upload de arquivos do PHP (limite atual <strong>%limit</strong>).', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9311, 'No menu administrativo <em>Gerenciar</em>, navegue até <em>Configuração</em> &gt; <em>Pessoas</em> &gt; <em>@ban_link</em>', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9312, 'No menu administrativo <em>Gerenciar</em>, navegue até <em>Estrutura</em> &gt; <em>@layout_link</em>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9313, 'No menu administrativo <em>Gerenciar</em>, navegue até <em>Configuração</em> &gt; <em>Desenvolvimento</em> &gt; <em>&gt; <em>Sincronização de Configuração</em> &gt; <em>@export_link</em>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9314, 'No menu administrativo <em>Gerenciar</em>, navegue até <em>Configuração</em> &gt; <em>Desenvolvimento</em> &gt; <em>Sincronização de Configuração</em> &gt; <em>Exportar</em> &gt; <em>@single_export_link</em>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9315, 'No menu administrativo <em>Gerenciar</em>, navegue até <em>Configuração</em> &gt; <em>Desenvolvimento</em> &gt; <em>Sincronização de Configuração</em> &gt; <em>@import_link</em>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9316, 'No menu administrativo <em>Gerenciar</em>, navegue até <em>Configuração</em> &gt; <em>Desenvolvimento</em> &gt; <em>Sincronização de Configuração</em> &gt; <em>Importar</em> &gt; <em>@single_import_link</em>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9317, 'No menu administrativo <em>Gerenciar</em>, navegue até <em>Estrutura</em> &gt; <em>@contact_link</em>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9318, 'No menu administrativo <em>Gerenciar</em>, navegue até <em>Configuração</em> &gt; <em>Pessoas</em> &gt; <em>@config_link</em>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9319, 'No menu administrativo <em>Gerenciar</em>, navegue até <em>Pessoas</em> &gt; <em>@permission_link</em>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9320, 'No menu administrativo <em>Gerenciar</em>, navegue até <em>Configuração</em> &gt; <em>Sistema</em> &gt; <em>@cron_link</em>. Veja o <em>Último tempo de execução</em> na página.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9321, 'O que são avisos de segurança?', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9634, 'Registra eventos no log do sistema do servidor web.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9322, 'Um comunicado de segurança é um anúncio público sobre um problema de segurança relatado no software principal. Os projetos contribuídos com um ícone de escudo e "Versões estáveis para este projeto são cobertas pela política de consultoria de segurança" na página do projeto também são cobertos pela política de consultoria de segurança do Drupal. Os avisos de segurança são gerenciados pela <a href="https://www.drupal.org/drupal-security-team">Equipe de Segurança do Drupal</a>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9323, '<a href="https://www.drupal.org/drupal-security-team/security-advisory-process-and-permissions-policy">Processo de consultoria de segurança e política de permissões</a>', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9324, 'No menu administrativo <em>Gerenciar</em>, navegue até <em>Configuração</em> <em>Criação de Conteúdo</em> &gt; <em>@overview_link</em>. A coluna <em>Editor de Texto</em> na tabela mostra o editor de texto que está atualmente conectado a cada formato de texto, se houver.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9325, 'Navegue até a página para gerenciar o subtipo de entidade ao qual você deseja adicionar o campo. Por exemplo, para adicionar um campo a um tipo de conteúdo, no menu administrativo <em>Gerenciar</em>, navegue até <em>Estrutura</em> &gt; <em>@content_types_link</em>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9326, 'Navegue até a página para gerenciar o tipo de entidade ao qual você deseja adicionar o campo. Por exemplo, para adicionar um campo a um tipo de conteúdo, no menu administrativo <em>Gerenciar</em>, navegue até <em>Estrutura</em> &gt; <em>@content_types_link</em>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9327, 'No menu administrativo <em>Gerenciar</em>, navegue até <em>Configuração</em> <em>Criação de Conteúdo</em> &gt; <em>@overview_link</em>. Se você não tiver o módulo principal do Editor de Texto instalado, o link do menu e o título da página serão <em>Formatos de texto</em>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9328, 'No menu administrativo <em>Gerenciar</em>, navegue até <em>@help_link</em>. Verifique se o bloco de pesquisa está visível e tente uma pesquisa.', 'pt-br', 0);
