INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9330, 'Navegue até a página para gerenciar o tipo de entidade ao qual você deseja adicionar o campo. Por exemplo, para adicionar um campo a um tipo de conteúdo, no menu administrativo <em>Gerenciar</em>, navegue até <em>Estrutura</em> &gt; @content_types_link.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9331, 'No menu administrativo <em>Gerenciar</em>, navegue até <em>Relatórios</em> &gt; <em>@translation_updates_link</em>. Esse relatório só estará disponível se o módulo de Update Status estiver instalado.', 'pt-br', 0);
