INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9347, 'A Biblioteca GD para PHP está habilitada, mas foi compilada sem suporte para funções usadas pelos efeitos de rotação e des-saturação. Provavelmente foi compilado usando as bibliotecas GD oficiais do <a href="https://libgd.github.io/">site gdLibrary</a> em vez da biblioteca GD empacotada com PHP. Você deve recompilar o PHP --with-gd usando a biblioteca GD empacotada. Consulte <a href="https://www.php.net/manual/book.image.php">o manual do PHP</a>.', 'pt-br', 0);
