INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9363, 'O diretório de stage tem @stage_count instâncias de @stage_info_file, em comparação com @active_count no diretório ativo. Isso provavelmente indica que uma extensão duplicada foi instalada.', 'pt-br', 0);
