INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9369, 'Estas configurações são aplicadas ao campo %field em qualquer lugar que seja usado. Algumas tem impacto na forma que dados são armazenados e não podem ser alterados uma vez que dados já foram criados.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9370, 'Há @count entidade com @delta ou mais valores nesse campo, logo o número permitido de valores não pode ser configurado com o valor @allowed.Há @count entidades com @delta ou mais valores nesse campo, logo o número permitido de valores não pode ser configurado com o valor @allowed.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9371, 'Permite apenas plugins Composer suportados. Se você tem algum, veja <a href="#package-manager-faq-unsupported-composer-plugin">E se aparecer que tenho plugins Composer não suportados na minha base de código?</a>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9372, 'E se disser que tenho plugins Composer não suportados na minha base de código?', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9373, 'É possível <em>confiar</em> em plugins adicionais do Composer, mas isso requer expertise significativa: entender o código desse plugin Composer, os efeitos no sistema de arquivos e como isso afeta o módulo Package Manager. Alguns plugins do Composer podem resultar em um site quebrado!', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9374, 'O que fazer se aparecer <code>cweagans/composer-patches</code> não pode ser instalado/removido?', 'pt-br', 0);
