INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9377, 'E se disser que <code>cweagans/composer-patches</code>  deve ser uma dependência raiz?', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9378, 'Se <code>cweagans/composer-patches</code> estiver instalado, ele deve ser definido como uma dependência do projeto principal (ou seja, deve ser listado na seção <code>require</code> ou <code>require-dev</code> do <code>composer.json</code>). Você pode executar o seguinte comando na raiz do seu site para adicioná-lo como uma dependência do projeto principal:', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9379, 'Plugins adicionais de composer confiáveis', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9380, 'Plugin confiável do composer', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9381, 'Não é possível reivindicar o stage porque não foi criado nenhum.', 'pt-br', 0);
