INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9394, 'Não foi possível determinar a configuração <code>allow-plugins</code> do Composer.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9395, 'Todos os plugins do Composer são permitidos porque <code>config.allow-plugins</code> está configurado como <code>true</code>. Isso representa um risco de segurança inaceitável.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9396, 'j M Y - H:i', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9397, 'A migração do CKEditor 5 habilitou os seguintes plugins para suporte de tags que são permitidas pelo formato de texto %text_format: %enabling_message_content. O formato de texto deve ser salvo para ativar estas alterações.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9398, 'As seguintes tags são permitidas pela configuração do filtro do formato de texto %text_format, mas não existem plugins disponíveis para suportá-las. Para ter certeza que as tags continuam disponíveis por este formato de texto, foram adicionados aos plugins de Edição de Fonte <em>Tags HTML manualmente editáveis</em>: @unsupported_string. O formato de texto deve ser salvo para ativas estas alterações.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9399, 'O processo de migração do CKEditor 5 habilitou os seguintes plug-ins para oferecer suporte a atributos específicos permitidos pelo formato de texto %text_format: %enabled_for_attributes_message_content.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9400, 'Como parte da migração para o CKEditor 5, descobriu-se que os formatos de texto HTML %text_format incluem plugins que suportam as tags a seguir, mas não alguns de seus atributos. Para garantir que esses atributos continuem suportados, os seguintes atributos foram adicionados às <em>tags HTML editáveis manualmente</em> do plug-in de edição de código-fonte: @missing_attributes. O formato de texto deve ser salvo para ativar essas alterações.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9401, 'Como parte da migração do formato de texto %text_format para o CKEditor 5, a(s) seguinte(s) tag(s) foi(foram) adicionada(s) a <em>Limitar tags HTML permitidas e corrigir HTML defeituoso,</em> pois elas são necessárias para fornecer a funcionalidade fundamental do CKEditor 5: @missing_tags. O formato de texto deve ser salvo para tornar essas alterações ativas.', 'pt-br', 0);
