INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9426, 'Use o placeholder <code>@interval</code> para representar o intervalo de diferença de tempo formatado. Por exemplo, <code>@interval hence</code> será exibido como <em>daqui a 2 horas e 5 minutos</em>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9427, 'Use o placeholder <code>@interval</code> para representar o intervalo de diferença de tempo formatado. Por exemplo, <code>@interval ago</code> será exibido como <em>2 horas e 5 minutos atrás</em>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9428, 'Quantas unidades de tempo serão usadas na formatação da diferença de horário. Por exemplo, se ''1'' for selecionado, a diferença de tempo exibida conterá apenas uma única unidade de tempo, como ''2 anos'' ou ''5 minutos'', nunca ''2 anos e 3 meses'' ou ''5 minutos e 8 segundos''.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9429, 'Com que frequência atualizar a diferença de horário exibida. A diferença de horário é atualizada no lado do cliente, por JavaScript, sem recarregar a página.', 'pt-br', 0);
