INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9440, 'O kit de ferramentas de imagem ''@toolkit'' falhou ao processar ''@operation'' para a imagem ''@image''. Erro reportado: @class - @message', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9441, 'O plugin existe', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9442, 'O plugin ''@plugin_id'' não existe.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9443, 'O plug-in ''@plugin_id'' deve implementar ou estender @interface.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9444, 'Arquivos de ativos otimizados', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9445, 'Arquivos de ativos locais públicos otimizados servidos pelo servidor web.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9446, 'Chaves de mapeamento válidas', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9447, 'A chave ''@key'' não é suportada.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9448, 'Matrizes indexadas numericamente não são permitidas.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9449, 'Editar nome de máquina', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9450, 'O módulo Announcements exibe anúncios da comunidade Drupal. Para obter mais informações, consulte a <a href=":documentation">documentação online do módulo Announcements</a>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9451, 'Acessando anúncios', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9452, 'Exibe anúncios da comunidade Drupal.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9453, 'Veja os anúncios oficiais relacionados ao Drupal', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9454, 'Anúncios da comunidade', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9455, 'Configurações de anúncios', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9456, 'Anúncios de cache por segundos de idade máxima.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9457, 'Intervalo Cron para buscar anúncios, em segundos.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9458, 'Número de anúncios que serão exibidos.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9459, 'O formato do feed não é válido.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9460, 'Ocorreu um erro ao analisar o feed de anúncios, verifique os logs para obter mais informações.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9461, 'Não há anúncios disponíveis', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9462, 'Permite banir visitas de endereços IP específicos.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9463, 'Fornece um provedor de autenticação HTTP Basic.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9464, 'Adicionando blocos de conteúdo', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9465, 'Você pode adicionar blocos de conteúdo se o módulo <em>Block Content</em> estiver instalado. Para obter mais informações, consulte a <a href=":blockcontent-help">página de ajuda do Block Content</a>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9466, 'Permite configurar blocos (contendo conteúdo, formulários, etc.) e colocá-los nas regiões de um tema.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9503, 'Uma lista de linguagens de programação que serão fornecidas no menu suspenso "Bloco de código". Insira um valor por linha, no formato key|label. Exemplo: php|PHP.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9504, 'O número @line linha não contém um valor válido. Insira uma chave de idioma válida seguida por um símbolo de barra vertical e um rótulo.As linhas @line números não contêm um valor válido. Insira uma chave de idioma válida seguida por um símbolo de barra vertical e um rótulo.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9505, 'Permite importar e exportar alterações de configuração.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9506, 'A Moderação de conteúdo permite que você aplique <a href=":workflows">fluxos de trabalho</a> à conteúdo, blocos de conteúdo e outras <a href=":field_help" title="Field module help, with background on content entities">entidades de conteúdo</a>, para fornecer opções de publicação mais refinadas. Por exemplo, uma página Básica pode ter estados como Rascunho e Publicado, com transições permitidas, como Rascunho para Publicado (tornando a revisão atual "ativa") e Publicado para Rascunho (fazendo uma nova revisão de rascunho do conteúdo publicado).', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9507, 'Fornece estados de publicação adicionais que podem ser usados por outros módulos para moderar o conteúdo.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9508, 'O módulo de Content Translation permite traduzir conteúdo, comentários, blocos de conteúdo, termos de taxonomia, usuários e outras <a href=":field_help" title="Field module help, with background on content entities">entidades de conteúdo</a>. Juntamente com os módulos <a href=":language">Language</a>, <a href=":config-trans">Configuration Translation</a> e <a href=":locale">Interface Translation</a>, permite construir sites multilíngues. Para obter mais informações, consulte a <a href=":translation-entity">documentação on-line do módulo Content Translation</a>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9509, 'Define os tipos de campo para armazenar datas e horas.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9510, 'Quando ativado, as imagens só podem ser carregadas. Quando desabilitado, as imagens só podem ser adicionadas via URL.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9511, 'O módulo Text Editor fornece uma estrutura para gerenciar editores. Para usá-lo, você também precisa instalar um editor de texto. Pode ser o módulo do núcleo <a href=":ckeditor5">CKEditor5</a>, que pode ser instalado na página <a href=":extend">Estender</a>, ou um módulo contribuído para qualquer outro editor de texto. Ao instalar um módulo de editor de texto contribuído, certifique-se de verificar as instruções de instalação, pois você provavelmente precisará baixar uma biblioteca externa, bem como o módulo Drupal.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9512, 'Fornece uma estrutura para associar editores de texto (como WYSIWYGs) e barras de ferramentas à formatos de texto.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9514, 'Garante que as versões mais recentes das imagens carregadas por meio de um Editor de Texto sejam exibidas, juntamente com suas dimensões.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9635, 'A URL base do site, atualmente: @base_url', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9636, 'O caminho base do site, atualmente: @base_path', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9515, 'O conteúdo e a configuração do site são gerenciados usando <em>entidades</em>, que são agrupadas em <em>tipos de entidade.</em> <em>Os tipos de entidade de conteúdo</em> são os tipos de entidade para o conteúdo do site (como o conteúdo principal do site, comentários, blocos de conteúdo, termos de taxonomia e contas de usuário). <em>Os tipos de entidade de configuração</em> são usados para armazenar informações de configuração para seu site, como exibições individuais no módulo Views e configurações para seus principais tipos de conteúdo do site.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9516, 'Fornece recursos para adicionar campos a entidades.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9517, 'Depois de criar um campo, você pode usá-lo novamente em outros subtipos do mesmo tipo de entidade. Por exemplo, se você criar um campo para o tipo de conteúdo do artigo, também poderá usá-lo para o tipo de conteúdo da página, mas não poderá usá-lo para blocos de conteúdo ou termos de taxonomia. Se houver campos disponíveis para reutilização, depois de clicar em <em>Adicionar campo</em> na página <em>Gerenciar campos</em>, você verá uma lista de campos disponíveis para reutilização. Depois de selecionar um campo para reutilização, você pode definir as configurações de nível de subtipo.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9518, 'Forneça um valor pré-preenchido para o formulário de edição.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9519, 'Você precisa selecionar um tipo de campo.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9520, 'Você pode reutilizar um campo de outros subtipos do mesmo tipo de entidade. A reutilização de um campo cria outro uso do mesmo armazenamento de campo.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9521, 'Filtrar por campo ou tipo de campo', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9522, 'Usado em: @list', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9523, 'Re-usar', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9524, 'Reusar @field_name', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9525, 'Houve um problema ao reutilizar o campo %label: @message', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9526, 'Valor únicoValor único', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9527, 'Criar um novo campo', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9528, 'Fornece um tipo de campo para arquivos e define um elemento “managed_file” da API de formulário.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9529, 'Filtra o conteúdo de texto em preparação para exibição.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9530, 'Carregamento "lazy load" de imagens', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9531, 'Instrua os navegadores a carregar imagens lentamente se as dimensões forem especificadas. Usar em conjunto com ''Rastrear imagens carregadas por meio de um editor de texto'' e colocar após o filtro que adiciona as dimensões de imagem necessárias para o carregamento lento. Os resultados podem ser substituídos por <code>&lt;img loading=&quot;eager&quot;&gt;</code>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9532, 'Gera páginas de ajuda e fornece um bloco de Ajuda com ajuda no nível da página.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9533, 'O que são blocos de conteúdo?', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9534, 'Os blocos de conteúdo são blocos cujo conteúdo você pode editar. Você pode definir um ou mais <em>tipos de bloco</em> e anexar campos a cada tipo de bloco. Os blocos de conteúdo podem ser colocados da mesma forma que os blocos fornecidos por outros módulos.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9535, 'Visão geral para gerenciamento de blocos', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9536, 'O módulo <em>Block</em> permite que você coloque blocos em regiões de seus temas instalados e defina as configurações de bloco. O módulo <em>Block Content</em> permite gerenciar tipos de blocos e blocos de conteúdo. Consulte os tópicos relacionados listados abaixo para tarefas específicas.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9537, 'Criando um bloco de conteúdo', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9538, 'Crie um bloco de conteúdo que pode ser colocado posteriormente no site.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9539, 'No menu administrativo <em>Gerenciar</em>, navegue até <em>Conteúdo</em>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9540, 'Abra a guia @library_link.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9541, 'Clique em <em>Adicionar bloco de conteúdo</em>. Se você tiver mais de um tipo de bloco definido em seu site, clique no nome do tipo que deseja criar.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9542, 'Definindo um tipo de bloco', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9543, 'Defina um tipo de bloco e seus campos.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9544, 'No menu administrativo <em>Gerenciar</em>, navegue até <em>Estrutura</em> &gt; <em>@types_link</em>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9545, 'Clique em  <em>Adicionar tipo de bloco</em>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9546, 'Um comentário é um conteúdo normalmente postado por um visitante do site que fornece discussão ou comentário sobre outro conteúdo, como postagens de blog e artigos de notícias. Os comentários são um tipo de entidade de conteúdo e podem ter campos que armazenam texto, marcação HTML e outros dados. Os comentários são anexados a outras entidades de conteúdo por meio de campos de comentário. Consulte @content_structure_topic para obter mais informações sobre entidades e campos de conteúdo.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9547, 'No menu administrativo <em>Gerenciar</em>, navegue até <em>Configuração</em> &gt; <em>Região e Idioma</em> &gt; <em>@config_translation_link</em>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9548, 'Os formulários de contato pessoais e de todo o site sempre terão os campos <em>Assunto</em> e <em>Mensagem</em>. Você pode adicionar novos campos para os usuários preencherem, se desejar. Observe que, se você quiser exibir outro conteúdo em uma página de formulário, como texto ou imagens, poderá usar um bloco de conteúdo.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9549, 'Os usuários com <em>permissões de moderação de conteúdo</em> podem alterar os estados do fluxo de trabalho. Há permissões separadas para cada transição. Consulte Permissões &gt; <em>@content_moderation_permissions_link</em> para configurar permissões de moderação de conteúdo.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9550, 'Localize a entidade que você deseja moderar na página de exibição de moderação de conteúdo, se você criou uma, ou na página administrativa apropriada para gerenciar esse tipo de entidade (como a página de administração de itens de conteúdo; consulte @content_link).', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9551, 'Usuários com <em>permissões de fluxos de trabalho</em> (normalmente administradores) podem configurar fluxos de trabalho. Consulte Permissões &gt; <em>@workflows_permissions_link</em> para configurar permissões de fluxos de trabalho.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9552, 'Para implementar seu plano, no menu administrativo <em>Gerenciar</em>, navegue até <em>Configuração</em> &gt; <em>Fluxo de Trabalho</em> &gt; <em>@workflows_link</em>. Uma lista de fluxos de trabalho é mostrada, incluindo o fluxo de trabalho padrão <em>Editorial</em> que você pode adaptar.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9553, 'Em <em>Este fluxo de trabalho se aplica a:</em>, localize o tipo de entidade ao qual você deseja que esse fluxo de trabalho se aplique, como Revisões de conteúdo, Revisões de bloco de conteúdo ou Revisões de termos de taxonomia. Clique em <em>Selecionar</em>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9554, 'Siga as etapas de @user_permissions_topic para atribuir permissões para cada transição em papéis. As permissões estão listadas na seção <em>@content_moderation_permissions_link</em>. Há uma permissão para cada transição em cada fluxo de trabalho.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9750, '@project_name (@package_name) @version', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9556, 'Uma <em>entidade de conteúdo</em> (ou, mais comumente, <em>entidade</em>) é um item de dados de conteúdo, que pode consistir em texto, marcação HTML, imagens, arquivos anexados e outros dados. As entidades de conteúdo são agrupadas em <em>tipos de entidade</em>, que têm finalidades diferentes e são exibidas de maneiras muito diferentes no site. A maioria dos tipos de entidade também é dividida em <em>subtipos de entidade</em>, que são divisões dentro de um tipo de entidade para permitir variações menores na forma como as entidades são usadas e exibidas. Por exemplo, o tipo de entidade <em>de item de conteúdo</em> que armazena conteúdo no nível da página é dividido em subtipos de <em>tipo de conteúdo</em>; o tipo <em>de entidade de bloco de conteúdo</em> tem <em>tipos de bloco</em>; mas o tipo <em>de entidade Usuário</em> (para informações de perfil de usuário) não tem subtipos.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9557, 'Dependendo dos módulos do núcleo e de contribuição que você instalou em seu site, os tópicos relacionados abaixo e outros tópicos listados na página de ajuda principal (consulte @help_link) ajudarão você com tarefas relacionadas à estrutura de conteúdo.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9558, 'No menu administrativo <em>Gerenciar</em>, navegue até <em>Configuração</em> &gt; <em>Região e Idioma</em> &gt; @languages_link.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9559, 'No menu administrativo <em>Gerenciar</em>, navegue até <em>Configuração</em> &gt; <em>Região e Idioma</em> &gt; <em>Idiomas</em> &gt; @detection_link.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9560, 'No menu administrativo <em>Gerenciar</em>, navegue até <em>Configuração</em> &gt; <em>Região e Idioma</em> &gt; <em>Tradução da interface do usuário</em> &gt; @import_link.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9561, 'No menu administrativo <em>Gerenciar</em>, navegue até <em>Configuração</em> &gt; <em>Região e Idioma</em> &gt; @translate_link.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9562, 'No menu administrativo <em>Gerenciar</em>, navegue até <em>Configuração</em> &gt; <em>Região e Idioma</em> &gt; @language_link.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9563, 'Quando os usuários visitam a página de pesquisa principal (consulte @search_link), eles verão as páginas de pesquisa configuradas às quais têm acesso. Cada página de pesquisa tem um formulário de pesquisa e a página exibirá os resultados da pesquisa depois que o usuário inserir palavras-chave no formulário e clicar no botão de pesquisa.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9564, 'No menu administrativo <em>Gerenciar</em>, navegue até <em>Configuração</em> &gt; <em>&gt; Desenvolvimento</em> <em>@performance_link</em>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9565, 'No menu administrativo <em>Gerenciar</em>, navegue até <em>Configuração</em> &gt; <em>Sistema</em> &gt; <em>@information_link</em>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9566, 'No menu administrativo <em>Gerenciar</em>, navegue até <em>Configuração</em> &gt; <em>Região e Idioma</em> &gt; <em>@regional_link</em>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9567, 'No menu administrativo <em>Gerenciar</em>, navegue até <em>Configuração</em> &gt; <em>Região e Idioma</em> &gt; <em>@datetime_link</em>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9568, 'Na seção <em>Páginas de erro</em>, digite a URL das páginas 403/404, começando após a URL da página inicial do site. Por exemplo, se a URL do seu site é <em>https://example.com</em> e sua página 404 é <em>https://example.com/not-found</em>, você deve digitar <em>/not-found</em>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9569, 'No menu administrativo <em>Gerenciar</em>, navegue até <em>Configuração</em> &gt; <em>Desenvolvimento</em> &gt; <em>@log_settings_link</em>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9570, 'No menu administrativo <em>Gerenciar</em>, navegue até <em>Configuração</em> &gt; <em>Desenvolvimento</em> &gt; <em>@maintenance_link</em>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9571, 'No menu administrativo <em>Gerenciar</em>, navegue até <em>@extend_link</em>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9572, 'No menu administrativo <em>Gerenciar</em>, navegue até <em>Estender</em> &gt; <em>@uninstall_link</em>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9573, 'No menu administrativo <em>Gerenciar</em>, navegue até <em>Relatórios</em> &gt; <em>@status_link</em> para ver um relatório que resume a integridade e o status do seu site. Se houver algum aviso ou erro, você precisará corrigi-lo. Atente-se a todas próximas versões de segurança altamente críticas que podem afetar seu site.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9574, 'No menu administrativo <em>Gerenciar</em>, navegue até <em>@themes_link</em>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9575, 'Clique no link <em>Desinstalar</em> para desinstalar o tema. Se não houver um link <em>Desinstalar</em>, o tema não poderá ser desinstalado porque está sendo usado como o tema padrão do site, usado como o <em>tema Administração</em> ou é o tema base para outro tema instalado.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9576, 'Os campos de referência de taxonomia podem ser adicionados a qualquer entidade, como contas de usuário, blocos de conteúdo ou itens de conteúdo regulares. Se você usá-los para classificar itens de conteúdo regulares, seu site será configurado automaticamente com páginas de listagem de taxonomia para cada termo. Cada uma dessas páginas lista todos os itens de conteúdo classificados com esse termo.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9577, 'No menu administrativo <em>Gerenciar</em>, navegue até <em>@people_link</em>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9578, 'No menu administrativo <em>Gerenciar</em>, navegue até <em>Pessoas</em> &gt; <em>@roles_link</em>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9579, 'No menu administrativo <em>Gerenciar</em>, navegue até <em>Pessoas</em> &gt; <em>@permissions_link</em>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9580, 'No menu administrativo <em>Gerenciar</em>, navegue até <em>Configuração</em> &gt; <em>Pessoas</em> <em>&gt; @account_settings_link</em>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9581, 'Views que usam um formato de exibição de tabela podem incluir um formulário de operações em massa, que permite que os usuários com permissão suficiente selecionem um ou mais itens da view e apliquem uma ação administrativa a eles. As ações em massa disponíveis são específicas para o tipo de dados base da view; por exemplo, uma view de itens de conteúdo pode dar suporte a ações de publicação e cancelamento de publicação em massa. Se você tiver o módulo Actions UI do núcleo instalado, consulte o tópico relacionado "Configurando ações" para obter mais informações sobre ações.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9582, 'Se você ainda não estiver editando sua exibição, no menu administrativo <em>Gerenciar</em>, navegue até <em>Estrutura</em> <em>&gt; @views_link</em>. Localize a vista que você deseja editar e clique no link <em>Editar</em>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9583, 'Adicione uma ou mais ações existentes como operações em massa em uma view de estilo de tabela existente. Se você tiver o módulo Actions UI do núcleo instalado, consulte o tópico relacionado "Configurando ações" para obter mais informações sobre ações.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9584, 'No menu administrativo <em>Gerenciar</em>, navegue até <em>Estrutura</em> &gt; <em>@views_link</em>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9585, 'Registra qual conteúdo os usuários visualizaram e o marca como novo ou atualizado.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9586, 'O Construtor de layout permite que você use layouts para personalizar como o conteúdo, os blocos de conteúdo e outras <a href=":field_help" title="Field module help, with background on content entities">entidades de conteúdo</a> são exibidas.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9594, 'Renderização lenta oEmbed com atributo de carregamento nativo (<em>loading="lazy"</em>). Isso melhora o desempenho, permitindo que os navegadores carreguem ativos lentamente.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9595, 'Atributo de carregamento oEmbed', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9596, 'Selecione o atributo de carregamento para oEmbed. <a href=":link">Saiba mais sobre o atributo de carregamento para oEmbed.</a>', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9597, 'Atrasa o carregamento do recurso até que essa seção da página fique visível no navegador. Em caso de dúvida, recomenda-se o carregamento lento.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9598, 'Forçar os navegadores a baixar um recurso o mais rápido possível. Este é o padrão do navegador por motivos herdados. Use essa opção somente quando o recurso sempre for renderizado.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9599, 'Carregando atributo: @attribute', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9600, 'O conteúdo desse tipo pode ser colocado nos menus selecionados.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9601, 'Fornece uma interface de usuário para gerenciar menus.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9602, 'Fornece uma estrutura para migrar dados para o Drupal.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9603, 'Fornece uma estrutura para migrar dados de versões anteriores do Drupal para o site.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9604, 'Isto não é suportado pelo Drupal.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9605, 'O nível recomendado para o Drupal é "READ COMMITTED".', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9606, 'Para que isso funcione corretamente, todas as tabelas devem ter uma chave primária. A(s) seguinte(s) tabela(s) não têm uma chave primária: @tables.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9607, 'Consulte a página <a href=":performance_doc">de configuração do nível de isolamento de transação do MySQL</a> para obter mais informações.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9608, 'Nível de isolamento da transação', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9609, 'Fornece o driver de banco de dados MySQL.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (11793, 'LEITURA REPETÍVEL', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9611, 'Usar banco de dados padrão', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9612, 'O nível de transação de banco de dados recomendado para o Drupal é "READ COMMITTED". Para obter mais informações, consulte a página <a href=":performance_doc">de configuração do nível de isolamento de transação do MySQL</a> .', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9613, 'Gerencia a criação, configuração e exibição do conteúdo principal do site.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9614, 'Define tipos de campo com listas de seleção, caixas de seleção e botões de opção para selecionar valores de listas fixas de opções.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9615, 'Permite que os usuários criem URLs personalizados para caminhos existentes no site.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9616, 'Fornece o driver de banco de dados PostgreSQL.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9617, 'Compatibilidade de Senha', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9618, 'O grupo de pontos de interrupção normalmente precisa apenas de um único ponto de interrupção com uma consulta de mídia vazia para fazer o <em>dimensionamento da visualização</em>. Vários pontos de interrupção são usados para alterar o corte ou a proporção de imagens em diferentes tamanhos de janela de visualização, o que geralmente é chamado de <em>direção de arte</em>. Um novo grupo de pontos de interrupção deve ser criado para cada taxa de proporção para evitar a mudança de conteúdo. Depois de selecionar um grupo de pontos de interrupção, você pode escolher quais pontos de interrupção usar para o estilo de imagem responsivo. Por padrão, a opção <em>não usar este ponto de interrupção</em> é selecionada para cada ponto de interrupção. Consulte a <a href=":breakpoint_help">página de ajuda do módulo Breakpoint</a> para obter mais informações.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9619, 'Embora você tenha a opção de fornecer apenas um estilo de imagem por ponto de interrupção, o atributo tamanhos permite que você forneça mais opções aos navegadores sobre qual arquivo de imagem ele pode exibir. Se estiver usando o campo de tamanhos e a direção de arte, todos os estilos de imagem selecionados devem usar a mesma proporção para evitar a mudança de conteúdo. Os pontos de interrupção são definidos nos arquivos de configuração do tema.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9620, 'O atributo sizes emparelhado com o atributo srcset fornece informações sobre quanto espaço essas imagens ocupam na janela de visualização em diferentes pontos de interrupção do navegador, mas as taxas de proporção devem permanecer as mesmas nesses pontos de interrupção. Uma vez selecionada a opção de tamanhos, você pode informar ao navegador o tamanho dessa imagem em relação ao layout do site, usando o campo <em>Tamanhos</em>. Para uma imagem principal que sempre preenche a tela inteira, você pode simplesmente inserir 100vw, o que significa 100% da largura da tela. Para uma imagem que preenche 90% da tela para telas pequenas, mas preenche apenas 40% da tela quando a ponto de visualização é maior que 40em (normalmente 640px), você pode inserir "(min-width: 40em) 40vw, 90vw" no campo Tamanhos. O último item na lista separada por vírgulas é o menor tamanho da janela de visualização: outros itens na lista separada por vírgulas devem ter uma condição de mídia emparelhada com uma largura de imagem. <em>As condições de mídia</em> são semelhantes a uma consulta de mídia, geralmente uma largura mínima emparelhada com uma largura de janela de visualização usando unidades em ou px: por exemplo, (largura mínima: 640px) ou (largura mínima: 40em). Isso é emparelhado com a <em>largura da imagem</em> nesse tamanho de janela de visualização usando unidades px, em ou vw. A unidade vw é a largura da janela de visualização e é usada em vez de uma porcentagem porque a porcentagem sempre se refere à largura de toda a janela de visualização.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9621, 'Fornece a funcionalidade de gerar imagens responsivas usando a tag HTML5 de imagem.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9622, 'Selecione o estilo de imagem que deseja usar como estilo quando um navegador não oferecer suporte a imagens responsivas.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9623, 'Imagens de renderização lenta com atributo de carregamento de imagem nativo (<em>loading="lazy"</em>). Isso melhora o desempenho, permitindo que os navegadores carreguem imagens lentamente. Consulte <a href="@url">Carregamento lento</a>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9624, 'Lazy', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9625, 'Ansioso', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9626, 'Atributo de carregamento lento', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9627, 'Selecione o atributo de carregamento lento para imagens. <a href=":link">Saiba Mais.</a>', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9628, 'Para usar o REST em um site, você precisa instalar módulos que forneçam serviços de serialização e autenticação. Você pode usar o módulo do núcleo <a href=":serialization">serialization</a> para serialização e a <a href=":basic_auth">HTTP Basic Authentication</a> para autenticação ou instalar um módulo contribuído ou personalizado.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9629, 'Fornece uma estrutura para expor recursos REST.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9630, 'Permite a descoberta e a renderização de componentes de interface do usuário independentes.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (55, 'Todos os componentes', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9631, 'Fornece um serviço para converter dados de e para formatos como JSON e XML.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9632, 'Permite que os usuários criem conjuntos de atalhos dentro do site.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9638, 'Extensões obsoletas encontradas: %extensions. Extensões obsoletas são fornecidas apenas para que possam ser desinstaladas de forma limpa. Você deve <a href=":uninstall_url">desinstalar imediatamente essas extensões</a> pois elas podem ser removidas em uma versão futura.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9639, 'Cache disponível de PHP APCu', 'pt-br', 0);
