INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9641, 'O APCu está usando mais de 75% de sua memória alocada (@apcu_actual_size). Para melhorar o desempenho do APCu, considere aumentar esse limite.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9642, 'Atributo de cookie SameSite', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9643, 'Esse atributo deve ser definido explicitamente como Lax, Strict ou None. Se definido como None, a solicitação deverá ser feita via HTTPS. Veja <a href=":url" target="_blank">a documentação do PHP</a>', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9644, 'Fornece interfaces de usuário para sistemas do núcleo.', 'pt-br', 0);
