INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9650, 'Use este utilitário para atualizar seu banco de dados sempre que um módulo, tema ou software principal for atualizado.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9651, 'Atualize seus arquivos (conforme descrito na página do manual vinculada acima).', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9652, 'Caminho otimizado do sistema de arquivos de ativos', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9653, 'Um caminho do sistema de arquivos local em que os arquivos de ativos otimizados serão armazenados. Este diretório deve existir e ser gravável pelo Drupal. Esse diretório deve ser relativo ao diretório de instalação do Drupal e ser acessível pela web. Isso deve ser alterado em settings.php', 'pt-br', 0);
