INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9655, '<strong class="error">Configure o <a href=":file-system">caminho do sistema de arquivos de elementos otimizados</a> para disponibilizar essas otimizações.</strong>', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9656, 'Especifique uma URL relativa a ser exibida como primeira página.', 'pt-br', 0);
