INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9661, 'A ID bruta do vocabulário.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9662, 'Define tipos de campo para texto curto e longo com resumos opcionais.', 'pt-br', 0);
