INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9668, 'Revise regularmente as <a href=":updates">atualizações disponíveis</a> e atualize conforme necessário para manter um site seguro e atual. Sempre execute o <a href=":update-php">script de atualização</a> sempre que atualizar o software.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9669, 'As permissões permitem controlar o que os usuários podem fazer e ver em seu site. Você pode definir um conjunto específico de permissões para cada papel. (Consulte a página <a href=":role">Papéis</a> para criar uma função.) Todas as permissões concedidas ao papel de usuário Autenticado serão concedidas a qualquer usuário que esteja conectado ao seu site. Na página <a href=":settings">Configurações de papel</a>, você pode transformar qualquer papel em um papel de administrador para o site, o que significa que esse papel receberá todas as permissões. Você deve ter cuidado para garantir que apenas usuários confiáveis tenham esse acesso e nível de controle do seu site.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9670, 'Permite que os usuários se registrem e façam login e gerencia funções e permissões de usuário.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9672, 'Fornece uma estrutura para buscar informações do banco de dados e exibi-las em diferentes formatos.', 'pt-br', 0);
