INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9687, 'O que são os anúncios do Drupal?', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9688, 'Um feed de anúncios sobre o projeto Drupal e os programas da Drupal Association.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9689, 'O objetivo desse feed é fornecer um canal de divulgação diretamente para os proprietários de sites do Drupal. Este conteúdo deve ser altamente relevante para os interesses dos proprietários do site, servir os objetivos estratégicos do projeto e/ou promover a sustentabilidade do projeto e da Drupal Association.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9690, 'O módulo obtém seu conteúdo de um feed JSON gerado <a href="https://www.drupal.org/about/announcements">a partir daqui</a>. A política de governança para o conteúdo está documentada <a href="https://www.drupal.org/node/3274085">aqui</a>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9691, 'Como eu posso ver os anúncions em meu site?', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9692, 'Se você tiver o módulo toolbar ativado, verá um link direto para eles na barra de ferramentas. Se o módulo toolbar não estiver habilitado, o conteúdo sempre poderá ser acessado na página <em>@actions_link</em>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9693, 'Quem pode ver os anúncios?', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9694, 'Os usuários com a permissão <em>@permissions_link</em> podem visualizar os anúncios do Drupal.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9695, 'Visão geral do módulo Announcement', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9696, 'Modo de desenvolvimento do Twig', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9697, 'As configurações do modo de desenvolvimento do Twig estão ativadas. Vá para @link para desativá-los.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9698, 'Cache de marcação desabilitado', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9699, 'O cache de renderização, o cache de página dinâmica e o cache de página são ignorados. Vá para @link para habilitá-los.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9700, 'Definir configurações de desenvolvimento de tema', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9701, 'Essas configurações só devem ser habilitadas em ambientes de desenvolvimento e nunca em produção.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9702, 'Expõe as configurações de desenvolvimento do Twig.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9703, 'Fornece a função <code>dump()</code> do Twig para depuração, gera sugestões de modelos para comentários HTML e recompila automaticamente os templates do Twig após as alterações.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9704, 'Desabilitar Twig cache', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9705, 'Os templates Twig não são armazenados em cache e são sempre compilados quando renderizados.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9706, 'Não fazer cache de marcação', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9707, 'Desabilita o cache de renderização, o cache de página dinâmica e o cache de página.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9708, 'O arquivo <code>composer.json</code> do seu site Drupal deve ser válido de acordo com <code>composer validate</code>. Veja a <a href=":url">Documentação do Composer</a> para mais informações.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9709, 'O Composer deve ser configurado para downloads seguros. Isso significa que <a href=":disable-tls">a opção <code>disable-tls</code></a> deve ser <code>false</code>, e <a href=":secure-http">a opção <code>secure-http</code></a> deve ser <code>true</code> na seção <code>config</code> do seu arquivo <code>composer.json</code>. Se essas opções não estiverem definidas no seu <code>composer.json</code>, o Composer se comportará de forma segura por padrão. Para definir esses valores na linha de comando, execute os seguintes comandos:', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9710, 'Para obter mais informações, consulte a <a href=":url">documentação on-line do módulo Package Manager</a>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9711, 'Perguntas frequentes relacionadas ao Composer', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9712, 'E se disser que a função <code>proc_open()</code> está desabilitada na sua instalação do PHP?', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9713, 'Peça ao administrador do sistema para remover <code>proc_open()</code> da configuração <a href=":url">disable_functions</a> no <code>php.ini</code>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9714, 'E se disser que o executável <code>composer</code> não pode ser encontrado?', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9715, 'E se disser que a versão detectada do Composer não é suportada?', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9716, 'E se disser que o comando <code>composer validate</code> falhou?', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9717, 'O Composer detectou problemas com seus arquivos <code>composer.json</code> e/ou <code>composer.lock</code>, e o projeto não está em um estado completamente válido. Veja a <a href=":url">documentação do Composer</a> para mais informações.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9718, 'Usando rsync', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9719, 'Habilitando a proteção PHP-TUF', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9720, 'O Package Manager requer o <a href=":php-tuf">PHP-TUF</a>, que implementa o <a href=":tuf">Update Framework</a> como uma forma de ajudar a proteger os downloads de pacotes do Composer por meio do <a href=":php-tuf-plugin">plugin de integração do Composer PHP-TUF</a>. Este plugin deve ser instalado e configurado corretamente para usar o Package Manager.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9721, 'Para instalar e configurar o plugin conforme necessário, você pode executar os seguintes comandos:', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9722, 'A instalação ou remoção do <code>cweagans/composer-patches</code> via Package Manager não é suportada. Você pode instalá-lo ou removê-lo manualmente executando comandos do Composer na raiz do seu site.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9723, 'composer.lock não encontrado em @dir.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9724, 'A versão detectada do Composer, @version, não satisfaz <code>@constraint</code>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9725, 'Nenhum pacote que não seja os pacotes implicitamente permitidos tem permissão para fazer scaffold de arquivos. Veja <a href=":url">a documentação do scaffold</a> para mais informações.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9726, '<code>@name</code>', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9727, '<code>@name</code> é suportado, mas apenas a versão <code>@supported_version</code>, encontrada <code>@installed_version</code>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9728, 'O Composer não pode ser usado porque a função <code>proc_open()</code> está desabilitada.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9729, 'Não é possível determinar a configuração <code>@key</code> do Composer.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9730, 'O TLS deve estar habilitado para downloads do HTTPS Composer.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9731, '@message Consulte <a href=":url">a página de ajuda</a> para obter mais informações sobre como configurar o Composer para baixar pacotes com segurança.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9732, '@message Veja <a href=":url">a documentação do Composer</a> para mais informações.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9733, 'Você também deve verificar o valor de <code>secure-http</code> e certificar-se que ele esteja definido como <code>verdadeiro</code> ou não esteja definido.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9734, 'O HTTPS deve estar habilitado para downloads do Composer.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9735, 'As configurações do compositor não atendem aos requisitos do Gerenciador de Pacotes.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9736, '''@name'' @type (fornecido por <code>@package</code>)', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9737, 'A atualização não pode prosseguir porque a seguinte extensão habilitada do Drupal foi removida durante a atualização.A atualização não pode prosseguir porque as seguintes extensões habilitadas do Drupal foram removidas durante a atualização.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9738, '<a href=":url">@message</a>', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9739, 'Problema detectado no arquivo de bloqueio durante operações de stage.Problemas detectados no arquivo de bloqueio durante operações de stage.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9740, 'A extensão OpenSSL não está habilitada, o que é um risco de segurança. Veja a <a href=":url">documentação do PHP</a> para informações sobre como habilitar esta extensão.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9741, 'O diretório ativo não é protegido pelo PHP-TUF, que é necessário para usar o Gerenciador de Pacotes com segurança.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9742, 'O diretório de stage não está protegido pelo PHP-TUF, o que é necessário para usar o  Package Manager de forma segura.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9743, 'O plugin <code>@plugin</code> não está instalado.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9744, '@message Veja a <a href=":url">página de ajuda</a> para mais informações sobre como instalar o plugin.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9745, 'O plugin <code>@plugin</code> não está listado como um plugin permitido.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9746, '@message Veja <a href=":url">a página de ajuda</a> para mais informações sobre como configurar o plugin.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9747, '@message Veja <a href=":url">a página de ajuda</a> para mais informações sobre como configurar este repositório.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9748, '@message Veja a <a href=":url">ajuda do Package Manager</a> para mais informações sobre como resolver isso.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9751, 'O módulo Password Compatibility fornece o algoritmo de verificação de senha para contas de usuário criadas com o Drupal antes da versão 10.1.0. Para obter mais informações, consulte a <a href=":phpass">documentação online do módulo Password Compatibility</a>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9752, 'O Drupal 10.1.0 e versões posteriores usam um algoritmo diferente para calcular a senha com hash. Isso fornece melhor segurança contra ataques de força bruta. As senhas com hash são diferentes daquelas calculadas com as versões do Drupal anteriores à 10.1.0.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9753, 'Quando o módulo Password Compatibility é instalado, um usuário pode efetuar login com um nome de usuário e senha criados antes do Drupal 10.1.0. Na primeira vez que essas credenciais são usadas, um novo hash é calculado e salvo. A partir de então, o usuário poderá fazer login com o mesmo nome de usuário e senha, independentemente de este módulo estar instalado ou não.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9754, 'As senhas criadas antes do Drupal 10.1.0 <strong>não funcionarão</strong> a menos que sejam usadas pelo menos uma vez enquanto este módulo estiver instalado. Certifique-se de que você pode fazer login antes de desinstalar este módulo.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9755, 'Certifique-se de que você pode fazer login antes de desinstalar o módulo Password Compatibility. Para obter mais informações, consulte a <a href=":phpass">documentação online do módulo Password Compatibility</a>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9756, 'Fornece o algoritmo de verificação de senha para contas de usuário criadas com o Drupal antes da versão 10.1.0.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9757, '* (qualquer versão)', 'pt-br', 0);
