INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9764, 'Os usuários com a permissão "Exibir anúncios do drupal.org" podem clicar no item "Anúncios" na barra de ferramentas de administração ou acessar @link para ver todos os anúncios relevantes para a versão Drupal do seu site.', 'pt-br', 0);
