INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9769, 'Uma nova instalação do Drupal apenas utiliza plugins suportados pelo Composer, mas alguns módulos ou temas podem depender de plugins adicionais do Composer. <a href=":new-issue">Crie uma nova questão</a> quando encontrar isso.', 'pt-br', 0);
