INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9772, 'O Composer não foi encontrado. A mensagem de erro foi: @message', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9773, 'O arquivo de bloqueio ativo (@file) não existe.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9774, 'Alterações inesperadas foram detectadas no arquivo de bloqueio ativo (@file), o que indica que outras operações do Composer foram realizadas desde que esta operação do Package Manager começou. Isso pode colocar a base de código em um estado não confiável e, portanto, não é permitido.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9775, 'Parece não haver operações pendentes do Composer porque o arquivo de bloqueio ativo (@active_file) e o arquivo de bloqueio em stage (@staged_file) são idênticos.', 'pt-br', 0);
