INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9801, 'A lista de idiomas no menu suspenso "Idioma" do CKEditor pode apresentar os <a href=":united-nations-official">@count_united_nations idiomas oficiais da ONU</a>, todos os @count_predefined idiomas predefinidos no Drupal ou os <a href=":admin-configure-languages">@count_configured idiomas configurados para este site</a>.', 'pt-br', 0);
