INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9824, 'Essas configurações se aplicam apenas a novos arquivos à medida que são carregados. As alterações aqui não afetam os nomes de arquivo existentes.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9825, 'Traço (-)', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9826, 'Usado ao substituir espaços em branco, substituir caracteres não alfanuméricos ou transliterar caracteres desconhecidos.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9827, 'A transliteração substitui todos os caracteres que não sejam alfanuméricos, sublinhados, pontos ou hífens pelo caractere de substituição. Ela garante que os nomes de arquivo contenham apenas caracteres ASCII. Recomenda-se manter a transliteração ativada.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9828, 'Substitui espaço em branco pelo caractere de substituição', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9829, 'Substitui caracteres não alfanuméricos pelo caractere de substituição', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9830, 'Caracteres alfanuméricos, pontos <span aria-hidden="true">(.)</span>, sublinhados <span aria-hidden="true">(_)</span> e traços <span aria-hidden="true">(-)</span> são preservados.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9831, 'Substitui sequências de pontos, sublinhados e/ou traços pelo caractere de substituição', 'pt-br', 0);
