INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9842, 'O módulo Help gera <a href=":help-page">tópicos de ajuda e páginas de referência</a> para guiá-lo pelo uso e configuração de módulos e fornece um bloco de ajuda com ajuda no nível da página. As páginas de referência são um ponto de partida para <a href=":handbook">documentação online</a> no Drupal.org que contém informações mais extensas e atualizadas, são anotadas com comentários contribuídos pelos usuários e servem como o ponto de referência definitivo para toda a documentação do Drupal. Para obter mais informações, consulte a <a href=":help">documentação on-line do módulo Help</a>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9843, 'Módulos e temas podem fornecer tópicos de ajuda como plug-ins baseados em arquivos Twig em um subdiretório do projeto chamado <em>help_topics</em>; os metadados do plug-in são fornecidos via sintaxe YAML em cada arquivo Twig. Os tópicos de ajuda baseados em plug-ins fornecidos por módulos e temas serão atualizados automaticamente quando um módulo ou tema for atualizado. Use os plug-ins em <em>core/modules/help/help_topics</em> como um guia ao escrever e formatar um plug-in de tópico de ajuda para seu tema ou módulo.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9844, 'Usar páginas de ajuda', 'pt-br', 0);
