INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9853, '<a href="https://www.drupal.org/docs/user_guide/en/security-cron-concept.html">Conceito: Cron (Guia do Usuário do Drupal)</a>', 'pt-br', 0);
