INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9856, '<a href="https://www.drupal.org/docs/user_guide/en/extend-chapter.html">Estendendo e Personalizando seu Site (Guia do Usuário do Drupal)</a>', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9857, 'Ao realizar manutenção, como instalar, desinstalar ou atualizar um módulo, coloque seu site no modo de manutenção.', 'pt-br', 0);
