INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9860, '<a href="https://www.drupal.org/docs/user_guide/en/menu-concept.html">Conceito: Menu (Guia do Usuário do Drupal)</a>', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9861, 'Os seguintes módulos do núcleo e mecanismos podem melhorar o desempenho do seu site:', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9862, 'Os seguintes componentes de interface administrativa são fornecidos pelo software principal e seus módulos (alguns módulos contribuídos oferecem funcionalidade adicional):', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9863, 'Os seguintes módulos do núcleo fornecem web services:', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9864, 'Fornece uma maneira para web services serem autenticados usando a autenticação HTTP Basic em contas de usuário do site.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9865, 'No menu administrativo <em>Gerenciar</em>, navegue até <em>@extend_link</em>. Verifique se os módulos Search, Help e Block estão instalados (ou instale-os se ainda não estiverem instalados).', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9866, 'Trabalhando com tópicos de ajuda', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9874, 'O título e o corpo do texto dos tópicos de ajuda fornecidos pelos módulos e temas contribuídos podem ser traduzidos usando @translate_link (fornecido pelo módulo Interface Translation). Os tópicos fornecidos por módulos e temas personalizados também podem ser traduzidos se tiverem sido visualizados pelo menos uma vez em um idioma diferente do inglês, o que aciona a colocação de seu texto traduzível no banco de dados de tradução.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9875, 'Como os usuários podem pesquisar tópicos de ajuda?', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9876, 'Para permitir que os usuários pesquisem ajuda, incluindo tópicos de ajuda, você precisará instalar o módulo Search do núcleo, configurar uma página de pesquisa e adicionar um bloco de pesquisa à página de Ajuda ou a outra página administrativa. (Uma página de pesquisa é fornecida automaticamente e, se você usar o tema administrativo Claro, um bloco de pesquisa de ajuda será mostrado na página principal da Ajuda.) Em seguida, os usuários com permissões de pesquisa e permissão para exibir a ajuda poderão pesquisar ajuda. Consulte o tópico relacionado, @help_search_topic, para obter instruções passo a passo.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9877, 'Tópicos de Ajuda Padrão', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9878, 'Campo para referenciar mídia. Permite o carregamento e seleção de mídia carregada.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9879, 'O nome legível para esse tipo de mídia, exibido na página <em>Tipos de mídia</em>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9880, 'Exibido na página <em>Tipos de mídia</em>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9881, 'No momento, há @total item selecionado. O número máximo de itens para o campo é @max. Remova @count item da seleção.No momento, há @total itens selecionados. O número máximo de itens para o campo é @max. Remova @count itens da seleção.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9882, 'Não há tipos de mídia permitidos configurados para este campo. Entre em contato com o administrador do site.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9883, 'Fornece migração de dados de versões mais antigas do núcleo para um novo site.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9884, 'Fornece uma interface de usuário para executar a migração de dados de versões mais antigas do núcleo para um novo site.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9885, 'Se a fonte dos dados que você deseja migrar for um sistema de gerenciamento de conteúdo diferente ou se a fonte de dados for um site que foi criado usando módulos contribuídos que os módulos principais de migração não suportam, você também precisará de um ou mais módulos contribuídos ou personalizados para migrar seus dados.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9886, '@migration_id de migração: ID de origem @source_id: @message', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9887, 'O status de publicação do node ("Publicado" ou "Não Publicado").', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9888, 'Gerenciamento Básico de Páginas (Guia do Usuário do Drupal)', 'pt-br', 0);
