INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9893, 'O nome legível para esse tipo de conteúdo, exibido na página <em>Tipos de conteúdo</em>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9894, 'Exibido na página <em>Tipos de conteúdo</em>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9895, '@language_name revisões para %title', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9896, 'A data e hora que o conteúdo foi criado.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9897, 'O nome será usado nas opções exibidas e nos formulários de edição. O valor é o valor armazenado e deve ser numérico.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9898, 'Não pode ser removido: opção em uso.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9899, 'Adicionando um novo item...', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9900, 'O nome será usado nas opções exibidas e nos formulários de edição.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9901, 'O valor nome da máquina é gerado automaticamente do nome fornecido e será o valor armazenado.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9902, 'Conceito: Caminhos, Apelidos e URLs (Guia do Usuário do Drupal)', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9903, 'Número de itens a serem indexados por execução', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9904, 'O número máximo de itens processados por execução de indexação. Se necessário, reduza o número de itens para evitar timeouts e erros de memória durante a indexação. Alguns tipos de página de pesquisa podem ter sua própria configuração para isso.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9905, 'Alterar essas configurações fará com que o índice de pesquisa padrão seja recriado para refletir as novas configurações. A pesquisa continuará funcionando com base no índice existente, mas o novo conteúdo não será indexado até que todo o conteúdo existente tenha sido reindexado.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9906, 'Digite algumas palavras-chave.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9907, 'Certifique-se de que o módulo Shortcut esteja instalado e que você tenha um papel com a permissão <em>Editar conjunto de atalhos atual</em> ou <em>Administrar atalhos</em>. Além disso, certifique-se de que um módulo da barra de ferramentas esteja instalado (o módulo Toolbar do núcleo ou um módulo contribuído substituto).', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9908, 'Buffer de Saída', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9909, '<a href="https://www.php.net/manual/en/function.ob-start.php">O buffer de saída</a> não está habilitado. Isso pode degradar o desempenho do Drupal. Você pode habilitar o buffer de saída padrão <a href="https://www.php.net/manual/en/outcontrol.configuration.php#ini.output-buffering">nas configurações do PHP</a>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9910, 'A conversão de entrada de string multibyte no PHP está ativa e deve ser desabilitada. Verifique a configuração <em>mbstring.encoding_translation php.ini</em> . Consulte a <a href="http://php.net/mbstring">documentação do PHP mbstring</a> para obter mais informações.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9911, 'Symfony mailer transport DSN', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9912, '<a href="https://www.drupal.org/docs/user_guide/en/prevent-cache.html">Conceito: Cache (Guia do Usuário do Drupal)</a>', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9913, '<a href="https://www.drupal.org/docs/user_guide/en/security-chapter.html">Segurança e Manutenção (Guia do Usuário do Drupal),</a> que inclui informações sobre como atualizar o núcleo, módulos e temas do seu site.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9914, 'Autentique-se para acessar esta página.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9915, 'Observe que o tema de administração ainda está definido como o tema %admin_theme; consequentemente, o tema nesta página permanece inalterado. Todas as seções não administrativas do site, no entanto, mostrarão o tema %selected_theme selecionado por padrão.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9916, 'Os módulos selecionados não puderam ser desinstalados, seja devido a um problema no site ou devido ao tempo limite do formulário de confirmação de desinstalação.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9917, 'Successo (@status_code)', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9918, 'Accesso negado (@status_code)', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9919, 'Página não encontrada (@status_code)', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9920, 'Mostra o bloco em páginas com qualquer status de resposta correspondente. Se nada for marcado, o bloco será mostrado em todas as páginas. Outros status de resposta não são usados.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9921, 'O código de resposta da solicitação não é: @codesO código de resposta da solicitação não é: @codes', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9922, 'O código de resposta da solicitação é: @codesO código de resposta da solicitação é: @codes', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9923, 'Cria um novo objeto transparente e o define para a imagem.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9924, 'Configurando uma Taxonomia (Guia do Usuário do Drupal)', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9925, 'Conceito: Taxonomia (Guia do Usuário do Drupal)', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9926, 'Um vocabulário inválido está selecionado. Altere-o nas opções.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9927, 'Este campo armazena um número de telefone.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9928, 'Outro usuário (%other_user) já está conectado ao site neste computador mas você tentou usar um link único para o usuário %resetting_user. <a href=":logout">Saia</a> e tente usar o link novamente.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9929, 'Você tentou usar um link de login único que expirou. Solicite um novo usando o formulário abaixo.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9930, 'Você tentou usar um link de login único que foi usado ou não é mais válido. Solicite um novo usando o formulário abaixo.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9931, 'Você tentou usar um link de cancelamento de conta que expirou. Solicite um novo usando o formulário abaixo.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9932, 'Filtrar pelo nome da permissão', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9933, '<a href="https://www.drupal.org/docs/user_guide/en/views-chapter.html">Criando listagens com Views (Guia do Usuário do Drupal)</a>', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9934, '%current_display: The link in the %area area points to the %linked_display display which uses different settings than the %current_display display for: %unequal_options. To make sure users see the exact same result when clicking the link, check that the settings are the same.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9935, 'Espaços reservados numéricos não podem ser usados. Use espaços reservados simples (%).', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9936, 'Se marcado, vários valores para este campo serão mostrados na mesma linha. Se não estiver marcado, cada valor neste campo criará uma nova linha. Se estiver usando agrupar por, certifique-se de agrupar por "ID da entidade" para que essa configuração tenha algum efeito.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9937, 'Isso aparecerá na URL após o ? para identificar esse filtro. Não pode ficar em branco. Somente letras, dígitos e os caracteres de ponto ("."), hífen ("-"), sublinhado ("_") e til ("~") são permitidos. @reserved_identifiers são palavras reservadas e não podem ser usadas.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9938, 'Expressão regular negada', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9939, 'Hero tiny', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9940, 'Hero medium', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9941, 'Hero large', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9942, 'Hero wide', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9943, 'Escala crop 7:3 médio', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9944, 'Escala crop 7:3 pequeno', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9945, 'Escala crop 7:3 minúsculo', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9946, 'Escala crop 7:3 larga', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9947, 'Sark', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9948, 'Türkiye', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9949, 'O CKEditor 5 deve ser instalado e configurado separadamente para formatos de texto individuais na página <a href=":formats">Formatos e editores de texto</a> porque as configurações de filtro para cada formato de texto podem ser diferentes. Para obter mais informações, consulte a <a href=":text_editor">página de ajuda do Editor de Texto</a> e a <a href=":filter">página de ajuda do Filtro</a>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9950, 'A tag <code>@tag</code> ainda não é suportada pelo plug-in Style.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9951, 'A funcionalidade de comentário pode ser habilitada para qualquer subtipo de entidade (por exemplo, um <a href=":content-type">tipo de conteúdo</a>) adicionando um campo <em>Comentários</em> em sua página <em>Gerenciar campos</em>. Adicionar ou remover comentários para uma entidade por meio da interface do usuário requer que o módulo <a href=":field_ui">Field UI</a> seja instalado, mesmo que a funcionalidade de comentários funcione sem ele. Para obter mais informações sobre campos e entidades, consulte a <a href=":field">página de ajuda do módulo Field</a>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9952, 'As configurações de comentários podem ser definidas editando o campo <em>Comentários</em> na <em>página Gerenciar campos</em> de um tipo de entidade, se o <em>módulo Field UI</em> estiver instalado. A configuração inclui o rótulo do campo de comentários, o número de comentários a serem exibidos e se eles são mostrados na lista encadeada. Os comentários podem ser configurados como: <em>Aberto</em> para permitir novos comentários, <em>Fechado</em> para exibir comentários existentes, mas impedir novos comentários ou <em>Oculto</em> para ocultar comentários existentes e impedir novos comentários. Alterar essa configuração para um tipo de entidade não alterará os itens de entidade existentes.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9953, 'Se você tiver o <a href=":toolbar">módulo Toolbar</a> instalado, clicar no botão de links contextuais na barra de ferramentas (que se parece com um lápis) tornará visíveis todos os botões de links contextuais na página. Clicar neste botão novamente irá alterná-los para invisíveis.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9954, 'O módulo Field fornece a infraestrutura para campos; os tipos de campo, formatadores e widgets são fornecidos pelo núcleo do Drupal ou módulos adicionais. Alguns dos módulos são necessários; os módulos opcionais podem ser instalados na página de administração <a href=":modules">Estender</a>. Campos, formatadores e widgets adicionais podem ser fornecidos pelos módulos contribuídos, que você pode encontrar na seção de <a href=":contrib">módulos contribuídos do Drupal.org</a>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9955, 'Aqui está uma lista dos módulos de campo, formatador e widget instalados no momento:', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9976, 'Se você tiver o módulo Block instalado, cada menu criado será renderizado em um bloco que você habilita e posiciona na <a href=":blocks">página Layout do bloco</a>. Em alguns <a href=":themes">temas</a>, o menu principal e possivelmente o menu secundário serão emitidos automaticamente. Você pode desativar esse comportamento na <a href=":themes">página de configurações do tema</a>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9956, 'O módulo Field UI fornece uma interface de usuário (UI) administrativa para gerenciar e exibir campos. Os campos podem ser anexados à maioria dos subtipos de entidade de conteúdo. Diferentes tipos de campo, widgets e formatadores são fornecidos pelos módulos instalados em seu site e gerenciados pelo módulo Field. Para obter informações básicas e terminologia relacionadas a campos e entidades, consulte a <a href=":field">página de ajuda do módulo Field</a>. Para obter mais informações sobre o Field UI, consulte a <a href=":field_ui_docs">documentação online do módulo Field UI</a>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9957, 'Há dois relatórios disponíveis que listam os campos definidos em seu site. O relatório <a href=":entity-list" title="Entities field list report">Entidades</a> lista todos os seus campos, mostrando os nomes de máquina do campo, os tipos e os tipos ou subtipos de entidade em que são usados (cada subtipo é vinculado à página Gerenciar campos). Se os módulos <a href=":views">Views</a> e <a href=":views-ui">Views UI</a> estiverem instalados, o relatório <a href=":views-list" title="Used in views field list report">Usado em Views</a> listará cada campo usado em uma view, com um link para editar essa view.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9958, 'Você pode criar e editar formatos de texto na página <a href=":formats">Formatos de texto</a> (se o módulo Text Editor estiver instalado, essa página será chamada de Formatos e editores de texto). Um formato de texto é incluído por padrão: texto simples (que remove todas as tags HTML). Formatos de texto adicionais podem ser criados durante a instalação. Você pode criar um formato de texto clicando em "<a href=":add_format">Adicionar formato de texto</a>".', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9959, '<strong>Habilitar funcionalidade adicional</strong> Em seguida, visite a <a href=":modules">página Estender</a> e instale os módulos que atendam às suas necessidades específicas. Você pode encontrar módulos adicionais na <a href=":download_modules">página de módulos no Drupal.org</a>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9960, 'Os tópicos de ajuda fornecidos por módulos e temas também fazem parte do módulo Help. Se o módulo do núcleo Search estiver instalado, esses tópicos poderão ser pesquisados. Para mais informações, consulte a <a href=":online">documentação on-line, Padrões do tópico de ajuda</a>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9961, 'Algumas das configurações para campos de imagem são definidas uma vez quando você cria o campo e não podem ser alteradas posteriormente. Isso inclui a escolha do armazenamento de arquivos público ou privado e o número de imagens que podem ser armazenadas no campo. O restante das configurações pode ser editado posteriormente. Essas configurações incluem o rótulo do campo, o texto de ajuda, as extensões de arquivo permitidas, as restrições de dimensões da imagem e o subdiretório no armazenamento de arquivos público ou privado onde as imagens serão armazenadas. As configurações editáveis também podem ter valores diferentes para diferentes subtipos de entidade; por exemplo, se o campo de imagem for usado nos tipos de conteúdo Página e Artigo, você poderá armazenar os arquivos em um subdiretório diferente para os dois tipos de conteúdo.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9962, 'Você também pode configurar dimensões mínimas e/ou máximas para imagens carregadas. Imagens muito pequenas serão rejeitadas. As imagens muito grandes serão redimensionadas. Durante o redimensionamento, os <a href="http://wikipedia.org/wiki/Exchangeable_image_file_format">dados EXIF</a> na imagem serão perdidos.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9963, 'Dimensões mínimas da imagem', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9964, 'O módulo Language permite configurar os idiomas usados em seu site e fornece informações para os módulos <a href=":content">Content Translation</a>, <a href=":interface">Interface Translation</a> e <a href=":configuration">Interface Translation</a> , se estiverem instalados. Para obter mais informações, consulte a <a href=":doc_url">documentação on-line do módulo Language</a>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9965, 'Você pode adicionar idiomas na página <a href=":language_list">Idiomas</a> selecionando <em>Adicionar idioma</em> e escolhendo um idioma no menu suspenso. Esse idioma é exibido na lista de idiomas, onde pode ser configurado ainda mais. Se o módulo <a href=":interface">Interface translation</a> estiver instalado e o <em>servidor de tradução</em> estiver definido como uma fonte de tradução, a tradução de interface para esse idioma também será baixada automaticamente.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9966, 'Se o módulo Block estiver instalado, você poderá adicionar um bloco de alternador de idioma na página <a href=":blocks">Layout do bloco</a> para permitir que os usuários alternem entre os idiomas.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9967, 'Se o módulo Block estiver instalado, o módulo Language permitirá que você defina a visibilidade de um bloco com base nos idiomas selecionados na página <a href=":blocks">Layout do bloco</a>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9968, 'Os arquivos de tradução com texto de interface traduzido são importados automaticamente quando os idiomas são adicionados na página <a href=":languages">Idiomas</a> ou quando módulos ou temas são instalados. Na página Configurações de <a href=":locale-settings">tradução da interface</a>, a <em>fonte de tradução</em> pode ser restrita apenas a arquivos locais ou incluir o servidor de <a href=":server">tradução do Drupal</a>. Embora os módulos e temas possam não ser totalmente traduzidos em todos os idiomas, novas traduções são disponibilizadas com frequência. Você pode especificar se e com que frequência deseja verificar se há atualizações de arquivos de tradução e se deseja substituir as traduções existentes na página <a href=":locale-settings">Configurações de tradução da interface</a>. Você também pode importar manualmente um arquivo de tradução na página <a href=":import">de importação de tradução da interface</a>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9969, 'As traduções de interface são importadas automaticamente quando um idioma é adicionado ou quando novos módulos ou temas são instalados. O relatório <a href=":update">Atualizações de tradução disponíveis</a> mostra o status. O texto da interface pode ser personalizado na página de <a href=":translate">tradução da interface do usuário</a> .', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9970, 'Os arquivos de tradução são baixados e importados automaticamente quando <a title="Languages" href=":language">idiomas</a> são adicionados ou quando módulos ou temas são instalados.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9971, 'Use campos de referência de <em>Mídia</em> para a maioria dos arquivos, imagens, áudio, vídeos e mídia remota. Use os campos de referência <em>Arquivo</em> ou <em>Imagem</em> ao criar seus próprios tipos de mídia ou para arquivos e imagens legados criados antes da instalação do módulo Media.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9972, '%type_name: Exibir todas as páginas de revisão de mídia', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9973, 'Reverter %type_name: Reverter revisões de mídia', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9974, 'Excluir %type_name: Excluir revisões de mídia', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9975, 'Para mais informações, consulte a <a href=":drupal-org-help">documentação on-line do módulo Custom Menu Links</a>. Se você instalar o módulo Menu UI, ele fornecerá uma interface para gerenciar menus e links de menu.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (10009, 'Selecione Manipulação do logotipo de navegação', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (10010, 'Tamanhos máximos de arquivo (bytes)', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9977, 'Você precisa instalar todos os módulos neste site que estão instalados no site anterior. Por exemplo, se você usou o módulo Book no site anterior, deverá instalar o módulo Book neste site para que esses dados estejam disponíveis neste site.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9978, 'O módulo RESTful Web Services fornece uma estrutura para expor recursos REST em seu site. Ele fornece suporte para tipos de entidade de conteúdo, como o conteúdo do site principal, comentários, blocos de conteúdo, termos de taxonomia e contas de usuário, etc. (consulte a <a href=":field">página de ajuda do módulo Field</a> para obter mais informações sobre entidades). O suporte REST para itens de conteúdo do módulo Node é instalado por padrão e o suporte para outros tipos de entidades de conteúdo pode ser ativado. Outros módulos podem adicionar suporte para outros tipos de recursos REST. Para obter mais informações, consulte a <a href=":rest">documentação on-line do módulo RESTful Web Services</a>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9979, 'Os módulos que fornecem plugins de página de pesquisa geralmente garantem que as ações relacionadas ao conteúdo em seu site (criar, editar ou excluir conteúdo e comentários) façam com que os itens de conteúdo afetados sejam marcados automaticamente para indexação ou reindexação na próxima execução do cron. Quando o conteúdo é marcado para reindexação, o conteúdo anterior permanece no índice até que o cron seja executado, momento em que é substituído pelo novo conteúdo. No entanto, existem algumas ações relacionadas à estrutura do seu site que não fazem com que o conteúdo afetado seja marcado para reindexação. Exemplos de ações relacionadas à estrutura que afetam o conteúdo incluem excluir ou editar termos de taxonomia, instalar ou desinstalar módulos que adicionam texto ao conteúdo (como Taxonomy, Comment e módulos de fornecimento de campo) e modificar os campos ou parâmetros de exibição de seus tipos de conteúdo. Se você realizar uma dessas ações e quiser garantir que o índice de pesquisa seja atualizado para refletir a estrutura alterada do site, marque todo o conteúdo para reindexação clicando no botão "Reindexar site" na página <a href=":search-settings">Páginas de pesquisa</a>. Se você tiver muito conteúdo em seu site, pode levar várias execuções de cron para que o conteúdo seja reindexado.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9980, 'O módulo Search inclui um bloco que pode ser ativado e configurado na <a href=":blocks">página Layout do bloco</a>, se você tiver o módulo Block instalado; o título do bloco padrão é Pesquisar e é o bloco de formulário Pesquisar na categoria Formulários, se você deseja adicionar outra instância. O bloco está disponível para usuários com a permissão <a href=":search_permission">Usar pesquisa</a> e executa uma pesquisa usando a página de pesquisa padrão configurada.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9981, 'A data atual em formato ''curto''. (%date)', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9982, 'A data atual em formato ''médio''. (%date)', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9983, 'A data atual no formato ''longo''. (%date)', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9984, 'A data atual em um formato personalizado. Consulte <a href="https://www.php.net/manual/datetime.format.php#refsect1-datetime.format-parameters">a documentação do PHP</a> para obter detalhes.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9985, 'A data atual no formato ''time-since''. (%date)', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9986, 'A data atual no formato UNIX timestamp (%date)', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9987, 'A versão instalada de pelo menos um de seus módulos ou temas foi revogada e não está mais disponível para download. Atualizar ou desinstalar é altamente recomendado!', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9988, 'A versão instalada de pelo menos um de seus módulos ou temas não é mais suportada. Atualizar ou desinstalar é altamente recomendado. Veja a página inicial do projeto para mais detalhes.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9989, '<em>Papéis</em> são usados para agrupar e classificar usuários; Cada usuário pode receber um ou mais papéis. Normalmente, há dois papéis predefinidos: <em>Usuário anônimo</em> (usuários que não estão conectados) e <em>Usuário autenticado</em> (usuários registrados e conectados). Dependendo de como seu site foi configurado, um papel <em>de administrador</em> também pode estar disponível: os usuários com esse papel receberão automaticamente novas permissões sempre que um módulo for instalado. Você pode criar papéis adicionais na <a href=":roles">página de administração de papéis</a>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9990, 'A <a href=":accounts">página Configurações da conta</a> permite que você gerencie as configurações do nome exibido do papel de usuário anônimo, formulários de contato pessoal, configurações de registro de usuário e configurações de cancelamento de conta. Nesta página, você também pode gerenciar as configurações de personalização da conta e adaptar o texto das mensagens de e-mail que os usuários recebem quando se registram ou solicitam uma recuperação de senha. Você também pode definir qual função recebe automaticamente novas permissões sempre que um módulo é instalado (a função de Administrador).', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9991, 'Para criar e modificar suas próprias views usando a interface do usuário de administração e configuração, você precisará instalar o módulo Views UI do núcleo ou um módulo contribuído que forneça uma interface do usuário para Views. Consulte a <a href=":views-ui">página de ajuda do módulo Views UI</a> para obter mais informações.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9992, 'Limpador do diretório de stage', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9993, 'Os seguintes @element_type podem opcionalmente ser suportados por plugins habilitados e não devem ser adicionados ao campo "Tags HTML editáveis manualmente" da edição de código-fonte: %overlapping_tags.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9994, 'Incluir na raiz do projeto arquivos e diretórios não reconhecidos em operações de stage', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (9995, 'Os seguintes caminhos em @project_root não são reconhecidos como parte do seu site Drupal, então, para ficar seguro, o Package Manager está excluindo-os de todas as operações de stage. Se esses arquivos não forem necessários para que o Composer funcione corretamente no seu site, nenhuma ação será necessária. Caso contrário, você pode desabilitar esse comportamento definindo a configuração <code>package_manager.settings:include_unknown_files_in_project_root</code> como <code>TRUE</code>. 
