INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (10029, 'Ideal para contagens e medidas exatas (preços, temperaturas, distâncias, volumes, etc.)', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (10030, 'Armazena um número no banco de dados em um formato decimal fixo', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (10031, 'Por exemplo, 12,34 km ou € quando usado para cálculos mais detalhados (como somar muitos deles)', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (10032, 'Na maioria dos casos, é melhor usar Número (decimal), pois os números decimais armazenados como floats podem conter erros de precisão', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (10033, 'Esse tipo de campo oferece processamento mais rápido e armazenamento mais compacto, mas as diferenças geralmente são insignificantes em sites modernos', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (10034, 'Por exemplo, 123,4 km quando usado em contextos imprecisos, como uma distância de trilha de caminhada', 'pt-br', 0);
