INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (10043, 'Pode usar mais armazenamento e ser mais lendo para pesquisa e ordenamento', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (10044, 'Ideal para cálculos ou comparações de data e hora', 'pt-br', 0);
