INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (10047, 'O usuário %username não tem acesso de administrador. Para mais informações, consulte a documentação sobre <a href="@secure-user-1-docs">como proteger o super-usuário administrador</a>.', 'pt-br', 0);
