INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (10084, 'Quando habilitado, este módulo expõe todos os campos para todas as exibições de exibição de entidade. Quando desabilitado, somente os pacotes de tipo de entidade que têm o construtor de layout habilitado terão seus campos expostos. A habilitação desse módulo pode diminuir significativamente o desempenho em sites com um grande número de tipos de entidade e pacotes.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (10085, 'Não foi possível recuperar a URL remoto (@url): %error', 'pt-br', 0);
