INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (10094, 'Quando há um erro ao processar uma linha, o sistema de migração salva a mensagem de erro, mas não a(s) ID(s) de origem da linha. É por isso que algumas mensagens nesta tabela têm ''Não disponível'' na(s) coluna(s) de ID de origem.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (10095, 'O processo de atualização pode registrar mensagens sobre etapas que exigem ação ou erros do usuário. Esta página permite que você visualize estas mensagens', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (10096, 'Revise o log detalhado de atualização.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (10097, 'Digite as credenciais do banco de dados do site Drupal que você deseja atualizar, não do novo site.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (10098, 'Verifique se há conteúdo traduzido desses tipos:', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (10099, 'Possíveis conflitos de ID para traduções não são detectados automaticamente na versão atual do Drupal. Consulte o manual <a target="_blank" href=":id-conflicts-handbook">Atualizando o Drupal</a> para obter instruções sobre como evitar conflitos de ID com o conteúdo traduzido.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (10100, '<strong>Instale todos os módulos neste novo site</strong> que estão habilitados no site antigo. Por exemplo, se o site antigo usar o módulo Book, instale o módulo Book nesse novo site para que os dados existentes possam ser importados para ele.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (10101, 'O módulo Navigation fornece uma navegação na barra lateral vertical, recolhível e alinhada à esquerda.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (10102, 'Para mais informações, consulte a <a href=":docs">documentação on-line do módulo Navigation</a>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (10103, 'Esta ferramenta de criação de layout permite configurar os blocos na barra de ferramentas de navegação.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (10104, 'Os módulos Toolbar e Navigation estão instalados', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (10105, 'O módulo Navigation é um substituto completo para o módulo Toolbar e desativa sua funcionalidade quando ambos os módulos são instalados. Se você planeja continuar usando o módulo Navigation, pode desinstalar o módulo Toolbar agora.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (10106, 'Barra superior de navegação', 'pt-br', 0);
