INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (10110, 'Valores armazenados são números de ponto flutuante', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (10111, 'Por exemplo, ''Fração'': 0 => 0, .25 => 1/4, .75 => 3/4, 1 => 1', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (10112, 'Os valores armazenados são números sem decimais', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (10113, 'Por exemplo, ''Vida útil em dias'': 1 => 1 dia, 7 => 1 semana, 31 => 1 mês', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (10114, 'Valores armazenados são valores de texto', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (10115, 'Por exemplo, ''Estados Americanos'': IL => Illinois, IA => Iowa, IN => Indiana', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (10116, 'Especifique o caminho existente que você deseja criar um apelido. Por exemplo: /node/28, /media/1, /taxonomy/term/1.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (10117, 'Instale o módulo Help para obter mais informações sobre o atributo sizes.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (10118, 'Este tema requer que os módulos listados funcionem corretamente. Eles devem primeiro ser instalados por um usuário com permissões para fazer isso.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (10119, 'Este tema requer que os módulos listados funcionem corretamente. Eles devem primeiro ser instalados por meio da página <a href=":modules_url">Estender</a>.', 'pt-br', 0);
