INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (10171, 'O conteúdo está sendo editado no espaço de trabalho @label. Como resultado, suas alterações não podem ser salvas.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (10172, 'Umami é um exemplo de site de revista de comida que demonstra alguns dos recursos do núcleo do Drupal. Destina-se a ser usado como um site de exemplo, e não como uma base para a construção de seu próprio site. Para obter mais informações, consulte a <a href=":demo_umami">documentação on-line do perfil de instalação do Umami</a>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (10173, 'Demonstrando a funcionalidade principal do núcleo do Drupal', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (10174, 'Você pode procurar no site para obter ideias sobre quais tipos de recursos o Drupal é capaz e para ver como um site real pode ser construído usando o núcleo do Drupal.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (10175, 'O perfil Umami é muito útil se você estiver desenvolvendo um recurso e precisar de algum conteúdo de amostra.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (10176, 'O que fazer quando estiver pronto para criar seu site Drupal', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (10177, 'Depois de experimentar o Drupal usando o Umami e quiser criar seu próprio site, basta reinstalar o Drupal e selecionar um perfil de instalação diferente (como Padrão) na tela de instalação.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (10178, 'Alternar o menu', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (10179, 'Digite a cor no formato hexadecimal (#abc123).', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (10180, 'Obtenha suporte e converse com a comunidade Drupal no <a href="@drupal_slack">Slack</a> ou <a href="@drupal_chat">DrupalChat</a>. Quando você estiver procurando uma solução para um problema, acesse <a href="@drupal_support">Suporte do Drupal</a> ou <a href="@drupal_answers">Respostas do Drupal no Stack Exchange</a>.', 'pt-br', 0);
