INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (10231, 'Não conseguimos encontrar nenhum perfil de instalação. Os perfis de instalação nos dizem quais módulos instalar e qual esquema instalar no banco de dados. Um perfil é necessário para continuar com o processo de instalação.', 'pt-br', 0);
