INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (10233, 'O módulo Expose All Field Blocks do Layout Builder é um módulo Feature Flag que expõe todos os campos em todos os pacotes como blocos de campos para uso no Layout Builder.', 'pt-br', 0);
