INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (10235, 'Embora seja recomendado desinstalar este módulo, isso pode remover blocos que estão sendo usados ​​no seu site.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (10236, 'Por exemplo, se o Layout Builder estiver habilitado em um pacote Node (tipo de conteúdo) e a exibição desse pacote estiver usando blocos de campo de entidade Usuário (por exemplo, o nome do autor), mas o Layout Builder não estiver habilitado para o pacote Usuário, esse bloco de campo não mais existirá  após a desinstalação deste módulo.', 'pt-br', 0);
