INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (10281, 'O display "@display" precisa de um valor "Campos de busca" selecionado para funcionar corretamente. Veja as configurações para o formato "Lista de referência de entidade".', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (10282, 'Tipo de referência "@type"', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (10283, 'Por motivos de desempenho e UX, a contagem máxima de entidades selecionáveis ​​para o tipo de seleção "Selecionar lista" é limitada a @count. Se for esperado mais, selecione "Autocomplete".', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (10284, 'O módulo Workflows fornece uma API e uma interface para criar fluxos de trabalho com transições entre diferentes estados (por exemplo, publicação ou status do usuário). Eles precisam ser fornecidos por outros módulos, como o módulo <a href=":moderation">Content Moderation</a>. Para obter mais informações, consulte a <a href=":workflow">documentação on-line do módulo Workflows</a>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (10285, 'O módulo Workflows fornece uma API e uma interface para criar fluxos de trabalho com transições entre diferentes estados (por exemplo, publicação ou status do usuário). Eles precisam ser fornecidos por outros módulos, como o módulo Content Moderation. Para obter mais informações, consulte a <a href=":workflow">documentação on-line do módulo Workflows</a>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (10286, 'Adicionando fluxos de trabalho', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (10287, 'Você só pode adicionar fluxos de trabalho na <a href=":workflows">página Fluxos de trabalho</a> depois de instalar um módulo que aproveite a API, como o <a href=":moderation">módulo Moderação de conteúdo</a>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (10288, 'Você <em>só</em> pode adicionar fluxos de trabalho na <a href=":workflows">página Fluxos de trabalho</a> depois de instalar um módulo que aproveite a API, como o módulo Moderação de conteúdo.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (10289, 'Adicionando estados', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (10290, 'Um fluxo de trabalho requer pelo menos dois estados. Os estados podem ser adicionados quando você adiciona ou edita um fluxo de trabalho na <a href=":workflows">página Fluxos de trabalho</a>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (10291, 'Adicionando transições', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (10292, 'Uma transição define em qual estado um item pode ser salvo como próximo. Ele tem um estado de destino, mas pode ter vários estados <em>de</em> nos quais a transição pode ser aplicada. Transições podem ser adicionadas quando você adiciona ou edita um fluxo de trabalho na página <a href=":workflows">Fluxos de trabalho</a>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (10293, 'Configurando fluxos de trabalho ainda mais', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (10294, 'Dependendo do tipo de fluxo de trabalho instalado, configurações adicionais podem estar disponíveis no formulário de edição de um fluxo de trabalho.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (10295, 'Fornece uma API para preparar e visualizar conteúdo em um contexto de site completo.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (10296, 'Workspaces UI', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (10297, 'Fornece uma interface de usuário para criar e gerenciar espaços de trabalho.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (10298, 'O módulo Workspaces UI fornece uma interface para gerenciar workspaces para o <a href=":workspaces_module">módulo Workspaces</a>. Para obter mais informações, consulte a <a href=":workspaces">documentação on-line do módulo Workspaces UI</a>.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (10299, 'l, j F Y - H:i', 'pt-br', 0);
