INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (10301, 'E-mails de usuários conflitantes', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (10302, 'Algumas contas de usuário possuem endereços de e-mail que diferem apenas por maiúsculas e minúsculas. Por exemplo, uma conta pode ter alice@example.com e outra pode ter Alice@Example.com. Veja <a href=":url">E-mails de usuário conflitantes</a> para mais informações.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (10303, 'Extensão de caminho de ícone inválida @filename.@extension na origem: @source', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (10304, 'Caminho de ícone inválido na origem: @source', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (10305, 'Nenhum ícone encontrado na origem: @source', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (10306, 'Gerencia caminhos ou URLs para ícones.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (10307, 'Gerencia arquivos SVG de um ou vários caminhos; remoto não é permitido e será ignorado.', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (10308, 'Adicionar bloco de navegação', 'pt-br', 0);
INSERT INTO public.drupal_locales_target (lid, translation, language, customized) VALUES (10309, 'Você usou um link de login único. Agora você pode definir sua nova senha.', 'pt-br', 0);
